# >>> BEGIN FILE: R/core/statistical_tests.R
# ============================================================================
# statistical_tests.R - Advanced Statistical Testing Framework
# ============================================================================
# Provides hypothesis testing with multiple comparison correction,
# power analysis, and effect size reporting

#' Apply multiple testing correction to hypothesis results
#'
#' @param hypotheses List of hypothesis test results
#' @param method Correction method: "fdr" (BH), "bonferroni", "holm", "none"
#' @return Updated hypotheses with adjusted p-values
#' @export
apply_multiple_testing_correction <- function(hypotheses, method = "fdr") {
  if (!is.list(hypotheses) || length(hypotheses) == 0) {
    return(hypotheses)
  }
  
  # Extract p-values
  p_values <- sapply(hypotheses, function(h) {
    if (is.list(h) && "p_value" %in% names(h)) {
      h$p_value
    } else {
      NA
    }
  })
  
  # Apply correction
  if (method != "none" && length(p_values) > 1) {
    # Remove NAs for correction
    valid_idx <- !is.na(p_values)
    adjusted <- numeric(length(p_values))
    adjusted[!valid_idx] <- NA
    
    if (sum(valid_idx) > 0) {
      adjusted[valid_idx] <- p.adjust(p_values[valid_idx], method = method)
    }
  } else {
    adjusted <- p_values
  }
  
  # Update hypotheses
  for (i in seq_along(hypotheses)) {
    if (is.list(hypotheses[[i]]) && "p_value" %in% names(hypotheses[[i]])) {
      hypotheses[[i]]$p_value_adjusted <- adjusted[i]
      hypotheses[[i]]$correction_method <- method
      
      # Update significance based on adjusted p-value
      if (!is.na(adjusted[i])) {
        hypotheses[[i]]$significant_adjusted <- adjusted[i] < 0.05
      }
    }
  }
  
  hypotheses
}

#' Compute statistical power for a test
#'
#' @param effect_size Cohen's d effect size
#' @param n Sample size
#' @param alpha Significance level
#' @param test_type Type of test: "t", "correlation", "anova"
#' @return Power estimate
#' @export
compute_statistical_power <- function(effect_size, n, alpha = 0.05, test_type = "t") {
  if (effect_size == 0 || n < 2) return(0)
  
  if (test_type == "t") {
    # Power for two-sample t-test
    df <- n - 2
    ncp <- effect_size * sqrt(n / 2)
    crit <- qt(1 - alpha / 2, df)
    power <- 1 - pt(crit, df, ncp) + pt(-crit, df, ncp)
    return(power)
  } else if (test_type == "correlation") {
    # Power for correlation test
    z_r <- atanh(effect_size)  # Fisher's z
    se <- 1 / sqrt(n - 3)
    z_crit <- qnorm(1 - alpha / 2)
    power <- pnorm(z_r / se - z_crit) + pnorm(-z_r / se - z_crit)
    return(power)
  } else if (test_type == "anova") {
    # Power for one-way ANOVA
    # Cohen's f for ANOVA
    f <- effect_size
    df1 <- 1
    df2 <- n - 2
    lambda <- f^2 * n
    crit <- qf(1 - alpha, df1, df2)
    power <- 1 - pf(crit, df1, df2, lambda)
    return(power)
  }
  
  NA
}

#' Kolmogorov-Smirnov test for distribution fitting
#'
#' @param x Data vector
#' @param distribution Distribution to test: "norm", "lnorm", "exp", "gamma", "weibull"
#' @return Test results with p-value
#' @export
ks_distribution_test <- function(x, distribution = "lnorm") {
  x <- x[!is.na(x) & x > 0]
  
  if (length(x) < 10) {
    return(list(
      statistic = NA,
      p_value = NA,
      distribution = distribution,
      parameters = NULL,
      status = "error: insufficient data"
    ))
  }
  
  # Fit distribution
  fit_result <- tryCatch({
    if (distribution == "norm") {
      params <- fitdistrplus::fitdist(x, "norm")
      list(mean = params$estimate["mean"], sd = params$estimate["sd"])
    } else if (distribution == "lnorm") {
      params <- fitdistrplus::fitdist(x, "lnorm")
      list(meanlog = params$estimate["meanlog"], sdlog = params$estimate["sdlog"])
    } else if (distribution == "exp") {
      params <- fitdistrplus::fitdist(x, "exp")
      list(rate = params$estimate["rate"])
    } else if (distribution == "gamma") {
      params <- fitdistrplus::fitdist(x, "gamma")
      list(shape = params$estimate["shape"], rate = params$estimate["rate"])
    } else if (distribution == "weibull") {
      params <- fitdistrplus::fitdist(x, "weibull")
      list(shape = params$estimate["shape"], scale = params$estimate["scale"])
    }
  }, error = function(e) {
    # Fallback to simple estimation
    if (distribution == "norm") {
      list(mean = mean(x), sd = sd(x))
    } else if (distribution == "lnorm") {
      log_x <- log(x)
      list(meanlog = mean(log_x), sdlog = sd(log_x))
    } else if (distribution == "exp") {
      list(rate = 1 / mean(x))
    } else if (distribution == "gamma") {
      m <- mean(x)
      v <- var(x)
      list(shape = m^2 / v, rate = m / v)
    } else if (distribution == "weibull") {
      # Method of moments approximation
      list(shape = 1, scale = mean(x))
    }
  })
  
  # Run KS test
  ks_result <- tryCatch({
    if (distribution == "norm") {
      ks.test(x, "pnorm", mean = fit_result$mean, sd = fit_result$sd)
    } else if (distribution == "lnorm") {
      ks.test(x, "plnorm", meanlog = fit_result$meanlog, sdlog = fit_result$sdlog)
    } else if (distribution == "exp") {
      ks.test(x, "pexp", rate = fit_result$rate)
    } else if (distribution == "gamma") {
      ks.test(x, "pgamma", shape = fit_result$shape, rate = fit_result$rate)
    } else if (distribution == "weibull") {
      ks.test(x, "pweibull", shape = fit_result$shape, scale = fit_result$scale)
    }
  }, error = function(e) NULL)
  
  if (is.null(ks_result)) {
    return(list(
      statistic = NA,
      p_value = NA,
      distribution = distribution,
      parameters = fit_result,
      status = "error: KS test failed"
    ))
  }
  
  list(
    statistic = ks_result$statistic,
    p_value = ks_result$p.value,
    distribution = distribution,
    parameters = fit_result,
    significant = ks_result$p.value < 0.05,
    interpretation = if (ks_result$p.value < 0.05) {
      sprintf("Data does NOT fit %s distribution (p = %.4f)", distribution, ks_result$p.value)
    } else {
      sprintf("Data is consistent with %s distribution (p = %.4f)", distribution, ks_result$p.value)
    },
    status = "success"
  )
}

#' Anderson-Darling normality test
#'
#' @param x Data vector
#' @return Test results
#' @export
anderson_darling_test <- function(x) {
  x <- x[!is.na(x)]
  n <- length(x)
  
  if (n < 8) {
    return(list(
      statistic = NA,
      p_value = NA,
      normal = NA,
      status = "error: insufficient data (n <8)"
    ))
  }
  
  # If nortest is available, use it
  ad_result <- tryCatch({
    if (requireNamespace("nortest", quietly = TRUE)) {
      test <- nortest::ad.test(x)
      list(statistic = test$statistic, p_value = test$p.value)
    } else {
      # Manual calculation
      mean_x <- mean(x)
      sd_x <- sd(x)
      y <- sort((x - mean_x) / sd_x)
      log_p <- pnorm(y, log.p = TRUE)
      log_q <- pnorm(-y, log.p = TRUE)
      AD <- -n - sum((2 * (1:n) - 1) * (log_p + rev(log_q))) / n
      
      # Adjusted p-value (approximation)
      AD_star <- AD * (1 + 0.75/n + 2.25/n^2)
      p_value <- exp(-1.2337141 - 1.096497 * AD_star)
      p_value <- min(1, max(0, p_value))
      
      list(statistic = AD, p_value = p_value)
    }
  }, error = function(e) {
    list(statistic = NA, p_value = NA)
  })
  
  list(
    statistic = ad_result$statistic,
    p_value = ad_result$p_value,
    normal = ad_result$p_value > 0.05,
    interpretation = if (ad_result$p_value > 0.05) {
      "Data is consistent with normal distribution"
    } else {
      "Data deviates significantly from normal distribution"
    },
    status = "success"
  )
}

#' Chi-square goodness of fit test
#'
#' @param observed Vector of observed counts
#' @param expected Vector of expected counts (or "equal" for uniform)
#' @return Test results
#' @export
chi_square_gof_test <- function(observed, expected = "equal") {
  observed <- observed[!is.na(observed)]
  n <- length(observed)
  
  if (n < 2) {
    return(list(
      statistic = NA,
      p_value = NA,
      df = NA,
      status = "error: insufficient categories"
    ))
  }
  
  if (is.character(expected) && expected == "equal") {
    expected <- rep(sum(observed) / n, n)
  }
  
  # Chi-square statistic
  chi_sq <- sum((observed - expected)^2 / expected)
  df <- n - 1
  p_value <- 1 - pchisq(chi_sq, df)
  
  list(
    statistic = chi_sq,
    p_value = p_value,
    df = df,
    observed = observed,
    expected = expected,
    significant = p_value < 0.05,
    interpretation = if (p_value < 0.05) {
      sprintf("Observed distribution differs from expected (chi-sq = %.2f, p = %.4f)", chi_sq, p_value)
    } else {
      sprintf("Observed distribution matches expected (chi-sq = %.2f, p = %.4f)", chi_sq, p_value)
    },
    status = "success"
  )
}

#' Benford's Law test for citation counts
#'
#' @param x Numeric vector (citation counts)
#' @return Test results
#' @export
benford_test <- function(x) {
  x <- x[!is.na(x) & x > 0]
  
  if (length(x) < 30) {
    return(list(
      statistic = NA,
      p_value = NA,
      significant = NA,
      status = "error: insufficient data (n< 30)"
    ))
  }
  
  # Extract first digits
  first_digits <- as.numeric(substr(as.character(x), 1, 1))
  first_digits <- first_digits[first_digits %in% 1:9]
  
  if (length(first_digits) < 30) {
    return(list(
      statistic = NA,
      p_value = NA,
      status = "error: insufficient valid first digits"
    ))
  }
  
  # Observed frequencies
  observed <- table(factor(first_digits, levels = 1:9))
  
  # Benford's Law expected frequencies
  expected <- length(first_digits) * log10(1 + 1 / (1:9))
  
  # Chi-square test
  chi_sq <- sum((observed - expected)^2 / expected)
  df <-8
  p_value <- 1 - pchisq(chi_sq, df)
  
  # Deviation from Benford's Law by digit
  deviation <- (observed - expected) / expected
  
  list(
    statistic = chi_sq,
    p_value = p_value,
    df = df,
    observed = observed,
    expected = expected,
    deviation = deviation,
    significant = p_value < 0.05,
    follows_benford = p_value >= 0.05,
    interpretation = if (p_value >= 0.05) {
      "Citation counts follow Benford's Law (no manipulation detected)"
    } else {
      "Citation counts deviate from Benford's Law (potential anomaly)"
    },
    status = "success"
  )
}

#' Levene's test for homogeneity of variance
#'
#' @param groups List of vectors to compare
#' @return Test results
#' @export
levene_test <- function(groups) {
  if (!is.list(groups) || length(groups) < 2) {
    return(list(
      statistic = NA,
      p_value = NA,
      status = "error: need at least 2 groups"
    ))
  }
  
  # Remove NAs
  groups <- lapply(groups, function(g) g[!is.na(g)])
  
  # Check minimum size
  if (any(sapply(groups, length) < 2)) {
    return(list(
      statistic = NA,
      p_value = NA,
      status = "error: each group needs at least 2 observations"
    ))
  }
  
  # Compute group medians
  medians <- sapply(groups, median)
  
  # Compute absolute deviations from median
  deviations <- lapply(seq_along(groups), function(i) {
    abs(groups[[i]] - medians[i])
  })
  
  # One-way ANOVA on deviations
  all_dev <- unlist(deviations)
  group_labels <- rep(seq_along(groups), sapply(groups, length))
  
  # Calculate ANOVA
  k <- length(groups)
  n_total <- length(all_dev)
  grand_mean <- mean(all_dev)
  
  group_means <- sapply(deviations, mean)
  group_sizes <- sapply(groups, length)
  
  ss_between <- sum(group_sizes * (group_means - grand_mean)^2)
  ss_within <- sum(sapply(seq_along(groups), function(i) {
    sum((deviations[[i]] - group_means[i])^2)
  }))
  
  df_between <- k - 1
  df_within <- n_total - k
  
  ms_between <- ss_between / df_between
  ms_within <- ss_within / df_within
  
  F_stat <- ms_between / ms_within
  p_value <- 1 - pf(F_stat, df_between, df_within)
  
  list(
    statistic = F_stat,
    p_value = p_value,
    df1 = df_between,
    df2 = df_within,
    homogeneous = p_value >= 0.05,
    interpretation = if (p_value >= 0.05) {
      "Variances are homogeneous (Levene's test p >= 0.05)"
    } else {
      "Variances are heterogeneous (Levene's test p <0.05)"
    },
    status = "success"
  )
}

#' Walsh test for multiple outliers
#'
#' @param x Numeric vector
#' @param alpha Significance level
#' @return Indices of outliers
#' @export
walsh_outlier_test <- function(x, alpha = 0.05) {
  x <- sort(x[!is.na(x)])
  n <- length(x)
  
  if (n < 10) {
    return(list(
      outliers = integer(0),
      n_outliers = 0,
      status = "error: insufficient data"
    ))
  }
  
  # Walsh test
  k <- ceiling(sqrt(n))
  lower_threshold <- x[k + 1] - (x[n - k] - x[k + 1]) / (n - 2 * k - 1) * qnorm(1 - alpha / 2)
  upper_threshold <- x[n - k] + (x[n - k] - x[k + 1]) / (n - 2 * k - 1) * qnorm(1 - alpha / 2)
  
  outliers <- which(x < lower_threshold | x > upper_threshold)
  
  list(
    outliers = outliers,
    outlier_values = x[outliers],
    lower_threshold = lower_threshold,
    upper_threshold = upper_threshold,
    n_outliers = length(outliers),
    status = "success"
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/core/statistical_tests.R

# >>> BEGIN FILE: R/core/utils_null_coalescing.R
# ============================================================================
# utils_null_coalescing.R - Null Coalescing Operator
# ============================================================================
# Central definition of null coalescing operator to avoid duplicate definitions

#' Null coalescing operator
#'
#' Returns the left operand if not NULL, otherwise the right operand.
#' This is a central definition to avoid duplicate definitions across modules.
#'
#' @param a First value (can be NULL)
#' @param b Second value (fallback)
#' @return a if not NULL, otherwise b
#' @export
`%||%` <- function(a, b) {
  if (is.null(a)) b else a
}

#' Null coalescing for strings
#'
#' Returns empty string if value is NA or NULL
#' @param x Value to check
#' @return x if not NA/NULL, otherwise ""
#' @export
null_to_empty <- function(x) {
  if (is.null(x) || is.na(x)) "" else as.character(x)
}

#' Safe get from list
#'
#' Safely get a value from a list with default
#' @param lst List to get from
#' @param key Key to retrieve
#' @param default Default value if not found
#' @return Value or default
#' @export
safe_get <- function(lst, key, default = NULL) {
  if (is.null(lst) || !is.list(lst)) return(default)
  if (!key %in% names(lst)) return(default)
  lst[[key]] %||% default
}
# <<< END FILE: R/core/utils_null_coalescing.R

# >>> BEGIN FILE: R/core/validation.R
# ============================================================================
# validation.R - Shared validation helpers
# ============================================================================

#' Validate that input is a data frame
#'
#' @param data An object to check.
#' @param label Character. Label for error messages.
#' @return TRUE invisibly if valid; stops with error otherwise.
#' @export
validate_is_data_frame <- function(data, label = "data") {
  if (!is.data.frame(data)) {
    cli::cli_abort("{label} must be a data frame, got {class(data)}.")
  }
  invisible(TRUE)
}

#' Validate required columns exist in a data frame
#'
#' @param data A data frame.
#' @param required_columns Character vector of column names.
#' @return A list with \code{ok} (logical) and \code{missing_columns} (character).
#' @export
validate_required_columns <- function(data, required_columns) {
  present <- intersect(required_columns, names(data))
  missing <- setdiff(required_columns, names(data))
  list(
    ok              = length(missing) == 0,
    missing_columns = missing
  )
}
# <<< END FILE: R/core/validation.R

# >>> BEGIN FILE: R/data/rbibliosynth_data.R
# ============================================================================
# rbibliosynth_data.R - Embedded Sample Dataset for RBiblioSynth
# ============================================================================
# This file creates a comprehensive sample dataset for testing, demos, and vignettes.
# The dataset simulates a bibliometric analysis in the field of renewable energy.

#' @title Sample Bibliometric Dataset for Renewable Energy Research
#' @description A simulated bibliometric dataset representing publications in renewable energyresearch from 2010-2023.
#' @format A data frame with 500 observations and 20 variables:
#' \itemize{
#'   \item \code{AU}: Authors (semicolon-separated)
#'   \item \code{TI}: Title
#'   \item \code{PY}: Publication year
#'   \item \code{SO}: Source/Journal name
#'   \item \code{TC}: Times cited
#'   \item \code{DI}: DOI
#'   \item \code{AB}: Abstract
#'   \item \code{AU_CO}: Author countries (semicolon-separated)
#'   \item \code{DE}: Author keywords (semicolon-separated)
#'   \item \code{ID}: Keywords Plus (semicolon-separated)
#'   \item \code{DT}: Document type
#'   \item \code{LA}: Language
#'   \item \code{NR}: Number of references
#'   \item \code{PN}: Page count
#'   \item \code{DB}: Source database
#' }
#' @keywords datasets
#' @export
"biblio_sample"

# ============================================================================
# Dataset Generation Function
# ============================================================================

#' Generate sample bibliometric dataset
#' @keywords internal
generate_biblio_sample <- function() {
  set.seed(42)
  n <- 500
  
  # Author pools by country
  authors <- list(
    USA = c("Smith J", "Johnson M", "Williams R", "Brown K", "Davis L", "Miller A", "Wilson T", "Moore E"),
    China = c("Wang Y", "Li X", "Zhang H", "Liu W", "Chen Z", "Yang M", "Huang G", "Zhou B"),
    UK = c("Taylor S", "Davies P", "Evans N", "Thomas R", "Johnson K", "Roberts M", "Walker J", "Wright B"),
    Germany = c("Mueller H", "Schmidt F", "Weber G", "Wagner K", "Becker L", "Hoffmann R", "Schulz M"),
    Japan = c("Tanaka K", "Suzuki Y", "Takahashi M", "Watanabe T", "Yamamoto H", "Nakamura J"),
    Brazil = c("Silva C", "Santos P", "Oliveira A", "Costa M", "Pereira R", "Rodrigues F"),
    India = c("Kumar S", "Sharma R", "Patel A", "Singh N", "Gupta V", "Verma P"),
    France = c("Martin L", "Bernard G", "Dubois R", "Thomas J", "Robert Y", "Richard M"),
    Australia = c("Brown D", "Jones M", "Miller K", "Davis R", "Wilson J", "Taylor P"),
    Canada = c("Tremblay M", "Gagnon L", "Roy P", "Gauthier R", "Lavoie J", "Belanger F")
  )
  
  countries <- names(authors)
  
  # Journal pool
  journals <- c(
    "Renewable Energy",
    "Solar Energy",
    "Wind Engineering",
    "Journal of Cleaner Production",
    "Energy Policy",
    "Applied Energy",
    "Energy Conversion and Management",
    "Renewable and Sustainable Energy Reviews",
    "International Journal of Energy Research",
    "Energy"
  )
  
  # Keywords pool
  keywords <- c(
    "solar energy", "photovoltaic", "wind power", "renewable energy",
    "energy storage", "battery", "fuel cell", "hydrogen",
    "sustainability", "carbon emissions", "energy efficiency",
    "smart grid", "microgrid", "energy management",
    "wind turbine", "solar panel", "biomass", "geothermal",
    "ocean energy", "hydropower", "nuclear energy",
    "energy policy", "climate change", "carbon footprint",
    "life cycle assessment", "energy economics"
  )
  
  # Document types
  doc_types <- c("article", "review", "conference paper", "book chapter", "letter")
  doc_probs <- c(0.65, 0.15, 0.12, 0.05, 0.03)
  
  # Generate records
  records <- vector("list", n)
  
  for (i in 1:n) {
    # Publication year (more recent = more publications)
    year_weights <- exp(seq(0, 1, length.out = 14))
    year_weights <- year_weights / sum(year_weights)
    year <- sample(2010:2023, 1, prob = year_weights)
    
    # Number of authors (1-8, skewed towards fewer)
    n_authors <- sample(1:8, 1, prob = c(0.15, 0.25, 0.25, 0.15, 0.10, 0.05, 0.03, 0.02))
    
    # Select countries for authors
    n_countries <- sample(1:min(4, n_authors), 1)
    selected_countries <- sample(countries, min(n_countries, length(countries)))
    
    # Generate authors
    author_list <- character(0)
    country_list <- character(0)
    
    for (j in 1:n_authors) {
      # Assign author to a country (may have multiple authors from same country)
      cntry <- sample(selected_countries, 1)
      auth_pool <- authors[[cntry]]
      author_list <- c(author_list, sample(auth_pool, 1))
      country_list <- c(country_list, cntry)
    }
    
    # Citation count (follows log-normal distribution, age-adjusted)
    age <- 2024 - year
    base_citations <- exp(rnorm(1, mean = log(10 + 5 * age), sd = 1))
    citations <- round(pmax(0, base_citations))
    
    # Journal
    journal <- sample(journals, 1)
    
    # Keywords (3-8 keywords)
    n_kw <- sample(3:8, 1)
    doc_keywords <- sample(keywords, min(n_kw, length(keywords)))
    
    # Document type
    dt <- sample(doc_types, 1, prob = doc_probs)
    
    # Title (realistic-sounding)
    title_parts <- c(
      paste(sample(c("Advances in", "Analysis of", "Development of", "Optimization of",
                      "Review of", "Assessment of", "Impact of", "Modeling of"), 1),
            sample(keywords, 1)),
      paste(sample(keywords, 1), "and", sample(keywords, 1)),
      paste(sample(c("A novel approach to", "Critical review of", "Comparative study of",
                      "Recent developments in", "Future prospects of"), 1),sample(keywords, 1))
    )
    title <- paste(sample(title_parts, 1), "in renewable energy")
    
    # Abstract (placeholder)
    abstract <- paste("This study investigates", paste(sample(keywords, 3), collapse = ", "),
                      ". Our analysis shows significant results.")
    
    # DOI
    doi <- paste0("10.", sample(1000:9999, 1), "/", sample(letters, 8, replace = TRUE), collapse = "")
    
    # Create record
    records[[i]] <- data.frame(
      AU = paste(unique(author_list), collapse = "; "),
      TI = title,
      PY = year,
      SO = journal,
      TC = citations,
      DI = doi,
      AB = abstract,
      AU_CO = paste(unique(country_list), collapse = "; "),
      DE = paste(doc_keywords, collapse = "; "),
      ID = paste(toupper(doc_keywords), collapse = "; "),
      DT = dt,
      LA = "English",
      NR = sample(5:80, 1),
      PN = sample(1:25, 1),
      DB = sample(c("SCOPUS", "WOS"), 1, prob = c(0.6, 0.4)),
      stringsAsFactors = FALSE
    )
  }
  
  # Combine all records
  df <- do.call(rbind, records)
  rownames(df) <- NULL
  
  # Add citations per year (age-adjusted citation metric)
  df$TC_PER_YEAR <- round(df$TC / (2024 - df$PY + 1), 2)
  
  # Add reference count if missing
  df$NR[is.na(df$NR)] <- sample(10:60, sum(is.na(df$NR)))
  
  df
}

# Generate dataset in memory
biblio_sample <- generate_biblio_sample()

#' @title Sample Annual Production Dataset
#' @description Aggregated annual production series derived from \code{biblio_sample}.
#' @format A data frame with yearly publication counts and cumulative growth metrics:
#' \itemize{
#'   \item \code{Year}: Publication year
#'   \item \code{Articles}: Number of publications
#'   \item \code{Cumulative}: Cumulative publications
#'   \item \code{Growth}: Year-over-year growth percentage
#' }
#' @keywords datasets
#' @export
"annual_sample"

# Also create annual production data
annual_sample <- aggregate(TC ~ PY, data = biblio_sample, FUN = length)
names(annual_sample) <- c("Year", "Articles")
annual_sample <- annual_sample[order(annual_sample$Year), ]

# Add cumulative
annual_sample$Cumulative <- cumsum(annual_sample$Articles)
annual_sample$Growth <- c(NA, diff(annual_sample$Articles) / head(annual_sample$Articles, -1) * 100)

# ============================================================================
# Sample Country Data for M3 Testing
# ============================================================================

#' @title Sample Country-Level Dataset for M3 Module
#' @description Aggregated country-level publication data derived from biblio_sample.
#' @keywords datasets
#' @export
"country_sample"

generate_country_sample <- function(bib_data) {
  # Extract country-author counts
  country_records <- strsplit(bib_data$AU_CO, "; ")
  country_records <- lapply(country_records, function(x) unique(trimws(x)))
  
  # Count publications per country
  all_countries <- unlist(country_records)
  country_counts <- table(all_countries)
  
  # Create data frame
  df <- data.frame(
    country = names(country_counts),
    articles = as.numeric(country_counts),
    stringsAsFactors = FALSE
  )
  
  # Sort by articles
  df <- df[order(-df$articles), ]
  rownames(df) <- NULL
  
  # Add rank
  df$rank <- seq_len(nrow(df))
  
  # Add SCP/MCP (simplified)
  # SCP = single country publications
  # MCP = multi-country publications
  scp_counts <- sapply(country_records, function(x) if (length(x) == 1) x[1] else NA)
  mcp_records <- sapply(country_records, function(x) if (length(x) > 1) x else NA)
  
  scp_table <- table(na.omit(scp_counts))
  mcp_list <- unlist(mcp_records[!is.na(mcp_records)])
  mcp_table <- table(mcp_list)
  
  df$scp <- scp_table[df$country]
  df$scp[is.na(df$scp)] <- 0
  df$mcp <- mcp_table[df$country]
  df$mcp[is.na(df$mcp)] <- 0
  
  # MCP ratio
  df$mcp_ratio <- df$mcp / (df$scp + df$mcp)
  df$mcp_ratio[is.na(df$mcp_ratio)] <- 0
  
  # Average citations (simplified)
  avg_cit <- tapply(bib_data$TC, sapply(country_records, function(x) x[1]), mean)
  df$avg_citations <- avg_cit[df$country]
  df$avg_citations[is.na(df$avg_citations)] <- 0
  
  df
}

country_sample <- generate_country_sample(biblio_sample)
# <<< END FILE: R/data/rbibliosynth_data.R

# >>> BEGIN FILE: R/module_m0/m0_connectors.R
# ============================================================================
# m0_connectors.R - API connectors and enrichment helpers for M0
# ============================================================================

#' Return available M0 API connectors
#' @export
m0_get_connector_registry <- function() {
  list(
    openalex = list(mode = "source", fetch = m0_fetch_openalex_source),
    crossref = list(mode = "source", fetch = m0_fetch_crossref_source),
    pubmed = list(mode = "source", fetch = m0_fetch_pubmed_source),
    orcid = list(mode = "enrichment", fetch = m0_fetch_orcid_profile),
    ror = list(mode = "enrichment", fetch = m0_fetch_ror_organization)
  )
}

#' Fetch an API source using the connector registry
#' @keywords internal
m0_fetch_api_source <- function(spec, config = biblio_config()) {
  registry <- m0_get_connector_registry()
  db <- tolower(trimws(as.character(spec$db %||% NA_character_)))
  if (!db %in% names(registry)) {
    cli::cli_abort("No API connector registered for db '{db}'.")
  }

  connector <- registry[[db]]
  connector$fetch(spec, config)
}

#' Enrich merged records and affiliations via API providers
#' @export
m0_enrich_merged_records <- function(merged, config = biblio_config(), providers = NULL) {
  config <- merge_biblio_config(config)
  if (is.null(providers) || identical(providers, TRUE)) {
    providers <- config$enrichment_sources
  }
  providers <- unique(tolower(as.character(providers)))
  merged <- m0_org_prepare_input(merged)

  enrichment_log <- list()

  if (any(providers %in% c("crossref", "openalex")) && "DI" %in% names(merged)) {
    lookup_rows <- vector("list", nrow(merged))
    for (i in seq_len(nrow(merged))) {
      doi <- trimws(as.character(merged$DI[i] %||% ""))
      if (!nzchar(doi)) next
      metadata <- m0_lookup_document_metadata(doi, providers, config)
      if (length(metadata) == 0) next
      updated <- m0_apply_document_enrichment(merged[i, , drop = FALSE], metadata)
      merged[i, names(updated)] <- updated[1, names(updated), drop = FALSE]
      lookup_rows[[i]] <- data.frame(
        M0_DOC_ID = merged$M0_DOC_ID[i],
        doi = doi,
        providers = paste(names(metadata), collapse = ";"),
        stringsAsFactors = FALSE
      )
    }
    enrichment_log$document_enrichment <- dplyr::bind_rows(lookup_rows)
  }

  affiliations <- m0_org_affiliations(merged)
  if ("ror" %in% providers && nrow(affiliations) > 0) {
    ror_matches <- m0_match_affiliations_to_ror(affiliations, config)
    enrichment_log$ror_matches <- ror_matches
  }

  if ("orcid" %in% providers && !is.null(config$orcid_access_token) && "OI" %in% names(merged)) {
    orcid_profiles <- m0_collect_orcid_profiles(merged$OI, config)
    enrichment_log$orcid_profiles <- orcid_profiles
  }

  list(merged = merged, enrichment = enrichment_log)
}

m0_is_api_source_spec <- function(spec) {
  mode <- tolower(trimws(as.character(spec$mode %||% "")))
  identical(mode, "api") || (is.null(spec$file) && !is.null(spec$query))
}

m0_fetch_openalex_source <- function(spec, config = biblio_config()) {
  params <- list(
    `per-page` = as.integer(spec$limit %||% config$api_limit),
    search = spec$query %||% NULL,
    filter = spec$filter %||% NULL,
    mailto = config$api_email %||% NULL,
    api_key = config$openalex_api_key %||% NULL
  )
  url <- m0_build_url("https://api.openalex.org/works", params)
  payload <- m0_api_get_json(url)
  records <- payload$results %||% list()
  m0_map_openalex_records(records)
}

m0_fetch_crossref_source <- function(spec, config = biblio_config()) {
  params <- list(
    rows = as.integer(spec$limit %||% config$api_limit),
    mailto = config$api_email %||% NULL
  )

  if (!is.null(spec$doi) && nzchar(trimws(as.character(spec$doi)))) {
    url <- paste0("https://api.crossref.org/works/", utils::URLencode(spec$doi, reserved = TRUE))
  } else {
    params[["query.bibliographic"]] <- spec$query %||% NULL
    if (!is.null(spec$filter)) params$filter <- spec$filter
    url <- m0_build_url("https://api.crossref.org/works", params)
  }

  payload <- m0_api_get_json(url)
  message <- payload$message %||% list()
  records <- if (!is.null(message$items)) message$items else list(message)
  m0_map_crossref_records(records)
}

m0_fetch_pubmed_source <- function(spec, config = biblio_config()) {
  ids <- spec$ids %||% NULL
  if (is.null(ids)) {
    search_params <- list(
      db = "pubmed",
      retmode = "json",
      retmax = as.integer(spec$limit %||% config$api_limit),
      term = spec$query %||% NULL
    )
    search_url <- m0_build_url("https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi", search_params)
    search_payload <- m0_api_get_json(search_url)
    ids <- search_payload$esearchresult$idlist %||% character()
  }

  ids <- unique(as.character(unlist(ids)))
  ids <- ids[nzchar(ids)]
  if (length(ids) == 0) return(data.frame())

  summary_params <- list(
    db = "pubmed",
    retmode = "json",
    id = paste(ids, collapse = ",")
  )
  summary_url <- m0_build_url("https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esummary.fcgi", summary_params)
  summary_payload <- m0_api_get_json(summary_url)
  m0_map_pubmed_records(summary_payload$result %||% list())
}

m0_fetch_orcid_profile <- function(orcid_id, config = biblio_config()) {
  token <- config$orcid_access_token %||% NULL
  if (is.null(token) || !nzchar(token)) {
    cli::cli_warn("ORCID enrichment requires an ORCID access token. Set config$orcid_access_token or ORCID_ACCESS_TOKEN.")
    return(list())
  }

  orcid_id <- gsub("^https?://orcid.org/", "", trimws(as.character(orcid_id)))
  url <- paste0("https://pub.orcid.org/v3.0/", orcid_id, "/record")
  headers <- c(
    "Accept" = "application/json",
    "Authorization" = paste("Bearer", token)
  )
  m0_api_get_json(url, headers = headers)
}

m0_fetch_ror_organization <- function(query, config = biblio_config()) {
  query <- trimws(as.character(query))
  if (!nzchar(query)) return(list())

  base <- "https://api.ror.org/v2/organizations"
  if (grepl("^https?://ror.org/", query, ignore.case = TRUE) || grepl("^[0-9a-z]{9}$", query, ignore.case = TRUE)) {
    clean_id <- gsub("^https?://ror.org/", "", query, ignore.case = TRUE)
    return(m0_api_get_json(paste0(base, "/", clean_id)))
  }

  url <- m0_build_url(base, list(query = query))
  m0_api_get_json(url)
}

m0_lookup_document_metadata <- function(doi, providers, config) {
  out <- list()
  doi <- gsub("^https?://(dx\\.)?doi\\.org/", "", trimws(as.character(doi)), ignore.case = TRUE)
  if (!nzchar(doi)) return(out)

  if ("crossref" %in% providers) {
    crossref <- tryCatch(
      m0_fetch_crossref_source(list(db = "crossref", mode = "api", doi = doi, limit = 1L), config),
      error = function(e) data.frame()
    )
    if (is.data.frame(crossref) && nrow(crossref) > 0) out$crossref <- crossref[1, , drop = FALSE]
  }
  if ("openalex" %in% providers) {
    params <- list(
      filter = paste0("doi:https://doi.org/", doi),
      limit = 1L,
      db = "openalex",
      mode = "api"
    )
    openalex <- tryCatch(m0_fetch_openalex_source(params, config), error = function(e) data.frame())
    if (is.data.frame(openalex) && nrow(openalex) > 0) out$openalex <- openalex[1, , drop = FALSE]
  }

  out
}

m0_apply_document_enrichment <- function(row_df, metadata) {
  out <- data.frame(row_df, stringsAsFactors = FALSE)
  if (length(metadata) == 0) return(out)

  missing_first_fields <- c("AB", "DE", "ID", "SO", "PU", "SN", "C1", "AU_UN", "AU_CO", "OI", "FX", "FU")
  for (provider in names(metadata)) {
    candidate <- metadata[[provider]]
    if (!is.data.frame(candidate) || nrow(candidate) == 0) next
    for (field in intersect(names(candidate), names(out))) {
      if (field %in% missing_first_fields) {
        if (!m0_has_value(out[[field]][1]) && m0_has_value(candidate[[field]][1])) {
          out[[field]][1] <- candidate[[field]][1]
        }
      } else if (field == "TC") {
        tc_vals <- c(
          suppressWarnings(as.numeric(out[[field]][1])),
          suppressWarnings(as.numeric(candidate[[field]][1]))
        )
        tc_vals <- tc_vals[!is.na(tc_vals)]
        out[[field]][1] <- if (length(tc_vals) > 0) max(tc_vals) else NA_real_
      }
    }
  }
  out
}

m0_match_affiliations_to_ror <- function(affiliations, config = biblio_config()) {
  if (!is.data.frame(affiliations) || nrow(affiliations) == 0) return(data.frame())

  institutions <- unique(affiliations$institution[!is.na(affiliations$institution) & nzchar(affiliations$institution)])
  rows <- list()

  for (inst in institutions) {
    payload <- tryCatch(m0_fetch_ror_organization(inst, config), error = function(e) list())
    items <- payload$items %||% payload$items_with_scores %||% list()
    if (length(items) == 0) next

    first_item <- items[[1]]
    item_obj <- first_item$organization %||% first_item
    chosen <- first_item$chosen %||% NA
    rows[[length(rows) + 1L]] <- data.frame(
      institution = inst,
      ror_id = item_obj$id %||% NA_character_,
      ror_name = item_obj$name %||% NA_character_,
      country = (item_obj$locations[[1]]$geonames_details$country_name %||% item_obj$country$country_name %||% NA_character_),
      confidence = suppressWarnings(as.numeric(first_item$score %||% NA_real_)),
      chosen = as.logical(chosen),
      stringsAsFactors = FALSE
    )
  }

  dplyr::bind_rows(rows)
}

m0_collect_orcid_profiles <- function(orcid_values, config = biblio_config()) {
  orcid_values <- unique(unlist(strsplit(paste(orcid_values, collapse = ";"), ";", fixed = TRUE)))
  orcid_values <- trimws(orcid_values)
  orcid_values <- orcid_values[!is.na(orcid_values) & nzchar(orcid_values)]

  rows <- list()
  for (orcid_id in orcid_values) {
    payload <- tryCatch(m0_fetch_orcid_profile(orcid_id, config), error = function(e) list())
    if (length(payload) == 0) next

    person <- payload$person %||% list()
    name_obj <- person$name %||% list()
    biography <- person$biography$content %||% NA_character_
    rows[[length(rows) + 1L]] <- data.frame(
      orcid = orcid_id,
      given_names = name_obj$`given-names`$value %||% NA_character_,
      family_name = name_obj$`family-name`$value %||% NA_character_,
      credit_name = name_obj$`credit-name`$value %||% NA_character_,
      biography = biography,
      stringsAsFactors = FALSE
    )
  }

  dplyr::bind_rows(rows)
}

m0_map_openalex_records <- function(records) {
  if (length(records) == 0) return(data.frame())

  rows <- lapply(records, function(rec) {
    authorships <- rec$authorships %||% list()
    authors <- vapply(authorships, function(a) a$author$display_name %||% NA_character_, character(1))
    institutions <- unique(unlist(lapply(authorships, function(a) {
      insts <- a$institutions %||% list()
      vapply(insts, function(i) i$display_name %||% NA_character_, character(1))
    })))
    countries <- unique(unlist(lapply(authorships, function(a) {
      if (!is.null(a$countries)) return(unlist(a$countries))
      insts <- a$institutions %||% list()
      vapply(insts, function(i) i$country_code %||% NA_character_, character(1))
    })))
    orcids <- unique(unlist(lapply(authorships, function(a) a$author$orcid %||% NA_character_)))
    concepts <- rec$concepts %||% list()
    keywords <- vapply(concepts, function(x) {
      score <- suppressWarnings(as.numeric(x$score %||% NA_real_))
      if (!is.na(score) && score < 0.3) return(NA_character_)
      x$display_name %||% NA_character_
    }, character(1))

    data.frame(
      TI = rec$display_name %||% NA_character_,
      PY = suppressWarnings(as.integer(rec$publication_year %||% NA_integer_)),
      SO = rec$primary_location$source$display_name %||% NA_character_,
      AB = m0_reconstruct_openalex_abstract(rec$abstract_inverted_index %||% NULL),
      DE = paste(stats::na.omit(unique(keywords)), collapse = ";"),
      ID = paste(stats::na.omit(unique(keywords)), collapse = ";"),
      C1 = paste(stats::na.omit(unique(institutions)), collapse = ";"),
      TC = suppressWarnings(as.numeric(rec$cited_by_count %||% NA_real_)),
      DI = gsub("^https?://doi.org/", "", rec$doi %||% "", ignore.case = TRUE),
      DT = rec$type %||% NA_character_,
      AU = paste(stats::na.omit(authors), collapse = ";"),
      AU_CO = paste(stats::na.omit(countries), collapse = ";"),
      AU_UN = paste(stats::na.omit(unique(institutions)), collapse = ";"),
      OI = paste(stats::na.omit(unique(gsub("^https?://orcid.org/", "", orcids, ignore.case = TRUE))), collapse = ";"),
      SN = paste(stats::na.omit(rec$primary_location$source$issn %||% character()), collapse = ";"),
      PU = rec$primary_location$source$host_organization_name %||% NA_character_,
      stringsAsFactors = FALSE
    )
  })

  m0_standardize_columns(dplyr::bind_rows(rows))
}

m0_map_crossref_records <- function(records) {
  if (length(records) == 0) return(data.frame())

  rows <- lapply(records, function(rec) {
    authors <- rec$author %||% list()
    author_names <- vapply(authors, function(a) {
      family <- a$family %||% ""
      given <- a$given %||% ""
      trimws(paste(family, given))
    }, character(1))
    affiliations <- unique(unlist(lapply(authors, function(a) {
      aff <- a$affiliation %||% list()
      vapply(aff, function(x) x$name %||% NA_character_, character(1))
    })))
    orcids <- unique(unlist(lapply(authors, function(a) {
      orcid <- a$ORCID %||% NA_character_
      gsub("^https?://orcid.org/", "", orcid, ignore.case = TRUE)
    })))
    funders <- rec$funder %||% list()
    funder_names <- vapply(funders, function(f) f$name %||% NA_character_, character(1))
    subjects <- unlist(rec$subject %||% character())
    references <- rec$reference %||% list()
    reference_lines <- vapply(references, function(ref) {
      paste(stats::na.omit(unlist(ref[c("author", "year", "journal-title", "DOI")])), collapse = ", ")
    }, character(1))

    data.frame(
      TI = (rec$title %||% list(NA_character_))[[1]] %||% NA_character_,
      PY = m0_extract_crossref_year(rec),
      SO = (rec$`container-title` %||% list(NA_character_))[[1]] %||% NA_character_,
      AB = rec$abstract %||% NA_character_,
      DE = paste(stats::na.omit(subjects), collapse = ";"),
      ID = paste(stats::na.omit(subjects), collapse = ";"),
      C1 = paste(stats::na.omit(affiliations), collapse = ";"),
      TC = suppressWarnings(as.numeric(rec$`is-referenced-by-count` %||% NA_real_)),
      DI = rec$DOI %||% NA_character_,
      DT = rec$type %||% NA_character_,
      AU = paste(stats::na.omit(author_names), collapse = ";"),
      AU_UN = paste(stats::na.omit(affiliations), collapse = ";"),
      OI = paste(stats::na.omit(orcids), collapse = ";"),
      FU = paste(stats::na.omit(funder_names), collapse = ";"),
      FX = paste(stats::na.omit(funder_names), collapse = ";"),
      CR = paste(stats::na.omit(reference_lines), collapse = ";"),
      SN = paste(stats::na.omit(rec$ISSN %||% character()), collapse = ";"),
      PU = rec$publisher %||% NA_character_,
      VL = rec$volume %||% NA_character_,
      IS = rec$issue %||% NA_character_,
      PG = rec$page %||% NA_character_,
      stringsAsFactors = FALSE
    )
  })

  m0_standardize_columns(dplyr::bind_rows(rows))
}

m0_map_pubmed_records <- function(result_obj) {
  uids <- result_obj$uids %||% character()
  if (length(uids) == 0) return(data.frame())

  rows <- lapply(uids, function(uid) {
    rec <- result_obj[[uid]] %||% list()
    authors <- rec$authors %||% list()
    author_names <- vapply(authors, function(a) a$name %||% NA_character_, character(1))
    article_ids <- rec$articleids %||% list()
    doi <- NA_character_
    if (length(article_ids) > 0) {
      doi_values <- vapply(article_ids, function(a) {
        if (identical(tolower(a$idtype %||% ""), "doi")) a$value %||% NA_character_ else NA_character_
      }, character(1))
      doi <- stats::na.omit(doi_values)[1] %||% NA_character_
    }

    data.frame(
      TI = rec$title %||% NA_character_,
      PY = suppressWarnings(as.integer(gsub("^(\\d{4}).*$", "\\1", rec$pubdate %||% NA_character_))),
      SO = rec$fulljournalname %||% rec$source %||% NA_character_,
      TC = NA_real_,
      DI = doi,
      DT = paste(stats::na.omit(rec$pubtype %||% character()), collapse = ";"),
      AU = paste(stats::na.omit(author_names), collapse = ";"),
      NR = suppressWarnings(as.numeric(rec$references %||% NA_real_)),
      stringsAsFactors = FALSE
    )
  })

  m0_standardize_columns(dplyr::bind_rows(rows))
}

m0_reconstruct_openalex_abstract <- function(index_obj) {
  if (is.null(index_obj) || length(index_obj) == 0) return(NA_character_)
  words <- list()
  for (term in names(index_obj)) {
    positions <- unlist(index_obj[[term]])
    for (pos in positions) {
      words[[as.character(pos)]] <- term
    }
  }
  if (length(words) == 0) return(NA_character_)
  ordered <- words[order(as.integer(names(words)))]
  paste(unlist(ordered), collapse = " ")
}

m0_extract_crossref_year <- function(rec) {
  candidates <- list(
    rec$published$`date-parts`,
    rec$`published-print`$`date-parts`,
    rec$`published-online`$`date-parts`,
    rec$created$`date-parts`
  )
  for (cand in candidates) {
    if (!is.null(cand) && length(cand) > 0) {
      year <- suppressWarnings(as.integer(cand[[1]][1]))
      if (!is.na(year)) return(year)
    }
  }
  NA_integer_
}

m0_build_url <- function(base, params = list()) {
  params <- params[!vapply(params, is.null, logical(1))]
  params <- params[!vapply(params, function(x) length(x) == 0 || all(is.na(x)) || all(!nzchar(as.character(x))), logical(1))]
  if (length(params) == 0) return(base)

  query <- paste(
    sprintf(
      "%s=%s",
      utils::URLencode(names(params), reserved = TRUE),
      vapply(params, function(x) utils::URLencode(as.character(x)[1], reserved = TRUE), character(1))
    ),
    collapse = "&"
  )
  paste0(base, "?", query)
}

m0_api_get_text <- function(url, headers = character(), timeout = 30) {
  old_timeout <- getOption("timeout")
  options(timeout = max(old_timeout, timeout))
  on.exit(options(timeout = old_timeout), add = TRUE)

  con <- base::url(url, open = "r", encoding = "UTF-8", headers = headers)
  on.exit(close(con), add = TRUE)
  paste(readLines(con, warn = FALSE), collapse = "\n")
}

m0_api_get_json <- function(url, headers = character(), timeout = 30) {
  text <- m0_api_get_text(url, headers = headers, timeout = timeout)
  jsonlite::fromJSON(text, simplifyVector = FALSE)
}
