# >>> BEGIN FILE: R/module_m0/m0_semantic_similarity.R
# ============================================================================
# m0_semantic_similarity.R - Semantic Similarity for Deduplication
# ============================================================================
# Uses text embeddings and semantic similarity for improved title matching

#' Semantic title similarity using TF-IDF
#'
#' @param titles Character vector of titles
#' @param threshold Similarity threshold for considering matches (default 0.8)
#' @return Matrix of similarity scores
#' @export
m0_semantic_similarity <- function(titles, threshold = 0.8) {
  if (length(titles) < 2) {
    return(matrix(1, 1, 1, dimnames = list(1, 1)))
  }
  
  # Normalize titles
  titles_norm <- normalize_titles(titles)
  
  # Create TF-IDF matrix
  tfidf_matrix <- create_tfidf_matrix(titles_norm)
  
  if (is.null(tfidf_matrix) || ncol(tfidf_matrix) == 0) {
    # Fallback to simple character-based similarity
    return(char_similarity_matrix(titles))
  }
  
  # Compute cosine similarity
  n <- nrow(tfidf_matrix)
  sim_matrix <- matrix(0, n, n)
  
  for (i in 1:n) {
    for (j in i:n) {
      if (i == j) {
        sim_matrix[i, j] <- 1
      } else {
        sim <- cosine_similarity(tfidf_matrix[i, ], tfidf_matrix[j, ])
        sim_matrix[i, j] <- sim
        sim_matrix[j, i] <- sim
      }
    }
  }
  
  rownames(sim_matrix) <- colnames(sim_matrix) <- seq_len(n)
  
  sim_matrix
}

#' Normalize titles for comparison
#' @keywords internal
normalize_titles <- function(titles) {
  titles <- tolower(as.character(titles))
  titles <- gsub("[[:punct:]]", " ", titles)
  titles <- gsub("[[:digit:]]", " ", titles)
  titles <- gsub("\\s+", " ", titles)
  titles <- trimws(titles)
  
  # Remove common stop words
  stopwords <- c("the", "a", "an", "and", "or", "but", "in", "on", "at", 
                 "to", "for", "of", "with", "by", "from", "is", "are", "was",
                 "were", "be", "been", "being", "have", "has", "had", "do",
                 "does", "did", "will", "would", "could", "should", "may",
                 "might", "must", "shall", "can", "need", "dare", "ought",
                 "used", "using", "use", "this", "that", "these", "those")
  
  for (sw in stopwords) {
    titles <- gsub(paste0("\\b", sw, "\\b"), "", titles)
  }
  
  titles <- gsub("\\s+", " ", titles)
  trimws(titles)
}

#' Create TF-IDF matrix
#' @keywords internal
create_tfidf_matrix <- function(titles) {
  # Tokenize
  tokens <- strsplit(titles, "\\s+")
  
  # Build vocabulary
  vocab <- unique(unlist(tokens))
  vocab <- vocab[vocab != "" & nchar(vocab) > 1]
  
  if (length(vocab) == 0) return(NULL)
  
  n <- length(titles)
  
  # Term frequency
  tf <- matrix(0, n, length(vocab))
  colnames(tf) <- vocab
  
  for (i in seq_along(tokens)) {
    token_freq <- table(tokens[[i]])
    for (term in names(token_freq)) {
      if (term %in% vocab) {
        tf[i, term] <- token_freq[term]
      }
    }
  }
  
  # Document frequency
  df <- colSums(tf > 0)
  
  # IDF
  idf <- log(n / (df + 1))
  
  # TF-IDF
  tfidf <- tf * matrix(idf, nrow = n, ncol = length(vocab), byrow = TRUE)
  
  # Normalize
  row_norms <- sqrt(rowSums(tfidf^2))
  row_norms[row_norms == 0] <- 1
  tfidf <- tfidf / row_norms
  
  tfidf
}

#' Cosine similarity
#' @keywords internal
cosine_similarity <- function(v1, v2) {
  if (length(v1) == 0 || length(v2) == 0) return(0)
  
  dot_product <- sum(v1 * v2, na.rm = TRUE)
  norm1 <- sqrt(sum(v1^2, na.rm = TRUE))
  norm2 <- sqrt(sum(v2^2, na.rm = TRUE))
  
  if (norm1 == 0 || norm2 == 0) return(0)
  
  dot_product / (norm1 * norm2)
}

#' Character similarity matrix (fallback)
#' @keywords internal
char_similarity_matrix <- function(titles) {
  n <- length(titles)
  sim_matrix <- matrix(0, n, n)
  
  for (i in 1:n) {
    for (j in i:n) {
      if (i == j) {
        sim_matrix[i, j] <- 1
      } else {
        sim <- levenshtein_similarity(titles[i], titles[j])
        sim_matrix[i, j] <- sim
        sim_matrix[j, i] <- sim
      }
    }
  }
  
  sim_matrix
}

#' Levenshtein similarity (normalized)
#' @keywords internal
levenshtein_similarity <- function(s1, s2) {
  if (is.na(s1) || is.na(s2)) return(0)
  
  dist <- adist(s1, s2)[1, 1]
  max_len <- max(nchar(s1), nchar(s2))
  
  if (max_len == 0) return(1)
  
  1 - dist / max_len
}

#' Jaccard similarity for tokenized strings
#'
#' @param s1 First string
#' @param s2 Second string
#' @return Jaccard similarity score
#' @export
jaccard_similarity <- function(s1, s2) {
  if (is.na(s1) || is.na(s2)) return(0)
  
  s1 <- tolower(s1)
  s2 <- tolower(s2)
  
  tokens1 <- unique(strsplit(s1, "\\s+")[[1]])
  tokens2 <- unique(strsplit(s2, "\\s+")[[1]])
  
  tokens1 <- tokens1[tokens1 != ""]
  tokens2 <- tokens2[tokens2 != ""]
  
  if (length(tokens1) == 0 || length(tokens2) == 0) return(0)
  
  intersection <- length(intersect(tokens1, tokens2))
  union <- length(union(tokens1, tokens2))
  
  if (union == 0) return(0)
  
  intersection / union
}

#' Find potential duplicates using semantic similarity
#'
#' @param titles Character vector of titles
#' @param threshold Similarity threshold (default 0.85)
#' @param n_grams Also use n-gram overlap (default TRUE)
#' @return List with potential duplicate pairs
#' @export
m0_find_duplicates_semantic <- function(titles, threshold = 0.85, n_grams = TRUE) {
  n <- length(titles)
  
  if (n < 2) {
    return(list(
      duplicates = data.frame(),
      n_pairs = 0,
      status = "insufficient data"
    ))
  }
  
  # Compute similarity matrix
  sim_matrix <- m0_semantic_similarity(titles, threshold)
  
  # Find pairs above threshold
  duplicates <- data.frame(
    index1 = integer(0),
    index2 = integer(0),
    title1 = character(0),
    title2 = character(0),
    similarity = numeric(0),
    jaccard = numeric(0),
    stringsAsFactors = FALSE
  )
  
  for (i in 1:(n - 1)) {
    for (j in (i + 1):n) {
      if (sim_matrix[i, j] >= threshold) {
        jaccard <- if (n_grams) jaccard_similarity(titles[i], titles[j]) else NA
        
        duplicates <- rbind(duplicates, data.frame(
          index1 = i,
          index2 = j,
          title1 = substr(titles[i], 1, 100),
          title2 = substr(titles[j], 1, 100),
          similarity = round(sim_matrix[i, j], 4),
          jaccard = round(jaccard, 4),
          stringsAsFactors = FALSE
        ))
      }
    }
  }
  
  duplicates <- duplicates[order(-duplicates$similarity), ]
  
  list(
    duplicates = duplicates,
    n_pairs = nrow(duplicates),
    n_examined = n * (n - 1) / 2,
    threshold = threshold,
    status = "success"
  )
}

#' Author matching with ORCID support
#'
#' @param authors1 First author list
#' @param authors2 Second author list
#' @param orcids1 Corresponding ORCIDs for first list
#' @param orcids2 Corresponding ORCIDs for second list
#' @return List with match scores
#' @export
m0_match_authors <- function(authors1, authors2, orcids1 = NULL, orcids2 = NULL) {
  n1 <- length(authors1)
  n2 <- length(authors2)
  
  matches <- data.frame(
    author1 = character(0),
    author2 = character(0),
    orcid_match = logical(0),
    name_match = numeric(0),
    overall_match = numeric(0),
    stringsAsFactors = FALSE
  )
  
  for (i in seq_along(authors1)) {
    for (j in seq_along(authors2)) {
      # ORCID match
      orcid_match <- FALSE
      if (!is.null(orcids1) && !is.null(orcids2)) {
        if (!is.na(orcids1[i]) && !is.na(orcids2[j])) {
          orcid_match <- orcids1[i] == orcids2[j]
        }
      }
      
      # Name match
      name_sim <- author_name_similarity(authors1[i], authors2[j])
      
      # Overall match score
      overall <- if (orcid_match) {
        1.0
      } else if (name_sim > 0.9) {
        0.95
      } else {
        name_sim
      }
      
      if (overall > 0.7) {
        matches <- rbind(matches, data.frame(
          author1 = authors1[i],
          author2 = authors2[j],
          orcid_match = orcid_match,
          name_match = round(name_sim, 4),
          overall_match = round(overall, 4),
          stringsAsFactors = FALSE
        ))
      }
    }
  }
  
  matches <- matches[order(-matches$overall_match), ]
  
  list(
    matches = matches,
    n_matches = nrow(matches),
    n_orcid_matches = sum(matches$orcid_match),
    status = "success"
  )
}

#' Author name similarity
#' @keywords internal
author_name_similarity <- function(name1, name2) {
  if (is.na(name1) || is.na(name2)) return(0)
  
  name1 <- normalize_author_name(name1)
  name2 <- normalize_author_name(name2)
  
  # Extract last name and initials
  parts1 <- strsplit(name1, "\\s+")[[1]]
  parts2 <- strsplit(name2, "\\s+")[[1]]
  
  if (length(parts1) == 0 || length(parts2) == 0) return(0)
  
  # Last name comparison (most important)
  last1 <- parts1[length(parts1)]
  last2 <- parts2[length(parts2)]
  
  last_sim <- if (last1 == last2) 1 else {
    levenshtein_similarity(last1, last2)
  }
  
  if (last_sim < 0.7) return(last_sim * 0.5)  # Last name mismatch is decisive
  
  # Initials comparison
  initials1 <- if (length(parts1) > 1) {
    paste(substr(parts1[-length(parts1)], 1, 1), collapse = "")
  } else ""
  
  initials2 <- if (length(parts2) > 1) {
    paste(substr(parts2[-length(parts2)], 1, 1), collapse = "")
  } else ""
  
  init_sim <- jaccard_similarity(initials1, initials2)
  
  # Weight: 60% last name, 40% initials
  last_sim * 0.6 + init_sim * 0.4
}

#' Normalize author name
#' @keywords internal
normalize_author_name <- function(name) {
  name <- tolower(name)
  name <- gsub("[[:punct:]]", " ", name)
  name <- gsub("\\s+", " ", name)
  name <- trimws(name)
  
  # Common name variations
  name <- gsub("\\bdr\\b", "", name)
  name <- gsub("\\bprof\\b", "", name)
  name <- gsub("\\bmr\\b", "", name)
  name <- gsub("\\bmrs\\b", "", name)
  name <- gsub("\\bms\\b", "", name)
  name <- gsub("\\bjr\\b", "", name)
  name <- gsub("\\bsr\\b", "", name)
  name <- gsub("\\biii\\b", "", name)
  name <- gsub("\\bii\\b", "", name)
  
  name <- gsub("\\s+", " ", name)
  trimws(name)
}

#' Journal name disambiguation
#'
#' @param journals Character vector of journal names
#' @return Data frame with normalized names and groups
#' @export
m0_disambiguate_journals <- function(journals) {
  journals <- as.character(journals)
  n <- length(journals)
  
  # Normalize
  journals_norm <- tolower(journals)
  journals_norm <- gsub("[[:punct:]]", " ", journals_norm)
  journals_norm <- gsub("\\s+", " ", journals_norm)
  journals_norm <- trimws(journals_norm)
  
  # Common abbreviation expansions
  abbrev_map <- c(
    "j " = "journal ",
    " j$" = " journal",
    " j " = " journal ",
    "proc" = "proceedings",
    "trans" = "transactions",
    "int" = "international",
    "nat" = "national",
    "acad" = "academy",
    "inst" = "institute",
    "univ" = "university",
    "res" = "research",
    "tech" = "technical",
    "sci" = "science",
    "eng" = "engineering",
    "med" = "medicine",
    "biol" = "biology",
    "phys" = "physics",
    "chem" = "chemistry",
    "math" = "mathematics",
    "comput" = "computational"
  )
  
  for (abbr in names(abbrev_map)) {
    journals_norm <- gsub(abbr, abbrev_map[abbr], journals_norm)
  }
  
  # Create groups
  groups <- data.frame(
    original = journals,
    normalized = journals_norm,
    group_id = integer(n),
    canonical_name = character(n),
    stringsAsFactors = FALSE
  )
  
  # Group by similarity
  processed <- rep(FALSE, n)
  group_id <- 1
  
  for (i in 1:n) {
    if (processed[i]) next
    
    # Find similar journals
    similar <- which(!processed & 
                     (journals_norm == journals_norm[i] |
                      sapply(journals_norm, function(x) jaccard_similarity(x, journals_norm[i])) > 0.85))
    
    groups$group_id[similar] <- group_id
    groups$canonical_name[similar] <- journals[i]  # Use first occurrence as canonical
    processed[similar] <- TRUE
    group_id <- group_id + 1
  }
  
  # Summary
  unique_groups <- length(unique(groups$group_id))
  
  list(
    journals = groups,
    n_unique = unique_groups,
    n_duplicates = n - unique_groups,
    status = "success"
  )
}
# <<< END FILE: R/module_m0/m0_semantic_similarity.R

# >>> BEGIN FILE: R/module_m0/m0_validate.R
# ============================================================================
# m0_validate.R - Validation for M0 Data Orchestrator
# ============================================================================

#' Validate source specifications for M0
#'
#' @param sources A named list of source specifications.
#' @return A list with \code{ok}, \code{error}, \code{details}.
#' @export
m0_validate_sources <- function(sources) {
  if (!is.list(sources) || length(sources) == 0) {
    return(list(ok = FALSE, error = "sources must be a non-empty named list"))
  }

  if (is.null(names(sources)) || any(names(sources) == "")) {
    return(list(ok = FALSE, error = "All source entries must be named"))
  }

  allowed_dbs <- c("scopus", "wos", "openalex", "crossref", "pubmed", "generic")
  allowed_fmt <- c("bibtex", "plaintext", "csv", "xlsx", "json")
  allowed_schemas <- c("scopus_csv", "wos_csv", "generic_csv")

  details <- list()
  for (nm in names(sources)) {
    spec <- sources[[nm]]
    is_api <- m0_is_api_source_spec(spec)
    if (!is.list(spec)) {
      return(list(ok = FALSE, error = paste0("Source '", nm, "' must be a list")))
    }
    if (is.null(spec$db) || !(spec$db %in% allowed_dbs)) {
      return(list(ok = FALSE, error = paste0("Source '", nm, "': db must be one of ",
                                              paste(allowed_dbs, collapse = ", "))))
    }
    schema <- m0_resolve_source_schema(spec)
    source_files <- if (!is_api) m0_resolve_source_files(spec) else character()
    if (!is_api && length(source_files) == 0) {
      return(list(ok = FALSE, error = paste0("Source '", nm, "': file not found: ", spec$file %||% spec$file_pattern %||% "<unspecified>")))
    }
    if (!is_api && any(!file.exists(source_files))) {
      missing_files <- source_files[!file.exists(source_files)]
      return(list(ok = FALSE, error = paste0("Source '", nm, "': file not found: ", paste(missing_files, collapse = ", "))))
    }
    if (is_api && is.null(spec$query) && is.null(spec$doi) && is.null(spec$ids) && is.null(spec$filter) && spec$db != "crossref") {
      return(list(ok = FALSE, error = paste0("Source '", nm, "': API sources require query, doi, or ids.")))
    }
    if (!is.null(spec$format) && !(spec$format %in% allowed_fmt)) {
      return(list(ok = FALSE, error = paste0("Source '", nm, "': format must be one of ",
                                              paste(allowed_fmt, collapse = ", "))))
    }
    if (!is.null(spec$schema) && !(tolower(as.character(spec$schema)[1]) %in% allowed_schemas)) {
      return(list(ok = FALSE, error = paste0("Source '", nm, "': schema must be one of ",
                                             paste(allowed_schemas, collapse = ", "))))
    }
    if (!is.null(spec$chunk_size_rows)) {
      chunk_size <- suppressWarnings(as.integer(spec$chunk_size_rows))
      if (is.na(chunk_size) || chunk_size <= 0) {
        return(list(ok = FALSE, error = paste0("Source '", nm, "': chunk_size_rows must be a positive integer")))
      }
    }
    if (!is.null(spec$delimiter) && !nzchar(as.character(spec$delimiter)[1])) {
      return(list(ok = FALSE, error = paste0("Source '", nm, "': delimiter must be a non-empty string")))
    }
    if (!is.null(spec$encoding) && !nzchar(as.character(spec$encoding)[1])) {
      return(list(ok = FALSE, error = paste0("Source '", nm, "': encoding must be a non-empty string")))
    }
    details[[nm]] <- list(
      db = spec$db,
      file = spec$file %||% NA_character_,
      files = if (length(source_files) > 0) source_files else spec$files %||% character(),
      n_files = length(source_files),
      file_pattern = spec$file_pattern %||% NA_character_,
      format = spec$format %||% if (!is.na(schema) && grepl("_csv$", schema)) "csv" else "bibtex",
      schema = schema,
      chunk_size_rows = spec$chunk_size_rows %||% NA_integer_,
      mode = if (is_api) "api" else "file"
    )
  }

  list(ok = TRUE, error = NULL, details = details)
}

#' Validate merged dataset has minimum required columns
#'
#' @param df A merged data frame.
#' @return A list with \code{ok}, \code{missing}, \code{n_rows}.
#' @export
m0_validate_merged <- function(df) {
  if (!is.data.frame(df) || nrow(df) == 0) {
    return(list(ok = FALSE, missing = NULL, n_rows = 0L,
                error = "Merged data is empty"))
  }

  # Minimal columns that bibliometrix modules expect
  minimal <- c("AU", "TI", "PY", "SO")
  present <- minimal %in% names(df)
  missing <- minimal[!present]

  list(ok = length(missing) == 0, missing = missing,
       n_rows = nrow(df), n_cols = ncol(df))
}

#' Validate loaded sources have content
#'
#' @param raw_list Named list of loaded data frames from sources.
#' @return A list with \code{ok}, \code{empty_sources}, \code{total_records}.
#' @export
m0_validate_loaded <- function(raw_list) {
  if (!is.list(raw_list) || length(raw_list) == 0) {
    return(list(ok = FALSE, empty_sources = names(raw_list), total_records = 0L,
                error = "No loaded sources"))
  }
  
  empty_sources <- character()
  total_records <- 0L
  
  for (nm in names(raw_list)) {
    df <- raw_list[[nm]]
    n <- if (is.data.frame(df)) nrow(df) else 0L
    total_records <- total_records + n
    if (n == 0) {
      empty_sources <- c(empty_sources, nm)
    }
  }
  
  if (length(empty_sources) == length(raw_list)) {
    return(list(ok = FALSE, empty_sources = empty_sources, total_records = 0L,
                error = "All sources produced empty results"))
  }
  
  if (length(empty_sources) > 0) {
    # Warning but not error - partial data is acceptable
    return(list(ok = TRUE, empty_sources = empty_sources, total_records = total_records,
                warning = paste0("Sources produced empty results: ", 
                                 paste(empty_sources, collapse = ", "))))
  }
  
  list(ok = TRUE, empty_sources = character(), total_records = total_records)
}

#' Validate column data types
#'
#' @param df A data frame.
#' @return A list with \code{ok}, \code{issues}.
#' @export
m0_validate_column_types <- function(df) {
  if (!is.data.frame(df) || nrow(df) == 0) {
    return(list(ok = FALSE, issues = list(error = "Empty data frame")))
  }
  
  issues <- list()
  
  # PY should be numeric/integer
  if ("PY" %in% names(df)) {
    py <- df$PY
    if (!is.numeric(py) && !is.integer(py)) {
      py_num <- suppressWarnings(as.numeric(py))
      if (any(is.na(py_num) & !is.na(py))) {
        issues$PY <- "Publication year (PY) contains non-numeric values"
      }
    }
    # Check for unreasonable years
    valid_years <- py[!is.na(py) & py > 0]
    if (length(valid_years) > 0) {
      current_year <- as.numeric(format(Sys.Date(), "%Y"))
      if (any(valid_years < 1500) || any(valid_years > current_year + 2)) {
        issues$PY_range <- paste0("Publication year outside reasonable range (1500-", current_year + 2, ")")
      }
    }
  }
  
  # TC should be numeric
  if ("TC" %in% names(df)) {
    tc <- df$TC
    if (!is.numeric(tc) && !is.integer(tc)) {
      issues$TC <- "Citation count (TC) is not numeric"
    }
    if (any(tc < 0, na.rm = TRUE)) {
      issues$TC_negative <- "Citation count (TC) contains negative values"
    }
  }
  
  list(ok = length(issues) == 0, issues = issues)
}
# <<< END FILE: R/module_m0/m0_validate.R

# >>> BEGIN FILE: R/module_m1/compute/m1_biblio_cache.R
# ============================================================================
# m1_biblio_cache.R - Cache biblioAnalysis results for M1
# ============================================================================

#' Cached biblioAnalysis computation
#'
#' Calls bibliometrix::biblioAnalysis once and caches the result
#' to avoid recomputing for every metric.
#'
#' @param input Bibliographic data frame
#' @return List with res (biblioAnalysis result) and summary (summary result)
#' @export
rbiblio_m1_cache_env <- local({
  env <- new.env(parent = emptyenv())
  env$cache <- list()
  env
})

get_cached_biblio_analysis <- function(input) {
  input <- m1_prepare_biblio_input(input)
  cache <- rbiblio_m1_cache_env$cache %||% list()
  cache_key <- digest::digest(input, algo = "xxhash32")

  if (!is.null(cache[[cache_key]])) {
    return(cache[[cache_key]])
  }

  result <- tryCatch({
    res <- bibliometrix::biblioAnalysis(input, sep = ";")
    s <- summary(res, pause = FALSE, verbose = FALSE)
    list(res = res, summary = s, status = "success")
  }, error = function(e) {
    list(res = NULL, summary = NULL, status = "error", error = conditionMessage(e))
  })

  cache[[cache_key]] <- result
  rbiblio_m1_cache_env$cache <- cache

  result
}

#' Clear the biblioAnalysis cache
#' @export
clear_biblio_cache <- function() {
  rbiblio_m1_cache_env$cache <- list()
  invisible(TRUE)
}

#' Prepare input for bibliometrix compatibility
#' @keywords internal
m1_prepare_biblio_input <- function(input) {
  if (!is.data.frame(input)) {
    return(input)
  }

  prepared <- input
  if (!"DB" %in% names(prepared)) {
    if ("SOURCE_DB" %in% names(prepared)) {
      prepared$DB <- toupper(as.character(prepared$SOURCE_DB))
    } else {
      prepared$DB <- rep("GENERIC", nrow(prepared))
    }
  }

  if ("SO" %in% names(prepared)) {
    if (!"JI" %in% names(prepared)) {
      prepared$JI <- as.character(prepared$SO)
    }
    if (!"J9" %in% names(prepared)) {
      prepared$J9 <- as.character(prepared$SO)
    }
  }

  if (!"C1" %in% names(prepared)) {
    prepared$C1 <- rep("", nrow(prepared))
  }

  prepared
}
# <<< END FILE: R/module_m1/compute/m1_biblio_cache.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_author_advanced.R
# ============================================================================
# m1_compute_author_advanced.R - Advanced Author Analysis
# ============================================================================
# Author career trajectory, collaboration networks, centrality metrics

#' Compute author career trajectory
#'
#' @param input Bibliographic data frame
#' @param config Configuration list
#' @return List with career metrics per author
#' @export
compute_m1_author_career <- function(input, config = biblio_config()) {
  au_col <- "AU"
  py_col <- "PY"
  tc_col <- "TC"
  
  if (!au_col %in% names(input) || !py_col %in% names(input)) {
    return(list(status = "error: missing author or year column"))
  }
  
  # Extract authors and their papers
  author_data <- extract_author_career_papers(input, au_col, py_col, tc_col)
  
  if (length(author_data) == 0) {
    return(list(status = "error: no authors found"))
  }
  
  # Compute career metrics
  safe_compute_career <- function(author) {
    papers <- author_data[[author]]
    if (is.null(papers) || !is.list(papers)) {
      return(list(
        author = author,
        total_papers = 0L,
        first_publication_year = NA_integer_,
        last_publication_year = NA_integer_,
        career_length = NA_integer_,
        total_citations = 0,
        mean_citations = NA_real_,
        h_index = 0L,
        g_index = 0L,
        m_index = NA_real_,
        citations_per_year = NA_real_,
        productivity_trend = NA_real_,
        citation_trend = NA_real_,
        active_years = 0L,
        publication_gaps = list(n_gaps = 0L, max_gap = 0L, gap_years = integer(0)),
        career_stage = NA_character_
      ))
    }
    
    years <- papers$year
    citations <- papers$citations
    
    # Handle NULL or non-numeric years
    if (is.null(years) || length(years) == 0 || all(is.na(years))) {
      years_val <- NA_integer_
      first_year <- NA_integer_
      last_year <- NA_integer_
    } else {
      years_val <- years[!is.na(years)]
      first_year <- as.integer(min(years_val, na.rm = TRUE))
      last_year <- as.integer(max(years_val, na.rm = TRUE))
    }
    
    career_len <- if (is.na(first_year) || is.na(last_year)) NA_integer_ else last_year - first_year + 1L
    
    # Handle citations
    if (is.null(citations) || length(citations) == 0) {
      citations_val <- numeric(0)
    } else {
      citations_val <- citations[!is.na(citations)]
    }
    
    list(
      author = author,
      total_papers = length(years),
      first_publication_year = first_year,
      last_publication_year = last_year,
      career_length = career_len,
      total_citations = sum(citations_val, na.rm = TRUE),
      mean_citations = if (length(citations_val) > 0) mean(citations_val, na.rm = TRUE) else NA_real_,
      h_index = compute_h_index(citations_val),
      g_index = compute_g_index(citations_val),
      m_index = compute_m_index(citations_val, years),
      citations_per_year = if (!is.na(career_len) && career_len > 0) sum(citations_val, na.rm = TRUE) / career_len else NA_real_,
      productivity_trend = compute_productivity_trend(years),
      citation_trend = compute_citation_trend(years, citations),
      active_years = length(unique(years_val)),
      publication_gaps = compute_publication_gaps(years),
      career_stage = determine_career_stage(first_year, last_year)
    )
  }
  
  career_metrics <- lapply(names(author_data), safe_compute_career)
  names(career_metrics) <- names(author_data)
  
  # Aggregate statistics - flatten nested lists before converting to data frame
  safe_flatten <- function(x) {
    x_flat <- as.list(x)
    pg <- x_flat$publication_gaps
    if (!is.null(pg) && is.list(pg)) {
      x_flat$publication_gaps_n <- if (!is.null(pg$n_gaps)) pg$n_gaps[1] else 0
      x_flat$publication_gaps_max <- if (!is.null(pg$max_gap)) pg$max_gap[1] else 0
    } else {
      x_flat$publication_gaps_n <- 0
      x_flat$publication_gaps_max <- 0
    }
    x_flat$publication_gaps <- NULL
    as.data.frame(x_flat, stringsAsFactors = FALSE)
  }
  
  career_df <- tryCatch({
    do.call(rbind, lapply(career_metrics, safe_flatten))
  }, error = function(e) {
    data.frame()
  })
  
  # Handle empty data frame
  if (is.null(career_df) || nrow(career_df) == 0) {
    return(list(
      career_metrics = career_metrics,
      career_df = data.frame(),
      top_by_papers = data.frame(),
      top_by_citations = data.frame(),
      top_by_h_index = data.frame(),
      rising_stars = data.frame(),
      established_stars = data.frame(),
      n_authors = length(author_data),
      status = "success"
    ))
  }

  career_df$display_author <- vapply(career_df$author, m1_author_display_label, character(1))
  
  # Top authors by various metrics
  top_by_papers <- head(career_df[order(-as.numeric(career_df$total_papers)), ], 20)
  top_by_citations <- head(career_df[order(-as.numeric(career_df$total_citations)), ], 20)
  top_by_h_index <- head(career_df[order(-as.numeric(career_df$h_index)), ], 20)
  trajectories <- build_author_trajectories(author_data, top_by_citations$author)
  
  # Rising stars (high M-index, early career)
  rising <- career_df[career_df$career_stage == "early", , drop = FALSE]
  rising_stars <- if (nrow(rising) > 0) head(rising[order(-as.numeric(rising$m_index)), , drop = FALSE], 10) else data.frame()
  
  # Established researchers (high h-index, mid-late career)
  established <- career_df[career_df$career_stage %in% c("mid", "late"), , drop = FALSE]
  established_stars <- if (nrow(established) > 0) head(established[order(-as.numeric(established$h_index)), , drop = FALSE], 10) else data.frame()
  
  list(
    career_metrics = career_metrics,
    career_df = career_df,
    top_by_papers = top_by_papers,
    top_by_citations = top_by_citations,
    top_by_h_index = top_by_h_index,
    rising_stars = rising_stars,
    established_stars = established_stars,
    trajectories = trajectories,
    n_authors = length(author_data),
    status = "success"
  )
}

#' Build cumulative author trajectories
#' @keywords internal
build_author_trajectories <- function(author_data, authors = character()) {
  if (length(author_data) == 0) {
    return(data.frame(
      author = character(),
      year = numeric(),
      papers = integer(),
      citations = numeric(),
      cumulative_papers = numeric(),
      cumulative_citations = numeric(),
      stringsAsFactors = FALSE
    ))
  }

  if (length(authors) == 0) {
    authors <- names(author_data)
  }

  authors <- unique(authors[authors %in% names(author_data)])
  authors <- authors[seq_len(min(length(authors), 10))]

  trajectory_rows <- lapply(authors, function(author) {
    papers <- author_data[[author]]
    if (is.null(papers) || !is.list(papers) || is.null(papers$year) || length(papers$year) == 0) {
      return(NULL)
    }

    years <- as.numeric(papers$year)
    citations <- as.numeric(papers$citations)
    valid <- !is.na(years)
    if (!any(valid)) {
      return(NULL)
    }

    yearly <- stats::aggregate(
      cbind(papers = rep(1L, sum(valid)), citations = citations[valid]) ~ year,
      data = data.frame(
        year = years[valid],
        citations = citations[valid]
      ),
      FUN = sum
    )
    yearly <- yearly[order(yearly$year), , drop = FALSE]
    yearly$cumulative_papers <- cumsum(yearly$papers)
    yearly$cumulative_citations <- cumsum(yearly$citations)
    yearly$author <- author
    yearly
  })

  out <- do.call(rbind, trajectory_rows[!vapply(trajectory_rows, is.null, logical(1))])
  if (is.null(out)) {
    return(data.frame(
      author = character(),
      year = numeric(),
      papers = integer(),
      citations = numeric(),
      cumulative_papers = numeric(),
      cumulative_citations = numeric(),
      stringsAsFactors = FALSE
    ))
  }

  rownames(out) <- NULL
  out
}

#' Extract author papers
#' @keywords internal
extract_author_career_papers <- function(input, au_col, py_col, tc_col) {
  authors_list <- strsplit(as.character(input[[au_col]]), ";")
  years <- as.numeric(input[[py_col]])
  citations <- if (tc_col %in% names(input)) as.numeric(input[[tc_col]]) else rep(0, nrow(input))
  
  # Handle NAs
  years[is.na(years)] <- NA_integer_
  citations[is.na(citations)] <- 0
  
  # Create author-paper mapping
  author_papers <- list()
  
  for (i in seq_along(authors_list)) {
    authors <- trimws(authors_list[[i]])
    authors <- authors[authors != ""]
    
    for (author in authors) {
      author <- normalize_author_name(author)
      
      if (!author %in% names(author_papers)) {
        author_papers[[author]] <- list(
          year = numeric(0),
          citations = numeric(0)
        )
      }
      
      # Only add valid year values
      if (!is.na(years[i])) {
        author_papers[[author]]$year <- c(author_papers[[author]]$year, years[i])
      }
      author_papers[[author]]$citations <- c(author_papers[[author]]$citations, citations[i])
    }
  }
  
  author_papers
}

#' Convert canonical author key into a journal-facing display label
#' @keywords internal
m1_author_display_label <- function(name) {
  raw_name <- trimws(as.character(name))
  if (!nzchar(raw_name) || is.na(raw_name)) {
    return(raw_name)
  }

  if (grepl(",", raw_name, fixed = TRUE)) {
    split_name <- strsplit(raw_name, ",", fixed = TRUE)[[1]]
    last_name <- trimws(split_name[1])
    initials <- gsub("\\s+", " ", trimws(paste(split_name[-1], collapse = " ")))
    initials <- gsub("[^A-Za-z ]", "", initials)
    initials <- trimws(initials)
    return(trimws(paste(last_name, initials)))
  }

  raw_name
}

#' Normalize author name
#' @keywords internal
normalize_author_name <- function(name) {
  raw_name <- trimws(as.character(name))
  if (!nzchar(raw_name)) return(raw_name)

  to_title <- function(x) {
    parts <- unlist(strsplit(tolower(x), "\\s+"))
    parts <- parts[nzchar(parts)]
    paste0(toupper(substr(parts, 1, 1)), substring(parts, 2), collapse = " ")
  }

  if (grepl(",", raw_name, fixed = TRUE)) {
    split_name <- strsplit(raw_name, ",", fixed = TRUE)[[1]]
    last_name <- trimws(split_name[1])
    given_name <- paste(trimws(split_name[-1]), collapse = " ")
    given_parts <- unlist(strsplit(gsub("[[:punct:]]", " ", given_name), "\\s+"))
    given_parts <- given_parts[nzchar(given_parts)]
    initials <- paste(toupper(substr(given_parts, 1, 1)), collapse = "")
    return(paste(to_title(last_name), initials, sep = ", "))
  }

  clean_name <- gsub("[[:punct:]]", " ", raw_name)
  clean_name <- gsub("\\s+", " ", clean_name)
  parts <- unlist(strsplit(trimws(clean_name), "\\s+"))
  if (length(parts) == 0) return(raw_name)

  # Heuristic: "Lastname Initial" or "Lastname Initial Initial" is common in
  # bibliographic exports and should not be inverted to "Initial, L".
  if (length(parts) >= 2 && nchar(parts[1]) > 1 && all(nchar(parts[-1]) <= 2)) {
    last_name <- parts[1]
    initials <- paste(toupper(substr(parts[-1], 1, 1)), collapse = "")
    return(paste(to_title(last_name), initials, sep = ", "))
  }

  last_name <- parts[length(parts)]
  initials <- if (length(parts) > 1) paste(toupper(substr(parts[-length(parts)], 1, 1)), collapse = "") else ""
  paste(to_title(last_name), initials, sep = ", ")
}

#' Compute M-index (h-index / career length)
#' @keywords internal
compute_m_index <- function(citations, years) {
  h <- compute_h_index(citations)
  years_valid <- years[!is.na(years)]
  if (length(years_valid) == 0) return(NA_real_)
  career_length <- as.numeric(max(years_valid)) - as.numeric(min(years_valid)) + 1
  if (career_length <= 0 || is.na(career_length)) return(NA_real_)
  h / career_length
}

#' Compute productivity trend
#' @keywords internal
compute_productivity_trend <- function(years) {
  years_valid <- years[!is.na(years)]
  if (length(years_valid) < 3) return(NA_real_)
  
  year_counts <- table(years_valid)
  years_unique <- as.numeric(names(year_counts))
  counts <- as.numeric(year_counts)
  
  if (length(years_unique) < 3) return(NA_real_)
  
  fit <- lm(counts ~ years_unique)
  slope <- coef(fit)[2]
  if (length(slope) > 1) slope <- slope[1]
  slope
}

#' Compute citation trend
#' @keywords internal
compute_citation_trend <- function(years, citations) {
  years_valid <- years[!is.na(years) & !is.na(citations)]
  citations_valid <- citations[!is.na(years) & !is.na(citations)]
  if (length(years_valid) < 3) return(NA_real_)
  
  # Mean citations per year
  year_citations <- aggregate(citations_valid ~ years_valid, FUN = sum)
  
  if (nrow(year_citations) < 3) return(NA_real_)
  
  fit <- lm(citations_valid ~ years_valid, data = year_citations)
  slope <- coef(fit)[2]
  if (length(slope) > 1) slope <- slope[1]
  slope
}

#' Compute publication gaps
#' @keywords internal
compute_publication_gaps <- function(years) {
  years_valid <- years[!is.na(years)]
  if (length(years_valid) < 2) return(list(n_gaps = 0L, max_gap = 0L, gap_years = integer(0)))
  
  years_sorted <- sort(unique(years_valid))
  gaps <- diff(years_sorted)
  gaps <- gaps[gaps > 1]  # Gap of 2+ years
  
  list(
    n_gaps = length(gaps),
    max_gap = if (length(gaps) > 0) as.integer(max(gaps)) else 0L,
    gap_years = as.integer(gaps)
  )
}

#' Determine career stage
#' @keywords internal
determine_career_stage <- function(first_year, last_year) {
  current_year <- as.numeric(format(Sys.Date(), "%Y"))
  
  career_start_age <- current_year - first_year
  
  if (career_start_age <= 5) {
    "early"
  } else if (career_start_age <= 15) {
    "mid"
  } else {
    "late"
  }
}

#' Compute author collaboration network
#'
#' @param input Bibliographic data frame
#' @param config Configuration list
#' @return List with network metrics
#' @export
compute_m1_author_network <- function(input, config = biblio_config()) {
  au_col <- "AU"
  
  if (!au_col %in% names(input)) {
    return(list(status = "error: no author column"))
  }
  
  # Create co-authorship matrix
  coauthor_matrix <- create_coauthor_matrix(input, au_col)
  
  if (is.null(coauthor_matrix) || nrow(coauthor_matrix) == 0) {
    return(list(status = "error: could not create co-author matrix"))
  }
  
  # Network metrics
  n_authors <- nrow(coauthor_matrix)
  n_edges <- sum(coauthor_matrix > 0) / 2
  
  # Degree centrality
  degree_centrality <- rowSums(coauthor_matrix > 0)
  
  # Weighted degree (strength)
  strength <- rowSums(coauthor_matrix)
  
  # Betweenness centrality (approximate)
  betweenness <- compute_network_betweenness(coauthor_matrix)
  
  # Closeness centrality
  closeness <- compute_network_closeness(coauthor_matrix)
  
  # Eigenvector centrality
  eigenvector <- compute_network_eigenvector(coauthor_matrix)
  
  # Clustering coefficient
  clustering <- compute_network_clustering(coauthor_matrix)
  
  # Create author metrics dataframe
  author_metrics <- data.frame(
    author = rownames(coauthor_matrix),
    degree = degree_centrality,
    strength = strength,
    betweenness = betweenness,
    closeness = closeness,
    eigenvector = eigenvector,
    clustering = clustering,
    stringsAsFactors = FALSE
  )
  
  # Sort by strength
  author_metrics <- author_metrics[order(-author_metrics$strength), ]
  
  # Network-level metrics
  density <- n_edges / (n_authors * (n_authors - 1) / 2)
  
  # Components
  components <- find_network_components(coauthor_matrix)
  n_components <- length(unique(components))
  
  # Modularity (approximate)
  modularity <- compute_network_modularity(coauthor_matrix, components)
  
  list(
    coauthor_matrix = coauthor_matrix,
    author_metrics = author_metrics,
    network_metrics = list(
      n_authors = n_authors,
      n_edges = n_edges,
      density = density,
      n_components = n_components,
      modularity = modularity,
      average_degree = mean(degree_centrality),
      average_clustering = mean(clustering, na.rm = TRUE)
    ),
    top_by_degree = head(author_metrics[order(-author_metrics$degree), ], 20),
    top_by_betweenness = head(author_metrics[order(-author_metrics$betweenness), ], 20),
    top_by_eigenvector = head(author_metrics[order(-author_metrics$eigenvector), ], 20),
    components = components,
    status = "success"
  )
}

#' Create co-authorship matrix
#' @keywords internal
create_coauthor_matrix <- function(input, au_col) {
  authors_list <- strsplit(as.character(input[[au_col]]), ";")
  
  # Get unique authors
  all_authors <- unique(unlist(lapply(authors_list, function(x) {
    trimws(x[x != ""])
  })))
  
  if (length(all_authors) == 0) return(NULL)
  
  all_authors <- all_authors[!is.na(all_authors)]
  
  # Limit to top authors if too many
  if (length(all_authors) > 1000) {
    author_freq <- table(unlist(authors_list))
    all_authors <- names(sort(author_freq, decreasing = TRUE))[1:1000]
  }
  
  n_authors <- length(all_authors)
  
  # Initialize matrix
  coauthor_matrix <- matrix(0, n_authors, n_authors)
  rownames(coauthor_matrix) <- colnames(coauthor_matrix) <- all_authors
  
  # Fill matrix
  for (authors in authors_list) {
    authors <- trimws(authors)
    authors <- authors[authors != "" & authors %in% all_authors]
    
    if (length(authors) > 1) {
      for (i in 1:(length(authors) - 1)) {
        for (j in (i + 1):length(authors)) {
          idx_i <- match(authors[i], all_authors)
          idx_j <- match(authors[j], all_authors)
          
          if (!is.na(idx_i) && !is.na(idx_j)) {
            coauthor_matrix[idx_i, idx_j] <- coauthor_matrix[idx_i, idx_j] + 1
            coauthor_matrix[idx_j, idx_i] <- coauthor_matrix[idx_j, idx_i] + 1
          }
        }
      }
    }
  }
  
  coauthor_matrix
}

#' Compute network betweenness (approximate)
#' @keywords internal
compute_network_betweenness <- function(adj_matrix) {
  n <- nrow(adj_matrix)
  betweenness <- numeric(n)
  
  # Simplified: count shortest paths through each node
  for (s in 1:n) {
    # BFS from s
    dist <- rep(Inf, n)
    dist[s] <- 0
    prev <- rep(NA, n)
    
    queue <- s
    while (length(queue) > 0) {
      v <- queue[1]
      queue <- queue[-1]
      
      neighbors <- which(adj_matrix[v, ] > 0)
      for (w in neighbors) {
        if (dist[w] == Inf) {
          dist[w] <- dist[v] + 1
          prev[w] <- v
          queue <- c(queue, w)
        }
      }
    }
    
    # Count nodes that pass through s
    for (t in 1:n) {
      if (t != s) {
        path <- t
        while (!is.na(prev[path[1]])) {
          path <- c(prev[path[1]], path)
        }
        if (length(path) > 2) {
          betweenness[path[-c(1, length(path))]] <- betweenness[path[-c(1, length(path))]] + 1
        }
      }
    }
  }
  
  # Normalize
  betweenness / (n * (n - 1) / 2)
}

#' Compute network closeness
#' @keywords internal
compute_network_closeness <- function(adj_matrix) {
  n <- nrow(adj_matrix)
  closeness <- numeric(n)
  
  for (i in 1:n) {
    # BFS for distances
    dist <- rep(Inf, n)
    dist[i] <- 0
    
    queue <- i
    while (length(queue) > 0) {
      v <- queue[1]
      queue <- queue[-1]
      
      neighbors <- which(adj_matrix[v, ] > 0)
      for (w in neighbors) {
        if (dist[w] == Inf) {
          dist[w] <- dist[v] + 1
          queue <- c(queue, w)
        }
      }
    }
    
    reachable <- sum(is.finite(dist)) - 1
    if (reachable > 0) {
      closeness[i] <- reachable / sum(dist[is.finite(dist)])
    }
  }
  
  closeness
}

#' Compute network eigenvector centrality
#' @keywords internal
compute_network_eigenvector <- function(adj_matrix) {
  n <- nrow(adj_matrix)
  
  # Power iteration
  eigenvec <- rep(1, n)
  
  for (iter in 1:100) {
    eigenvec_new <- adj_matrix %*% eigenvec
    eigenvec_new <- as.numeric(eigenvec_new)
    eigenvec_new <- eigenvec_new / max(eigenvec_new)
    
    if (max(abs(eigenvec_new - eigenvec)) < 1e-6) {
      break
    }
    eigenvec <- eigenvec_new
  }
  
  as.numeric(eigenvec)
}

#' Compute network clustering coefficient
#' @keywords internal
compute_network_clustering <- function(adj_matrix) {
  n <- nrow(adj_matrix)
  clustering <- numeric(n)
  
  binary <- adj_matrix > 0
  
  for (i in 1:n) {
    neighbors <- which(binary[i, ])
    k <- length(neighbors)
    
    if (k < 2) {
      clustering[i] <- 0
      next
    }
    
    # Count triangles
    n_triangles <- 0
    for (j in 1:(k - 1)) {
      for (l in (j + 1):k) {
        if (binary[neighbors[j], neighbors[l]]) {
          n_triangles <- n_triangles + 1
        }
      }
    }
    
    # Maximum possible triangles
    n_possible <- k * (k - 1) / 2
    
    clustering[i] <- if (n_possible > 0) n_triangles / n_possible else 0
  }
  
  clustering
}

#' Find network components
#' @keywords internal
find_network_components <- function(adj_matrix) {
  n <- nrow(adj_matrix)
  binary <- adj_matrix > 0
  
  visited <- rep(FALSE, n)
  components <- rep(NA, n)
  component_id <- 0
  
  for (i in 1:n) {
    if (!visited[i]) {
      component_id <- component_id + 1
      
      # BFS
      queue <- i
      visited[i] <- TRUE
      
      while (length(queue) > 0) {
        v <- queue[1]
        queue <- queue[-1]
        components[v] <- component_id
        
        neighbors <- which(binary[v, ])
        for (w in neighbors) {
          if (!visited[w]) {
            visited[w] <- TRUE
            queue <- c(queue, w)
          }
        }
      }
    }
  }
  
  components
}

#' Compute network modularity
#' @keywords internal
compute_network_modularity <- function(adj_matrix, components) {
  n <- nrow(adj_matrix)
  m <- sum(adj_matrix) / 2
  
  if (m == 0) return(0)
  
  Q <- 0
  unique_components <- unique(components)
  
  for (c in unique_components) {
    nodes_in_c <- which(components == c)
    
    # Edges within component
    edges_within <- sum(adj_matrix[nodes_in_c, nodes_in_c]) / 2
    
    # Total degree of nodes in component
    degree_within <- sum(rowSums(adj_matrix[nodes_in_c, , drop = FALSE]))
    
    Q <- Q + (edges_within / m - (degree_within / (2 * m))^2)
  }
  
  Q
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m1/compute/m1_compute_author_advanced.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_author_indices.R
# ============================================================================
# m1_compute_author_indices.R - Author Impact Indices
# ============================================================================
# Computes h-index, g-index, m-index (m-quotient) for authors.
#
# h-index: An author has h-index n if n of their papers have at least n citations
# g-index: An author has g-index n if the top g papers have at least g^2 citations
# m-index (m-quotient): h-index / years since first publication
#
# IEEE Q1 Enhancement: Includes 10-index, hI-index (normalized), and comprehensive
# citation statistics for robust bibliometric analysis.

#' Compute author impact indices (h-index, g-index, m-index)
#'
#' @param input Bibliographic data frame
#' @param config Configuration list
#' @return List with author indices
#' @export
compute_m1_author_indices <- function(input, config = biblio_config()) {
  validate_is_data_frame(input)
  
  tc_col <- "TC"
  py_col <- "PY"
  au_col <- "AU"
  if (!au_col %in% names(input)) au_col <- "AF"
  
  required_cols <- c(tc_col, au_col)
  missing <- setdiff(required_cols, names(input))
  if (length(missing) > 0) {
    return(list(
      indices = data.frame(),
      summary = list(),
      status = paste("error: missing columns:", paste(missing, collapse = ", "))
    ))
  }
  
  author_papers <- extract_author_papers(input, au_col, tc_col, py_col)
  
  if (is.null(author_papers) || nrow(author_papers) == 0) {
    return(list(
      indices = data.frame(),
      summary = list(),
      status = "error: could not extract author papers"
    ))
  }
  
  indices_df <- compute_all_author_indices(author_papers)
  
  if (nrow(indices_df) == 0) {
    return(list(
      indices = data.frame(),
      summary = list(),
      status = "error: no authors with valid data"
    ))
  }
  
  top_n <- config$top_n_authors %||% 10
  
  indices_df <- indices_df[order(-indices_df$h_index), ]
  
  summary_stats <- list(
    total_authors = nrow(indices_df),
    h_index_mean = mean(indices_df$h_index, na.rm = TRUE),
    h_index_median = median(indices_df$h_index, na.rm = TRUE),
    h_index_max = max(indices_df$h_index, na.rm = TRUE),
    h_index_90th = quantile(indices_df$h_index, 0.9, na.rm = TRUE),
    g_index_mean = mean(indices_df$g_index, na.rm = TRUE),
    g_index_median = median(indices_df$g_index, na.rm = TRUE),
    m_quotient_mean = mean(indices_df$m_quotient, na.rm = TRUE),
    highly_productive = sum(indices_df$n_papers >= 10),
    h_authors = sum(indices_df$h_index >= 10)
  )
  
  top_h <- head(indices_df[order(-indices_df$h_index), ], top_n)
  top_g <- head(indices_df[order(-indices_df$g_index), ], top_n)
  top_m <- head(indices_df[order(-indices_df$m_quotient), ], top_n)
  
  list(
    indices = indices_df,
    top_h_index = top_h,
    top_g_index = top_g,
    top_m_quotient = top_m,
    summary = summary_stats,
    status = "success"
  )
}

#' Extract author papers with citations
#' @keywords internal
extract_author_papers <- function(input, au_col, tc_col, py_col) {
  authors_list <- strsplit(as.character(input[[au_col]]), ";")
  authors_list <- lapply(authors_list, trimws)
  authors_list <- lapply(authors_list, function(x) x[x != ""])
  
  citations <- as.numeric(input[[tc_col]])
  citations[is.na(citations)] <- 0
  
  years <- if (py_col %in% names(input)) {
    as.numeric(input[[py_col]])
  } else {
    NA
  }
  years[is.na(years)] <- NA
  
  result_list <- lapply(seq_along(authors_list), function(i) {
    authors <- authors_list[[i]]
    if (length(authors) == 0) return(NULL)
    
    data.frame(
      author = authors,
      citations = citations[i],
      year = years[i],
      stringsAsFactors = FALSE
    )
  })
  
  result <- do.call(rbind, result_list[!sapply(result_list, is.null)])
  
  if (is.null(result) || nrow(result) == 0) {
    return(NULL)
  }
  
  result$citations[is.na(result$citations)] <- 0
  
  result
}

#' Compute all author indices
#' @keywords internal
compute_all_author_indices <- function(author_papers) {
  # Compute author summary statistics using dplyr-like approach
  author_stats <- lapply(unique(author_papers$author), function(au) {
    papers <- author_papers[author_papers$author == au, ]
    data.frame(
      author = au,
      citations_sum = sum(papers$citations, na.rm = TRUE),
      citations_count = length(papers$citations),
      year_min = min(papers$year, na.rm = TRUE),
      stringsAsFactors = FALSE
    )
  })
  author_summary <- do.call(rbind, author_stats)
  
  authors <- unique(author_papers$author)
  
  indices_list <- lapply(authors, function(au) {
    papers <- author_papers[author_papers$author == au, ]
    c_vec <- sort(papers$citations, decreasing = TRUE)
    
    h_idx <- compute_h_index(c_vec)
    g_idx <- compute_g_index(c_vec)
    
    n_papers <- length(c_vec)
    total_citations <- sum(c_vec, na.rm = TRUE)
    
    first_year <- if ("year" %in% names(papers) && any(!is.na(papers$year))) {
      min(papers$year, na.rm = TRUE)
    } else {
      NA
    }
    
    current_year <- as.numeric(format(Sys.Date(), "%Y"))
    m_q <- if (!is.na(first_year) && current_year > first_year) {
      h_idx / (current_year - first_year)
    } else {
      NA
    }
    
    i10 <- sum(c_vec >= 10)
    
    hI_norm <- if (n_papers > 0) {
      h_idx / sqrt(n_papers)
    } else {
      NA
    }
    
    data.frame(
      author = au,
      n_papers = n_papers,
      total_citations = total_citations,
      citations_per_paper = if (n_papers > 0) total_citations / n_papers else 0,
      h_index = h_idx,
      g_index = g_idx,
      m_quotient = m_q,
      i10_index = i10,
      hI_index = hI_norm,
      first_year = first_year,
      stringsAsFactors = FALSE
    )
  })
  
  do.call(rbind, indices_list)
}

#' Compute h-index
#' @keywords internal
compute_h_index <- function(citations_sorted_desc) {
  citations_sorted_desc <- citations_sorted_desc[!is.na(citations_sorted_desc)]
  if (length(citations_sorted_desc) == 0) return(0)
  
  citations_sorted_desc <- sort(citations_sorted_desc, decreasing = TRUE)
  
  h <- 0
  for (i in seq_along(citations_sorted_desc)) {
    if (citations_sorted_desc[i] >= i) {
      h <- i
    } else {
      break
    }
  }
  
  h
}

#' Compute g-index
#' @keywords internal
compute_g_index <- function(citations_sorted_desc) {
  citations_sorted_desc <- citations_sorted_desc[!is.na(citations_sorted_desc)]
  if (length(citations_sorted_desc) == 0) return(0)
  
  citations_sorted_desc <- sort(citations_sorted_desc, decreasing = TRUE)
  
  g <- 0
  cumsum_citations <- 0
  
  for (i in seq_along(citations_sorted_desc)) {
    cumsum_citations <- cumsum_citations + citations_sorted_desc[i]
    if (cumsum_citations >= i^2) {
      g <- i
    } else {
      break
    }
  }
  
  g
}
# <<< END FILE: R/module_m1/compute/m1_compute_author_indices.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_authors.R
# ============================================================================
# m1_compute_authors.R - Authors metric for M1
# ============================================================================

#' @export
compute_m1_authors <- function(input, config = biblio_config()) {
  if (!is.data.frame(input) || nrow(input) == 0) {
    return(list(top_authors = m1_empty_rank_table(), author_productivity = list(), author_gini = NA_real_, status = "error"))
  }

  top_n <- config$top_n_authors

  author_data <- if (identical(config$counting_mode, "fractional")) {
    m1_compute_authors_manual(input, counting_mode = "fractional")
  } else {
    tryCatch({
      cached <- get_cached_biblio_analysis(input); res <- cached$res
      s <- summary(res, pause = FALSE, verbose = FALSE)
      mp <- s$MostProdAuthors
      colnames(mp) <- make.unique(colnames(mp))
      art_col <- if ("Articles" %in% colnames(mp)) "Articles" else
        if ("Freq" %in% colnames(mp)) "Freq" else colnames(mp)[2]
      mp[[art_col]] <- suppressWarnings(as.numeric(mp[[art_col]]))
      mp <- mp[!is.na(mp[[art_col]]), ]
      mp <- mp[order(-mp[[art_col]]), ]
      au_col <- if ("Authors" %in% colnames(mp)) "Authors" else
        if ("AU" %in% colnames(mp)) "AU" else colnames(mp)[1]
      data.frame(
        Authors = mp[[au_col]],
        Articles = mp[[art_col]],
        stringsAsFactors = FALSE
      )
    }, error = function(e) {
      m1_compute_authors_manual(input, counting_mode = "full")
    })
  }

  top_n_actual <- min(top_n, nrow(author_data))
  top_authors <- tibble::tibble(
    rank  = seq_len(top_n_actual),
    label = author_data$Authors[seq_len(top_n_actual)],
    value = author_data$Articles[seq_len(top_n_actual)]
  )

  # Gini (FIXED: correct column names)
  lorenz <- m1_compute_lorenz(top_authors$value)
  author_gini <- m1_compute_gini(lorenz$cumulative_entities, lorenz$cumulative_values)

  list(top_authors = top_authors, author_productivity = author_data, author_gini = author_gini, status = "success")
}

#' Manual author aggregation with counting-mode support
#' @keywords internal
m1_compute_authors_manual <- function(input, counting_mode = "full") {
  if (!"AU" %in% names(input)) {
    return(data.frame(Authors = character(0), Articles = numeric(0), stringsAsFactors = FALSE))
  }

  rows <- vector("list", nrow(input))
  for (i in seq_len(nrow(input))) {
    authors <- trimws(unlist(strsplit(as.character(input$AU[i]), ";", fixed = TRUE)))
    authors <- authors[nzchar(authors)]
    if (length(authors) == 0) next
    weight <- if (identical(counting_mode, "fractional")) 1 / length(authors) else 1
    rows[[i]] <- data.frame(
      Authors = authors,
      Articles = rep(weight, length(authors)),
      stringsAsFactors = FALSE
    )
  }

  author_df <- dplyr::bind_rows(rows)
  if (nrow(author_df) == 0) {
    return(data.frame(Authors = character(0), Articles = numeric(0), stringsAsFactors = FALSE))
  }

  author_df %>%
    dplyr::group_by(Authors) %>%
    dplyr::summarise(Articles = sum(Articles, na.rm = TRUE), .groups = "drop") %>%
    dplyr::arrange(desc(Articles)) %>%
    as.data.frame(stringsAsFactors = FALSE)
}
# <<< END FILE: R/module_m1/compute/m1_compute_authors.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_bradford.R
# ============================================================================
# m1_compute_bradford.R - Bradford metric (CORRECT ALGORITHM)
#
# Bradford's Law states:
# - Zone 1: Top sources producing 1/3 of articles (core)
# - Zone 2: Next group producing 1/3 (moderate)
# - Zone 3: Remaining sources producing 1/3 (peripheral)
# - Sources in zones follow geometric progression: 1 : n : n²
# ============================================================================

#' @export
compute_m1_bradford <- function(input, config = biblio_config()) {
  if (!is.data.frame(input) || nrow(input) == 0) {
    return(list(bradford_table = tibble::tibble(), core_sources = m1_empty_rank_table(),
                zone_summary = list(), status = "error"))
  }

  source_df <- m1_bradford_manual(input)

  if (nrow(source_df) == 0) {
    return(list(bradford_table = tibble::tibble(), core_sources = m1_empty_rank_table(),
                zone_summary = list(), status = "error"))
  }

  colnames(source_df) <- make.unique(colnames(source_df))

  # Ensure Zone column exists
  if (!"Zone" %in% colnames(source_df)) {
    source_df <- m1_bradford_assign_zones(source_df)
  }

  bradford_table <- tibble::tibble(
    rank = seq_len(nrow(source_df)),
    source = source_df$SO,
    freq = source_df$Freq,
    zone = source_df$Zone
  )

  core <- source_df[source_df$Zone == "Zone 1: Core", ]
  core_sources <- if (nrow(core) > 0) {
    tibble::tibble(rank = seq_len(nrow(core)), label = core$SO, value = core$Freq)
  } else {
    m1_empty_rank_table()
  }

  zone_summary <- list(
    zone1 = list(n_sources = sum(source_df$Zone == "Zone 1: Core"),
                 n_articles = sum(source_df$Freq[source_df$Zone == "Zone 1: Core"])),
    zone2 = list(n_sources = sum(source_df$Zone == "Zone 2: Moderate"),
                 n_articles = sum(source_df$Freq[source_df$Zone == "Zone 2: Moderate"])),
    zone3 = list(n_sources = sum(source_df$Zone == "Zone 3: Peripheral"),
                 n_articles = sum(source_df$Freq[source_df$Zone == "Zone 3: Peripheral"]))
  )

  list(bradford_table = bradford_table, core_sources = core_sources,
       zone_summary = zone_summary, status = "success")
}

#' Manual Bradford computation
m1_bradford_manual <- function(input) {
  if (!"SO" %in% names(input)) return(data.frame())

  source_counts <- table(input$SO, useNA = "no")
  sdf <- data.frame(SO = names(source_counts), Freq = as.integer(source_counts), stringsAsFactors = FALSE)
  sdf <- sdf[order(-sdf$Freq), ]
  sdf$Rank <- seq_len(nrow(sdf))
  sdf$CumFreq <- cumsum(sdf$Freq)

  m1_bradford_assign_zones(sdf)
}

#' Assign Bradford zones using cumulative article distribution
m1_bradford_assign_zones <- function(sdf) {
  total <- sum(sdf$Freq)
  sdf$Zone <- ifelse(
    sdf$CumFreq <= total / 3, "Zone 1: Core",
    ifelse(sdf$CumFreq <= 2 * total / 3, "Zone 2: Moderate",
           "Zone 3: Peripheral"))
  sdf
}
# <<< END FILE: R/module_m1/compute/m1_compute_bradford.R

