# >>> BEGIN FILE: R/module_m1/compute/m1_compute_collaboration.R
# ============================================================================
# m1_compute_collaboration.R - Collaboration Metrics
# ============================================================================
# Computes collaboration indices for bibliometric analysis:
# - Collaboration Index (CI): Average authors per paper
# - Collaboration Coefficient (CC): Weighted measure of multi-authorship
# - Degree of Collaboration (DC): Proportion of multi-authored papers
# - Modified Collaboration Coefficient (CC')
#
# IEEE Q1 Enhancement: Includes comprehensive collaboration analysis
# following established bibliometric methodologies.

#' Compute collaboration metrics
#'
#' @param input Bibliographic data frame
#' @param config Configuration list
#' @return List with collaboration metrics
#' @export
compute_m1_collaboration <- function(input, config = biblio_config()) {
  validate_is_data_frame(input)
  
  au_col <- "AU"
  if (!au_col %in% names(input)) au_col <- "AF"
  
  if (!au_col %in% names(input)) {
    return(list(
      metrics = list(),
      by_year = data.frame(),
      by_document_type = data.frame(),
      summary = list(),
      status = "error: no author column found"
    ))
  }
  
  authors_per_paper <- compute_authors_per_paper(input, au_col)
  
  if (length(authors_per_paper) == 0) {
    return(list(
      metrics = list(),
      by_year = data.frame(),
      by_document_type = data.frame(),
      summary = list(),
      status = "error: could not compute authors per paper"
    ))
  }
  
  metrics <- compute_collaboration_indices(authors_per_paper)
  
  by_year <- if ("PY" %in% names(input)) {
    compute_collaboration_by_year(input, au_col)
  } else {
    data.frame()
  }
  
  by_doc_type <- if ("DT" %in% names(input)) {
    compute_collaboration_by_doc_type(input, au_col)
  } else {
    data.frame()
  }
  
  summary_stats <- list(
    total_papers = length(authors_per_paper),
    single_authored = sum(authors_per_paper == 1),
    multi_authored = sum(authors_per_paper > 1),
    single_author_pct = mean(authors_per_paper == 1) * 100,
    collaboration_index = metrics$CI,
    collaboration_coefficient = metrics$CC,
    degree_of_collaboration = metrics$DC,
    mean_authors_per_paper = metrics$mean_authors,
    median_authors_per_paper = metrics$median_authors,
    max_authors = metrics$max_authors
  )
  
  list(
    metrics = metrics,
    by_year = by_year,
    by_document_type = by_doc_type,
    summary = summary_stats,
    authors_per_paper = authors_per_paper,
    status = "success"
  )
}

#' Compute authors per paper
#' @keywords internal
compute_authors_per_paper <- function(input, au_col) {
  authors_col <- input[[au_col]]
  
  sapply(authors_col, function(au_str) {
    if (is.na(au_str) || au_str == "") return(1)
    authors <- strsplit(as.character(au_str), ";")[[1]]
    authors <- trimws(authors)
    authors <- authors[authors != ""]
    max(1, length(authors))
  })
}

#' Compute collaboration indices
#' @keywords internal
compute_collaboration_indices <- function(authors_per_paper) {
  n <- length(authors_per_paper)
  if (n == 0) {
    return(list(
      CI = NA_real_,
      CC = NA_real_,
      DC = NA_real_,
      CC_modified = NA_real_,
      mean_authors = NA_real_,
      median_authors = NA_real_,
      max_authors = NA_real_
    ))
  }
  
  freq_table <- table(authors_per_paper)
  k_values <- as.integer(names(freq_table))
  f_k <- as.integer(freq_table)
  
  # Collaboration Index (CI): mean number of authors per paper
  CI <- mean(authors_per_paper, na.rm = TRUE)
  
  # Degree of Collaboration (DC): proportion of multi-authored papers
  DC <- mean(authors_per_paper > 1, na.rm = TRUE)
  
  # Collaboration Coefficient (CC): Ajiferuke's formula
  # CC = sum(f_k * (1 - 1/k)) / n
  # where f_k = number of papers with k authors
  # Handle k = 0 case (should not occur) and ensure valid calculation
  CC <- sum(f_k * (1 - 1/k_values), na.rm = TRUE) / n
  
  list(
    CI = CI,
    CC = CC,
    DC = DC,
    mean_authors = mean(authors_per_paper, na.rm = TRUE),
    median_authors = median(authors_per_paper, na.rm = TRUE),
    max_authors = max(authors_per_paper, na.rm = TRUE),
    min_authors = min(authors_per_paper, na.rm = TRUE),
    sd_authors = sd(authors_per_paper, na.rm = TRUE),
    distribution = data.frame(
      n_authors = k_values,
      n_papers = f_k,
      proportion = f_k / n
    )
  )
}

#' Compute collaboration by year
#' @keywords internal
compute_collaboration_by_year <- function(input, au_col) {
  py_col <- "PY"
  if (!py_col %in% names(input)) {
    return(data.frame())
  }
  
  authors_per_paper <- compute_authors_per_paper(input, au_col)
  years <- input[[py_col]]
  
  valid_idx <- !is.na(years) & years > 1900 & years <= as.numeric(format(Sys.Date(), "%Y"))
  
  if (sum(valid_idx) == 0) {
    return(data.frame())
  }
  
  years_valid <- years[valid_idx]
  authors_valid <- authors_per_paper[valid_idx]
  
  # Use safer aggregation approach
  year_groups <- split(authors_valid, years_valid)
  result <- do.call(rbind, lapply(names(year_groups), function(yr) {
    x <- year_groups[[yr]]
    data.frame(
      year = as.numeric(yr),
      mean_authors = mean(x, na.rm = TRUE),
      median_authors = median(x, na.rm = TRUE),
      n_papers = length(x),
      single_author = sum(x == 1),
      multi_author = sum(x > 1),
      stringsAsFactors = FALSE
    )
  }))
  
  result$collaboration_rate <- result$multi_author / result$n_papers
  
  result[order(result$year), ]
}

#' Compute collaboration by document type
#' @keywords internal
compute_collaboration_by_doc_type <- function(input, au_col) {
  dt_col <- "DT"
  if (!dt_col %in% names(input)) {
    return(data.frame())
  }
  
  authors_per_paper <- compute_authors_per_paper(input, au_col)
  doc_types <- input[[dt_col]]
  
  valid_idx <- !is.na(doc_types) & doc_types != ""
  
  if (sum(valid_idx) == 0) {
    return(data.frame())
  }
  
  types_valid <- doc_types[valid_idx]
  authors_valid <- authors_per_paper[valid_idx]
  
  # Use safer aggregation approach
  type_groups <- split(authors_valid, types_valid)
  result <- do.call(rbind, lapply(names(type_groups), function(tp) {
    x <- type_groups[[tp]]
    data.frame(
      document_type = tp,
      mean_authors = mean(x, na.rm = TRUE),
      median_authors = median(x, na.rm = TRUE),
      n_papers = length(x),
      single_author = sum(x == 1),
      multi_author = sum(x > 1),
      stringsAsFactors = FALSE
    )
  }))
  
  result$collaboration_rate <- result$multi_author / result$n_papers
  
  result[order(-result$n_papers), ]
}
# <<< END FILE: R/module_m1/compute/m1_compute_collaboration.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_countries.R
# ============================================================================
# m1_compute_countries.R - Countries metric for M1
# ============================================================================

#' @export
compute_m1_countries <- function(input, config = biblio_config()) {
  if (!is.data.frame(input) || nrow(input) == 0) {
    return(list(top_countries_by_articles = m1_empty_rank_table(), top_countries_by_citations = m1_empty_rank_table(),
                avg_citations_by_country = m1_empty_rank_table(), scp_mcp_summary = tibble::tibble(),
                country_gini_articles = NA_real_, country_gini_citations = NA_real_, status = "error"))
  }

  top_n <- config$top_n_countries
  if (identical(config$counting_mode, "fractional") || any(c("AU_CO", "AU1_CO") %in% names(input))) {
    return(m1_compute_countries_manual(input, config))
  }

  # Try bibliometrix first
  country_data <- tryCatch({
    cached <- get_cached_biblio_analysis(input)
    res <- cached$res
    s <- summary(res, pause = FALSE, verbose = FALSE)
    list(most_prod = s$MostProdCountries, tc_per = s$TCperCountries)
  }, error = function(e) {
    list(most_prod = NULL, tc_per = NULL)
  })

  most_prod <- country_data$most_prod
  tc_per <- country_data$tc_per

  # Top countries by articles
  if (!is.null(most_prod) && nrow(most_prod) > 0) {
    colnames(most_prod) <- make.unique(colnames(most_prod))
    art_col     <- if ("Articles" %in% colnames(most_prod)) "Articles" else colnames(most_prod)[2]
    country_col <- if ("Country"  %in% colnames(most_prod)) "Country"  else colnames(most_prod)[1]
    most_prod[[art_col]] <- suppressWarnings(as.numeric(most_prod[[art_col]]))
    most_prod[[country_col]] <- m1_normalize_country_names(most_prod[[country_col]])
    most_prod <- most_prod[!is.na(most_prod[[art_col]]), ]
    most_prod <- most_prod[order(-most_prod[[art_col]]), ]

    n_mp <- min(top_n, nrow(most_prod))
    top_countries_by_articles <- tibble::tibble(
      rank  = seq_len(n_mp),
      label = most_prod[[country_col]][seq_len(n_mp)],
      value = most_prod[[art_col]][seq_len(n_mp)]
    )
    lorenz <- m1_compute_lorenz(most_prod[[art_col]])
    country_gini_articles <- m1_compute_gini(lorenz$cumulative_entities, lorenz$cumulative_values)
  } else {
    top_countries_by_articles <- m1_empty_rank_table()
    country_gini_articles <- NA_real_
    country_col <- "Country"
  }

  # Top countries by citations + avg citations
  avg_citations_by_country <- m1_empty_rank_table()
  if (!is.null(tc_per) && nrow(tc_per) > 0) {
    colnames(tc_per) <- make.unique(colnames(tc_per))
    cit_col     <- if ("Total Citations" %in% colnames(tc_per)) "Total Citations" else colnames(tc_per)[2]
    tc_country_col <- if ("Country" %in% colnames(tc_per)) "Country" else colnames(tc_per)[1]
    tc_per[[cit_col]] <- suppressWarnings(as.numeric(tc_per[[cit_col]]))
    tc_per[[tc_country_col]] <- m1_normalize_country_names(tc_per[[tc_country_col]])
    tc_per <- tc_per[!is.na(tc_per[[cit_col]]), ]
    tc_per <- tc_per[order(-tc_per[[cit_col]]), ]

    n_tc <- min(top_n, nrow(tc_per))
    top_countries_by_citations <- tibble::tibble(
      rank  = seq_len(n_tc),
      label = tc_per[[tc_country_col]][seq_len(n_tc)],
      value = tc_per[[cit_col]][seq_len(n_tc)]
    )
    lorenz_cit <- m1_compute_lorenz(tc_per[[cit_col]])
    country_gini_citations <- m1_compute_gini(lorenz_cit$cumulative_entities, lorenz_cit$cumulative_values)

    # F5h - Average Article Citations per country
    if ("Average Article Citations" %in% colnames(tc_per)) {
      avg_col <- "Average Article Citations"
      tc_per[[avg_col]] <- suppressWarnings(as.numeric(tc_per[[avg_col]]))
      tc_per_avg <- tc_per[!is.na(tc_per[[avg_col]]), ]
      tc_per_avg <- tc_per_avg[order(-tc_per_avg[[avg_col]]), ]
      if (nrow(tc_per_avg) > 0) {
        n_avg <- min(top_n, nrow(tc_per_avg))
        avg_citations_by_country <- tibble::tibble(
          rank  = seq_len(n_avg),
          label = tc_per_avg[[tc_country_col]][seq_len(n_avg)],
          value = tc_per_avg[[avg_col]][seq_len(n_avg)]
        )
      }
    }
  } else {
    top_countries_by_citations <- m1_empty_rank_table()
    country_gini_citations <- NA_real_
  }

  # SCP/MCP — country_col was set in the block above (defaults to "Country" if most_prod was empty)
  if (!is.null(most_prod) && all(c("SCP", "MCP") %in% colnames(most_prod))) {
    most_prod$SCP <- suppressWarnings(as.numeric(most_prod$SCP))
    most_prod$MCP <- suppressWarnings(as.numeric(most_prod$MCP))
    most_prod <- most_prod[!is.na(most_prod$SCP) & !is.na(most_prod$MCP), ]
    n <- min(top_n, nrow(most_prod))
    art_col2 <- if ("Articles" %in% colnames(most_prod)) "Articles" else colnames(most_prod)[2]
    denom <- most_prod$SCP[seq_len(n)] + most_prod$MCP[seq_len(n)]
    mcp_ratio <- ifelse(denom > 0, round(most_prod$MCP[seq_len(n)] / denom * 100, 1), NA_real_)
    scp_mcp <- tibble::tibble(
      rank      = seq_len(n),
      country   = most_prod[[country_col]][seq_len(n)],
      articles  = most_prod[[art_col2]][seq_len(n)],
      scp       = most_prod$SCP[seq_len(n)],
      mcp       = most_prod$MCP[seq_len(n)],
      mcp_ratio = mcp_ratio
    )
  } else {
    scp_mcp <- tibble::tibble()
  }

  list(
    top_countries_by_articles = top_countries_by_articles,
    top_countries_by_citations = top_countries_by_citations,
    avg_citations_by_country = avg_citations_by_country,
    scp_mcp_summary = scp_mcp, most_prod_countries = most_prod, tc_per_countries = tc_per,
    country_gini_articles = country_gini_articles, country_gini_citations = country_gini_citations,
    status = "success"
  )
}

#' Manual country aggregation with counting-mode support
#' @keywords internal
m1_compute_countries_manual <- function(input, config = biblio_config()) {
  country_col <- if ("AU_CO" %in% names(input)) "AU_CO" else if ("AU1_CO" %in% names(input)) "AU1_CO" else NULL
  top_n <- config$top_n_countries
  if (is.null(country_col)) {
    return(list(
      top_countries_by_articles = m1_empty_rank_table(),
      top_countries_by_citations = m1_empty_rank_table(),
      avg_citations_by_country = m1_empty_rank_table(),
      scp_mcp_summary = tibble::tibble(),
      country_gini_articles = NA_real_,
      country_gini_citations = NA_real_,
      status = "error"
    ))
  }

  rows <- vector("list", nrow(input))
  scp_rows <- vector("list", nrow(input))

  for (i in seq_len(nrow(input))) {
    countries <- trimws(unlist(strsplit(as.character(input[[country_col]][i]), ";", fixed = TRUE)))
    countries <- unique(m1_normalize_country_names(countries[nzchar(countries)]))
    countries <- countries[!is.na(countries) & nzchar(countries)]
    if (length(countries) == 0) next

    weight <- if (identical(config$counting_mode, "fractional")) 1 / length(countries) else 1
    tc_value <- if ("TC" %in% names(input)) suppressWarnings(as.numeric(input$TC[i])) else 0
    tc_value[is.na(tc_value)] <- 0
    rows[[i]] <- data.frame(
      country = countries,
      article_count = rep(weight, length(countries)),
      total_citations = rep(tc_value * weight, length(countries)),
      scp = if (length(countries) == 1) 1 else 0,
      mcp = if (length(countries) > 1) 1 else 0,
      stringsAsFactors = FALSE
    )

    scp_rows[[i]] <- data.frame(
      country = countries,
      scp_doc = if (length(countries) == 1) 1 else 0,
      mcp_doc = if (length(countries) > 1) 1 else 0,
      stringsAsFactors = FALSE
    )
  }

  country_df <- dplyr::bind_rows(rows)
  if (nrow(country_df) == 0) {
    return(list(
      top_countries_by_articles = m1_empty_rank_table(),
      top_countries_by_citations = m1_empty_rank_table(),
      avg_citations_by_country = m1_empty_rank_table(),
      scp_mcp_summary = tibble::tibble(),
      country_gini_articles = NA_real_,
      country_gini_citations = NA_real_,
      status = "error"
    ))
  }

  summary_df <- country_df %>%
    dplyr::group_by(country) %>%
    dplyr::summarise(
      article_count = sum(article_count, na.rm = TRUE),
      total_citations = sum(total_citations, na.rm = TRUE),
      .groups = "drop"
    ) %>%
    dplyr::mutate(
      average_citations = ifelse(article_count > 0, total_citations / article_count, 0),
      share = article_count / sum(article_count)
    ) %>%
    dplyr::arrange(desc(article_count))

  n_art <- min(top_n, nrow(summary_df))
  top_countries_by_articles <- tibble::tibble(
    rank = seq_len(n_art),
    label = summary_df$country[seq_len(n_art)],
    value = summary_df$article_count[seq_len(n_art)]
  )

  summary_cit <- summary_df %>% dplyr::arrange(desc(total_citations))
  n_cit <- min(top_n, nrow(summary_cit))
  top_countries_by_citations <- tibble::tibble(
    rank = seq_len(n_cit),
    label = summary_cit$country[seq_len(n_cit)],
    value = summary_cit$total_citations[seq_len(n_cit)]
  )

  summary_avg <- summary_df %>% dplyr::arrange(desc(average_citations))
  n_avg <- min(top_n, nrow(summary_avg))
  avg_citations_by_country <- tibble::tibble(
    rank = seq_len(n_avg),
    label = summary_avg$country[seq_len(n_avg)],
    value = summary_avg$average_citations[seq_len(n_avg)]
  )

  scp_summary <- dplyr::bind_rows(scp_rows) %>%
    dplyr::group_by(country) %>%
    dplyr::summarise(
      scp = sum(scp_doc, na.rm = TRUE),
      mcp = sum(mcp_doc, na.rm = TRUE),
      .groups = "drop"
    ) %>%
    dplyr::left_join(summary_df[, c("country", "article_count")], by = "country") %>%
    dplyr::mutate(
      mcp_ratio = ifelse((scp + mcp) > 0, round(mcp / (scp + mcp) * 100, 1), NA_real_)
    ) %>%
    dplyr::arrange(desc(article_count))

  lorenz_art <- m1_compute_lorenz(summary_df$article_count)
  lorenz_cit <- m1_compute_lorenz(summary_df$total_citations)

  list(
    top_countries_by_articles = top_countries_by_articles,
    top_countries_by_citations = top_countries_by_citations,
    avg_citations_by_country = avg_citations_by_country,
    scp_mcp_summary = scp_summary,
    most_prod_countries = summary_df,
    tc_per_countries = summary_cit,
    country_gini_articles = m1_compute_gini(lorenz_art$cumulative_entities, lorenz_art$cumulative_values),
    country_gini_citations = m1_compute_gini(lorenz_cit$cumulative_entities, lorenz_cit$cumulative_values),
    status = "success"
  )
}
# <<< END FILE: R/module_m1/compute/m1_compute_countries.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_country_trends.R
# ============================================================================
# module_m1/compute/m1_compute_country_trends.R - Country trend analysis
# ============================================================================

#' @export
compute_m1_country_trends <- function(bib_data, config = biblio_config()) {
  if (!is.data.frame(bib_data)) {
    return(list(status = "error", trends = data.frame()))
  }

  # Get country data from bibliometrix
  res <- tryCatch(bibliometrix::biblioAnalysis(bib_data, sep = ";"), error = function(e) NULL)
  if (is.null(res)) return(list(status = "error", trends = data.frame()))

  s <- tryCatch(summary(res, pause = FALSE, verbose = FALSE), error = function(e) NULL)
  if (is.null(s)) return(list(status = "error", trends = data.frame()))

  mp <- s$MostProdCountries
  tc <- s$TCperCountries

  if (is.null(mp) || nrow(mp) == 0) {
    return(list(status = "error", trends = data.frame()))
  }

  colnames(mp) <- make.unique(colnames(mp))
  art_col <- if ("Articles" %in% colnames(mp)) "Articles" else colnames(mp)[2]
  mp[[art_col]] <- suppressWarnings(as.numeric(mp[[art_col]]))
  mp <- mp[!is.na(mp[[art_col]]), ]

  # Build country data
  country_data <- data.frame(
    country = mp$Country,
    articles = mp[[art_col]],
    stringsAsFactors = FALSE
  )

  # Add citations if available
  if (!is.null(tc) && nrow(tc) > 0) {
    colnames(tc) <- make.unique(colnames(tc))
    cit_col <- if ("Total Citations" %in% colnames(tc)) "Total Citations" else colnames(tc)[2]
    tc[[cit_col]] <- suppressWarnings(as.numeric(tc[[cit_col]]))
    tc <- tc[!is.na(tc[[cit_col]]), ]

    merged <- merge(country_data, tc[, c("Country", cit_col)], by.x = "country", by.y = "Country", all.x = TRUE)
    merged$citations <- merged[[cit_col]]
    merged[[cit_col]] <- NULL
    country_data <- merged
  } else {
    country_data$citations <- NA_real_
  }

  # Sort by articles
  country_data <- country_data[order(-country_data$articles), ]

  # Assign quadrants based on medians
  med_art <- median(country_data$articles, na.rm = TRUE)
  med_cit <- median(country_data$citations, na.rm = TRUE)

  country_data$quadrant <- ifelse(
    country_data$articles >= med_art & country_data$citations >= med_cit, "High Productivity, High Impact",
    ifelse(country_data$articles >= med_art & (is.na(country_data$citations) | country_data$citations < med_cit), "High Productivity, Low Impact",
    ifelse((is.na(country_data$articles) | country_data$articles < med_art) & country_data$citations >= med_cit, "Low Productivity, High Impact",
           "Low Productivity, Low Impact")))

  list(status = "success", trends = head(country_data, config$top_n_countries))
}
# <<< END FILE: R/module_m1/compute/m1_compute_country_trends.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_doc_types.R
# ============================================================================
# m1_compute_doc_types.R - Document types metric for M1
# ============================================================================

#' Compute M1 document types
#' @param input A data frame of bibliographic data.
#' @param config A configuration list.
#' @export
compute_m1_doc_types <- function(input, config = biblio_config()) {
  if (!is.data.frame(input) || nrow(input) == 0) {
    return(list(
      doc_type_table  = m1_empty_rank_table(),
      doc_type_counts = list(),
      status          = "error"
    ))
  }

  # Try bibliometrix first, fallback to manual
  dt_counts <- tryCatch({
    cached <- get_cached_biblio_analysis(input)
    res <- cached$res
    s <- summary(res, pause = FALSE, verbose = FALSE)
    m1_extract_document_types(s$MainInformationDF)
  }, error = function(e) {
    # Fallback: count DT column directly
    if ("DT" %in% names(input)) {
      as.list(table(input$DT, useNA = "no"))
    } else {
      list(article = nrow(input))
    }
  })

  # Build table
  dt_df <- data.frame(
    type  = names(dt_counts),
    count = as.integer(unlist(dt_counts)),
    stringsAsFactors = FALSE
  )
  dt_df <- dt_df[dt_df$count > 0, , drop = FALSE]

  if (nrow(dt_df) == 0) {
    return(list(
      doc_type_table  = m1_empty_rank_table(),
      doc_type_counts = dt_counts,
      doc_type_percentages = list(),
      status          = "success"
    ))
  }

  total <- sum(dt_df$count)
  dt_df$percentage <- m1_compute_percentage(dt_df$count, total)
  dt_df <- dt_df[order(-dt_df$count), ]

  label_map <- get_label_mapping()
  dt_df$label <- ifelse(dt_df$type %in% names(label_map), label_map[dt_df$type], dt_df$type)

  doc_type_table <- tibble::tibble(
    rank       = seq_len(nrow(dt_df)),
    label      = dt_df$label,
    value      = dt_df$count,
    percentage = dt_df$percentage
  )

  list(
    doc_type_table  = doc_type_table,
    doc_type_counts = dt_counts,
    doc_type_percentages = stats::setNames(as.list(dt_df$percentage), dt_df$label),
    status          = "success"
  )
}
# <<< END FILE: R/module_m1/compute/m1_compute_doc_types.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_hypotheses.R
# ============================================================================
# m1_compute_hypotheses.R - Hypothesis Testing for M1
# ============================================================================
# Tests key bibliometric hypotheses for main information analysis

#' Compute hypothesis tests for M1
#'
#' Tests fundamental bibliometric hypotheses:
#' - Lotka's Law conformity
#' - Bradford's Law conformity
#' - Price's Law conformity
#' - Citation distribution patterns
#' - Collaboration patterns
#' - Concentration metrics
#'
#' @param input Bibliographic data frame
#' @param config Configuration list
#' @return List with hypothesis test results
#' @export
compute_m1_hypotheses <- function(input, config = biblio_config()) {
  validate_is_data_frame(input)
  
  hypotheses <- list()
  
  # H01.1: Author productivity follows Lotka's Law
  hypotheses$H01_1 <- test_lotka_law_hypothesis(input, config)
  
  # H01.2: Citation distribution follows power law
  hypotheses$H01_2 <- test_citation_power_law_hypothesis(input, config)
  
  # H01.3: Bradford's Law applies to source distribution
  hypotheses$H01_3 <- test_bradford_hypothesis(input, config)
  
  # H01.4: Collaboration rate has increased over time
  hypotheses$H01_4 <- test_collaboration_trend_hypothesis(input, config)
  
  # H01.5: Author productivity inequality follows Price's Law
  hypotheses$H01_5 <- test_price_law_hypothesis(input, config)
  
  # H01.6: Keywords follow Zipf's distribution
  hypotheses$H01_6 <- test_zipf_keywords_hypothesis(input, config)
  
  # H01.7: Citation distribution is highly skewed (Gini > 0.7)
  hypotheses$H01_7 <- test_citation_gini_hypothesis(input, config)
  
  # H01.8: Document types follow expected proportions for the field
  hypotheses$H01_8 <- test_document_type_hypothesis(input, config)
  
  # H01.9: International collaboration correlates with citation impact
  hypotheses$H01_9 <- test_intl_collab_citation_hypothesis(input, config)
  
  # H01.10: Source concentration follows Bradford zones (1/3 in core)
  hypotheses$H01_10 <- test_bradford_zones_hypothesis(input, config)
  
  # Additional tests if data permits
  hypotheses$H01_11 <- test_keyword_concentration_hypothesis(input, config)
  hypotheses$H01_12 <- test_author_dominance_hypothesis(input, config)
  
  summary_stats <- summarize_hypothesis_results(hypotheses)
  
  list(
    hypotheses = hypotheses,
    n_hypotheses = length(hypotheses),
    n_rejected = summary_stats$n_rejected,
    n_not_rejected = summary_stats$n_failed_to_reject,
    rejection_rate = summary_stats$rejection_rate,
    summary = summary_stats,
    status = "success"
  )
}

# ============================================================================
# Individual Hypothesis Tests
# ============================================================================

test_lotka_law_hypothesis <- function(input, config) {
  lotka_result <- tryCatch({
    compute_m1_lotka(input, config)
  }, error = function(e) NULL)
  
  if (is.null(lotka_result) || !is.list(lotka_result)) {
    return(list(
      hyphypothesis = "Author productivity follows Lotka's Law (alpha = 2)",
      null = "Author productivity does NOT follow Lotka's Law",
      result = "inconclusive",
      interpretation = "Could not compute Lotka's Law parameters"
    ))
  }
  
  if (is.null(lotka_result$status) || lotka_result$status != "success") {
    return(list(
      hyphypothesis = "Author productivity follows Lotka's Law (alpha = 2)",
      null = "Author productivity does NOT follow Lotka's Law",
      result = "inconclusive",
      interpretation = "Lotka computation was not successful"
    ))
  }
  
  # Safely extract lotka sub-list
  lotka <- lotka_result$lotka
  if (is.null(lotka) || !is.list(lotka)) {
    return(list(
      hyphypothesis = "Author productivity follows Lotka's Law (alpha = 2)",
      null = "Author productivity does NOT follow Lotka's Law",
      result = "inconclusive",
      interpretation = "Lotka results not available"
    ))
  }
  
  # Safely extract alpha
  alpha <- lotka$alpha
  if (is.null(alpha) || length(alpha) == 0) {
    alpha <- NA
  } else if (is.list(alpha)) {
    alpha <- NA
  } else {
    alpha <- as.numeric(alpha)[1]
  }
  
  if (is.na(alpha)) {
    return(list(
      hyphypothesis = "Author productivity follows Lotka's Law (alpha = 2)",
      null = "Author productivity does NOT follow Lotka's Law",
      result = "inconclusive",
      interpretation = "Could not estimate alpha parameter"
    ))
  }
  
  alpha_diff <- abs(alpha - 2)
  
  # Safely extract gof_pvalue
  gof_pvalue <- lotka$gof_pvalue
  if (is.null(gof_pvalue) || length(gof_pvalue) == 0 || is.list(gof_pvalue)) {
    gof_pvalue <- NA_real_
  } else {
    gof_pvalue <- as.numeric(gof_pvalue)[1]
  }
  
  result <- if (alpha_diff < 0.3 && (is.na(gof_pvalue) || gof_pvalue > 0.05)) {
    "fail_to_reject"
  } else {
    "reject"
  }
  
  pval_str <- if (is.na(gof_pvalue)) "NA" else sprintf("%.4f", gof_pvalue)
  
  interpretation <- sprintf(
    "Power-law exponent alpha = %.2f (classical = 2.0). %s K-S p-value = %s.",
    alpha,
    if (alpha_diff < 0.3) "Close to theoretical value." else "Deviates from theoretical value.",
    pval_str
  )
  
  # Safely extract other values
  gof_ks <- lotka$gof_ks
  if (is.null(gof_ks) || length(gof_ks) == 0 || is.list(gof_ks)) gof_ks <- NA_real_
  else gof_ks <- as.numeric(gof_ks)[1]
  
  n_authors <- lotka$n_authors
  if (is.null(n_authors) || length(n_authors) == 0 || is.list(n_authors)) n_authors <- NA_integer_
  else n_authors <- as.integer(n_authors)[1]
  
  list(
    hyphypothesis = "Author productivity follows Lotka's Law (alpha = 2)",
    null = "Author productivity does NOT follow Lotka's Law",
    result = result,
    alpha = alpha,
    classical_alpha = 2,
    alpha_difference = alpha_diff,
    ks_statistic = gof_ks,
    ks_pvalue = gof_pvalue,
    n_authors = n_authors,
    interpretation = interpretation
  )
}

test_citation_power_law_hypothesis <- function(input, config) {
  tc_col <- get_citation_column(input)
  if (is.null(tc_col)) {
    return(list(
      hyphypothesis = "Citation distribution follows power law",
      null = "Citations do not follow power law",
      result = "inconclusive",
      interpretation = "No citation data available"
    ))
  }
  
  citations <- input[[tc_col]]
  citations <- citations[!is.na(citations) & citations > 0]
  
  if (length(citations) < 50) {
    return(list(
      hyphypothesis = "Citation distribution follows power law",
      null = "Citations do not follow power law",
      result = "inconclusive",
      interpretation = "Insufficient citation data"
    ))
  }
  
  log_citations <- log(citations)
  fit <- lm(log_citations ~ seq_along(citations))
  r2 <- summary(fit)$r.squared
  
  sorted_cites <- sort(citations, decreasing = TRUE)
  rank <- seq_along(sorted_cites)
  
  log_fit <- lm(log(sorted_cites) ~ log(rank))
  power_exp <- coef(log_fit)[2]
  if (length(power_exp) > 1) power_exp <- power_exp[1]
  
  result <- if (abs(power_exp + 1) < 0.5) "fail_to_reject" else "reject"
  
  interpretation <- sprintf(
    "Fitted power exponent = %.2f (expected ~-1 for power law). R² = %.3f",
    as.numeric(power_exp)[1],
    r2[1]
  )
  
  list(
    hyphypothesis = "Citation distribution follows power law",
    null = "Citations do not follow power law",
    result = result,
    power_exponent = power_exp,
    r_squared = r2,
    n_citations = length(citations),
    interpretation = interpretation
  )
}

test_bradford_hypothesis <- function(input, config) {
  bradford_result <- tryCatch({
    compute_m1_bradford(input, config)
  }, error = function(e) NULL)
  
  if (is.null(bradford_result) || bradford_result$status != "success") {
    return(list(
      hyphypothesis = "Bradford's Law applies to source distribution",
      null = "Source distribution does not follow Bradford's Law",
      result = "inconclusive",
      interpretation = "Could not compute Bradford zones"
    ))
  }
  
  n_sources <- bradford_result$n_sources %||% NA
  bradford_coeff <- bradford_result$bradford_coefficient %||% NA
  
  # Ensure scalars
  if (length(n_sources) > 1) n_sources <- n_sources[1]
  if (length(bradford_coeff) > 1) bradford_coeff <- bradford_coeff[1]
  
  result <- if (!is.na(bradford_coeff[1]) && bradford_coeff[1] < 2) "fail_to_reject" else "reject"
  
  interpretation <- sprintf(
    "Bradford coefficient = %.2f. %s",
    as.numeric(bradford_coeff)[1],
    if (result == "fail_to_reject") "Distribution follows Bradford pattern."
    else "Distribution deviates from Bradford pattern."
  )
  
  list(
    hyphypothesis = "Bradford's Law applies to source distribution",
    null = "Source distribution does not follow Bradford's Law",
    result = result,
    bradford_coefficient = bradford_coeff[1],
    n_sources = n_sources[1],
    interpretation = interpretation
  )
}

test_collaboration_trend_hypothesis <- function(input, config) {
  collab_result <- tryCatch({
    compute_m1_collaboration(input, config)
  }, error = function(e) NULL)
  
  if (is.null(collab_result) || collab_result$status != "success") {
    return(list(
      hyphypothesis = "Collaboration rate has increased over time",
      null = "Collaboration rate is stable or decreasing",
      result = "inconclusive",
      interpretation = "Could not compute collaboration trends"
    ))
  }
  
  collaboration_by_year <- collab_result$by_year
  
  if (is.null(collaboration_by_year) || nrow(collaboration_by_year) < 5) {
    return(list(
      hyphypothesis = "Collaboration rate has increased over time",
      null = "Collaboration rate is stable or decreasing",
      result = "inconclusive",
      interpretation = "Insufficient temporal data"
    ))
  }
  
  # Check for required columns
  if (!"collaboration_rate" %in% names(collaboration_by_year)) {
    # Try to use alternative column names
    if ("mcp_ratio" %in% names(collaboration_by_year)) {
      collaboration_by_year$collaboration_rate <- collaboration_by_year$mcp_ratio
    } else {
      return(list(
        hyphypothesis = "Collaboration rate has increased over time",
        null = "Collaboration rate is stable or decreasing",
        result = "inconclusive",
        interpretation = "Collaboration rate data not available"
      ))
    }
  }
  
  # Check minimum sample size for regression
  if (nrow(collaboration_by_year) < 3) {
    return(list(
      hyphypothesis = "Collaboration rate has increased over time",
      null = "Collaboration rate is stable or decreasing",
      result = "inconclusive",
      interpretation = "Insufficient data points for trend analysis (need at least 3 years)"
    ))
  }
  
  fit <- lm(collaboration_rate ~ year, data = collaboration_by_year)
  
  # Check model convergence and coefficient availability
  if (is.null(fit) || length(coef(fit)) < 2 || is.na(coef(fit)[2])) {
    return(list(
      hyphypothesis = "Collaboration rate has increased over time",
      null = "Collaboration rate is stable or decreasing",
      result = "inconclusive",
      interpretation = "Could not fit regression model"
    ))
  }
  
  slope <- coef(fit)[2]
  p_value <- suppressWarnings(summary(fit)$coefficients[2, 4])
  
  # Ensure scalar values
  slope <- slope[1]
  p_value <- p_value[1]

  if (!is.finite(slope) || !is.finite(p_value)) {
    return(list(
      hyphypothesis = "Collaboration rate has increased over time",
      null = "Collaboration rate is stable or decreasing",
      result = "inconclusive",
      slope = slope,
      p_value = p_value,
      interpretation = "Collaboration trend statistics were not estimable from the available yearly profile."
    ))
  }
  
  result <- if (slope > 0 && p_value < 0.05) "reject_null"
            else if (slope <= 0 && p_value < 0.05) "reject"
            else "fail_to_reject"
  
  if (result == "reject_null") result <- "fail_to_reject"
  
  interpretation <- sprintf(
    "Collaboration trend slope = %.4f articles/year (p = %.4f). %s",
    slope, p_value,
    if (slope > 0) "Increasing trend detected." else "No significant increasing trend."
  )
  
  list(
    hyphypothesis = "Collaboration rate has increased over time",
    null = "Collaboration rate is stable or decreasing",
    result = result,
    slope = slope,
    p_value = p_value,
    interpretation = interpretation
  )
}

test_price_law_hypothesis <- function(input, config) {
  price_result <- tryCatch({
    compute_m1_price_law(input, config)
  }, error = function(e) NULL)
  
  if (is.null(price_result) || price_result$status != "success") {
    return(list(
      hyphypothesis = "Author productivity inequality follows Price's Law",
      null = "Productivity distribution does not follow Price's Law",
      result = "inconclusive",
      interpretation = "Could not compute Price's Law metrics"
    ))
  }
  
  price_index <- price_result$price_index$index %||% NA
  core_prop <- price_result$author_concentration$top_10_pct_share %||% NA
  
  # Ensure scalars
  if (length(price_index) > 1) price_index <- price_index[1]
  if (length(core_prop) > 1) core_prop <- core_prop[1]
  
  n_authors_val <- price_result$price_law$n_authors %||% 100
  if (length(n_authors_val) > 1) n_authors_val <- n_authors_val[1]
  expected_core_prop <- 1 / sqrt(n_authors_val)
  
  result <- if (!is.na(price_index[1]) && abs(price_index[1] - 0.5) < 0.2) "fail_to_reject" else "reject"
  
  interpretation <- sprintf(
    "Price index = %.2f (expected ~0.5). Core authors = %.1f%% (sqrt(N) = %.1f%%).",
    as.numeric(price_index)[1],
    as.numeric(core_prop)[1] * 100,
    as.numeric(expected_core_prop)[1] * 100
  )
  
  list(
    hyphypothesis = "Author productivity inequality follows Price's Law",
    null = "Productivity distribution does not follow Price's Law",
    result = result,
    price_index = price_index,
    core_author_proportion = core_prop,
    expected_core = expected_core_prop,
    interpretation = interpretation
  )
}

test_zipf_keywords_hypothesis <- function(input, config) {
  kw_cols <- c("KW", "DE", "ID", "Keywords")
  kw_col <- NULL
  for (col in kw_cols) {
    if (col %in% names(input)) {
      kw_col <- col
      break
    }
  }
  
  if (is.null(kw_col)) {
    return(list(
      hyphypothesis = "Keywords follow Zipf's distribution",
      null = "Keywords do not follow Zipf's distribution",
      result = "inconclusive",
      interpretation = "No keyword data available"
    ))
  }
  
  keywords <- unlist(strsplit(as.character(input[[kw_col]]), ";"))
  keywords <- trimws(keywords)
  keywords <- keywords[keywords != ""]
  
  if (length(keywords) < 50) {
    return(list(
      hyphypothesis = "Keywords follow Zipf's distribution",
      null = "Keywords do not follow Zipf's distribution",
      result = "inconclusive",
      interpretation = "Insufficient keyword data"
    ))
  }
  
  freq <- sort(table(keywords), decreasing = TRUE)
  rank <- seq_along(freq)
  
  log_fit <- lm(log(as.numeric(freq)) ~ log(rank))
  zipf_exp <- coef(log_fit)[2]
  if (length(zipf_exp) > 1) zipf_exp <- zipf_exp[1]
  
  result <- if (abs(zipf_exp + 1) < 0.5) "fail_to_reject" else "reject"
  
  interpretation <- sprintf(
    "Zipf exponent = %.2f (expected -1). %s",
    as.numeric(zipf_exp)[1],
    if (result == "fail_to_reject") "Distribution closely follows Zipf's Law."
    else "Distribution deviates from Zipf's Law."
  )
  
  list(
    hyphypothesis = "Keywords follow Zipf's distribution",
    null = "Keywords do not follow Zipf's distribution",
    result = result,
    zipf_exponent = zipf_exp,
    n_unique_keywords = length(freq),
    interpretation = interpretation
  )
}

test_citation_gini_hypothesis <- function(input, config) {
  tc_col <- get_citation_column(input)
  if (is.null(tc_col)) {
    return(list(
      hyphypothesis = "Citation distribution is highly concentrated (Gini > 0.7)",
      null = "Citations are relatively evenly distributed (Gini < 0.7)",
      result = "inconclusive",
      interpretation = "No citation data available"
    ))
  }
  
  citations <- input[[tc_col]]
  citations <- citations[!is.na(citations)]
  
  if (length(citations) < 20) {
    return(list(
      hyphypothesis = "Citation distribution is highly concentrated (Gini > 0.7)",
      null = "Citations are relatively evenly distributed (Gini < 0.7)",
      result = "inconclusive",
      interpretation = "Insufficient citation data"
    ))
  }
  
  citations <- sort(citations)
  n <- length(citations)
  index <- 2:n
  gini <- (n + 1 - 2 * sum((n + 1 - index) * citations[index]) / (n * sum(citations))) / n
  
  result <- if (gini > 0.7) "reject_null" else "fail_to_reject"
  if (result == "reject_null") result <- "reject" else result <- "fail_to_reject"
  
  interpretation <- sprintf(
    "Gini coefficient = %.3f. %s",
    gini,
    if (gini > 0.7) "High concentration detected (>0.7)."
    else "Moderate concentration detected."
  )
  
  list(
    hyphypothesis = "Citation distribution is highly concentrated (Gini > 0.7)",
    null = "Citations are relatively evenly distributed (Gini < 0.7)",
    result = result,
    gini = gini,
    threshold = 0.7,
    interpretation = interpretation
  )
}

test_document_type_hypothesis <- function(input, config) {
  dt_result <- tryCatch({
    compute_m1_doc_types(input, config)
  }, error = function(e) NULL)
  
  if (is.null(dt_result) || dt_result$status != "success") {
    return(list(
      hyphypothesis = "Document types follow expected proportions",
      null = "Document type distribution is unusual",
      result = "inconclusive",
      interpretation = "Could not analyze document types"
    ))
  }
  
  dt_table <- dt_result$doc_type_table
  
  if (is.null(dt_table) || nrow(dt_table) == 0) {
    return(list(
      hyphypothesis = "Document types follow expected proportions",
      null = "Document type distribution is unusual",
      result = "inconclusive",
      interpretation = "No document type data"
    ))
  }
  
  labels <- if ("label" %in% names(dt_table)) as.character(dt_table$label) else
    if ("type" %in% names(dt_table)) as.character(dt_table$type) else character(nrow(dt_table))
  article_mask <- tolower(labels) == "article"
  article_prop <- if ("proportion" %in% names(dt_table)) {
    dt_table$proportion[article_mask]
  } else if ("percentage" %in% names(dt_table)) {
    dt_table$percentage[article_mask] / 100
  } else if ("value" %in% names(dt_table)) {
    values <- suppressWarnings(as.numeric(dt_table$value))
    total <- sum(values, na.rm = TRUE)
    if (total > 0) values[article_mask] / total else numeric(0)
  } else {
    numeric(0)
  }
  if (length(article_prop) == 0) article_prop <- NA
  if (length(article_prop) > 1) article_prop <- article_prop[1]
  
  result <- if (!is.na(article_prop[1]) && article_prop[1] > 0.5) "fail_to_reject" else "reject"
  
  interpretation <- sprintf(
    "Articles = %.1f%% of documents. %s",
    as.numeric(article_prop)[1] * 100,
    if (result == "fail_to_reject") "Distribution appears normal."
    else "Unusual document type distribution."
  )
  
  list(
    hyphypothesis = "Document types follow expected proportions",
    null = "Document type distribution is unusual",
    result = result,
    article_proportion = article_prop,
    interpretation = interpretation
  )
}

test_intl_collab_citation_hypothesis <- function(input, config) {
  tc_col <- get_citation_column(input)
  c1_col <- "C1"
  
  if (!tc_col %in% names(input) || !c1_col %in% names(input)) {
    return(list(
      hyphypothesis = "International collaboration correlates with higher citations",
      null = "No relationship between collaboration and citations",
      result = "inconclusive",
      interpretation = "Insufficient data for collaboration-citation analysis"
    ))
  }
  
  citations <- input[[tc_col]]
  c1 <- input[[c1_col]]
  
  is_intl <- sapply(as.character(c1), function(x) {
    if (is.na(x) || x == "") return(NA)
    countries <- unique(extract_countries_from_c1(x))
    length(countries) > 1
  })
  
  valid_idx <- !is.na(is_intl) & !is.na(citations)
  if (sum(valid_idx) < 20) {
    return(list(
      hyphypothesis = "International collaboration correlates with higher citations",
      null = "No relationship between collaboration and citations",
      result = "inconclusive",
      interpretation = "Insufficient international collaboration data"
    ))
  }
  
  intl_cites <- citations[valid_idx & is_intl]
  domestic_cites <- citations[valid_idx & !is_intl]
  
  if (length(intl_cites) < 5 || length(domestic_cites) < 5) {
    return(list(
      hyphypothesis = "International collaboration correlates with higher citations",
      null = "No relationship between collaboration and citations",
      result = "inconclusive",
      interpretation = "Insufficient data in one group"
    ))
  }
  
  test_result <- tryCatch(wilcox.test(intl_cites, domestic_cites), error = function(e) NULL)
  
  mean_intl <- mean(intl_cites, na.rm = TRUE)
  mean_dom <- mean(domestic_cites, na.rm = TRUE)
  p_val <- if (!is.null(test_result) && !is.null(test_result$p.value)) test_result$p.value[1] else NA
  
  result <- if (!is.na(p_val) && mean_intl > mean_dom && p_val < 0.05) "fail_to_reject" else "reject"
  
  interpretation <- sprintf(
    "Intl collab mean citations = %.1f, Domestic = %.1f. Wilcox p = %.4f. %s",
    mean_intl, mean_dom, p_val,
    if (result == "fail_to_reject") "Intl collaboration associated with higher citations."
    else "No significant difference detected."
  )
  
  list(
    hyphypothesis = "International collaboration correlates with higher citations",
    null = "No relationship between collaboration and citations",
    result = result,
    mean_intl_citations = mean_intl,
    mean_domestic_citations = mean_dom,
    p_value = p_val,
    n_intl = length(intl_cites),
    n_domestic = length(domestic_cites),
    interpretation = interpretation
  )
}

test_bradford_zones_hypothesis <- function(input, config) {
  bradford_result <- tryCatch({
    compute_m1_bradford(input, config)
  }, error = function(e) NULL)
  
  if (is.null(bradford_result)) {
    return(list(
      hyphypothesis = "Core sources (top 1/3) contain 1/3 of articles",
      null = "Core sources do not contain 1/3 of articles",
      result = "inconclusive",
      interpretation = "Could not compute Bradford zones"
    ))
  }
  
  core_prop <- bradford_result$core_proportion %||% NA
  article_prop <- bradford_result$core_article_proportion %||% NA
  
  # Ensure scalars
  if (length(core_prop) > 1) core_prop <- core_prop[1]
  if (length(article_prop) > 1) article_prop <- article_prop[1]
  
  result <- if (!is.na(article_prop[1]) && abs(article_prop[1] - 1/3) < 0.15) "fail_to_reject" else "reject"
  
  interpretation <- sprintf(
    "Core sources (1/3) contain %.1f%% of articles (expected ~33%%).",
    as.numeric(article_prop)[1] * 100
  )
  
  list(
    hyphypothesis = "Core sources (top 1/3) contain 1/3 of articles",
    null = "Core sources do not contain 1/3 of articles",
    result = result,
    core_proportion = core_prop,
    core_article_proportion = article_prop,
    interpretation = interpretation
  )
}

test_keyword_concentration_hypothesis <- function(input, config) {
  kw_cols <- c("KW", "DE", "ID", "Keywords")
  kw_col <- NULL
  for (col in kw_cols) {
    if (col %in% names(input)) {
      kw_col <- col
      break
    }
  }
  
  if (is.null(kw_col)) {
    return(list(
      hyphypothesis = "Keywords are concentrated (top 20% = 80% of occurrences)",
      null = "Keywords are distributed more evenly",
      result = "inconclusive",
      interpretation = "No keyword data"
    ))
  }
  
  keywords <- unlist(strsplit(as.character(input[[kw_col]]), ";"))
  keywords <- trimws(keywords)
  keywords <- keywords[keywords != ""]
  
  if (length(keywords) < 50) {
    return(list(
      hyphypothesis = "Keywords are concentrated (top 20% = 80% of occurrences)",
      null = "Keywords are distributed more evenly",
      result = "inconclusive",
      interpretation = "Insufficient keywords"
    ))
  }
  
  freq <- sort(table(keywords), decreasing = TRUE)
  cumsum_freq <- cumsum(freq)
  total <- sum(freq)
  
  top_20_pct <- ceiling(length(freq) * 0.2)
  # Ensure index is within bounds
  top_20_pct <- min(top_20_pct, length(cumsum_freq))
  prop_top_20 <- cumsum_freq[top_20_pct] / total
  if (length(prop_top_20) > 1) prop_top_20 <- prop_top_20[1]
  
  result <- if (prop_top_20 > 0.7) "reject_null" else "fail_to_reject"
  if (result == "reject_null") result <- "reject" else result <- "fail_to_reject"
  
  interpretation <- sprintf(
    "Top 20%% keywords account for %.1f%% of occurrences.",
    as.numeric(prop_top_20)[1] * 100
  )
  
  list(
    hyphypothesis = "Keywords are concentrated (top 20% = 80% of occurrences)",
    null = "Keywords are distributed more evenly",
    result = result,
    top_20_prop = prop_top_20,
    n_unique = length(freq),
    interpretation = interpretation
  )
}

test_author_dominance_hypothesis <- function(input, config) {
  au_col <- "AU"
  if (!au_col %in% names(input)) {
    return(list(
      hyphypothesis = "Top 10% authors produce > 50% of articles",
      null = "Authorship is more distributed",
      result = "inconclusive",
      interpretation = "No author data"
    ))
  }
  
  authors <- unlist(strsplit(as.character(input[[au_col]]), ";"))
  authors <- trimws(authors)
  authors <- authors[authors != ""]
  
  if (length(authors) < 50) {
    return(list(
      hyphypothesis = "Top 10% authors produce > 50% of articles",
      null = "Authorship is more distributed",
      result = "inconclusive",
      interpretation = "Insufficient author data"
    ))
  }
  
  freq <- sort(table(authors), decreasing = TRUE)
  cumsum_freq <- cumsum(freq)
  total <- sum(freq)
  
  top_10_pct <- ceiling(length(freq) * 0.1)
  # Ensure index is within bounds
  top_10_pct <- min(top_10_pct, length(cumsum_freq))
  prop_top_10 <- cumsum_freq[top_10_pct] / total
  if (length(prop_top_10) > 1) prop_top_10 <- prop_top_10[1]
  
  result <- if (prop_top_10 > 0.4) "reject_null" else "fail_to_reject"
  if (result == "reject_null") result <- "reject" else result <- "fail_to_reject"
  
  interpretation <- sprintf(
    "Top 10%% authors produce %.1f%% of articles.",
    as.numeric(prop_top_10)[1] * 100
  )
  
  list(
    hyphypothesis = "Top 10% authors produce > 50% of articles",
    null = "Authorship is more distributed",
    result = result,
    top_10_prop = prop_top_10,
    n_unique = length(freq),
    interpretation = interpretation
  )
}

# ============================================================================
# Helper Functions
# ============================================================================

get_citation_column <- function(input) {
  tc_cols <- c("TC", "Times_Cited", "Citations", "citation_count")
  for (col in tc_cols) {
    if (col %in% names(input)) return(col)
  }
  NULL
}

extract_countries_from_c1 <- function(c1_string) {
  if (is.na(c1_string) || c1_string == "") return(character(0))
  affiliations <- strsplit(as.character(c1_string), ";")[[1]]
  countries <- gsub(".*;\\s*([^;]+)$", "\\1", affiliations)
  countries <- gsub(".*;\\s*([^,]+)$", "\\1", countries)
  countries <- trimws(countries)
  countries[countries != ""]
}

summarize_hypothesis_results <- function(hypotheses) {
  hyp_list <- hypotheses
  n_total <- length(hyp_list)
  n_rejected <- sum(vapply(hyp_list, function(h) isTRUE(h$result == "reject"), logical(1)), na.rm = TRUE)
  n_failed_to_reject <- sum(vapply(hyp_list, function(h) isTRUE(h$result == "fail_to_reject"), logical(1)), na.rm = TRUE)
  n_inconclusive <- n_total - n_rejected - n_failed_to_reject
  
  list(
    n_total = n_total,
    n_rejected = n_rejected,
    n_failed_to_reject = n_failed_to_reject,
    n_inconclusive = n_inconclusive,
    rejection_rate = if (n_total > 0) n_rejected / n_total else NA_real_
  )
}

#' Conservative power-law test override with cleaner reporting
#' @keywords internal
test_citation_power_law_hypothesis <- function(input, config) {
  tc_col <- get_citation_column(input)
  if (is.null(tc_col)) {
    return(list(
      hyphypothesis = "Citation distribution follows power law",
      null = "Citations do not follow power law",
      result = "inconclusive",
      interpretation = "No citation data available"
    ))
  }

  citations <- input[[tc_col]]
  citations <- citations[!is.na(citations) & citations > 0]
  if (length(citations) < 50) {
    return(list(
      hyphypothesis = "Citation distribution follows power law",
      null = "Citations do not follow power law",
      result = "inconclusive",
      interpretation = "Insufficient citation data"
    ))
  }

  log_citations <- log(citations)
  fit <- lm(log_citations ~ seq_along(citations))
  r2 <- summary(fit)$r.squared
  sorted_cites <- sort(citations, decreasing = TRUE)
  rank <- seq_along(sorted_cites)
  log_fit <- lm(log(sorted_cites) ~ log(rank))
  power_exp <- coef(log_fit)[2]
  if (length(power_exp) > 1) power_exp <- power_exp[1]

  result <- if (abs(power_exp + 1) < 0.5) "fail_to_reject" else "reject"

  list(
    hyphypothesis = "Citation distribution follows power law",
    null = "Citations do not follow power law",
    result = result,
    power_exponent = power_exp,
    r_squared = r2,
    n_citations = length(citations),
    interpretation = sprintf(
      "Fitted power exponent = %.2f (expected about -1 for power law). R^2 = %.3f.",
      as.numeric(power_exp)[1],
      r2[1]
    )
  )
}

#' Conservative Bradford test override
#' @keywords internal
test_bradford_hypothesis <- function(input, config) {
  bradford_result <- tryCatch(compute_m1_bradford(input, config), error = function(e) NULL)
  if (is.null(bradford_result) || (bradford_result$status %||% "error") != "success") {
    return(list(
      hyphypothesis = "Bradford's Law applies to source distribution",
      null = "Source distribution does not follow Bradford's Law",
      result = "inconclusive",
      interpretation = "Could not compute Bradford zones"
    ))
  }

  coeff <- bradford_result$bradford_coefficient %||% NA_real_
  n_sources <- bradford_result$n_sources %||% NA_real_
  coeff <- suppressWarnings(as.numeric(coeff)[1])
  n_sources <- suppressWarnings(as.numeric(n_sources)[1])

  if (!is.finite(coeff)) {
    return(list(
      hyphypothesis = "Bradford's Law applies to source distribution",
      null = "Source distribution does not follow Bradford's Law",
      result = "inconclusive",
      interpretation = "Bradford coefficient could not be estimated"
    ))
  }

  result <- if (coeff < 2) "fail_to_reject" else "reject"
  list(
    hyphypothesis = "Bradford's Law applies to source distribution",
    null = "Source distribution does not follow Bradford's Law",
    result = result,
    bradford_coefficient = coeff,
    n_sources = n_sources,
    interpretation = sprintf(
      "Bradford coefficient = %.2f. %s",
      coeff,
      if (result == "fail_to_reject") "Distribution follows a Bradford-like pattern." else "Distribution deviates from a Bradford-like pattern."
    )
  )
}

#' Conservative Price-law test override
#' @keywords internal
test_price_law_hypothesis <- function(input, config) {
  price_result <- tryCatch(compute_m1_price_law(input, config), error = function(e) NULL)
  if (is.null(price_result) || (price_result$status %||% "error") != "success") {
    return(list(
      hyphypothesis = "Author productivity inequality follows Price's Law",
      null = "Productivity distribution does not follow Price's Law",
      result = "inconclusive",
      interpretation = "Could not compute Price's Law metrics"
    ))
  }

  price_index <- suppressWarnings(as.numeric((price_result$price_index$index %||% NA_real_))[1])
  core_prop <- suppressWarnings(as.numeric((price_result$author_concentration$top_10_pct_share %||% NA_real_))[1])
  n_authors_val <- suppressWarnings(as.numeric((price_result$price_law$n_authors %||% 100))[1])
  expected_core_prop <- 1 / sqrt(max(n_authors_val, 1))

  if (!is.finite(price_index)) {
    return(list(
      hyphypothesis = "Author productivity inequality follows Price's Law",
      null = "Productivity distribution does not follow Price's Law",
      result = "inconclusive",
      interpretation = "Price index could not be estimated from the available data"
    ))
  }

  result <- if (abs(price_index - 0.5) < 0.2) "fail_to_reject" else "reject"
  list(
    hyphypothesis = "Author productivity inequality follows Price's Law",
    null = "Productivity distribution does not follow Price's Law",
    result = result,
    price_index = price_index,
    core_author_proportion = core_prop,
    expected_core = expected_core_prop,
    interpretation = sprintf(
      "Price index = %.2f (expected near 0.5). Core authors = %.1f%% (sqrt(N) = %.1f%%).",
      price_index,
      core_prop * 100,
      expected_core_prop * 100
    )
  )
}
