# ============================================================================
# m1_compute_overview.R - Overview metric for M1
# ============================================================================

#' Compute M1 overview
#'
#' @param input A data frame of bibliographic data.
#' @param config A configuration list.
#' @return A list with summary_table, main_indicators, status.
#' @export
compute_m1_overview <- function(input, config = biblio_config()) {
  if (!is.data.frame(input) || nrow(input) == 0) {
    return(list(
      summary_table   = m1_empty_summary_table(),
      main_indicators = list(),
      status          = "error"
    ))
  }

  # Try cached bibliometrix first, fallback to manual computation
  main_indicators <- tryCatch({
    cached <- get_cached_biblio_analysis(input)
    if (cached$status == "success") {
      m1_extract_main_information(cached$summary$MainInformationDF)
    } else {
      # Fallback: manual computation
      m1_compute_overview_manual(input)
    }
  }, error = function(e) {
    # Fallback: manual computation
    m1_compute_overview_manual(input)
  })

  # Build summary table
  summary_table <- tibble::tibble(
    metric = c("Documents", "Sources", "Authors", "Timespan"),
    value = c(
      main_indicators$documents,
      main_indicators$sources,
      main_indicators$authors,
      main_indicators$timespan
    )
  )

  list(
    summary_table   = summary_table,
    main_indicators = main_indicators,
    status          = "success"
  )
}

#' Manual overview computation fallback
#' @param input A data frame.
#' @return A list of indicators.
m1_compute_overview_manual <- function(input) {
  n_docs <- nrow(input)
  n_sources <- if ("SO" %in% names(input)) length(unique(input$SO)) else NA
  n_authors <- if ("AU" %in% names(input)) length(m1_extract_authors(input)) else NA
  years <- if ("PY" %in% names(input)) as.integer(input$PY) else NA
  timespan <- if (all(!is.na(years))) paste(min(years, na.rm = TRUE), max(years, na.rm = TRUE), sep = "-") else NA

  list(
    timespan                      = as.character(timespan),
    sources                       = as.integer(n_sources),
    documents                     = as.integer(n_docs),
    annual_growth_rate             = NA_character_,
    document_average_age           = NA_character_,
    avg_citations_per_doc          = if ("TC" %in% names(input)) as.character(round(mean(as.numeric(input$TC), na.rm = TRUE), 2)) else NA_character_,
    avg_citations_per_year_per_doc = NA_character_,
    references                    = NA_character_,
    authors                       = as.integer(n_authors),
    authors_per_doc               = NA_character_,
    co_authors_per_doc            = NA_character_,
    international_collaborations  = NA_character_,
    single_author_documents       = NA_character_,
    multi_author_documents        = NA_character_
  )
}
# <<< END FILE: R/module_m1/compute/m1_compute_overview.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_price_law.R
# ============================================================================
# m1_compute_price_law.R - Price's Law and Literature Half-Life Analysis
# ============================================================================
# Price's Law: Half of the significant contributions come from the square root
# of the number of authors (Price's square root law).
#
# Also computes:
# - Literature half-life (citations/age)
# - Price's Index (proportion of recent references)
# - Median citation age
# - Bibliometric aging indicators
#
# IEEE Q1 Enhancement: Comprehensive analysis of literature dynamics
# following Derek J. de Solla Price's foundational work.

#' Compute Price's Law and literature half-life analysis
#'
#' @param input Bibliographic data frame
#' @param config Configuration list
#' @return List with Price's Law results
#' @export
compute_m1_price_law <- function(input, config = biblio_config()) {
  validate_is_data_frame(input)
  
  tc_col <- "TC"
  py_col <- "PY"
  au_col <- "AU"
  if (!au_col %in% names(input)) au_col <- "AF"
  
  cr_col <- "CR"
  
  price_law <- compute_price_square_root_law(input, au_col)
  
  half_life <- compute_literature_half_life(input, tc_col, py_col)
  
  price_index <- if (cr_col %in% names(input)) {
    compute_price_index(input, cr_col, py_col)
  } else {
    list(index = NA_real_, n_references = 0, n_recent = 0, status = "no references column")
  }
  
  author_concentration <- compute_price_author_concentration(input, au_col)
  
  current_year <- as.numeric(format(Sys.Date(), "%Y"))
  
  summary_stats <- list(
    total_authors = price_law$n_authors,
    sqrt_authors = price_law$sqrt_n_authors,
    publications_top_sqrt = price_law$publications_top_sqrt,
    actual_proportion = price_law$actual_proportion,
    price_law_holds = price_law$price_law_holds,
    half_life = half_life$median_age,
    citation_half_life = half_life$citation_half_life,
    price_index = price_index$index,
    mean_citation_age = half_life$mean_citation_age,
    max_citation_age = half_life$max_citation_age,
    interpretation = interpret_price_results(price_law, half_life, price_index)
  )
  
  list(
    price_law = price_law,
    half_life = half_life,
    price_index = price_index,
    author_concentration = author_concentration,
    summary = summary_stats,
    status = "success"
  )
}

#' Compute Price's square root law for authors
#' @keywords internal
compute_price_square_root_law <- function(input, au_col) {
  if (!au_col %in% names(input)) {
    return(list(
      n_authors = 0,
      sqrt_n_authors = 0,
      publications_top_sqrt = 0,
      actual_proportion = NA_real_,
      price_law_holds = NA,
      expected_proportion = 0.5,
      author_distribution = data.frame()
    ))
  }
  
  authors_list <- strsplit(as.character(input[[au_col]]), ";")
  authors_list <- lapply(authors_list, trimws)
  authors_list <- lapply(authors_list, function(x) x[x != ""])
  
  author_counts <- table(unlist(authors_list))
  
  author_df <- data.frame(
    author = names(author_counts),
    n_papers = as.integer(author_counts),
    stringsAsFactors = FALSE
  )
  
  author_df <- author_df[order(-author_df$n_papers), ]
  
  n_authors <- nrow(author_df)
  if (n_authors == 0) {
    return(list(
      n_authors = 0,
      sqrt_n_authors = 0,
      publications_top_sqrt = 0,
      actual_proportion = NA_real_,
      price_law_holds = NA,
      expected_proportion = 0.5,
      author_distribution = author_df
    ))
  }
  
  sqrt_n_authors <- ceiling(sqrt(n_authors))
  
  total_papers <- author_df$n_papers[1]
  for (i in 2:n_authors) {
    total_papers <- total_papers + author_df$n_papers[i]
  }
  
  top_sqrt_papers <- 0
  for (i in 1:min(sqrt_n_authors, n_authors)) {
    top_sqrt_papers <- top_sqrt_papers + author_df$n_papers[i]
  }
  
  actual_proportion <- top_sqrt_papers / total_papers
  
  expected_proportion <- 0.5
  
  price_law_holds <- actual_proportion >= 0.4 && actual_proportion <= 0.6
  
  list(
    n_authors = n_authors,
    sqrt_n_authors = sqrt_n_authors,
    publications_top_sqrt = sum(author_df$n_papers[1:min(sqrt_n_authors, n_authors)]),
    actual_proportion = actual_proportion,
    price_law_holds = price_law_holds,
    expected_proportion = expected_proportion,
    deviation_from_expected = actual_proportion - expected_proportion,
    top_authors = head(author_df, min(10, n_authors)),
    author_distribution = author_df
  )
}

#' Compute literature half-life
#' @keywords internal
compute_literature_half_life <- function(input, tc_col, py_col) {
  current_year <- as.numeric(format(Sys.Date(), "%Y"))
  
  if (!tc_col %in% names(input) || !py_col %in% names(input)) {
    return(list(
      median_age = NA_real_,
      mean_citation_age = NA_real_,
      citation_half_life = NA_real_,
      max_citation_age = NA_real_
    ))
  }
  
  citations <- as.numeric(input[[tc_col]])
  years <- as.numeric(input[[py_col]])
  
  valid_idx <- !is.na(citations) & !is.na(years) & years > 1900 & years <= current_year
  
  if (sum(valid_idx) == 0) {
    return(list(
      median_age = NA_real_,
      mean_citation_age = NA_real_,
      citation_half_life = NA_real_,
      max_citation_age = NA_real_
    ))
  }
  
  ages <- current_year - years[valid_idx]
  valid_citations <- citations[valid_idx]
  
  median_age <- median(ages, na.rm = TRUE)
  mean_age <- mean(ages, na.rm = TRUE)
  max_age <- max(ages, na.rm = TRUE)
  
  citation_half_life <- compute_citation_half_life(valid_citations, ages)
  
  list(
    median_age = median_age,
    mean_citation_age = mean_age,
    citation_half_life = citation_half_life,
    max_citation_age = max_age,
    age_distribution = data.frame(
      age = ages,
      citations = valid_citations
    )
  )
}

#' Compute citation half-life
#' @keywords internal
compute_citation_half_life <- function(citations, ages) {
  if (length(citations) == 0 || sum(citations, na.rm = TRUE) == 0) {
    return(NA_real_)
  }
  
  cum_citations <- cumsum(sort(citations, decreasing = TRUE))
  total_citations <- sum(citations, na.rm = TRUE)
  half_citations <- total_citations / 2
  
  half_idx <- which(cum_citations >= half_citations)[1]
  
  if (is.na(half_idx)) return(NA_real_)
  
  sorted_ages <- sort(ages, decreasing = FALSE)
  sorted_citations <- sort(citations, decreasing = FALSE)
  
  cumulative_citations <- cumsum(sorted_citations)
  
  sorted_ages[cumulative_citations >= half_citations][1]
}

#' Compute Price's Index
#' @keywords internal
compute_price_index <- function(input, cr_col, py_col) {
  if (!cr_col %in% names(input)) {
    return(list(
      index = NA_real_,
      n_references = 0,
      n_recent = 0,
      status = "no references column"
    ))
  }
  
  current_year <- as.numeric(format(Sys.Date(), "%Y"))
  
  references <- input[[cr_col]]
  pub_years <- input[[py_col]]
  
  valid_idx <- !is.na(pub_years) & !is.na(references) & references != ""
  
  if (length(valid_idx) == 0 || sum(valid_idx) == 0) {
    return(list(
      index = NA_real_,
      n_references = 0,
      n_recent = 0,
      status = "no valid references"
    ))
  }
  
  ref_years <- extract_reference_years(references[valid_idx])
  
  n_refs <- length(ref_years)
  if (n_refs == 0) {
    return(list(
      index = NA_real_,
      n_references = 0,
      n_recent = 0,
      status = "could not extract reference years"
    ))
  }
  
  n_recent <- sum(ref_years >= (current_year - 5), na.rm = TRUE)
  
  price_index <- n_recent / n_refs
  
  list(
    index = price_index,
    n_references = n_refs,
    n_recent = n_recent,
    recency_window = 5,
    status = "success"
  )
}

#' Extract publication years from references
#' @keywords internal
extract_reference_years <- function(references) {
  years <- lapply(references, function(ref_string) {
    if (is.na(ref_string) || ref_string == "") return(integer(0))
    
    year_matches <- regmatches(ref_string, gregexpr("\\b(19|20)\\d{2}\\b", ref_string))
    
    as.integer(unlist(year_matches))
  })
  
  unlist(years)
}

#' Compute Price's author concentration
#' @keywords internal
compute_price_author_concentration <- function(input, au_col) {
  if (!au_col %in% names(input)) {
    return(list(
      gini = NA_real_,
      top_1_pct_share = NA_real_,
      top_5_pct_share = NA_real_,
      top_10_pct_share = NA_real_,
      entropy = NA_real_,
      concentration_type = NA_character_
    ))
  }
  
  authors_list <- strsplit(as.character(input[[au_col]]), ";")
  authors_list <- lapply(authors_list, trimws)
  authors_list <- lapply(authors_list, function(x) x[x != ""])
  
  author_counts <- table(unlist(authors_list))
  sorted_counts <- sort(author_counts, decreasing = TRUE)
  n_authors <- length(sorted_counts)
  total_papers <- sum(sorted_counts)
  
  if (n_authors == 0 || total_papers == 0) {
    return(list(
      gini = NA_real_,
      top_1_pct_share = NA_real_,
      top_5_pct_share = NA_real_,
      top_10_pct_share = NA_real_,
      entropy = NA_real_,
      concentration_type = NA_character_
    ))
  }
  
  gini <- compute_gini(sorted_counts)
  
  top_1_pct <- max(1, floor(n_authors * 0.01))
  top_5_pct <- max(1, floor(n_authors * 0.05))
  top_10_pct <- max(1, floor(n_authors * 0.10))
  
  top_1_pct_share <- sum(sorted_counts[1:top_1_pct]) / total_papers
  top_5_pct_share <- sum(sorted_counts[1:top_5_pct]) / total_papers
  top_10_pct_share <- sum(sorted_counts[1:top_10_pct]) / total_papers
  
  proportions <- sorted_counts / total_papers
  entropy <- -sum(proportions * log2(proportions + 1e-10))
  
  max_entropy <- log2(n_authors)
  normalized_entropy <- entropy / max_entropy
  
  if (top_10_pct_share > 0.5) {
    concentration_type <- "highly concentrated"
  } else if (top_10_pct_share > 0.3) {
    concentration_type <- "moderately concentrated"
  } else {
    concentration_type <- "evenly distributed"
  }
  
  list(
    gini = gini,
    top_1_pct_share = top_1_pct_share,
    top_5_pct_share = top_5_pct_share,
    top_10_pct_share = top_10_pct_share,
    entropy = entropy,
    normalized_entropy = normalized_entropy,
    concentration_type = concentration_type
  )
}

#' Compute Gini coefficient
#' @keywords internal
compute_gini <- function(x) {
  x <- as.numeric(x)
  x <- x[!is.na(x)]
  n <- length(x)
  
  if (n == 0 || sum(x) == 0) return(NA_real_)
  
  x <- sort(x)
  n <- length(x)
  
  # Brown's formula for Gini coefficient
  # G = (2 * Σ(i * x_i)) / (n * Σx) - (n + 1) / n
  # This is algebraically equivalent to the Lorenz curve approach
  gini <- (2 * sum((1:n) * x)) / (n * sum(x)) - (n + 1) / n
  
  # Gini should be between 0 and 1
  max(0, min(1, gini))
}

#' Interpret Price's Law results
#' @keywords internal
interpret_price_results <- function(price_law, half_life, price_index) {
  interpretations <- character(0)
  
  if (!is.na(price_law$price_law_holds) && price_law$price_law_holds) {
    interpretations <- c(interpretations, 
      sprintf("Price's Law holds: top sqrt(n)=%.0f authors account for %.1f%% of publications.",
              price_law$sqrt_n_authors, price_law$actual_proportion * 100))
  } else if (!is.na(price_law$actual_proportion)) {
    if (price_law$actual_proportion > 0.6) {
      interpretations <- c(interpretations,
        sprintf("Higher concentration than Price's Law predicts: top sqrt(n)=%.0f authors account for %.1f%% of publications (> 50%%).",
                price_law$sqrt_n_authors, price_law$actual_proportion * 100))
    } else {
      interpretations <- c(interpretations,
        sprintf("Lower concentration than Price's Law predicts: top sqrt(n)=%.0f authors account for %.1f%% of publications (< 50%%).",
                price_law$sqrt_n_authors, price_law$actual_proportion * 100))
    }
  }
  
  if (!is.na(half_life$median_age)) {
    interpretations <- c(interpretations,
      sprintf("Literature half-life: median citation age is %.1f years.", half_life$median_age))
  }
  
  if (!is.na(price_index$index) && price_index$index > 0) {
    interpretations <- c(interpretations,
      sprintf("Price's Index: %.1f%% of references are from the last 5 years.", price_index$index * 100))
  }
  
  paste(interpretations, collapse = " ")
}
# <<< END FILE: R/module_m1/compute/m1_compute_price_law.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_sources.R
# ============================================================================
# m1_compute_sources.R - Sources metric for M1
# ============================================================================

#' @export
compute_m1_sources <- function(input, config = biblio_config()) {
  if (!is.data.frame(input) || nrow(input) == 0) {
    return(list(top_sources = m1_empty_rank_table(), source_summary = list(), source_gini = NA_real_, status = "error"))
  }

  top_n <- config$top_n_sources

  # Try bibliometrix first
  source_data <- tryCatch({
    cached <- get_cached_biblio_analysis(input)
    res <- cached$res
    s <- summary(res, pause = FALSE, verbose = FALSE)
    mr <- s$MostRelSources
    colnames(mr) <- make.unique(colnames(mr))
    art_col <- if ("Articles" %in% colnames(mr)) "Articles" else colnames(mr)[2]
    mr[[art_col]] <- suppressWarnings(as.numeric(mr[[art_col]]))
    mr <- mr[!is.na(mr[[art_col]]), ]
    mr <- mr[order(-mr[[art_col]]), ]
    src_col <- if ("Sources" %in% colnames(mr)) "Sources" else colnames(mr)[1]
    list(sources = mr[[src_col]], articles = mr[[art_col]])
  }, error = function(e) {
    # Fallback: count SO column
    if ("SO" %in% names(input)) {
      so_counts <- table(input$SO, useNA = "no")
      so_counts <- sort(so_counts, decreasing = TRUE)
      list(sources = names(so_counts), articles = as.integer(so_counts))
    } else {
      list(sources = character(0), articles = integer(0))
    }
  })

  if (length(source_data$sources) > 0) {
    top_sources <- tibble::tibble(
      rank  = seq_len(min(top_n, length(source_data$sources))),
      label = source_data$sources[1:min(top_n, length(source_data$sources))],
      value = source_data$articles[1:min(top_n, length(source_data$articles))]
    )
    lorenz <- m1_compute_lorenz(top_sources$value)
    source_gini <- m1_compute_gini(lorenz$cumulative_entities, lorenz$cumulative_values)
  } else {
    top_sources <- m1_empty_rank_table()
    source_gini <- NA_real_
  }

  list(
    top_sources = top_sources,
    source_summary = list(total_sources = if ("SO" %in% names(input)) length(unique(input$SO)) else 0, top_n = top_n),
    source_gini = source_gini,
    status = "success"
  )
}
# <<< END FILE: R/module_m1/compute/m1_compute_sources.R

# >>> BEGIN FILE: R/module_m1/compute/m1_compute_topic_modeling.R
# ============================================================================
# m1_compute_topic_modeling.R - Topic Modeling with LDA
# ============================================================================
# Latent Dirichlet Allocation and topic analysis for bibliometric data

#' Compute LDA topic model
#'
#' @param input Bibliographic data frame with KW/DE/ID columns
#' @param config Configuration list
#' @return List with topics, document-topic distributions, and metrics
#' @export
compute_m1_topic_modeling <- function(input, config = biblio_config()) {
  kw_cols <- c("KW", "DE", "ID", "Keywords", "AB")
  kw_col <- NULL
  for (col in kw_cols) {
    if (col %in% names(input)) {
      kw_col <- col
      break
    }
  }
  
  if (is.null(kw_col)) {
    return(list(
      status = "error: no keyword column found",
      topics = data.frame(),
      n_topics = 0
    ))
  }
  
  # Extract keywords
  keywords_list <- extract_keywords(input[[kw_col]])
  
  if (length(keywords_list) < 10) {
    return(list(
      status = "error: insufficient documents",
      topics = data.frame(),
      n_topics = 0
    ))
  }
  
  # Determine optimal number of topics
  n_topics <- config$n_topics %||% determine_optimal_topics(keywords_list)
  n_topics <- min(n_topics, length(keywords_list) %/% 5)
  n_topics <- max(n_topics, 2)
  
  # Create document-term matrix
  dtm <- create_dtm(keywords_list)
  
  # Fit LDA model
  lda_result <- fit_lda_model(dtm, n_topics)
  
  if (lda_result$status == "error") {
    return(lda_result)
  }
  
  # Extract topics
  topics_result <- extract_topics(lda_result, dtm)
  topics_df <- topics_result$topics
  
  # Document-topic distribution
  doc_topics <- get_document_topics(lda_result, nrow(dtm))
  doc_topic_weights <- flatten_document_topic_weights(lda_result$gamma)
  
  # Topic metrics
  topic_metrics <- compute_topic_metrics(lda_result, topics_df, doc_topics)
  
  # Topic evolution over time
  py_col <- if ("PY" %in% names(input)) input$PY else if ("Year" %in% names(input)) input$Year else NULL
  topic_evolution <- compute_topic_evolution(doc_topics, py_col, keywords_list)
  
  # Topic co-occurrence
  topic_cooccurrence <- compute_topic_cooccurrence(doc_topics)
  
  list(
    status = "success",
    n_topics = n_topics,
    topics = topics_df,
    topic_terms_long = topics_result$topic_terms_long,
    document_topics = doc_topics,
    document_topic_weights = doc_topic_weights,
    topic_metrics = topic_metrics,
    topic_evolution = topic_evolution,
    topic_cooccurrence = topic_cooccurrence,
    coherence = lda_result$coherence,
    perplexity = lda_result$perplexity,
    method = "LDA",
    keywords_used = kw_col
  )
}

#' Extract keywords from column
#' @keywords internal
extract_keywords <- function(keyword_column) {
  abstract_stopwords <- c(
    "the", "and", "for", "with", "from", "into", "that", "this", "these", "those",
    "study", "studies", "analysis", "review", "reviews", "paper", "article",
    "using", "based", "approach", "approaches", "method", "methods", "results",
    "through", "across", "among", "between", "within", "their", "there", "which"
  )

  keywords_list <- lapply(as.character(keyword_column), function(x) {
    if (is.na(x) || x == "") return(character(0))

    if (grepl("[;,]", x)) {
      kw <- strsplit(x, "[;,]")[[1]]
      kw <- trimws(kw)
      kw <- m1_normalize_keyword_phrase(kw)
      kw <- kw[!is.na(kw) & nzchar(kw)]
      return(unique(kw))
    }

    kw <- tolower(x)
    kw <- gsub("[^a-z0-9 ]", " ", kw)
    kw <- gsub("\\s+", " ", trimws(kw))
    tokens <- unlist(strsplit(kw, "\\s+"))
    tokens <- tokens[nchar(tokens) > 2 & !tokens %in% abstract_stopwords]
    tokens <- unique(m1_title_case_phrase(tokens))
    tokens[!is.na(tokens) & nzchar(tokens)]
  })
  
  names(keywords_list) <- seq_along(keywords_list)
  keywords_list
}

#' Create document-term matrix
#' @keywords internal
create_dtm <- function(keywords_list) {
  # Get all unique terms
  all_terms <- unique(unlist(keywords_list))
  n_docs <- length(keywords_list)
  n_terms <- length(all_terms)
  
  # Filter terms that appear in at least 2 documents
  term_freq <- table(unlist(keywords_list))
  all_terms <- names(term_freq[term_freq >= 2])
  
  if (length(all_terms) == 0) {
    return(NULL)
  }
  
  # Create matrix
  dtm <- matrix(0, nrow = n_docs, ncol = length(all_terms))
  colnames(dtm) <- all_terms
  
  for (i in seq_along(keywords_list)) {
    doc_terms <- keywords_list[[i]]
    doc_terms <- doc_terms[doc_terms %in% all_terms]
    if (length(doc_terms) > 0) {
      term_counts <- table(doc_terms)
      dtm[i, names(term_counts)] <- as.numeric(term_counts)
    }
  }
  
  # Ensure no entirely empty rows to prevent LDA failure
  row_sums <- rowSums(dtm)
  if (any(row_sums == 0)) {
    # Add a tiny value to prevent row sum = 0
    dtm[row_sums == 0, 1] <- 1e-10
  }
  
  dtm
}

#' Fit LDA model
#' @keywords internal
fit_lda_model <- function(dtm, n_topics) {
  if (is.null(dtm) || nrow(dtm) < 5) {
    return(list(
      status = "error: insufficient data",
      topics = data.frame()
    ))
  }
  
  # Try topicmodels package first
  lda_result <- tryCatch({
    if (requireNamespace("topicmodels", quietly = TRUE)) {
      lda_model <- topicmodels::LDA(dtm, k = n_topics, method = "Gibbs", 
                                     control = list(seed = 12345, burnin = 1000, iter = 2000))
      
      # Get posterior
      posterior <- topicmodels::posterior(lda_model)
      
      list(
        status = "success",
        model = lda_model,
        beta = posterior$terms,        # Topic-term distribution
        gamma = posterior$topics,       # Document-topic distribution
        n_topics = n_topics,
        coherence = calculate_coherence(posterior$terms, dtm),
        perplexity = tryCatch(topicmodels::perplexity(lda_model, dtm), error = function(e) NA)
      )
    } else {
      # Fallback: simple implementation
      fit_simple_lda(dtm, n_topics)
    }
  }, error = function(e) {
    fit_simple_lda(dtm, n_topics)
  })
  
  lda_result
}

#' Simple LDA implementation (fallback)
#' @keywords internal
fit_simple_lda <- function(dtm, n_topics) {
  n_docs <- nrow(dtm)
  n_terms <- ncol(dtm)
  
  # Initialize
  set.seed(12345)
  beta <- matrix(runif(n_topics * n_terms), n_topics, n_terms)
  beta <- beta / rowSums(beta)
  
  gamma <- matrix(runif(n_docs * n_topics), n_docs, n_topics)
  gamma <- gamma / rowSums(gamma)
  
  # EM iterations
  for (iter in 1:50) {
    # E-step: update gamma
    for (d in 1:n_docs) {
      for (k in 1:n_topics) {
        gamma[d, k] <- prod(beta[k, ] ^ dtm[d, ])
      }
      # Ensure scalar values and handle NA
      row_sum <- sum(gamma[d, ], na.rm = TRUE)
      if (!is.na(row_sum) && row_sum > 0) {
        gamma[d, ] <- gamma[d, ] / row_sum
      }
    }
    
    # M-step: update beta
    for (k in 1:n_topics) {
      for (v in 1:n_terms) {
        beta[k, v] <- sum(gamma[, k] * dtm[, v]) + 0.01
      }
      beta[k, ] <- beta[k, ] / sum(beta[k, ])
    }
  }
  
  # Calculate coherence
  coherence <- calculate_coherence(beta, dtm)
  
  # Calculate perplexity
  perplexity <- calculate_perplexity(beta, gamma, dtm)
  
  list(
    status = "success",
    model = NULL,
    beta = beta,
    gamma = gamma,
    n_topics = n_topics,
    coherence = coherence,
    perplexity = perplexity
  )
}

#' Calculate topic coherence
#' @keywords internal
calculate_coherence <- function(beta, dtm) {
  n_topics <- nrow(beta)
  coherence_scores <- numeric(n_topics)
  
  # Get top words per topic
  for (k in 1:n_topics) {
    top_words <- order(beta[k, ], decreasing = TRUE)[1:10]
    
    # Calculate U-mass coherence
    coherence_sum <- 0
    for (i in 2:min(10, length(top_words))) {
      for (j in 1:(i - 1)) {
        # Co-occurrence
        cooccur <- sum(dtm[, top_words[i]] > 0 & dtm[, top_words[j]] > 0, na.rm = TRUE)
        occur_j <- sum(dtm[, top_words[j]] > 0, na.rm = TRUE)
        
        if (!is.na(occur_j) && occur_j > 0) {
          coherence_sum <- coherence_sum + log((cooccur + 1) / occur_j)
        }
      }
    }
    coherence_scores[k] <- coherence_sum
  }
  
  mean(coherence_scores, na.rm = TRUE)
}

#' Calculate perplexity
#' @keywords internal
calculate_perplexity <- function(beta, gamma, dtm) {
  n_docs <- nrow(dtm)
  n_terms <- ncol(dtm)
  
  # Reconstruct document probabilities
  reconstructed <- gamma %*% beta
  
  # Calculate log-likelihood
  loglik <- sum(dtm * log(reconstructed + 1e-10), na.rm = TRUE)
  
  # Perplexity
  perplexity <- exp(-loglik / sum(dtm))
  
  perplexity
}

#' Determine optimal number of topics
#' @keywords internal
determine_optimal_topics <- function(keywords_list, max_topics = 20) {
  n_docs <- length(keywords_list)
  
  # Heuristic: sqrt of documents, but between 5 and 20
  optimal <- round(sqrt(n_docs))
  optimal <- min(optimal, max_topics)
  optimal <- max(optimal, 5)
  
  # For small datasets
  if (n_docs < 50) {
    optimal <- min(optimal, 5)
  }
  
  optimal
}

#' Extract topics from LDA result
#' @keywords internal
extract_topics <- function(lda_result, dtm, n_top_words = 10) {
  n_topics <- lda_result$n_topics
  beta <- lda_result$beta
  terms <- colnames(beta)
  
  if (is.null(terms)) {
    terms <- colnames(dtm)
  }
  if (is.null(terms)) {
    terms <- paste0("term", 1:ncol(beta))
  }
  
  topics_list <- list()
  topic_terms_long <- list()
  
  for (k in 1:n_topics) {
    top_idx <- order(beta[k, ], decreasing = TRUE)[1:n_top_words]
    top_words <- terms[top_idx]
    top_probs <- beta[k, top_idx]
    
    label <- m1_make_topic_label(top_words)
    
    topics_list[[k]] <- list(
      topic_id = k,
      label = label,
      top_words = top_words,
      probabilities = top_probs,
      weight = mean(lda_result$gamma[, k])
    )

    topic_terms_long[[k]] <- data.frame(
      topic_id = k,
      topic_label = label,
      term = m1_normalize_keyword_phrase(top_words),
      probability = as.numeric(top_probs),
      rank = seq_along(top_words),
      stringsAsFactors = FALSE
    )
  }
  
  # Convert to data frame
  if (length(topics_list) == 0) {
    return(list(topics = data.frame(), topics_list = list(), topic_terms_long = data.frame()))
  }
  
  topics_df <- do.call(rbind, lapply(topics_list, function(t) {
      data.frame(
      topic_id = t$topic_id,
      label = t$label,
      top_words = paste(m1_normalize_keyword_phrase(t$top_words), collapse = ", "),
      top_probabilities = paste(round(t$probabilities, 4), collapse = ", "),
      weight = t$weight,
      stringsAsFactors = FALSE
    )
  }))
  
  if (nrow(topics_df) > 0) {
    topics_df <- topics_df[order(-topics_df$weight), ]
  }
  
  list(
    topics = topics_df,
    topics_list = topics_list,
    topic_terms_long = do.call(rbind, topic_terms_long)
  )
}

#' Get document-topic distribution
#' @keywords internal
get_document_topics <- function(lda_result, n_docs) {
  gamma <- lda_result$gamma
  
  # Dominant topic for each document
  dominant_topic <- apply(gamma, 1, function(x) {
    if (all(is.na(x)) || length(x) == 0) return(NA_integer_)
    which.max(x)
  })
  dominant_prob <- apply(gamma, 1, function(x) {
    if (all(is.na(x)) || length(x) == 0) return(NA_real_)
    max(x, na.rm = TRUE)
  })
  
  data.frame(
    doc_id = 1:n_docs,
    dominant_topic = dominant_topic,
    dominant_prob = dominant_prob,
    stringsAsFactors = FALSE
  )
}

#' Flatten document-topic weights for plotting
#' @keywords internal
flatten_document_topic_weights <- function(gamma) {
  if (is.null(gamma) || length(dim(gamma)) != 2L || nrow(gamma) == 0 || ncol(gamma) == 0) {
    return(data.frame(
      doc_id = integer(),
      topic_id = integer(),
      probability = numeric(),
      stringsAsFactors = FALSE
    ))
  }

  out <- expand.grid(
    doc_id = seq_len(nrow(gamma)),
    topic_id = seq_len(ncol(gamma)),
    KEEP.OUT.ATTRS = FALSE,
    stringsAsFactors = FALSE
  )
  out$probability <- as.numeric(gamma)
  out
}

#' Compute topic metrics
#' @keywords internal
compute_topic_metrics <- function(lda_result, topics_df, doc_topics) {
  gamma <- lda_result$gamma
  n_topics <- nrow(topics_df)
  
  if (n_topics == 0 || is.null(gamma) || nrow(gamma) == 0) {
    return(data.frame(
      topic_id = integer(0),
      prevalence = numeric(0),
      exclusivity = numeric(0),
      entropy = numeric(0),
      doc_count = integer(0)
    ))
  }
  
  # Topic prevalence
  prevalence <- colMeans(gamma, na.rm = TRUE)
  
  # Topic exclusivity (how distinct each topic is)
  exclusivity <- numeric(n_topics)
  for (k in 1:n_topics) {
    # Find terms most associated with this topic
    top_terms <- order(lda_result$beta[k, ], decreasing = TRUE)[1:min(50, ncol(lda_result$beta))]
    
    # How exclusive are these terms to this topic?
    col_sums <- colSums(lda_result$beta, na.rm = TRUE)
    if (length(top_terms) > 0 && all(!is.na(col_sums[top_terms])) && all(col_sums[top_terms] > 0)) {
      exclusivity[k] <- mean(lda_result$beta[k, top_terms] / col_sums[top_terms], na.rm = TRUE)
    } else {
      exclusivity[k] <- 0
    }
  }
  # Topic entropy
  entropy <- apply(gamma, 2, function(x) {
    probs <- x[x > 0]
    if (length(probs) == 0) return(0)
    -sum(probs * log(probs))
  })
  
  # Document count per topic
  dominant_topic <- doc_topics$dominant_topic
  if (is.null(dominant_topic) || length(dominant_topic) == 0) {
    doc_count_per_topic <- rep(0L, n_topics)
  } else {
    doc_count_per_topic <- tabulate(dominant_topic[!is.na(dominant_topic)], nbins = n_topics)
  }
  
  data.frame(
    topic_id = 1:n_topics,
    prevalence = round(prevalence, 4),
    exclusivity = round(exclusivity, 4),
    entropy = round(entropy, 4),
    doc_count = doc_count_per_topic,
    stringsAsFactors = FALSE
  )
}

#' Compute topic evolution over time
#' @keywords internal
compute_topic_evolution <- function(doc_topics, years, keywords_list) {
  if (is.null(years) || length(years) != nrow(doc_topics)) {
    return(data.frame())
  }
  
  years <- as.numeric(years)
  valid_years <- !is.na(years)
  
  if (sum(valid_years) < 5) {
    return(data.frame())
  }
  
  years_valid <- years[valid_years]
  doc_topics_valid <- doc_topics[valid_years, ]
  
  # Group by year
  year_range <- range(years_valid)
  years_seq <- year_range[1]:year_range[2]
  
  n_topics <- max(doc_topics_valid$dominant_topic, na.rm = TRUE)
  if (is.infinite(n_topics) || n_topics < 1) {
    return(data.frame())
  }
  topic_prevalence <- matrix(0, length(years_seq), n_topics)
  rownames(topic_prevalence) <- years_seq
  
  for (y in years_seq) {
    year_docs <- doc_topics_valid$dominant_topic[years_valid == y]
    year_docs <- year_docs[!is.na(year_docs)]  # Remove NAs
    if (length(year_docs) > 0) {
      topic_prevalence[as.character(y), ] <- tabulate(year_docs, nbins = n_topics) / length(year_docs)
    }
  }
  
  # Find emerging topics
  first_half <- years_seq[1]:floor(mean(years_seq))
  second_half <- ceiling(mean(years_seq)):years_seq[length(years_seq)]
  
  early_prev <- colMeans(topic_prevalence[as.character(first_half), , drop = FALSE], na.rm = TRUE)
  late_prev <- colMeans(topic_prevalence[as.character(second_half), , drop = FALSE], na.rm = TRUE)
  
  topic_change <- late_prev - early_prev
  
  emerging <- which(topic_change > 0.05)
  declining <- which(topic_change < -0.05)
  
  list(
    prevalence_matrix = topic_prevalence,
    years = years_seq,
    early_prevalence = early_prev,
    late_prevalence = late_prev,
    change = topic_change,
    emerging_topics = emerging,
    declining_topics = declining
  )
}

#' Compute topic co-occurrence
#' @keywords internal
compute_topic_cooccurrence <- function(gamma, threshold = 0.2) {
  n_topics <- ncol(gamma)
  
  # Binary co-occurrence (topic > threshold)
  binary <- gamma > threshold
  
  # Co-occurrence matrix
  cooccur <- t(binary) %*% binary
  
  # Normalize
  cooccur_norm <- cooccur / diag(cooccur)
  
  rownames(cooccur_norm) <- colnames(cooccur_norm) <- paste0("Topic", 1:n_topics)
  
  list(
    cooccurrence = cooccur,
    cooccurrence_normalized = cooccur_norm,
    n_pairs = sum(cooccur[upper.tri(cooccur)]> 0)
  )
}

#' Compute NMF topic model (alternative)
#'
#' @param input Bibliographic data frame
#' @param config Configuration list
#' @return List with topics
#' @export
compute_m1_nmf_topics <- function(input, config = biblio_config()) {
  # Similar to LDA but uses NMF
  kw_cols <- c("KW", "DE", "ID", "Keywords")
  kw_col <- NULL
  for (col in kw_cols) {
    if (col %in% names(input)) {
      kw_col <- col
      break
    }
  }
  
  if (is.null(kw_col)) {
    return(list(status = "error: no keywords"))
  }
  
  keywords_list <- extract_keywords(input[[kw_col]])
  dtm <- create_dtm(keywords_list)
  
  if (is.null(dtm)) return(list(status = "error: DTM creation failed"))
  
  n_topics <- config$n_topics %||% determine_optimal_topics(keywords_list)
  
  #Fit NMF
  nmf_result <- tryCatch({
    if (requireNamespace("NMF", quietly = TRUE)) {
      NMF::nmf(dtm, n_topics, seed = 12345)
    } else {
      fit_simple_nmf(dtm, n_topics)
    }
  }, error = function(e) {
    fit_simple_nmf(dtm, n_topics)
  })
  
  nmf_result
}

#' Simple NMF implementation
#' @keywords internal
fit_simple_nmf <- function(dtm, n_topics, max_iter = 100) {
  n_docs <- nrow(dtm)
  n_terms <- ncol(dtm)
  
  set.seed(12345)
  W <- matrix(runif(n_docs * n_topics), n_docs, n_topics)
  H <- matrix(runif(n_topics * n_terms), n_topics, n_terms)
  
  # Multiplicative update
  for (iter in 1:max_iter) {
    # Update H
    H <- H * (t(W) %*% dtm) / (t(W) %*% W %*% H + 1e-10)
    
    # Update W
    W <- W * (dtm %*% t(H)) / (W %*% H %*% t(H) + 1e-10)
  }
  
  list(
    status = "success",
    W = W,  # Document-topic
    H = H,  # Topic-term
    n_topics = n_topics,
    coherence = calculate_coherence(H, dtm)
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
