  labels <- if ("label" %in% names(cit)) cit$label else if ("label_short" %in% names(cit)) cit$label_short else cit$title
  paste(seq_len(min(5, nrow(cit))), ".", labels[1:min(5, nrow(cit))], "-", cit$value[1:min(5, nrow(cit))], "citations")
}

