#' @export
export_m1 <- function(result, config = biblio_config()) {
  config <- merge_biblio_config(config)

  exported_plots   <- character()
  exported_tables  <- character()
  exported_reports <- character()
  exported_jsons   <- character()

  if (config$export_plots) {
    for (nm in names(result$artifacts$plots)) {
      plot_section <- result$artifacts$plots[[nm]]
      if (!is.list(plot_section) || is.null(plot_section$plots) || length(plot_section$plots) == 0) {
        next
      }
      for (pnm in names(plot_section$plots)) {
        plot_obj <- plot_section$plots[[pnm]]
        if (is.null(plot_obj)) {
          next
        }
        plot_obj <- ieee_prepare_plot_for_export(
          plot_obj,
          module_id = "m1",
          section_id = nm,
          plot_id = pnm,
          config = config
        )
        spec <- ieee_get_plot_export_spec(
          plot_obj,
          config = config,
          section_id = nm,
          plot_id = pnm
        )
        p <- build_artifact_path("m1", "plots", paste0("m1_", nm, "_", pnm), "png", config)
        tryCatch({
          exported_paths <- export_plot_artifact(plot_obj, tools::file_path_sans_ext(p),
                                                 width = spec$width, height = spec$height, dpi = spec$dpi)
          exported_plots <- c(exported_plots, unname(exported_paths[!is.na(exported_paths)]))
        }, error = function(e) cli::cli_warn("Plot export failed: {pnm} - {e$message}"))
      }
    }
  }

  if (config$export_json) {
    for (nm in names(result$data)) {
      j <- build_artifact_path("m1", "json", paste0("m1_", nm), "json", config)
      tryCatch({
        write_json_artifact(result$data[[nm]], j)
        exported_jsons <- c(exported_jsons, j)
      }, error = function(e) cli::cli_warn("JSON export failed: {nm} - {e$message}"))
    }
  }

  if (length(result$artifacts$tables) > 0) {
    for (section_nm in names(result$artifacts$tables)) {
      table_section <- result$artifacts$tables[[section_nm]]
      flat_tables <- m1_flatten_table_collection(table_section)
      for (table_nm in names(flat_tables)) {
        csv_path <- build_artifact_path(
          "m1", "tables",
          paste0("m1_", section_nm, "_", table_nm), "csv", config
        )
        dir.create(dirname(csv_path), recursive = TRUE, showWarnings = FALSE)
        tryCatch({
          utils::write.csv(flat_tables[[table_nm]], csv_path, row.names = FALSE, na = "")
          exported_tables <- c(exported_tables, csv_path)
        }, error = function(e) cli::cli_warn("Table export failed: {table_nm} - {e$message}"))
      }
    }
  }

  if (config$export_reports && length(result$artifacts$reports) > 0) {
    report <- result$artifacts$reports[[1]]
    if (!is.null(report$lines) && length(report$lines) > 0) {
      r <- build_artifact_path("m1", "reports", "m1_report", "txt", config)
      write_text_report(report$lines, r)
      exported_reports <- c(exported_reports, r)
    }
    if (!is.null(report$tex) && length(report$tex) > 0) {
      t <- build_artifact_path("m1", "reports", "m1_report", "tex", config)
      writeLines(report$tex, t)
      exported_reports <- c(exported_reports, t)
    }
  }

  list(plots = exported_plots, tables = exported_tables, reports = exported_reports, files = exported_jsons)
}

m1_flatten_table_collection <- function(x, prefix = NULL) {
  if (is.data.frame(x)) {
    table_name <- if (is.null(prefix) || identical(prefix, "")) "table" else prefix
    out <- list(x)
    names(out) <- table_name
    return(out)
  }

  if (!is.list(x) || length(x) == 0) {
    return(list())
  }

  if ("table" %in% names(x) && is.data.frame(x$table)) {
    table_name <- if (is.null(prefix) || identical(prefix, "")) "table" else prefix
    out <- list(x$table)
    names(out) <- table_name
    return(out)
  }

  flattened <- list()
  child_names <- names(x)
  if (is.null(child_names)) {
    child_names <- as.character(seq_along(x))
  }

  for (i in seq_along(x)) {
    child_prefix <- if (is.null(prefix) || identical(prefix, "")) {
      child_names[i]
    } else {
      paste(prefix, child_names[i], sep = "_")
    }
    flattened <- c(flattened, m1_flatten_table_collection(x[[i]], child_prefix))
  }

  flattened
}
# <<< END FILE: R/module_m1/m1_run.R

# >>> BEGIN FILE: R/module_m1/m1_validate.R
# ============================================================================
# m1_validate.R - Input validation for M1
# ============================================================================

#' Validate M1 input
#'
#' Checks that the input is a data frame and has the minimal required columns.
#'
#' @param input A data frame or tibble.
#' @param config A configuration list.
#' @return A list with \code{ok}, \code{missing_columns}, \code{n_rows}, \code{n_cols}.
#' @export
validate_m1_input <- function(input, config = biblio_config()) {
  if (!is.data.frame(input)) {
    return(list(
      ok              = FALSE,
      missing_columns = character(),
      n_rows          = 0L,
      n_cols          = 0L,
      error           = "Input is not a data frame."
    ))
  }

  required <- m1_required_columns_minimal()
  col_check <- validate_required_columns(input, required)

  list(
    ok              = col_check$ok,
    missing_columns = col_check$missing_columns,
    n_rows          = nrow(input),
    n_cols          = ncol(input)
  )
}
# <<< END FILE: R/module_m1/m1_validate.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_author_career.R
# ============================================================================
# m1_render_author_career.R - Author Career Visualization
# ============================================================================

#' Render author career results
#'
#' @param data Output from compute_m1_author_career
#' @param config Configuration list
#' @return List with author career plots
#' @export
render_m1_author_career <- function(data, config = biblio_config()) {
  if (is.null(data) || startsWith(data$status %||% "error", "error")) {
    return(list(plots = list(), status = data$status %||% "error"))
  }

  plots <- list()

  if (!is.null(data$career_df) && nrow(data$career_df) > 0) {
    plots$career_length <- create_career_length_plot(data, config)
    plots$productivity <- create_productivity_distribution_plot(data, config)
    plots$h_index <- create_h_index_distribution_plot(data, config)
    plots$career_stage <- create_career_stage_plot(data, config)
  }

  if (!is.null(data$trajectories) && nrow(data$trajectories) > 0) {
    plots$trajectory <- create_career_trajectory_plot(data, config)
  }

  list(
    plots = plots,
    status = "success"
  )
}

#' Create career length distribution plot
#' @keywords internal
create_career_length_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  metrics <- data$career_df
  if (is.null(metrics) || nrow(metrics) == 0) return(NULL)

  ggplot2::ggplot(metrics, ggplot2::aes(x = career_length)) +
    ggplot2::geom_histogram(bins = 30, fill = "#2166AC", alpha = 0.7) +
    ggplot2::labs(
      title = "Distribution of Author Career Lengths",
      x = "Career Length (Years)",
      y = "Number of Authors"
    ) +
    ieee_theme()
}

#' Create productivity distribution plot
#' @keywords internal
create_productivity_distribution_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  metrics <- data$career_df
  if (is.null(metrics) || nrow(metrics) == 0) return(NULL)

  positive <- metrics[!is.na(metrics$total_papers) & metrics$total_papers > 0, , drop = FALSE]
  if (nrow(positive) == 0) return(NULL)

  ggplot2::ggplot(positive, ggplot2::aes(x = total_papers)) +
    ggplot2::geom_histogram(bins = 40, fill = "#67A9CF", alpha = 0.7) +
    ggplot2::scale_x_log10() +
    ggplot2::labs(
      title = "Author Productivity Distribution",
      x = "Total Papers (log10 scale)",
      y = "Number of Authors"
    ) +
    ieee_theme()
}

#' Create H-index distribution plot
#' @keywords internal
create_h_index_distribution_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  metrics <- data$career_df
  if (is.null(metrics) || nrow(metrics) == 0) return(NULL)

  top_n <- config$top_n_authors %||% 20
  top_authors <- metrics[order(-metrics$h_index, -metrics$total_citations), , drop = FALSE]
  top_authors <- top_authors[seq_len(min(top_n, nrow(top_authors))), , drop = FALSE]
  label_col <- if ("display_author" %in% names(top_authors)) "display_author" else "author"
  top_authors$author_label <- top_authors[[label_col]]
  top_authors$author_label <- factor(top_authors$author_label, levels = rev(top_authors$author_label))

  ggplot2::ggplot(top_authors, ggplot2::aes(x = author_label, y = h_index)) +
    ggplot2::geom_col(fill = "#2166AC", alpha = 0.8) +
    ggplot2::coord_flip() +
    ggplot2::labs(
      title = paste("Top", nrow(top_authors), "Authors by H-index"),
      x = "Author",
      y = "H-index"
    ) +
    ieee_theme()
}

#' Create career stage plot
#' @keywords internal
create_career_stage_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  metrics <- data$career_df
  if (is.null(metrics) || !"career_stage" %in% names(metrics)) return(NULL)

  stage_table <- table(metrics$career_stage, useNA = "no")
  plot_data <- data.frame(
    career_stage = names(stage_table),
    n_authors = as.numeric(stage_table),
    stringsAsFactors = FALSE
  )
  plot_data <- plot_data[plot_data$career_stage != "", , drop = FALSE]
  if (nrow(plot_data) == 0) return(NULL)

  ggplot2::ggplot(plot_data, ggplot2::aes(x = career_stage, y = n_authors, fill = career_stage)) +
    ggplot2::geom_col(show.legend = FALSE, alpha = 0.8) +
    ggplot2::labs(
      title = "Career Stage Distribution",
      x = "Career Stage",
      y = "Authors"
    ) +
    ieee_theme()
}

#' Create career trajectory plot
#' @keywords internal
create_career_trajectory_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  trajectories <- data$trajectories
  if (is.null(trajectories) || nrow(trajectories) == 0) return(NULL)

  trajectories$author_label <- vapply(trajectories$author, m1_author_display_label, character(1))

  ggplot2::ggplot(trajectories, ggplot2::aes(x = year, y = cumulative_citations, color = author_label)) +
    ggplot2::geom_line(linewidth = 1) +
    ggplot2::geom_point(size = 1.8) +
    ggplot2::labs(
      title = "Career Trajectories of Leading Authors",
      x = "Year",
      y = "Cumulative Citations",
      color = "Author"
    ) +
    ggplot2::theme(legend.position = "bottom") +
    ieee_theme()
}

#' Build author career table
#' @export
build_m1_author_career_table <- function(data, config = biblio_config()) {
  empty <- list(
    status = "stub",
    table = tibble::tibble(),
    summary = list()
  )

  if (is.null(data) || startsWith(data$status %||% "error", "error")) {
    return(empty)
  }

  metrics <- data$career_df
  if (is.null(metrics) || nrow(metrics) == 0) {
    return(empty)
  }

  top_n <- config$top_n_authors %||% 100
  metrics <- metrics[order(-metrics$h_index, -metrics$total_citations), , drop = FALSE]
  metrics <- metrics[seq_len(min(top_n, nrow(metrics))), , drop = FALSE]

  if ("display_author" %in% names(metrics)) {
    metrics$author <- metrics$display_author
  }

  keep <- c("author", "total_papers", "total_citations", "h_index", "g_index", "career_length", "career_stage", "m_index")
  keep <- keep[keep %in% names(metrics)]

  list(
    status = "success",
    table = tibble::as_tibble(metrics[, keep, drop = FALSE]),
    summary = list(
      n_authors = data$n_authors %||% nrow(data$career_df),
      rising_stars = nrow(data$rising_stars %||% data.frame()),
      established_stars = nrow(data$established_stars %||% data.frame())
    )
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m1/render/m1_render_author_career.R

