# ============================================================================
# m1_render_author_indices.R - Author Impact Indices Visualization (IEEE Q1)
# ============================================================================

#' Render author impact indices plots
#'
#' @param result Output from compute_m1_author_indices
#' @param config Configuration list
#' @return List with plots
#' @export
render_m1_author_indices <- function(result, config = biblio_config()) {
  if (is.null(result) || result$status != "success") {
    return(list(plots = list(), status = "error: invalid data"))
  }
  
  plots <- list()
  
  if (!is.null(result$author_indices) && nrow(result$author_indices) > 0) {
    plots$h_index_plot <- create_h_index_plot(result, config)
    plots$g_index_plot <- create_g_index_plot(result, config)
    plots$h_vs_g <- create_h_vs_g_comparison_plot(result, config)
  }
  
  if (!is.null(result$h_index_distribution)) {
    plots$h_distribution <- create_h_index_distribution_plot(result, config)
  }
  
  list(
    plots = plots,
    status = "success"
  )
}

#' Create h-index bar chart for top authors
#' @keywords internal
create_h_index_plot <- function(result, config) {
  df <- result$author_indices
  
  top_n <- min(15, nrow(df))
  df_top <- head(df[order(-df$h_index), ], top_n)
  
  df_top$author <- factor(df_top$author, levels = rev(df_top$author))
  
  p <- ggplot2::ggplot(df_top, ggplot2::aes(x = author, y = h_index)) +
    ggplot2::geom_col(fill = "#0072BD", color = "black", linewidth = 0.2, width = 0.7) +
    ggplot2::geom_text(ggplot2::aes(label = h_index), hjust = -0.1, size = 2.5) +
    ggplot2::coord_flip() +
    ggplot2::scale_y_continuous(
      name = "h-index",
      expand = ggplot2::expansion(mult = c(0, 0.15))
    ) +
    ieee_theme_bar() +
    ggplot2::labs(
      title = "Top Authors by h-index",
      subtitle = sprintf("Showing top %d authors", top_n),
      x = NULL
    )
  
  p
}

#' Create g-index bar chart for top authors
#' @keywords internal
create_g_index_plot <- function(result, config) {
  df <- result$author_indices
  
  if (!"g_index" %in% names(df)) return(NULL)
  
  top_n <- min(15, nrow(df))
  df_top <- head(df[order(-df$g_index), ], top_n)
  
  df_top$author <- factor(df_top$author, levels = rev(df_top$author))
  
  p <- ggplot2::ggplot(df_top, ggplot2::aes(x = author, y = g_index)) +
    ggplot2::geom_col(fill = "#D95319", color = "black", linewidth = 0.2, width = 0.7) +
    ggplot2::geom_text(ggplot2::aes(label = g_index), hjust = -0.1, size = 2.5) +
    ggplot2::coord_flip() +
    ggplot2::scale_y_continuous(
      name = "g-index",
      expand = ggplot2::expansion(mult = c(0, 0.15))
    ) +
    ieee_theme_bar() +
    ggplot2::labs(
      title = "Top Authors by g-index",
      subtitle = sprintf("Showing top %d authors", top_n),
      x = NULL
    )
  
  p
}

#' Create h-index vs g-index comparison plot
#' @keywords internal
create_h_vs_g_comparison_plot <- function(result, config) {
  df <- result$author_indices
  
  if (!"g_index" %in% names(df)) return(NULL)
  
  top_n <- min(20, nrow(df))
  df_top <- head(df[order(-df$h_index), ], top_n)
  
  df_long <- reshape2::melt(
    df_top[, c("author", "h_index", "g_index")],
    id.vars = "author",
    variable.name = "index_type",
    value.name = "value"
  )
  
  df_long$index_label <- ifelse(df_long$index_type == "h_index", "h-index", "g-index")
  df_long$index_label <- factor(df_long$index_label, levels = c("h-index", "g-index"))
  
  df_long$author <- factor(df_long$author, levels = rev(df_top$author))
  
  colors <- c("h-index" = "#0072BD", "g-index" = "#D95319")
  
  p <- ggplot2::ggplot(df_long, ggplot2::aes(x = author, y = value, fill = index_label)) +
    ggplot2::geom_col(position = ggplot2::position_dodge(width = 0.8), width = 0.7,
                     color = "black", linewidth = 0.2) +
    ggplot2::coord_flip() +
    ggplot2::scale_fill_manual(values = colors, name = "Index") +
    ggplot2::scale_y_continuous(name = "Index Value", expand = ggplot2::expansion(mult = c(0, 0.1))) +
    ieee_theme_bar() +
    ggplot2::labs(
      title = "h-index vs g-index Comparison",
      subtitle = sprintf("Top %d authors", top_n),
      x = NULL
    ) +
    ggplot2::theme(legend.position = "bottom")
  
  p
}

#' Create h-index distribution plot
#' @keywords internal
create_h_index_distribution_plot <- function(result, config) {
  dist <- result$h_index_distribution
  
  df <- data.frame(
    h = as.integer(names(dist)),
    count = as.integer(dist),
    stringsAsFactors = FALSE
  )
  
  df <- df[df$h > 0, ]
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = h, y = count)) +
    ggplot2::geom_col(fill = "#77AC30", color = "black", linewidth = 0.2, width = 0.8) +
    ggplot2::scale_x_continuous(name = "h-index") +
    ggplot2::scale_y_continuous(
      name = "Number of Authors",
      expand = ggplot2::expansion(mult = c(0, 0.1))
    ) +
    ieee_theme_bar() +
    ggplot2::labs(
      title = "Distribution of h-index Values",
      subtitle = sprintf("Total authors: %d", sum(df$count))
    )
  
  p
}
# <<< END FILE: R/module_m1/render/m1_render_author_indices.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_authors.R
# ============================================================================
# m1_render_authors.R - Authors Plots (IEEE REFACTORED)
# ============================================================================

#' @export
render_m1_authors <- function(result, config = biblio_config()) {
  if (!inherits(result, "list") || !"top_authors" %in% names(result)) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  authors <- result$top_authors
  if (nrow(authors) == 0 || !"label" %in% names(authors) || !"value" %in% names(authors)) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  plots <- list()

  # 1. Bar chart (top 10, clean)
  authors_top <- authors[seq_len(min(10, nrow(authors))), ]
  authors_top$label_clean <- substr(trimws(authors_top$label), 1, 25)

  plots$bar <- ggplot2::ggplot(authors_top, ggplot2::aes(x = reorder(label_clean, value), y = value)) +
    ggplot2::geom_col(fill = ieee_colors$blue, color = "black", linewidth = 0.2) +
    ggplot2::geom_text(ggplot2::aes(label = value), hjust = -0.1, size = 2.0, color = "black") +
    ggplot2::coord_flip() +
    ggplot2::scale_y_continuous(expand = ggplot2::expansion(mult = c(0, 0.10))) +
    ggplot2::labs(x = NULL, y = "Publications") +
    ieee_theme()

  # 2. Lorenz curve (smooth interpolation)
  if (!is.null(result$author_gini) && !is.na(result$author_gini)) {
    lorenz <- m1_compute_lorenz(authors$value, smooth = TRUE)

    plots$lorenz <- ggplot2::ggplot(lorenz, ggplot2::aes(x = cumulative_entities, y = cumulative_values)) +
      ggplot2::geom_ribbon(ggplot2::aes(ymin = cumulative_values, ymax = cumulative_entities),
                           fill = ieee_colors$blue, alpha = 0.08) +
      ggplot2::geom_line(color = ieee_colors$blue, linewidth = 0.5) +
      ggplot2::geom_abline(slope = 1, intercept = 0, linetype = "dashed", color = ieee_colors$gray, linewidth = 0.3) +
      ggplot2::annotate("text", x = 0.3, y = 0.7,
                        label = sprintf("Gini = %.3f", result$author_gini),
                        size = 2.2, fontface = "italic", color = "black") +
      ggplot2::scale_x_continuous(breaks = seq(0, 1, 0.25), labels = scales::percent_format(accuracy = 25)) +
      ggplot2::scale_y_continuous(breaks = seq(0, 1, 0.25), labels = scales::percent_format(accuracy = 25)) +
      ggplot2::coord_fixed(ratio = 1, xlim = c(0, 1), ylim = c(0, 1)) +
      ggplot2::labs(x = "Cumulative % of Authors", y = "Cumulative % of Publications") +
      ggplot2::ggtitle(NULL) +
      ieee_theme()
  }

  list(status = "success", plots = plots, tables = list())
}
# <<< END FILE: R/module_m1/render/m1_render_authors.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_bradford.R
# ============================================================================
# m1_render_bradford.R - Bradford Plots (IEEE REFACTORED)
# ============================================================================

#' @export
render_m1_bradford <- function(result, config = biblio_config()) {
  if (!inherits(result, "list") || !"bradford_table" %in% names(result)) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  bt <- result$bradford_table
  if (nrow(bt) == 0) return(list(status = "stub", plots = list(), tables = list()))

  plots <- list()

  zone_colors <- c(
    "Zone 1: Core" = ieee_colors$blue,
    "Zone 2: Moderate" = ieee_colors$orange,
    "Zone 3: Peripheral" = ieee_colors$green
  )

  # Show only top sources to avoid clutter
  n_show <- min(15, nrow(bt))
  bt_top <- bt[1:n_show, ]
  bt_top$source_clean <- sapply(bt_top$source, function(x) {
    if (nchar(x) > 25) paste0(substr(x, 1, 22), "...") else x
  })

  # 1. Zone bar chart
  plots$bar <- ggplot2::ggplot(bt_top, ggplot2::aes(x = reorder(source_clean, freq), y = freq, fill = zone)) +
    ggplot2::geom_col(color = "black", linewidth = 0.2) +
    ggplot2::coord_flip() +
    ggplot2::scale_fill_manual(values = zone_colors, name = NULL) +
    ggplot2::labs(x = NULL, y = "Publications") +
    ggplot2::ggtitle(NULL) +
    ieee_theme(base_size = 6) +
    ggplot2::theme(legend.position = "right")

  # 2. Cumulative distribution (smooth)
  bt$cumulative <- cumsum(bt$freq) / sum(bt$freq) * 100
  bt$rank_pct <- bt$rank / max(bt$rank) * 100

  # Interpolate for smooth curve — use "natural" spline (universally available)
  # with linear fallback; clamp output to [0, 100].
  if (nrow(bt) >= 4) {
    smooth_x  <- seq(0, 100, length.out = 200)
    bt_unique <- bt[!duplicated(bt$rank_pct), ]          # guard against dup x
    smooth_y  <- tryCatch(
      stats::spline(bt_unique$rank_pct, bt_unique$cumulative,
                    xout = smooth_x, method = "natural")$y,
      error = function(e)
        stats::approx(bt_unique$rank_pct, bt_unique$cumulative,
                      xout = smooth_x, rule = 2)$y
    )
    smooth_y  <- pmax(0, pmin(100, smooth_y))
    smooth_df <- data.frame(rank_pct = smooth_x, cumulative = smooth_y)
  } else {
    smooth_df <- bt[, c("rank_pct", "cumulative")]
  }

  plots$cumulative <- ggplot2::ggplot(smooth_df, ggplot2::aes(x = rank_pct, y = cumulative)) +
    ggplot2::geom_line(color = ieee_colors$blue, linewidth = 0.5) +
    ggplot2::labs(x = "Cumulative % of Sources", y = "Cumulative % of Publications") +
    ggplot2::scale_x_continuous(breaks = seq(0, 100, 25)) +
    ggplot2::scale_y_continuous(breaks = seq(0, 100, 25)) +
    ggplot2::ggtitle(NULL) +
    ieee_theme()

  list(status = "success", plots = plots, tables = list())
}
# <<< END FILE: R/module_m1/render/m1_render_bradford.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_bubble_charts.R
# ============================================================================
# module_m1/render/m1_render_bubble_charts.R - Bubble chart visualizations
# ============================================================================

#' @export
render_m1_bubble_charts <- function(result, config = biblio_config()) {
  if (!inherits(result, "list")) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  plots <- list()

  # Countries: TP vs TC bubble
  if ("top_countries_by_articles" %in% names(result) && "top_countries_by_citations" %in% names(result)) {
    tp <- result$top_countries_by_articles
    tc <- result$top_countries_by_citations

    if (nrow(tp) > 0 && nrow(tc) > 0) {
      merged <- merge(tp, tc, by = "label", suffixes = c("_tp", "_tc"))
      if (nrow(merged) > 0) {
        # Compute avg citations per article
        merged$avg_tc <- merged$value_tc / merged$value_tp

        # Quadrant bounds (medians)
        median_tp <- median(merged$value_tp)
        median_tc <- median(merged$value_tc)

        merged$quadrant <- ifelse(merged$value_tp >= median_tp & merged$value_tc >= median_tc, "High TP, High TC",
                           ifelse(merged$value_tp >= median_tp & merged$value_tc < median_tc, "High TP, Low TC",
                           ifelse(merged$value_tp < median_tp & merged$value_tc >= median_tc, "Low TP, High TC",
                                  "Low TP, Low TC")))

        plots$countries_tp_tc <- ggplot2::ggplot(merged, ggplot2::aes(x = value_tp, y = value_tc, size = avg_tc, color = quadrant)) +
          ggplot2::geom_point(alpha = 0.7) +
          ggplot2::geom_hline(yintercept = median_tc, linetype = "dashed", color = "gray50", linewidth = 0.3) +
          ggplot2::geom_vline(xintercept = median_tp, linetype = "dashed", color = "gray50", linewidth = 0.3) +
          ggrepel::geom_text_repel(ggplot2::aes(label = label), size = 2.5, max.overlaps = 15) +
          ggplot2::scale_color_manual(values = c(
            "High TP, High TC" = ieee_colors$green,
            "High TP, Low TC" = ieee_colors$orange,
            "Low TP, High TC" = ieee_colors$blue,
            "Low TP, Low TC" = ieee_colors$gray
          )) +
          ggplot2::scale_size_continuous(range = c(2, 10), name = "Avg TC/Article") +
          ggplot2::labs(
            title = "Country Productivity vs Impact",
            x = "Total Publications",
            y = "Total Citations"
          ) +
          ieee_theme(base_size = 8) +
          ggplot2::theme(legend.position = "right")
      }
    }
  }

  # Papers: TC vs TCperYear bubble
  if ("top_cited_documents" %in% names(result) && "citations_per_year" %in% names(result)) {
    tc <- result$top_cited_documents
    cpy <- result$citations_per_year

    if (nrow(tc) > 0 && nrow(cpy) > 0) {
      merged_papers <- merge(tc, cpy, by = "label", suffixes = c("_tc", "_cpy"))
      if (nrow(merged_papers) > 0) {
        plots$papers_tc_cpy <- ggplot2::ggplot(merged_papers, ggplot2::aes(x = value_tc, y = value_cpy)) +
          ggplot2::geom_point(color = ieee_colors$blue, size = 3, alpha = 0.7) +
          ggrepel::geom_text_repel(ggplot2::aes(label = label), size = 2, max.overlaps = 10) +
          ggplot2::labs(
            title = "Papers: Total Citations vs Citations/Year",
            x = "Total Citations",
            y = "Citations per Year"
          ) +
          ieee_theme(base_size = 8)
      }
    }
  }

  list(status = "success", plots = plots, tables = list())
}
# <<< END FILE: R/module_m1/render/m1_render_bubble_charts.R

