# ============================================================================
# m1_render_price_law.R - Price's Law Visualization (IEEE Q1)
# ============================================================================
# Price's Law: Square root of authors produce half of the literature
# Price Index: Proportion of papers by core authors

#' Render Price's Law plots
#'
#' @param result Output from compute_m1_price_law
#' @param config Configuration list
#' @return List with plots
#' @export
render_m1_price_law <- function(result, config = biblio_config()) {
  if (is.null(result) || result$status != "success") {
    return(list(plots = list(), status = "error: invalid data"))
  }
  
  plots <- list()
  
  # Access author_distribution from price_law sub-object
  author_dist <- result$price_law$author_distribution
  if (!is.null(author_dist) && nrow(author_dist) > 0) {
    plots$price_law <- create_price_law_plot(result, config)
  }
  
  if (!is.null(result$author_concentration)) {
    plots$core_peripheral <- create_core_peripheral_plot(result, config)
  }
  
  list(
    plots = plots,
    status = "success"
  )
}

#' Create Price's Law cumulative contribution plot
#' @keywords internal
create_price_law_plot <- function(result, config) {
  author_dist <- result$price_law$author_distribution
  
  if (is.null(author_dist) || nrow(author_dist) == 0) return(NULL)
  
  # Calculate cumulative percentages
  author_dist <- author_dist[order(-author_dist$n_papers), ]
  author_dist$author_rank <- seq_len(nrow(author_dist))
  author_dist$cumulative_articles <- cumsum(author_dist$n_papers)
  total_papers <- sum(author_dist$n_papers)
  author_dist$cumulative_articles_pct <- author_dist$cumulative_articles / total_papers
  
  n_authors <- nrow(author_dist)
  sqrt_n <- sqrt(n_authors)
  half_articles <- total_papers / 2
  
  p <- ggplot2::ggplot(author_dist, ggplot2::aes(x = author_rank, y = cumulative_articles_pct)) +
    ggplot2::geom_line(color = "#0072BD", linewidth = 0.8) +
    ggplot2::geom_ribbon(
      ggplot2::aes(ymin = 0, ymax = cumulative_articles_pct),
      fill = "#0072BD", alpha = 0.1
    ) +
    ggplot2::geom_hline(yintercept = 0.5, color = "#D95319", linetype = "dashed", linewidth = 0.5) +
    ggplot2::geom_vline(xintercept = sqrt_n, color = "#77AC30", linetype = "dotted", linewidth = 0.5) +
    ggplot2::annotate(
      "text", x = sqrt_n, y = 0.05, hjust = -0.1, vjust = 0,
      label = sprintf("sqrt(n) = %.0f", sqrt_n), size = 2.5, color = "#77AC30"
    ) +
    ggplot2::scale_x_continuous(
      name = "Author Rank",
      expand = ggplot2::expansion(mult = c(0, 0.05))
    ) +
    ggplot2::scale_y_continuous(
      name = "Cumulative Articles (%)",
      labels = scales::percent_format(accuracy = 1),
      expand = ggplot2::expansion(mult = c(0, 0.05))
    ) +
    ieee_theme_timeseries() +
    ggplot2::labs(
      title = "Price's Law - Author Contribution Concentration",
      subtitle = sprintf("Top sqrt(n)=%.0f authors: %.1f%% of papers", 
                        sqrt_n, result$price_law$actual_proportion * 100)
    )
  
  p
}

#' Create core vs peripheral authors bar plot
#' @keywords internal
create_core_peripheral_plot <- function(result, config) {
  conc <- result$author_concentration
  
  if (is.null(conc) || is.null(conc$top_10_pct_share)) return(NULL)
  
  df <- data.frame(
    category = c("Top 10%", "Bottom 90%"),
    proportion = c(conc$top_10_pct_share, 1 - conc$top_10_pct_share),
    stringsAsFactors = FALSE
  )
  
  df$category <- factor(df$category, levels = c("Bottom 90%", "Top 10%"))
  
  colors <- c("Top 10%" = "#0072BD", "Bottom 90%" = "#A2142F")
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = "", y = proportion, fill = category)) +
    ggplot2::geom_col(width = 0.7, color = "black", linewidth = 0.2) +
    ggplot2::coord_flip() +
    ggplot2::scale_fill_manual(values = colors, name = "Category") +
    ggplot2::scale_y_continuous(
      name = "Proportion of Articles",
      labels = scales::percent_format(accuracy = 1),
      expand = ggplot2::expansion(mult = c(0, 0.1))
    ) +
    ieee_theme_bar() +
    ggplot2::labs(
      title = "Author Concentration",
      subtitle = sprintf("Gini: %.3f | %s", conc$gini %||% NA_real_, conc$concentration_type %||% ""),
      x = NULL
    )
  
  p
}

#' Create contribution pie chart
#' @keywords internal
create_contribution_pie <- function(result, config) {
  author_dist <- result$price_law$author_distribution
  
  if (is.null(author_dist) || nrow(author_dist) == 0) return(NULL)
  
  top_n <- min(10, nrow(author_dist))
  top_contrib <- head(author_dist[order(-author_dist$n_papers), ], top_n)
  other <- sum(author_dist$n_papers) - sum(top_contrib$n_papers)
  
  df <- data.frame(
    author = c(top_contrib$author, "Other"),
    articles = c(top_contrib$n_papers, other),
    stringsAsFactors = FALSE
  )
  
  df$author <- factor(df$author, levels = df$author)
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = "", y = articles, fill = author)) +
    ggplot2::geom_col(position = "stack", color = "black", linewidth = 0.2) +
    ggplot2::scale_fill_discrete(name = "Author") +
    ieee_theme() +
    ggplot2::labs(
      title = "Top Authors by Contribution",
      subtitle = sprintf("Top %d authors + Others", top_n),
      y = "Articles"
    ) +
    ggplot2::theme(axis.text.x = ggplot2::element_blank())
  
  p
}
# <<< END FILE: R/module_m1/render/m1_render_price_law.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_sources.R
# ============================================================================
# m1_render_sources.R - Sources Plots (IEEE REFACTORED)
# ============================================================================

#' @export
render_m1_sources <- function(result, config = biblio_config()) {
  if (!inherits(result, "list") || !"top_sources" %in% names(result)) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  sources <- result$top_sources
  if (nrow(sources) == 0 || !"label" %in% names(sources) || !"value" %in% names(sources)) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  plots <- list()
  sources_top <- sources[seq_len(min(10, nrow(sources))), ]

  # Truncate long source names intelligently
  sources_top$label_clean <- sapply(sources_top$label, function(x) {
    if (nchar(x) > 30) paste0(substr(x, 1, 27), "...") else x
  })

  # 1. Bar chart
  plots$bar <- ggplot2::ggplot(sources_top, ggplot2::aes(x = reorder(label_clean, value), y = value)) +
    ggplot2::geom_col(fill = ieee_colors$purple, color = "black", linewidth = 0.2) +
    ggplot2::geom_text(ggplot2::aes(label = value), hjust = -0.1, size = 2.0) +
    ggplot2::coord_flip() +
    ggplot2::scale_y_continuous(expand = ggplot2::expansion(mult = c(0, 0.10))) +
    ggplot2::labs(x = NULL, y = "Publications") +
    ieee_theme()

  # 2. Lorenz (smooth)
  if ("source_gini" %in% names(result) && !is.na(result$source_gini)) {
    lorenz <- m1_compute_lorenz(sources$value, smooth = TRUE)
    plots$lorenz <- ggplot2::ggplot(lorenz, ggplot2::aes(x = cumulative_entities, y = cumulative_values)) +
      ggplot2::geom_ribbon(ggplot2::aes(ymin = cumulative_values, ymax = cumulative_entities),
                           fill = ieee_colors$purple, alpha = 0.08) +
      ggplot2::geom_line(color = ieee_colors$purple, linewidth = 0.5) +
      ggplot2::geom_abline(slope = 1, intercept = 0, linetype = "dashed", color = ieee_colors$gray, linewidth = 0.3) +
      ggplot2::annotate("text", x = 0.3, y = 0.7, label = sprintf("Gini = %.3f", result$source_gini),
                        size = 2.2, fontface = "italic") +
      ggplot2::scale_x_continuous(breaks = seq(0, 1, 0.25), labels = scales::percent_format(accuracy = 25)) +
      ggplot2::scale_y_continuous(breaks = seq(0, 1, 0.25), labels = scales::percent_format(accuracy = 25)) +
      ggplot2::coord_fixed(ratio = 1, xlim = c(0, 1), ylim = c(0, 1)) +
      ggplot2::labs(x = "Cumulative % of Sources", y = "Cumulative % of Publications") +
      ggplot2::ggtitle(NULL) +
      ieee_theme()
  }

  list(status = "success", plots = plots, tables = list())
}
# <<< END FILE: R/module_m1/render/m1_render_sources.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_three_field.R
# ============================================================================
# m1_render_three_field.R - Three-Field Plot (Sankey Tripartite)
# ============================================================================
# Creates three-field plots showing relationships between three entities
# (e.g., Authors-Keywords-Sources, Countries-Keywords-Years)

#' Render three-field plot
#'
#' Creates a Sankey-style tripartite diagram showing relationships between
#' three fields (e.g., authors, keywords, sources).
#'
#' @param data Bibliographic data frame
#' @param fields Named list with three fields: field1, field2, field3
#'        Each should be a list with name and column (e.g., list(name = "Authors", column = "AU"))
#' @param config Configuration list
#' @param n_items Number of top items to show per field (default 10)
#' @return List with three-field plot
#' @export
render_m1_three_field <- function(data, fields = NULL, config = biblio_config(), n_items = 10) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(list(plots = list(), status = "error: ggplot2 not installed"))
  }
  
  # Default fields: Authors - Keywords - Sources
  if (is.null(fields)) {
    fields <- list(
      field1 = list(name = "Authors", column = "AU"),
      field2 = list(name = "Keywords", column = "DE"),
      field3 = list(name = "Sources", column = "SO")
    )
  }
  
  # Validate data has required columns
  required_cols <- c(fields$field1$column, fields$field2$column, fields$field3$column)
  missing_cols <- setdiff(required_cols, names(data))
  
  if (length(missing_cols) > 0) {
    return(list(plots = list(), status = paste("error: missing columns:", paste(missing_cols, collapse = ", "))))
  }
  
  # Prepare three-field data
  three_field_data <- prepare_three_field_data(
    data,
    fields$field1$column,
    fields$field2$column,
    fields$field3$column,
    n_items
  )
  
  if (is.null(three_field_data) || nrow(three_field_data$flows) == 0) {
    return(list(plots = list(), status = "error: no valid relationships"))
  }
  
  # Create plot
  if (requireNamespace("ggalluvial", quietly = TRUE)) {
    plot <- create_alluvial_three_field(three_field_data, fields, n_items, config)
  } else {
    plot <- create_network_three_field(three_field_data, fields, n_items, config)
  }
  
  list(
    plots = list(three_field = plot),
    data = three_field_data,
    status = "success"
  )
}

#' Prepare three-field relationship data
#' @keywords internal
prepare_three_field_data <- function(data, col1, col2, col3, n_items) {
  # Extract and count items for each field
  extract_items <- function(column, n) {
    items <- unlist(strsplit(as.character(column), ";"))
    items <- trimws(items)
    items <- items[items != "" & !is.na(items)]
    tab <- table(items)
    tab <- sort(tab, decreasing = TRUE)
    names(tab)[1:min(n, length(tab))]
  }
  
  # Get top items
  top1 <- extract_items(data[[col1]], n_items)
  top2 <- extract_items(data[[col2]], n_items)
  top3 <- extract_items(data[[col3]], n_items)
  
  # Create flows between fields
  flows12 <- create_field_flows(data, col1, col2, top1, top2)
  flows23 <- create_field_flows(data, col2, col3, top2, top3)
  
  # Count node frequencies
  count1 <- table(unlist(strsplit(as.character(data[[col1]]), ";")))
  count2 <- table(unlist(strsplit(as.character(data[[col2]]), ";")))
  count3 <- table(unlist(strsplit(as.character(data[[col3]]), ";")))
  
  list(
    nodes1 = data.frame(name = top1, count = as.numeric(count1[top1])),
    nodes2 = data.frame(name = top2, count = as.numeric(count2[top2])),
    nodes3 = data.frame(name = top3, count = as.numeric(count3[top3])),
    flows = rbind(flows12, flows23),
    n_fields = 3
  )
}

#' Create flows between two fields
#' @keywords internal
create_field_flows <- function(data, col_a, col_b, top_a, top_b) {
  flows <- data.frame(
    from = character(),
    to = character(),
    value = numeric(),
    stringsAsFactors = FALSE
  )
  
  for (i in seq_len(nrow(data))) {
    items_a <- trimws(strsplit(as.character(data[[col_a]][i]), ";")[[1]])
    items_b <- trimws(strsplit(as.character(data[[col_b]][i]), ";")[[1]])
    
    items_a <- items_a[items_a %in% top_a]
    items_b <- items_b[items_b %in% top_b]
    
    # Add flows for each combination
    for (a in items_a) {
      for (b in items_b) {
        idx <- which(flows$from == a & flows$to == b)
        if (length(idx) > 0) {
          flows$value[idx] <- flows$value[idx] + 1
        } else {
          flows <- rbind(flows, data.frame(from = a, to = b, value = 1, stringsAsFactors = FALSE))
        }
      }
    }
  }
  
  flows
}

#' Create alluvial three-field plot
#' @keywords internal
create_alluvial_three_field <- function(tf_data, fields, n_items, config) {
  if (!requireNamespace("ggalluvial", quietly = TRUE)) {
    return(create_network_three_field(tf_data, fields, n_items, config))
  }
  
  # Create alluvial format data
  alluvial_data <- data.frame(
    field1 = character(),
    field2 = character(),
    field3 = character(),
    value = numeric(),
    stringsAsFactors = FALSE
  )
  
  # Process flows
  for (i in seq_len(nrow(tf_data$flows))) {
    row <- tf_data$flows[i, ]
    
    # Determine which fields this flow connects
    if (row$from %in% tf_data$nodes1$name) {
      # Flow from field1 to field2
      field1_val <- row$from
      field2_val <- row$to
      field3_val <- NA
    } else {
      # Flow from field2 to field3
      field1_val <- NA
      field2_val <- row$from
      field3_val <- row$to
    }
    
    alluvial_data <- rbind(alluvial_data, data.frame(
      field1 = field1_val,
      field2 = field2_val,
      field3 = field3_val,
      value = row$value,
      stringsAsFactors = FALSE
    ))
  }
  
  # Create separate alluvial for 1-2 and 2-3 links
  flows_12 <- tf_data$flows[tf_data$flows$from %in% tf_data$nodes1$name, ]
  flows_23 <- tf_data$flows[tf_data$flows$from %in% tf_data$nodes2$name, ]
  
  # Create long format for alluvial
  long_data_12 <- data.frame(
    source = factor(flows_12$from, levels = tf_data$nodes1$name),
    target = factor(flows_12$to, levels = tf_data$nodes2$name),
    value = flows_12$value,
    stringsAsFactors = FALSE
  )
  
  palette <- get_biblio_palette(n = n_items * 3)
  
  # Create simplified alluvial plot
  p <- ggplot2::ggplot(long_data_12,
    ggplot2::aes(
      axis1 = source,
      axis2 = target,
      y = value
    )
  ) +
    ggalluvial::geom_alluvium(ggplot2::aes(fill = source), width = 1/4, alpha = 0.7) +
    ggalluvial::geom_stratum(width = 1/4, fill = "grey80", color = "white") +
    ggplot2::geom_text(stat = "stratum", ggplot2::aes(label = after_stat(ggplot2::stratum)), size = 3) +
    ggplot2::scale_x_discrete(
      limits = c(fields$field1$name, fields$field2$name),
      expand = c(0.05, 0.05)
    ) +
    ggplot2::scale_fill_manual(values = palette, guide = "none") +
    ggplot2::labs(
      title = paste(fields$field1$name, "-", fields$field2$name, "Relationship"),
      y = "Number of Co-occurrences"
    ) +ieee_theme()
  
  p
}

#' Create network-style three-field plot (fallback)
#' @keywords internal
create_network_three_field <- function(tf_data, fields, n_items, config) {
  if (!requireNamespace("igraph", quietly = TRUE)) {
    return(ggplot2::ggplot() +
      ggplot2::annotate("text", x = 0.5, y = 0.5, label = "igraph package required") +
      ggplot2::labs(title = "Three-Field Plot") +
      ggplot2::theme_void())
  }
  
  # Create graph
  edges <- tf_data$flows
  nodes <- data.frame(
    name = c(tf_data$nodes1$name, tf_data$nodes2$name, tf_data$nodes3$name),
    field = c(
      rep(fields$field1$name, nrow(tf_data$nodes1)),
      rep(fields$field2$name, nrow(tf_data$nodes2)),
      rep(fields$field3$name, nrow(tf_data$nodes3))
    ),
    stringsAsFactors = FALSE
  )
  
  g <- igraph::graph_from_data_frame(edges, directed = FALSE, vertices = nodes)
  
  # Layout
  layout <- igraph::layout_with_fr(g)
  
  # Plot
  palette <- get_biblio_palette(n = 3)
  
  ggplot2::ggplot() +
    ggplot2::annotate("text", x = 0.5, y = 0.5, 
                      label = "Install ggalluvial for proper three-field plot") +
    ggplot2::labs(title = paste(fields$field1$name, fields$field2$name, fields$field3$name, sep = " - ")) +
    ggplot2::theme_void()
}

#' Build three-field relationship table
#' @export
build_m1_three_field_table <- function(data, fields = NULL, config = biblio_config(), n_items = 10) {
  # Default fields
  if (is.null(fields)) {
    fields <- list(
      field1 = list(name = "Authors", column = "AU"),
      field2 = list(name = "Keywords", column = "DE"),
      field3 = list(name = "Sources", column = "SO")
    )
  }
  
  three_field_data <- prepare_three_field_data(
    data,fields$field1$column,
    fields$field2$column,
    fields$field3$column,
    n_items
  )
  
  if (is.null(three_field_data)) {
    return(data.frame(
      from = character(),
      to = character(),
      value = integer(),
      stringsAsFactors = FALSE
    ))
  }
  
  three_field_data$flows
}

#' Render Authors-Keywords-Sources three-field plot (convenience wrapper)
#' @param data Bibliographic data frame
#' @param config Configuration list
#' @param n_items Number of top items per field
#' @return List with three-field plot
#' @export
render_m1_authors_keywords_sources <- function(data, config = biblio_config(), n_items = 10) {
  fields <- list(
    field1 = list(name = "Authors", column = "AU"),
    field2 = list(name = "Keywords", column = "DE"),
    field3 = list(name = "Sources", column = "SO")
  )
  
  render_m1_three_field(data, fields, config, n_items)
}

#' Render Countries-Keywords-Years three-field plot (convenience wrapper)
#' @param data Bibliographic data frame with AU_CO, DE, PY columns
#' @param config Configuration list
#' @param n_items Number of top items per field
#' @return List with three-field plot
#' @export
render_m1_countries_keywords_years <- function(data, config = biblio_config(), n_items = 10) {
  fields <- list(
    field1 = list(name = "Countries", column = "AU_CO"),
    field2 = list(name = "Keywords", column = "DE"),
    field3 = list(name = "Years", column = "PY")
  )
  
  render_m1_three_field(data, fields, config, n_items)
}
