# >>> BEGIN FILE: R/module_m1/render/m1_render_topic_modeling.R
# ============================================================================
# m1_render_topic_modeling.R - Topic Modeling Visualization
# ============================================================================

#' Render topic modeling results
#'
#' @param data Output from compute_m1_topic_modeling
#' @param config Configuration list
#' @return List with topic plots
#' @export
render_m1_topic_modeling <- function(data, config = biblio_config()) {
  if (is.null(data) || startsWith(data$status %||% "error", "error")) {
    return(list(plots = list(), status = data$status %||% "error"))
  }

  plots <- list()

  if (!is.null(data$topic_terms_long) && nrow(data$topic_terms_long) > 0) {
    plots$topic_words <- create_topic_word_plot(data, config)
  }

  if (!is.null(data$document_topic_weights) && nrow(data$document_topic_weights) > 0) {
    plots$topic_distribution <- create_topic_distribution_plot(data, config)
  }

  if (!is.null(data$topic_evolution) && is.list(data$topic_evolution) &&
      !is.null(data$topic_evolution$prevalence_matrix) &&
      length(data$topic_evolution$prevalence_matrix) > 0) {
    plots$topic_evolution <- create_topic_evolution_plot(data, config)
  }

  if (!is.null(data$coherence) || !is.null(data$perplexity)) {
    plots$model_quality <- create_topic_quality_plot(data, config)
  }

  list(
    plots = plots,
    status = "success"
  )
}

#' Create topic word plot
#' @keywords internal
create_topic_word_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  terms <- data$topic_terms_long
  if (is.null(terms) || nrow(terms) == 0) return(NULL)

  n_top_words <- config$n_top_words %||% 10
  terms <- terms[terms$rank <= n_top_words, , drop = FALSE]
  terms$facet_term <- paste0("T", terms$topic_id, ": ", terms$term)
  terms$facet_term <- stats::reorder(terms$facet_term, terms$probability)

  ggplot2::ggplot(terms, ggplot2::aes(x = facet_term, y = probability, fill = factor(topic_id))) +
    ggplot2::geom_col(show.legend = FALSE) +
    ggplot2::facet_wrap(~ topic_label, scales = "free_y") +
    ggplot2::coord_flip() +
    ggplot2::labs(
      title = "Top Terms per Topic",
      x = "Term",
      y = "Topic-Term Probability"
    ) +
    ieee_theme()
}

#' Create topic distribution plot
#' @keywords internal
create_topic_distribution_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  doc_topics <- data$document_topic_weights
  if (is.null(doc_topics) || nrow(doc_topics) == 0) return(NULL)

  ggplot2::ggplot(doc_topics, ggplot2::aes(x = factor(topic_id), y = probability)) +
    ggplot2::geom_boxplot(fill = "#2166AC", alpha = 0.75) +
    ggplot2::labs(
      title = "Document-Topic Weight Distribution",
      x = "Topic",
      y = "Document-Topic Probability"
    ) +
    ieee_theme()
}

#' Create topic evolution plot
#' @keywords internal
create_topic_evolution_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  evolution <- data$topic_evolution
  matrix_data <- evolution$prevalence_matrix
  if (is.null(matrix_data) || length(matrix_data) == 0) return(NULL)

  evolution_df <- as.data.frame(as.table(matrix_data), stringsAsFactors = FALSE)
  names(evolution_df) <- c("year", "topic_id", "prevalence")
  evolution_df$year <- as.numeric(as.character(evolution_df$year))
  evolution_df$topic_id <- as.integer(gsub("[^0-9]", "", as.character(evolution_df$topic_id)))
  evolution_df$topic <- paste0("Topic ", evolution_df$topic_id)

  ggplot2::ggplot(evolution_df, ggplot2::aes(x = year, y = prevalence, color = topic)) +
    ggplot2::geom_line(linewidth = 0.9) +
    ggplot2::geom_point(size = 1.8) +
    ggplot2::labs(
      title = "Topic Prevalence Over Time",
      x = "Year",
      y = "Prevalence",
      color = "Topic"
    ) +
    ggplot2::theme(legend.position = "bottom") +
    ieee_theme()
}

#' Create topic quality plot
#' @keywords internal
create_topic_quality_plot <- function(data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(NULL)
  }

  quality_df <- data.frame(
    metric = c("Coherence", "Perplexity"),
    value = c(as.numeric(data$coherence %||% NA_real_), as.numeric(data$perplexity %||% NA_real_)),
    stringsAsFactors = FALSE
  )
  quality_df <- quality_df[!is.na(quality_df$value), , drop = FALSE]
  if (nrow(quality_df) == 0) return(NULL)

  ggplot2::ggplot(quality_df, ggplot2::aes(x = metric, y = value, fill = metric)) +
    ggplot2::geom_col(show.legend = FALSE, alpha = 0.8) +
    ggplot2::geom_text(ggplot2::aes(label = round(value, 3)), vjust = -0.4, size = 3) +
    ggplot2::labs(
      title = "Topic Model Quality Metrics",
      x = NULL,
      y = "Value"
    ) +
    ieee_theme()
}

#' Build topic modeling table
#' @export
build_m1_topic_modeling_table <- function(data, config = biblio_config()) {
  empty <- list(
    status = "stub",
    table = tibble::tibble(),
    summary = list()
  )

  if (is.null(data) || startsWith(data$status %||% "error", "error")) {
    return(empty)
  }

  topics <- tibble::as_tibble(data$topics %||% data.frame())
  metrics <- tibble::as_tibble(data$topic_metrics %||% data.frame())
  if (nrow(topics) == 0) {
    return(empty)
  }

  if (nrow(metrics) > 0 && "topic_id" %in% names(topics) && "topic_id" %in% names(metrics)) {
    topics <- dplyr::left_join(topics, metrics, by = "topic_id")
  }

  if ("doc_count" %in% names(topics)) {
    topics <- topics[order(-topics$doc_count, -topics$weight), , drop = FALSE]
  } else if ("weight" %in% names(topics)) {
    topics <- topics[order(-topics$weight), , drop = FALSE]
  }

  list(
    status = "success",
    table = topics,
    summary = list(
      n_topics = data$n_topics %||% nrow(topics),
      coherence = data$coherence %||% NA_real_,
      perplexity = data$perplexity %||% NA_real_,
      keyword_source = data$keywords_used %||% NA_character_
    )
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m1/render/m1_render_topic_modeling.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_treemap.R
# ============================================================================
# m1_render_treemap.R - Treemap Visualization for M1
# ============================================================================
# Creates treemap visualizations for hierarchical data display
# (countries, sources, keywords, authors)

#' Render treemap visualization
#'
#' @param data Output from compute_m1_* functions
#' @param type Type of treemap: "countries", "sources", "keywords", "authors"
#' @param config Configuration list
#' @return List with treemap plot
#' @export
render_m1_treemap <- function(data, type = "countries", config = biblio_config()) {
  if (!requireNamespace("treemapify", quietly = TRUE)) {
    cli::cli_warn("treemapify package required for treemap visualization")
    return(list(plots = list(), status = "error: treemapify not installed"))
  }
  
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(list(plots = list(), status = "error: ggplot2 not installed"))
  }
  
  plots <- list()
  
  # Prepare data based on type
  treemap_data <- prepare_treemap_data(data, type)
  
  if (is.null(treemap_data) || nrow(treemap_data) == 0) {
    return(list(plots = list(), status = "error: no data for treemap"))
  }
  
  # Create treemap
  plots$treemap <- create_treemap_plot(treemap_data, type, config)
  
  list(
    plots = plots,
    status = "success"
  )
}

#' Prepare data for treemap
#' @keywords internal
prepare_treemap_data <- function(data, type) {
  df <- NULL
  
  if (type == "countries") {
    if (!is.null(data$countries) && is.data.frame(data$countries)) {
      df <- data.frame(
        name = data$countries$country,
        value = data$countries$total_docs,
        stringsAsFactors = FALSE
      )
    } else if (!is.null(data$country_summary) && is.data.frame(data$country_summary)) {
      df <- data.frame(
        name = data$country_summary$country,
        value = data$country_summary$total_docs,
        stringsAsFactors = FALSE
      )
    }
  } else if (type == "sources") {
    if (!is.null(data$sources) && is.data.frame(data$sources)) {
      df <- data.frame(
        name = data$sources$source,
        value = data$sources$n_docs,
        stringsAsFactors = FALSE
      )
    }
  } else if (type == "keywords") {
    if (!is.null(data$keywords) && is.data.frame(data$keywords)) {
      df <- data.frame(
        name = data$keywords$keyword,
        value = data$keywords$freq,
        stringsAsFactors = FALSE
      )
    }
  } else if (type == "authors") {
    if (!is.null(data$authors) && is.data.frame(data$authors)) {
      df <- data.frame(
        name = data$authors$author,
        value = data$authors$n_docs,
        stringsAsFactors = FALSE
      )
    }
  }
  
  if (is.null(df) || nrow(df) == 0) {
    return(NULL)
  }
  
  # Remove NA values
  df <- df[!is.na(df$value) & df$value > 0, ]
  
  # Sort and take top N
  df <- df[order(-df$value), ]
  top_n <- min(50, nrow(df))
  df <- df[1:top_n, ]
  
  # Add parent for hierarchical treemap
  df$parent <- "All"
  
  # Add percentage
  df$percentage <- df$value / sum(df$value) * 100
  
  df
}

#' Create treemap plot
#' @keywords internal
create_treemap_plot <- function(df, type, config) {
  if (nrow(df) == 0) return(NULL)
  
  # Create labels
  df$label <- paste0(df$name, "\n", df$value, " (", sprintf("%.1f", df$percentage), "%)")
  
  # Color palette
  palette <- get_biblio_palette(n = nrow(df))
  
  p <- ggplot2::ggplot(df, ggplot2::aes(
    area = value,
    fill = name,
    label = label
  )) +
    treemapify::geom_treemap() +
    treemapify::geom_treemap_text(
      colour = "white",
      place = "centre",
      size = 10,
      grow = TRUE
    ) +
    ggplot2::scale_fill_manual(values = palette, guide = "none") +
    ggplot2::labs(
      title = paste0("Treemap: ", tools::toTitleCase(type)),
      subtitle = sprintf("Top %d by publication count", nrow(df))
    ) +
    ieee_theme() +
    ggplot2::theme(
      legend.position = "none",
      plot.title = ggplot2::element_text(size = 14, face = "bold"),
      plot.subtitle = ggplot2::element_text(size = 10)
    )
  
  p
}

#' Build treemap table
#' @export
build_m1_treemap_table <- function(data, type = "countries", config = biblio_config()) {
  df <- prepare_treemap_data(data, type)
  
  if (is.null(df)) {
    return(data.frame(
      name = character(),
      value = integer(),
      percentage = numeric(),
      stringsAsFactors = FALSE
    ))
  }
  
  df
}

#' Render nested treemap with groupings
#'
#' @param data Output from compute_m1_* functions
#' @param group_col Column to group by
#' @param type Type of treemap
#' @param config Configuration list
#' @return List with nested treemap plot
#' @export
render_m1_nested_treemap <- function(data, group_col = NULL, type = "countries", config = biblio_config()) {
  if (!requireNamespace("treemapify", quietly = TRUE)) {
    return(list(plots = list(), status = "error: treemapify not installed"))
  }
  
  df <- prepare_treemap_data(data, type)
  
  if (is.null(df)) {
    return(list(plots = list(), status = "error: no data"))
  }
  
  # If grouping column provided, create nested structure
  if (!is.null(group_col) && group_col %in% names(df)) {
    df$group <- df[[group_col]]
  } else {
    # Auto-group: assign top items to "Top", others to "Other"
    top_n <- config$treemap_top_n %||% 10
    df$group <- ifelse(seq_len(nrow(df)) <= top_n, "Top", "Other")
  }
  
  palette <- get_biblio_palette(n = nrow(df))
  
  p <- ggplot2::ggplot(df, ggplot2::aes(
    area = value,
    fill = name,
    subgroup = group,
    label = name
  )) +
    treemapify::geom_treemap() +
    treemapify::geom_treemap_subgroup_border() +
    treemapify::geom_treemap_subgroup_text(place = "centre", grow = TRUE, alpha = 0.5) +
    treemapify::geom_treemap_text(colour = "white", place = "topleft", grow = FALSE, size = 8) +
    ggplot2::scale_fill_manual(values = palette, guide = "none") +
    ggplot2::labs(title = paste0("Nested Treemap: ", tools::toTitleCase(type))) +
    ieee_theme()
  
  list(plots = list(treemap = p), status = "success")
}
# <<< END FILE: R/module_m1/render/m1_render_treemap.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_treemaps.R
# ============================================================================
# module_m1/render/m1_render_treemaps.R - Treemap visualizations
# ============================================================================

#' @export
render_m1_treemaps <- function(countries_result, sources_result, config = biblio_config()) {
  plots <- list()
  ec <- unname(unlist(ieee_colors[1:8]))

  # Countries treemap
  if (!is.null(countries_result) && "top_countries_by_articles" %in% names(countries_result)) {
    countries <- countries_result$top_countries_by_articles
    if (nrow(countries) > 0) {
      countries$label_text <- paste0(countries$label, "\n", countries$value)

      plots$countries <- ggplot2::ggplot(countries, ggplot2::aes(
        area = value, fill = as.factor(rank), label = label_text)) +
        treemapify::geom_treemap(color = "white", size = 2) +
        treemapify::geom_treemap_text(
          place = "centre", size = 12, color = "white", fontface = "bold",
          grow = TRUE, reflow = TRUE) +
        ggplot2::scale_fill_manual(values = ec) +
        ggplot2::labs(title = "Most Productive Countries") +
        ggplot2::theme_void() +
        ggplot2::theme(
          plot.title = ggplot2::element_text(size = 9, face = "bold", hjust = 0.5, family = "mono"),
          legend.position = "none"
        )
    }
  }

  # Sources treemap
  if (!is.null(sources_result) && "top_sources" %in% names(sources_result)) {
    sources <- sources_result$top_sources
    if (nrow(sources) > 0) {
      # Truncate long source names
      sources$label_short <- substr(sources$label, 1, 30)
      sources$label_text <- paste0(sources$label_short, "\n", sources$value)

      plots$sources <- ggplot2::ggplot(sources, ggplot2::aes(
        area = value, fill = as.factor(rank), label = label_text)) +
        treemapify::geom_treemap(color = "white", size = 2) +
        treemapify::geom_treemap_text(
          place = "centre", size = 10, color = "white", fontface = "bold",
          grow = TRUE, reflow = TRUE) +
        ggplot2::scale_fill_manual(values = ec) +
        ggplot2::labs(title = "Most Productive Sources") +
        ggplot2::theme_void() +
        ggplot2::theme(
          plot.title = ggplot2::element_text(size = 9, face = "bold", hjust = 0.5, family = "mono"),
          legend.position = "none"
        )
    }
  }

  list(status = "success", plots = plots, tables = list())
}
# <<< END FILE: R/module_m1/render/m1_render_treemaps.R

# >>> BEGIN FILE: R/module_m1/render/m1_render_world_map.R
# ============================================================================
# module_m1/render/m1_render_world_map.R - World map visualization
# ============================================================================

#' @export
render_m1_world_map <- function(result, config = biblio_config()) {
  if (!inherits(result, "list") || !"top_countries_by_articles" %in% names(result)) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  countries <- result$top_countries_by_articles
  if (nrow(countries) == 0) {
    return(list(status = "stub", plots = list(), tables = list()))
  }

  plots <- list()

  # Load world map data
  world <- tryCatch(
    rnaturalearth::ne_countries(scale = "medium", returnclass = "sf"),
    error = function(e) NULL
  )

  if (!is.null(world)) {
    # Normalize country names for matching
    countries$name_clean <- toupper(trimws(countries$label))

    # Try to match using countrycode
    countries$iso3 <- tryCatch(
      countrycode::countrycode(countries$name_clean, "country.name", "iso3c"),
      error = function(e) rep(NA, nrow(countries))
    )

    # Merge with world data
    world$articles <- 0
    for (i in seq_len(nrow(countries))) {
      if (!is.na(countries$iso3[i])) {
        idx <- which(world$iso_a3 == countries$iso3[i])
        if (length(idx) > 0) world$articles[idx] <- countries$value[i]
      }
    }

    # Articles map
    plots$articles_map <- ggplot2::ggplot() +
      ggplot2::geom_sf(data = world, ggplot2::aes(fill = articles), color = "gray30", linewidth = 0.1) +
      ggplot2::scale_fill_viridis_c(option = "viridis", na.value = "gray90", name = "Articles") +
      ggplot2::labs(title = "Global Distribution of Articles") +
      ggplot2::theme_void(base_size = 8) +
      ggplot2::theme(
        plot.title = ggplot2::element_text(size = 9, face = "bold", hjust = 0.5),
        legend.position = "right"
      )

    # Citations map (if available)
    if ("top_countries_by_citations" %in% names(result)) {
      citations <- result$top_countries_by_citations
      citations$name_clean <- toupper(trimws(citations$label))
      citations$iso3 <- tryCatch(
        countrycode::countrycode(citations$name_clean, "country.name", "iso3c"),
        error = function(e) rep(NA, nrow(citations))
      )

      world$citations <- 0
      for (i in seq_len(nrow(citations))) {
        if (!is.na(citations$iso3[i])) {
          idx <- which(world$iso_a3 == citations$iso3[i])
          if (length(idx) > 0) world$citations[idx] <- citations$value[i]
        }
      }

      plots$citations_map <- ggplot2::ggplot() +
        ggplot2::geom_sf(data = world, ggplot2::aes(fill = citations), color = "gray30", linewidth = 0.1) +
        ggplot2::scale_fill_viridis_c(option = "magma", na.value = "gray90", name = "Citations") +
        ggplot2::labs(title = "Global Distribution of Citations") +
        ggplot2::theme_void(base_size = 8) +
        ggplot2::theme(
          plot.title = ggplot2::element_text(size = 9, face = "bold", hjust = 0.5, family = "mono"),
          legend.position = "right"
        )
    }
  }

  list(status = "success", plots = plots, tables = list())
}
# <<< END FILE: R/module_m1/render/m1_render_world_map.R

