# ============================================================================
# m2_compute_growth_models.R - Advanced Growth Models
# ============================================================================
# Bass diffusion, Gompertz, Weibull, Richards, von Bertalanffy, Morgan-Mercer-Flodin

#' Fit Bass diffusion model
#'
#' @param years Vector of years
#' @param articles Vector of article counts
#' @return List with model parameters and predictions
#' @export
fit_bass_model <- function(years, articles) {
  n <- length(articles)
  if (n < 5) {
    return(list(status = "error: insufficient data", model = "bass"))
  }
  
  # Bass model: N(t) = m * (1 - exp(-(p+q)*t)) / (1 + (q/p)*exp(-(p+q)*t))
  # N(t) = cumulative adopters
  # p = innovation coefficient, q = imitation coefficient, m = market potential
  
  cumulative <- cumsum(articles)
  
  # Initial parameter estimates
  m_init <- max(cumulative) * 1.5
  
  # Fit using nonlinear least squares
  bass_fit <- tryCatch({
    nls(cumulative ~ m * (1 - exp(-(p + q) * (years - years[1]))) / 
        (1 + (q / p) * exp(-(p + q) * (years - years[1]))),
        start = list(m = m_init, p = 0.01, q = 0.3),
        control = nls.control(maxiter = 1000, warnOnly = TRUE))
  }, error = function(e) NULL)
  
  if (is.null(bass_fit)) {
    return(list(
      status = "error: bass model convergence failed",
      model = "bass",
      params = list(m = NA, p = NA, q = NA),
      predictions = rep(NA, n),
      fitted = rep(NA, n)
    ))
  }
  
  params <- coef(bass_fit)
  fitted_vals <- predict(bass_fit)
  residuals_val <- cumulative - fitted_vals
  
  # Bass curves types
  if (params["q"] > params["p"]) {
    curve_type <- "imitation-dominant"
  } else {
    curve_type <- "innovation-dominant"
  }
  
  # Peak time
  peak_time <- years[1] - log(params["p"] / params["q"]) / (params["p"] + params["q"])
  
  list(
    status = "success",
    model = "bass",
    params = list(
      m = params["m"],    # Market potential
      p = params["p"],    # Innovation coefficient
      q = params["q"]     # Imitation coefficient
    ),
    fitted = fitted_vals,
    residuals = residuals_val,
    peak_time = peak_time,
    curve_type = curve_type,
    cumsum = cumulative,
    years = years,
    AIC = AIC(bass_fit),
    BIC = BIC(bass_fit),
    R_squared = 1 - sum(residuals_val^2) / sum((cumulative - mean(cumulative))^2)
  )
}

#' Fit Gompertz growth model
#'
#' @param years Vector of years
#' @param articles Vector of article counts
#' @return List with model parameters and predictions
#' @export
fit_gompertz_model <- function(years, articles) {
  n <- length(articles)
  if (n < 4) {
    return(list(status = "error: insufficient data", model = "gompertz"))
  }
  
  # Gompertz: y(t) = K * exp(-exp(a - b*t))
  # Asymmetric S-curve, inflection at y = K/e
  
  cumulative <- cumsum(articles)
  t <- years - years[1]
  
  # Initial estimates
  K_init <- max(cumulative) * 1.5
  a_init <- log(log(K_init / cumulative[1]))
  b_init <- 0.1
  
  gomp_fit <- tryCatch({
    nls(cumulative ~ K * exp(-exp(a - b * t)),
        start = list(K = K_init, a = a_init, b = b_init),
        control = nls.control(maxiter = 1000, warnOnly = TRUE))
  }, error = function(e) NULL)
  
  if (is.null(gomp_fit)) {
    # Simplified fitting
    params <- fit_gompertz_simple(years, cumulative)
  } else {
    params <- coef(gomp_fit)
    fitted_vals <- predict(gomp_fit)
    residuals_val <- cumulative - fitted_vals
  }
  
  if (is.null(gomp_fit)) {
    fitted_vals <- params$K * exp(-exp(params$a - params$b * t))
    residuals_val <- cumulative - fitted_vals
  }
  
  # Inflection point
  inflection_t <- params["a"] / params["b"]
  inflection_y <- params["K"] / exp(1)
  
  list(
    status = "success",
    model = "gompertz",
    params = list(
      K = params["K"],    # Carrying capacity
      a = params["a"],    # Initial growth rate
      b = params["b"]     # Growth rate parameter
    ),
    fitted = fitted_vals,
    residuals = residuals_val,
    inflection_t = years[1] + inflection_t,
    inflection_y = inflection_y,
    years = years,
    cumsum = cumulative,
    AIC = if (!is.null(gomp_fit)) AIC(gomp_fit) else NA,
    BIC = if (!is.null(gomp_fit)) BIC(gomp_fit) else NA,
    R_squared = 1 - sum(residuals_val^2) / sum((cumulative - mean(cumulative))^2)
  )
}

#' Simple Gompertz fitting fallback
#' @keywords internal
fit_gompertz_simple <- function(years, cumulative) {
  t <- years - years[1]
  
  K <- max(cumulative) * 1.5
  
  # Linearize: ln(ln(K/y)) = a - b*t
  y_valid <- cumulative[cumulative >0 & cumulative < K]
  t_valid <- t[cumulative > 0 & cumulative < K]
  
  if (length(y_valid) < 3) {
    return(c(K = K, a = 1, b = 0.1))
  }
  
  y_trans <- log(log(K / y_valid))
  
  fit <- lm(y_trans ~ t_valid)
  
  c(K = K, a = coef(fit)[1], b = -coef(fit)[2])
}

#' Fit Weibull growth model
#'
#' @param years Vector of years
#' @param articles Vector of article counts
#' @return List with model parameters and predictions
#' @export
fit_weibull_model <- function(years, articles) {
  n <- length(articles)
  if (n < 4) {
    return(list(status = "error: insufficient data", model = "weibull"))
  }
  
  # Weibull cumulative: F(t) = 1 - exp(-(t/scale)^shape)
  # For growth: y(t) = K * (1 - exp(-(t/scale)^shape))
  
  cumulative <- cumsum(articles)
  t <- years - years[1]
  
  K_init <- max(cumulative) * 1.5
  scale_init <- max(t)
  shape_init <- 2
  
  weib_fit <- tryCatch({
    nls(cumulative ~ K * (1 - exp(-(t/scale)^shape)),
        start = list(K = K_init, scale = scale_init, shape = shape_init),
        control = nls.control(maxiter = 1000, warnOnly = TRUE))
  }, error = function(e) NULL)
  
  if (is.null(weib_fit)) {
    # Simple estimate
    params <- c(K = K_init, scale = scale_init, shape = shape_init)
    fitted_vals <- K_init * (1 - exp(-(t/scale_init)^shape_init))
    residuals_val <- cumulative - fitted_vals
  } else {
    params <- coef(weib_fit)
    fitted_vals <- predict(weib_fit)
    residuals_val <- cumulative - fitted_vals
  }
  
  list(
    status = "success",
    model = "weibull",
    params = list(
      K = params["K"],
      scale = params["scale"],
      shape = params["shape"]
    ),
    fitted = fitted_vals,
    residuals = residuals_val,
    years = years,
    cumsum = cumulative,
    AIC = if (!is.null(weib_fit)) AIC(weib_fit) else NA,
    BIC = if (!is.null(weib_fit)) BIC(weib_fit) else NA,
    R_squared = 1 - sum(residuals_val^2) / sum((cumulative - mean(cumulative))^2)
  )
}

#' Fit Richards growth model (generalized logistic)
#'
#' @param years Vector of years
#' @param articles Vector of article counts
#' @return List with model parameters and predictions
#' @export
fit_richards_model <- function(years, articles) {
  n <- length(articles)
  if (n < 5) {
    return(list(status = "error: insufficient data", model = "richards"))
  }
  
  # Richards: y(t) = K / (1 + exp(-r*(t-t0)))^(1/v)
  # When v=1, reduces to logistic
  
  cumulative <- cumsum(articles)
  t <- years - years[1]
  
  K_init <- max(cumulative) * 1.5
  r_init <- 0.1
  t0_init <- t[which.max(articles)]
  v_init <- 1
  
  rich_fit <- tryCatch({
    nls(cumulative ~ K / (1 + exp(-r * (t - t0)))^(1/v),
        start = list(K = K_init, r = r_init, t0 = t0_init, v = v_init),
        control = nls.control(maxiter = 1000, warnOnly = TRUE))
  }, error = function(e) NULL)
  
  if (is.null(rich_fit)) {
    params <- c(K = K_init, r = r_init, t0 = t0_init, v = v_init)
    fitted_vals <- K_init / (1 + exp(-r_init * (t - t0_init)))^(1/v_init)
    residuals_val <- cumulative - fitted_vals
  } else {
    params <- coef(rich_fit)
    fitted_vals <- predict(rich_fit)
    residuals_val <- cumulative - fitted_vals
  }
  
  # Inflection point
  inflection_t <- params["t0"] + log(params["v"]) / params["r"]
  
  list(
    status = "success",
    model = "richards",
    params = list(
      K = params["K"],      # Carrying capacity
      r = params["r"],      # Growth rate
      t0 = params["t0"],    # Inflection time parameter
      v = params["v"]       # Shape parameter
    ),
    fitted = fitted_vals,
    residuals = residuals_val,
    inflection_t = years[1] + inflection_t,
    years = years,
    cumsum = cumulative,
    AIC = if (!is.null(rich_fit)) AIC(rich_fit) else NA,
    BIC = if (!is.null(rich_fit)) BIC(rich_fit) else NA,
    R_squared = 1 - sum(residuals_val^2) / sum((cumulative - mean(cumulative))^2),
    is_asymmetric = params["v"] != 1
  )
}

#' Fit von Bertalanffy growth model
#'
#' @param years Vector of years
#' @param articles Vector of article counts
#' @return List with model parameters and predictions
#' @export
fit_von_bertalanffy_model <- function(years, articles) {
  n <- length(articles)
  if (n < 4) {
    return(list(status = "error: insufficient data", model = "von_bertalanffy"))
  }
  
  # Von Bertalanffy: L(t) = L_inf * (1 - exp(-k*(t - t0)))
  # Used for biological growth, applicable to knowledge growth
  
  cumulative <- cumsum(articles)
  t <- years - years[1]
  
  L_inf_init <- max(cumulative) * 1.5
  k_init <- 0.1
  t0_init <- -1
  
  vb_fit <- tryCatch({
    nls(cumulative ~ L_inf * (1 - exp(-k * (t - t0))),
        start = list(L_inf = L_inf_init, k = k_init, t0 = t0_init),
        control = nls.control(maxiter = 1000, warnOnly = TRUE))
  }, error = function(e) NULL)
  
  if (is.null(vb_fit)) {
    params <- c(L_inf = L_inf_init, k = k_init, t0 = t0_init)
    fitted_vals <- L_inf_init * (1 - exp(-k_init * (t - t0_init)))
    residuals_val <- cumulative - fitted_vals
  } else {
    params <- coef(vb_fit)
    fitted_vals <- predict(vb_fit)
    residuals_val <- cumulative - fitted_vals
  }
  
  list(
    status = "success",
    model = "von_bertalanffy",
    params = list(
      L_inf = params["L_inf"],  # Asymptotic maximum
      k = params["k"],         # Growth coefficient
      t0 = params["t0"]        # Theoretical age at size zero
    ),
    fitted = fitted_vals,
    residuals = residuals_val,
    years = years,
    cumsum = cumulative,
    AIC = if (!is.null(vb_fit)) AIC(vb_fit) else NA,
    BIC = if (!is.null(vb_fit)) BIC(vb_fit) else NA,
    R_squared = 1 - sum(residuals_val^2) / sum((cumulative - mean(cumulative))^2)
  )
}

#' Fit Morgan-Mercer-Flodin model
#'
#' @param years Vector of years
#' @param articles Vector of article counts
#' @return List with model parameters and predictions
#' @export
fit_mmf_model <- function(years, articles) {
  n <- length(articles)
  if (n < 5) {
    return(list(status = "error: insufficient data", model = "mmf"))
  }
  
  # MMF: y(t) = (a * t^d + c) / (b + t^d)
  # Flexible sigmoid with parameter d controlling shape
  
  cumulative <- cumsum(articles)
  t <- years - years[1] + 1  # Avoid t=0
  
  a_init <- max(cumulative)
  b_init <- 1
  c_init <- cumulative[1]
  d_init <- 2
  
  mmf_fit <- tryCatch({
    nls(cumulative ~ (a * t^d + c) / (b + t^d),
        start = list(a = a_init, b = b_init, c = c_init, d = d_init),
        control = nls.control(maxiter = 1000, warnOnly = TRUE))
  }, error = function(e) NULL)
  
  if (is.null(mmf_fit)) {
    params <- c(a = a_init, b = b_init, c = c_init, d = d_init)
    fitted_vals <- (a_init * t^d_init + c_init) / (b_init + t^d_init)
    residuals_val <- cumulative - fitted_vals
  } else {
    params <- coef(mmf_fit)
    fitted_vals <- predict(mmf_fit)
    residuals_val <- cumulative - fitted_vals
  }
  
  list(
    status = "success",
    model = "mmf",
    params = list(
      a = params["a"],
      b = params["b"],
      c = params["c"],
      d = params["d"]
    ),
    fitted = fitted_vals,
    residuals = residuals_val,
    years = years,
    cumsum = cumulative,
    AIC = if (!is.null(mmf_fit)) AIC(mmf_fit) else NA,
    BIC = if (!is.null(mmf_fit)) BIC(mmf_fit) else NA,
    R_squared = 1 - sum(residuals_val^2) / sum((cumulative - mean(cumulative))^2)
  )
}

#' Compare all growth models
#'
#' @param years Vector of years
#' @param articles Vector of article counts
#' @return List with all model fits and comparison
#' @export
compare_growth_models <- function(years, articles) {
  if (is.list(years) && missing(articles)) {
    models <- years
    comparison <- data.frame(
      model = names(models),
      AIC = vapply(models, function(m) if (is.list(m)) m$AIC %||% NA_real_ else NA_real_, numeric(1)),
      BIC = vapply(models, function(m) if (is.list(m)) m$BIC %||% NA_real_ else NA_real_, numeric(1)),
      R_squared = vapply(models, function(m) if (is.list(m)) m$R_squared %||% NA_real_ else NA_real_, numeric(1)),
      stringsAsFactors = FALSE
    )
    return(comparison[!is.na(comparison$AIC), , drop = FALSE])
  }

  n <- length(articles)
  if (n < 5) {
    return(list(status = "error: insufficient data"))
  }
  
  models <- list()
  
  models$bass <- fit_bass_model(years, articles)
  models$gompertz <- fit_gompertz_model(years, articles)
  models$weibull <- fit_weibull_model(years, articles)
  models$richards <- fit_richards_model(years, articles)
  models$von_bertalanffy <- fit_von_bertalanffy_model(years, articles)
  models$mmf <- fit_mmf_model(years, articles)
  
  # Extract AIC/BIC/R² for comparison
  comparison <- data.frame(
    model = names(models),
    AIC = sapply(models, function(m) if(is.list(m)) m$AIC else NA),
    BIC = sapply(models, function(m) if(is.list(m)) m$BIC else NA),
    R_squared = sapply(models, function(m) if(is.list(m)) m$R_squared else NA),
    stringsAsFactors = FALSE
  )
  
  # Remove failed models
  comparison <- comparison[!is.na(comparison$AIC), ]
  
  if (nrow(comparison) == 0) {
    return(list(
      status = "error: all models failed to converge",
      models = models,
      comparison = data.frame()
    ))
  }
  
  comparison <- comparison[order(comparison$AIC), ]
  comparison$delta_AIC <- comparison$AIC - min(comparison$AIC)
  comparison$weight <- exp(-0.5 * comparison$delta_AIC)
  comparison$weight <- comparison$weight / sum(comparison$weight)
  
  best_model <- comparison$model[1]
  
  list(
    status = "success",
    models = models,
    comparison = comparison,
    best_model = best_model,
    best_fit = models[[best_model]],
    n_models = nrow(comparison)
  )
}

#' Forecast using growth model
#'
#' @param model_fit Output from a growth model fit
#' @param years_new Years to forecast
#' @return Forecasted values
#' @export
forecast_growth_model <- function(model_fit, years_new) {
  if (is.null(model_fit) || model_fit$status != "success") {
    return(rep(NA, length(years_new)))
  }
  
  # Calculate t relative to first observed year
  t_new <- years_new - model_fit$years[1]
  
  # Store baseline offset: last observed cumulative value
  # This ensures forecasts start from where data ends, not from zero
  baseline_cumsum <- model_fit$cumsum[length(model_fit$cumsum)]
  
  if (model_fit$model == "bass") {
    p <- model_fit$params$p
    q <- model_fit$params$q
    m <- model_fit$params$m
    # Bass cumulative formula: N(t) = m * (1 - exp(-(p+q)*t)) / (1 + (q/p)*exp(-(p+q)*t))
    forecast_cumsum <- m * (1 - exp(-(p + q) * t_new)) / (1 + (q / p) * exp(-(p + q) * t_new))
    # Add baseline to get absolute cumulative values
    forecast_cumsum <- baseline_cumsum + forecast_cumsum
    # Convert cumulative to period values
    forecast_vals <- c(forecast_cumsum[1], diff(forecast_cumsum))
    # For first forecast, also add the baseline
    if (length(forecast_vals) > 0 && t_new[1] <= 1) {
      forecast_vals[1] <- model_fit$fitted[length(model_fit$fitted)]
    }
  } else if (model_fit$model == "gompertz") {
    K <- model_fit$params$K
    a <- model_fit$params$a
    b <- model_fit$params$b
    forecast_cumsum <- K * exp(-exp(a - b * t_new))
    forecast_cumsum <- baseline_cumsum + forecast_cumsum
    forecast_vals <- c(forecast_cumsum[1], diff(forecast_cumsum))
  } else if (model_fit$model == "weibull") {
    K <- model_fit$params$K
    scale <- model_fit$params$scale
    shape <- model_fit$params$shape
    forecast_cumsum <- K * (1 - exp(-(t_new/scale)^shape))
    forecast_cumsum <- baseline_cumsum + forecast_cumsum
    forecast_vals <- c(forecast_cumsum[1], diff(forecast_cumsum))
  } else if (model_fit$model == "richards") {
    K <- model_fit$params$K
    r <- model_fit$params$r
    t0 <- model_fit$params$t0
    v <- model_fit$params$v
    forecast_cumsum <- K / (1 + exp(-r * (t_new - t0)))^(1/v)
    forecast_cumsum <- baseline_cumsum + forecast_cumsum
    forecast_vals <- c(forecast_cumsum[1], diff(forecast_cumsum))
  } else if (model_fit$model == "von_bertalanffy") {
    L_inf <- model_fit$params$L_inf
    k <- model_fit$params$k
    t0 <- model_fit$params$t0
    forecast_cumsum <- L_inf * (1 - exp(-k * (t_new - t0)))
    forecast_cumsum <- baseline_cumsum + forecast_cumsum
    forecast_vals <- c(forecast_cumsum[1], diff(forecast_cumsum))
  } else if (model_fit$model == "mmf") {
    a <- model_fit$params$a
    b<- model_fit$params$b
    c <- model_fit$params$c
    d <- model_fit$params$d
    t_new_shifted <- t_new + 1
    forecast_cumsum <- (a * t_new_shifted^d + c) / (b + t_new_shifted^d)
    forecast_cumsum <- baseline_cumsum + forecast_cumsum
    forecast_vals <- c(forecast_cumsum[1], diff(forecast_cumsum))
  } else {
    return(rep(NA, length(years_new)))
  }
  
  # Ensure non-negative values
  forecast_vals <- pmax(0, forecast_vals)
  
  list(
    years = years_new,
    cumulative = forecast_cumsum,
    values = forecast_vals,
    model = model_fit$model
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m2/compute/m2_compute_growth_models.R

# >>> BEGIN FILE: R/module_m2/compute/m2_compute_harmonics.R
# ============================================================================
# m2_compute_harmonics.R - Harmonic Analysis on Data and Residuals
# ============================================================================
# Performs spectral analysis on:
# 1. Underlying data (raw time series)
# 2. Residuals (error between model and data)
# Identifies hidden periodicities and model adequacy

#' Compute harmonic analysis for M2
#'
#' @param input Time series data (Year, Articles)
#' @param regression_result Output from compute_m2_regression (optional)
#' @param config Configuration list
#' @return List with harmonic analysis for data and residuals
#' @export
compute_m2_harmonics <- function(input, regression_result = NULL, config = biblio_config()) {
  if (!is.data.frame(input) || nrow(input) < 10) {
    return(list(
      status = "error",
      data_harmonics = list(),
      residual_harmonics = list()
    ))
  }
  
  year_col <- if ("Year" %in% names(input)) "Year" else names(input)[1]
  articles_col <- if ("Articles" %in% names(input)) "Articles" else names(input)[2]
  
  years <- as.numeric(input[[year_col]])
  articles <- as.numeric(input[[articles_col]])
  
  n <- length(articles)
  dt <- mean(diff(years))
  
  # =========================================
  # 1. Harmonic Analysis on Underlying Data
  # =========================================
  data_harmonics <- analyze_data_harmonics(years, articles, dt)
  
  # =========================================
  # 2. Harmonic Analysis on Residuals
  # =========================================
  residual_harmonics <- list()
  
  if (!is.null(regression_result) && !is.null(regression_result$best_model)) {
    predicted <- regression_result$best_model$predictions
    
    if (!is.null(predicted) && length(predicted) == length(articles)) {
      residuals <- articles - predicted
      residual_harmonics <- analyze_residual_harmonics(years, residuals, dt)
    }
  }
  
  # =========================================
  # 3. Cross-Analysis: Compare Data vs Residual Harmonics
  # =========================================
  cross_analysis <- compare_harmonics(data_harmonics, residual_harmonics)
  r_squared_table <- m2_build_harmonic_r2_table(data_harmonics$harmonic_models)
  
  # =========================================
  # 4. Wavelet Analysis
  # =========================================
  wavelet_result <- tryCatch({
    if (requireNamespace("WaveletComp", quietly = TRUE)) {
      WaveletComp::analyze.wavelet(
        my.data = data.frame(Time = years, Signal = articles),
        my.series = "Signal",
        verbose = FALSE
      )
    } else {
      NULL
    }
  }, error = function(e) NULL)
  
  wavelet_serialized <- if (!is.null(wavelet_result)) {
    list(
      time = wavelet_result$axis.1,
      period = wavelet_result$axis.2,
      power = wavelet_result$Power,
      dominant_period = find_dominant_wavelet_period(wavelet_result)
    )
  } else {
    list()
  }
  
  # =========================================
  # 5. Lomb-Scargle Periodogram
  # =========================================
  lomb_result <- tryCatch({
    if (requireNamespace("lomb", quietly = TRUE)) {
      lomb::lsp(articles, times = years, type = "period", ofac = 10, plot = FALSE)
    } else {
      NULL
    }
  }, error = function(e) NULL)
  
  lomb_serialized <- if (!is.null(lomb_result)) {
    list(
      frequency = lomb_result$freq,
      power = lomb_result$power,
      peak_period = lomb_result$peak.at[1],
      peak_power = lomb_result$peak.at[2],
      type = lomb_result$type
    )
  } else {
    list()
  }
  
  # =========================================
  # 6. Summary
  # =========================================
  summary <- list(
    data_dominant_period = data_harmonics$dominant_period,
    data_top_periods = if (!is.null(data_harmonics$top_periods)) 
      data_harmonics$top_periods$period[1:min(3, nrow(data_harmonics$top_periods))] else NA,
    residual_dominant_period = residual_harmonics$dominant_period,
    residual_variance_explained = residual_harmonics$variance_explained %||% NA,
    data_variance_explained = data_harmonics$variance_explained %||% NA,
    has_periodic_residuals = !is.null(residual_harmonics$dominant_period) && 
                            residual_harmonics$dominant_period > 0,
    wavelet_dominant_period = wavelet_serialized$dominant_period,
    lomb_peak_period = lomb_serialized$peak_period,
    interpretation = interpret_harmonic_results(data_harmonics, residual_harmonics)
  )
  
  list(
    status = "success",
    data_harmonics = data_harmonics,
    residual_harmonics = residual_harmonics,
    cross_analysis = cross_analysis,
    r_squared_table = r_squared_table,
    wavelet = wavelet_serialized,
    lomb = lomb_serialized,
    summary = summary
  )
}

#' Perform FFT and return spectral components
#' @export
m2_perform_fft <- function(y, dt = 1) {
  y <- suppressWarnings(as.numeric(y))
  y <- y[is.finite(y)]

  if (length(y) == 0) {
    return(list(
      frequencies = numeric(),
      magnitude = numeric(),
      power = numeric(),
      phase = numeric(),
      status = "error: no valid data"
    ))
  }

  n <- length(y)
  fft_result <- fft(y)
  frequencies <- (0:(floor(n / 2))) / (n * dt)
  magnitude <- Mod(fft_result[seq_along(frequencies)])
  phase <- Arg(fft_result[seq_along(frequencies)])

  list(
    frequencies = frequencies,
    magnitude = magnitude,
    power = magnitude^2,
    phase = phase,
    status = "success"
  )
}

# ============================================================================
# Data Harmonic Analysis
# ============================================================================

analyze_data_harmonics <- function(years, articles, dt) {
  n <- length(articles)
  
  # FFT analysis
  fft_result <- fft(articles)
  frequencies <- (0:(floor(n / 2))) / (n * dt)
  magnitude <- Mod(fft_result[1:length(frequencies)])
  phase <- Arg(fft_result[1:length(frequencies)])
  
  # Find peak frequencies
  power <- magnitude^2
  peak_idx <- order(-power)[1:min(10, length(power))]
  peak_idx <- peak_idx[is.finite(frequencies[peak_idx]) & frequencies[peak_idx] > 0]
  
  valid_freq_idx <- which(is.finite(frequencies[-1]) & frequencies[-1] > 0)
  dominant_idx <- if (length(valid_freq_idx) > 0) {
    which.max(power[valid_freq_idx + 1]) -> dp
    valid_freq_idx[dp]
  } else {
    1
  }
  dominant_freq <- frequencies[dominant_idx]
  dominant_period <- if (is.finite(dominant_freq) && dominant_freq > 0) 1 / dominant_freq else NA
  
  # Spectral density
  spectrum_df <- data.frame(
    frequency = frequencies,
    period = ifelse(frequencies > 0, 1 / frequencies, Inf),
    magnitude = magnitude,
    power = power,
    normalized_power = power / sum(power),
    variance_explained = power / sum(power)
  )
  
  # Top periods
  top_periods <- spectrum_df[spectrum_df$frequency > 0, ]
  top_periods <- top_periods[order(-top_periods$power), ]
  top_periods <- top_periods[1:min(10, nrow(top_periods)), ]
  top_periods$rank <- seq_len(nrow(top_periods))
  
  # Harmonic regression
  harmonic_models <- fit_harmonic_models(years, articles, frequencies[2:min(5, length(frequencies))])
  
  # Variance explained by top 3 harmonics
  variance_explained <- sum(power[1:min(3, length(power))]) / sum(power)
  
  list(
    fft = list(
      frequencies = frequencies,
      magnitude = magnitude,
      phase = phase,
      power = power
    ),
    spectrum = spectrum_df,
    top_periods = top_periods,
    dominant_period = dominant_period,
    dominant_frequency = dominant_freq,
    harmonic_models = harmonic_models,
    variance_explained = variance_explained,
    interpretation = sprintf(
      "Dominant period: %.1f years, Variance explained by top 3 harmonics: %.1f%%",
      dominant_period, variance_explained * 100
    )
  )
}

# ============================================================================
# Residual Harmonic Analysis
# ============================================================================

analyze_residual_harmonics <- function(years, residuals, dt) {
  n <- length(residuals)
  
  # Remove mean and trend from residuals
  residuals_detrended <- residuals - mean(residuals)
  
  # FFT analysis on residuals
  fft_result <- fft(residuals_detrended)
  frequencies <- (0:(floor(n / 2))) / (n * dt)
  magnitude <- Mod(fft_result[1:length(frequencies)])
  power <- magnitude^2
  
  # Find significant peaks in residual spectrum
  peak_idx <- order(-power)[1:min(10, length(power))]
  peak_idx <- peak_idx[frequencies[peak_idx] > 0]
  
  # Check if peaks are significant (above noise level)
  noise_level <- quantile(power, 0.95)
  significant_peaks <- peak_idx[power[peak_idx] > 2 * noise_level]
  
  if (length(significant_peaks) > 0) {
    dominant_idx <- significant_peaks[1]
    dominant_freq <- frequencies[dominant_idx]
    dominant_period <- if (dominant_freq > 0) 1 / dominant_freq else NA
  } else {
    dominant_idx <- which.max(power[2:floor(n/2)]) + 1
    dominant_freq <- frequencies[dominant_idx]
    dominant_period <- if (dominant_freq > 0) 1 / dominant_freq else NA
  }
  
  # Spectral density
  spectrum_df <- data.frame(
    frequency = frequencies,
    period = ifelse(frequencies > 0, 1 / frequencies, Inf),
    magnitude = magnitude,
    power = power,
    normalized_power = power / sum(power),
    variance_explained = power / sum(power)
  )
  
  # Top periods in residuals
  top_periods <- spectrum_df[spectrum_df$frequency > 0, ]
  top_periods <- top_periods[order(-top_periods$power), ]
  top_periods <- top_periods[1:min(5, nrow(top_periods)), ]
  top_periods$rank <- seq_len(nrow(top_periods))
  
  # Variance explained by harmonics in residuals (should be low for good model)
  variance_explained <- sum(power[1:min(3, length(power))]) / sum(power)
  
  # Periodicity test
  periodicity_test <- test_residual_periodicity(residuals, years)
  
  # Interpretation
  has_strong_periodicity <- variance_explained > 0.3
  
  interpretation <- if (has_strong_periodicity) {
    sprintf(
      "WARNING: Strong periodicity in residuals (period = %.1f years). Model may be misspecified.",
      dominant_period
    )
  } else {
    sprintf(
      "Residual harmonic analysis: No strong periodicity detected. Dominant period: %.1f years.",
      dominant_period
    )
  }
  
  list(
    fft = list(
      frequencies = frequencies,
      magnitude = magnitude,
      power = power
    ),
    spectrum = spectrum_df,
    top_periods = top_periods,
    dominant_period = dominant_period,
    dominant_frequency = dominant_freq,
    variance_explained = variance_explained,
    has_periodicity = has_strong_periodicity,
    periodicity_test = periodicity_test,
    interpretation = interpretation
  )
}

# ============================================================================
# Fit Harmonic Models
# ============================================================================

fit_harmonic_models <- function(years, articles, frequencies) {
  models <- list()
  
  for (freq in frequencies) {
    if (freq <= 0) next
    
    fit <- tryCatch({
      lm(articles ~ sin(2 * pi * freq * years) + cos(2 * pi * freq * years))
    }, error = function(e) NULL)
    
    if (!is.null(fit)) {
      ss_res <- sum(residuals(fit)^2)
      ss_tot <- sum((articles - mean(articles))^2)
      r2 <- 1 - ss_res / ss_tot
      
      models[[as.character(round(freq, 6))]] <- list(
        frequency = freq,
        period = 1 / freq,
        r2 = r2,
        coefficients = coef(fit),
        amplitude = sqrt(coef(fit)[2]^2 + coef(fit)[3]^2),
        phase = atan2(coef(fit)[3], coef(fit)[2])
      )
    }
  }
  
  models
}

# ============================================================================
# Test Residual Periodicity
# ============================================================================

test_residual_periodicity <- function(residuals, years) {
  n <- length(residuals)
  if (n < 10) {
    return(list(
      has_periodicity = NA,
      test = "insufficient_data",
      p_value = NA
    ))
  }
  
  # Fisher's test for periodicity
  fft_result <- fft(residuals - mean(residuals))
  power <- Mod(fft_result[1:(n %/% 2 + 1)])^2
  
  # Fisher's g statistic
  g_stat <- max(power) / sum(power)
  
  # Exact/Semi-exact p-value calculation for Fisher's G test
  # For small n, use exact formula; for large n, approximation is acceptable
  if (n <= 100) {
    # Use more accurate formula for small samples
    # p-value = n * (1 - g)^(n-1) for the basic form
    # But this is still approximation; exact requires special functions
    p_value <- n * exp(-n * g_stat / 2)
    # Apply correction for better accuracy
    p_value <- p_value * (1 + (n * g_stat - 1) / 6)
  } else {
    # Original approximation for large samples
    p_value <- n * exp(-n * g_stat / 2)
  }
  p_value <- min(1, max(0, p_value))
  
  has_periodicity <- p_value < 0.05
  
  list(
    has_periodicity = has_periodicity,
    test = "fisher_g",
    g_statistic = g_stat,
    p_value = p_value,
    interpretation = if (has_periodicity) {
      "Significant periodicity detected in residuals (Fisher's g test p < 0.05)"
    } else {
      "No significant periodicity in residuals"
    }
  )
}

# ============================================================================
# Compare Data vs Residual Harmonics
# ============================================================================

compare_harmonics <- function(data_harmonics, residual_harmonics) {
  if (is.null(data_harmonics) || is.null(residual_harmonics)) {
    return(list(
      interpretation = "Insufficient data for comparison"
    ))
  }
  
  data_period <- m2_scalar_or_na(data_harmonics$dominant_period)
  residual_period <- m2_scalar_or_na(residual_harmonics$dominant_period)
  
  # Check if residual periodicity overlaps with data periodicity
  period_overlap <- FALSE
  if (is.finite(data_period) && is.finite(residual_period) && data_period > 0) {
    period_overlap <- abs(data_period - residual_period) / data_period < 0.2
  }
  
  data_var <- m2_scalar_or_na(data_harmonics$variance_explained %||% NA_real_)
  residual_var <- m2_scalar_or_na(residual_harmonics$variance_explained %||% NA_real_)
  
  list(
    data_dominant_period = data_period,
    residual_dominant_period = residual_period,
    period_overlap = period_overlap,
    data_variance_explained = data_var,
    residual_variance_explained = residual_var,
    ratio = if (!is.na(residual_var) && !is.na(data_var) && data_var > 0) 
      residual_var / data_var else NA,
    interpretation = if (period_overlap && residual_var > 0.2) {
      sprintf(
        "WARNING: Residual periodicity (%.1f years) overlaps with data periodicity (%.1f years). Model may not capture all structure.",
        residual_period, data_period
      )
    } else if (!is.na(residual_var) && residual_var > 0.3) {
      "Unexplained periodic structure remains in residuals."
    } else {
      "Residual harmonics do not overlap significantly with data harmonics. Model captures main structure."
    }
  )
}

# ============================================================================
# Find Dominant Wavelet Period
# ============================================================================

find_dominant_wavelet_period <- function(wavelet_result) {
  if (is.null(wavelet_result) || is.null(wavelet_result$Power)) {
    return(NA)
  }
  
  mean_power <- rowMeans(wavelet_result$Power)
  dominant_idx <- which.max(mean_power)
  
  if (dominant_idx <= length(wavelet_result$axis.2)) {
    return(wavelet_result$axis.2[dominant_idx])
  }
  
  NA
}

# ============================================================================
# Interpret Results
# ============================================================================

interpret_harmonic_results <- function(data_harmonics, residual_harmonics) {
  data_period <- m2_scalar_or_na(data_harmonics$dominant_period)
  residual_period <- m2_scalar_or_na(residual_harmonics$dominant_period)
  residual_var <- m2_scalar_or_na(residual_harmonics$variance_explained %||% 0)
  
  if (!is.finite(data_period)) {
    return("Could not identify dominant period in data.")
  }
  
  if (!is.na(residual_period) && residual_var > 0.3) {
    return(sprintf(
      "Data has %.1f-year cycle. Residuals contain unexplained %.1f-year cycle (%.1f%% variance). Consider adding periodic terms to model.",
      data_period, residual_period, residual_var * 100
    ))
  }
  
  if (!is.na(residual_period)) {
    return(sprintf(
      "Data has %.1f-year dominant cycle. Residuals show weak %.1f-year cycle (%.1f%% variance). Model captures main periodic structure.",
      data_period, residual_period, residual_var * 100
    ))
  }
  
  sprintf(
    "Data has %.1f-year dominant cycle. No significant periodicity in residuals. Model adequately captures cyclical structure.",
    data_period
  )
}

#' Build a harmonic regression R-squared table
#' @keywords internal
m2_build_harmonic_r2_table <- function(harmonic_models) {
  if (!is.list(harmonic_models) || length(harmonic_models) == 0) {
    return(data.frame(Frequency = numeric(), Period = numeric(), R2 = numeric()))
  }

  rows <- lapply(harmonic_models, function(model) {
    data.frame(
      Frequency = m2_scalar_or_na(model$frequency),
      Period = m2_scalar_or_na(model$period),
      R2 = max(0, min(1, m2_scalar_or_na(model$r2))),
      stringsAsFactors = FALSE
    )
  })

  do.call(rbind, rows)
}

#' Coerce candidate scalar values to numeric NA-safe form
#' @keywords internal
m2_scalar_or_na <- function(x) {
  if (length(x) != 1L) {
    return(NA_real_)
  }

  value <- suppressWarnings(as.numeric(x))
  if (length(value) != 1L || !is.finite(value)) {
    return(NA_real_)
  }

  value
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
