      error = function(e) NULL
    )
    
    sv <- m2_get_start_values("Hill", data)
    models$Hill <- tryCatch(
      nls(Articles ~ m2_hill(Year, K, K50, n), data = data,
          start = list(K = sv$K, K50 = sv$K50, n = sv$n),
