# ============================================================================
# module_m2/m2_run.R - Orchestrator for M2
# ============================================================================

#' Run M2 module (Annual Production Analysis)
#'
#' @param input A data frame with Year and Articles columns.
#' @param config A configuration list.
#' @param export Logical. If TRUE, exports artifacts to disk.
#' @export
run_m2 <- function(input, config = biblio_config(), export = TRUE) {
  config <- merge_biblio_config(config)
  input <- m2_normalize_input(input)

  # 1. Validate
  validation <- validate_m2_input(input, config)
  if (!validation$ok && config$validate_strict) {
    cli::cli_abort("M2 validation failed: {paste(validation$missing_columns, collapse = ', ')}")
  }

  # 2. Compute all metrics
  data <- list(
    eda         = compute_m2_eda(input, config),
    regression  = compute_m2_regression(input, config),
    ridge       = compute_m2_ridge(input, config),
    changepoint = compute_m2_changepoint(input, config),
    stl         = compute_m2_stl(input, config),
    hypotheses  = compute_m2_hypotheses(input, config),
    forecasting = compute_m2_forecasting(input, config),
    advanced_ts = compute_m2_advanced_ts(input, config),
    growth_models = compute_m2_growth_models_wrapper(input, config)
  )
  
  # 2b. Compute harmonics AFTER regression (to enable residual analysis)
  data$harmonics <- compute_m2_harmonics(input, data$regression, config)
  
  # 2c. Compute residual analysis (requires regression)
  data$residual_analysis <- compute_m2_residual_analysis(input, data$regression, config)

  # 2d. Build unified model registry and diagnostics
  data$model_registry <- m2_build_model_registry(data, input, config)
  data$diagnostics <- compute_m2_diagnostics(
    input,
    data$model_registry,
    config,
    changepoint_result = data$changepoint,
    forecasting_result = data$forecasting
  )

  # 3. Build result
  result <- new_module_result(
    module_id   = "m2",
    module_name = "Annual Production",
    status      = if (validation$ok) "success" else "warning",
    inputs      = list(n_rows = validation$n_rows, n_cols = validation$n_cols),
    data        = data,
    diagnostics = list(warnings = character(), checks = list(validation = validation), notes = character())
  )

  # 4. Render
  plots <- list(
    eda        = render_m2_eda(data$eda, config),
    regression = render_m2_regression(data$regression, config),
    harmonics  = render_m2_harmonics(data$harmonics, config),
    residual_analysis = render_m2_residual_analysis(data$residual_analysis, config),
    forecasting = render_m2_forecasting(data$forecasting, config),
    wavelet    = if (!is.null(data$harmonics) && !is.null(data$harmonics$wavelet)) render_m2_wavelet(data$harmonics$wavelet, config) else list(plots = list()),
    advanced_ts = render_m2_advanced_ts(data$advanced_ts, config),
    growth_models = render_m2_growth_models(data$growth_models, config),
    diagnostics = render_m2_diagnostics(data$diagnostics, config)
  )
  result$artifacts$plots <- plots

  # 5. Tables
  tables <- list(
    eda        = build_m2_eda_table(data$eda, config),
    regression = build_m2_regression_table(data$regression, config),
    forecasting = build_m2_forecasting_table(data$forecasting, config),
    growth_models = build_m2_growth_models_table(data$growth_models, config),
    hypotheses = build_m2_hypotheses_table(data$hypotheses, config),
    diagnostics = build_m2_diagnostics_table(data$diagnostics, config)
  )
  result$artifacts$tables <- tables

  # 5b. Report
  report <- build_m2_report(data, config)
  result <- attach_report_to_result(result, report)

  # 6. Export
  if (export) {
    exported <- export_m2(result, config)
    manifest <- build_m2_manifest(result, exported, config)
    result <- attach_manifest_to_result(result, manifest)
  }

  result
}

#' Normalize supported M2 input column variants
#' @keywords internal
m2_normalize_input <- function(input) {
  if (!is.data.frame(input)) {
    return(input)
  }

  output <- input
  if ("PY" %in% names(output) && !"Year" %in% names(output)) {
    output$Year <- output$PY
  }
  if ("year" %in% names(output) && !"Year" %in% names(output)) {
    output$Year <- output$year
  }
  if ("article_count" %in% names(output) && !"Articles" %in% names(output)) {
    output$Articles <- output$article_count
  }
  if ("articles" %in% names(output) && !"Articles" %in% names(output)) {
    output$Articles <- output$articles
  }

  output
}

#' Collect models from computed data for diagnostics
#' @keywords internal
collect_models_for_diagnostics <- function(data) {
  models <- list()
  
  # From regression - extract all fitted models
  if (!is.null(data$regression) && data$regression$status == "success") {
    if (!is.null(data$regression$models)) {
      models <- c(models, data$regression$models)
    }
  }
  
  # From forecasting
  if (!is.null(data$forecasting) && data$forecasting$status == "success") {
    if (!is.null(data$forecasting$arima)) models$arima <- data$forecasting$arima
    if (!is.null(data$forecasting$ets)) models$ets <- data$forecasting$ets
  }
  
  # From growth models
  if (!is.null(data$growth_models) && data$growth_models$status == "success") {
    model_names <- c("bass", "gompertz", "weibull", "richards", "von_bertalanffy", "mmf")
    for (nm in model_names) {
      if (!is.null(data$growth_models[[nm]])) {
        models[[nm]] <- data$growth_models[[nm]]
      }
    }
  }
  
  models
}

#' Wrapper for growth models computation
#' @keywords internal
compute_m2_growth_models_wrapper <- function(input, config) {
  year_col <- if ("Year" %in% names(input)) "Year" else names(input)[1]
  articles_col <- if ("Articles" %in% names(input)) "Articles" else names(input)[2]
  
  years <- input[[year_col]]
  articles <- input[[articles_col]]
  
  if (length(years) < 5) {
    return(list(status = "error: insufficient data for growth models (need 5+ years)"))
  }
  
  results <- list()
  
  results$bass <- fit_bass_model(years, articles)
  results$gompertz <- fit_gompertz_model(years, articles)
  results$weibull <- fit_weibull_model(years, articles)
  results$richards <- fit_richards_model(years, articles)
  results$von_bertalanffy <- fit_von_bertalanffy_model(years, articles)
  results$mmf <- fit_mmf_model(years, articles)
  
  results$comparison <- compare_growth_models(results)
  results$best_model <- select_best_growth_model(results$comparison)
  results$status <- "success"
  
  results
}

#' Select the best fitted growth model from a comparison table
#' @keywords internal
select_best_growth_model <- function(comparison) {
  if (!is.data.frame(comparison) || nrow(comparison) == 0 || !"model" %in% names(comparison)) {
    return(NA_character_)
  }

  ranking_col <- if ("AIC" %in% names(comparison)) "AIC" else if ("R_squared" %in% names(comparison)) "R_squared" else NULL
  if (is.null(ranking_col)) {
    return(comparison$model[1])
  }

  values <- suppressWarnings(as.numeric(comparison[[ranking_col]]))
  if (ranking_col == "R_squared") {
    idx <- which.max(values)
  } else {
    idx <- which.min(values)
  }

  comparison$model[idx][1]
}

#' Export M2 artifacts
#' @export
export_m2 <- function(result, config = biblio_config()) {
  config <- merge_biblio_config(config)

  exported_plots <- character()
  exported_jsons <- character()
  exported_tables <- character()

  if (config$export_plots) {
    for (nm in names(result$artifacts$plots)) {
      plot_section <- result$artifacts$plots[[nm]]
      flat_plots <- m2_flatten_plot_collection(plot_section$plots)
      for (pnm in names(flat_plots)) {
        plot_obj <- ieee_prepare_plot_for_export(
          flat_plots[[pnm]],
          module_id = "m2",
          section_id = nm,
          plot_id = pnm,
          config = config
        )
        spec <- ieee_get_plot_export_spec(
          plot_obj,
          config = config,
          section_id = nm,
          plot_id = pnm
        )
        p <- build_artifact_path("m2", "plots", paste0("m2_", nm, "_", pnm), "png", config)
        tryCatch({
          exported_paths <- export_plot_artifact(plot_obj, tools::file_path_sans_ext(p),
                               width = spec$width, height = spec$height, dpi = spec$dpi)
          exported_plots <- c(exported_plots, unname(exported_paths[!is.na(exported_paths)]))
        }, error = function(e) NULL)
      }
    }
  }

  if (config$export_json) {
    for (nm in names(result$data)) {
      j <- build_artifact_path("m2", "json", paste0("m2_", nm), "json", config)
      tryCatch({
        write_json_artifact(result$data[[nm]], j)
        exported_jsons <- c(exported_jsons, j)
      }, error = function(e) NULL)
    }
  }

  for (nm in names(result$artifacts$tables)) {
    table_section <- result$artifacts$tables[[nm]]
    flat_tables <- m2_flatten_table_collection(table_section)
    if (length(flat_tables) == 0) {
      next
    }
    for (tnm in names(flat_tables)) {
      csv_path <- build_artifact_path("m2", "tables", paste0("m2_", nm, "_", tnm), "csv", config)
      dir.create(dirname(csv_path), recursive = TRUE, showWarnings = FALSE)
      tryCatch({
        utils::write.csv(flat_tables[[tnm]], csv_path, row.names = FALSE, na = "")
        exported_tables <- c(exported_tables, csv_path)
      }, error = function(e) NULL)
    }
  }

  exported_reports <- character()
  if (config$export_reports && length(result$artifacts$reports) > 0) {
    report <- result$artifacts$reports[[1]]
    if (!is.null(report$lines) && length(report$lines) > 0) {
      r <- build_artifact_path("m2", "reports", "m2_report", "txt", config)
      write_text_report(report$lines, r)
      exported_reports <- c(exported_reports, r)
    }
    if (!is.null(report$tex) && length(report$tex) > 0) {
      t <- build_artifact_path("m2", "reports", "m2_report", "tex", config)
      writeLines(report$tex, t)
      exported_reports <- c(exported_reports, t)
    }
  }

  list(plots = exported_plots, tables = exported_tables, reports = exported_reports, files = exported_jsons)
}

#' Flatten nested plot collections for export
#' @keywords internal
m2_flatten_plot_collection <- function(x, prefix = NULL) {
  if (inherits(x, "ggplot")) {
    plot_name <- if (is.null(prefix) || identical(prefix, "")) "plot" else prefix
    out <- list(x)
    names(out) <- plot_name
    return(out)
  }

  if (!is.list(x) || length(x) == 0) {
    return(list())
  }

  flattened <- list()
  child_names <- names(x)
  if (is.null(child_names)) {
    child_names <- as.character(seq_along(x))
  }

  for (i in seq_along(x)) {
    child_prefix <- if (is.null(prefix) || identical(prefix, "")) {
      child_names[i]
    } else {
      paste(prefix, child_names[i], sep = "_")
    }
    flattened <- c(flattened, m2_flatten_plot_collection(x[[i]], child_prefix))
  }

  flattened
}

#' Flatten nested table collections for export
#' @keywords internal
m2_flatten_table_collection <- function(x, prefix = NULL) {
  if (is.data.frame(x)) {
    table_name <- if (is.null(prefix) || identical(prefix, "")) "table" else prefix
    out <- list(x)
    names(out) <- table_name
    return(out)
  }

  if (!is.list(x) || length(x) == 0) {
    return(list())
  }

  flattened <- list()
  child_names <- names(x)
  if (is.null(child_names)) {
    child_names <- as.character(seq_along(x))
  }

  for (i in seq_along(x)) {
    child_prefix <- if (is.null(prefix) || identical(prefix, "")) {
      child_names[i]
    } else {
      paste(prefix, child_names[i], sep = "_")
    }
    flattened <- c(flattened, m2_flatten_table_collection(x[[i]], child_prefix))
  }

  flattened
}

#' Build M2 manifest
#' @export
build_m2_manifest <- function(result, exported = list(), config = biblio_config()) {
  status <- if (inherits(result, "biblio_module_result")) result$status else "stub"
  new_artifact_manifest(
    module_id = "m2",
    generated_at = Sys.time(),
    files = if (is.null(exported$files)) character() else exported$files,
    plots = if (is.null(exported$plots)) character() else exported$plots,
    tables = if (is.null(exported$tables)) character() else exported$tables,
    reports = if (is.null(exported$reports)) character() else exported$reports,
    status = status
  )
}

#' Build M2 report payload
#' @keywords internal
build_m2_report <- function(data, config = biblio_config()) {
  best_reg <- data$regression$best_model
  benchmark_reg <- data$regression$benchmark_best_model
  benchmark_name <- if (is.list(benchmark_reg) && !is.null(benchmark_reg$name)) benchmark_reg$name else NULL
  best_name <- if (is.list(best_reg) && !is.null(best_reg$name)) best_reg$name else "NA"
  best_forecast <- if (!is.null(data$forecasting$model_comparison$best_model)) {
    data$forecasting$model_comparison$best_model
  } else {
    NA_character_
  }
  trend_stats <- data$diagnostics$trend_statistics
  changepoints <- if (!is.null(data$changepoint$summary$changepoint_years)) data$changepoint$summary$changepoint_years else numeric(0)
  param <- best_reg$parameter_summary %||% list()
  hyp <- data$hypotheses$hypotheses %||% list()
  hyp_rows <- Filter(function(x) is.list(x), hyp)
  hyp_statistical <- hyp_rows[vapply(hyp_rows, function(x) identical(x$evidence_class %||% "", "statistical"), logical(1))]
  hyp_supported <- hyp_statistical[vapply(hyp_statistical, function(x) identical(x$result %||% "", "reject"), logical(1))]
  hyp_summary <- if (length(hyp_statistical) > 0) {
    sprintf("%d/%d statistical hypotheses showed evidence against their null.", length(hyp_supported), length(hyp_statistical))
  } else {
    "No statistical hypotheses were available."
  }
  top_hypothesis <- if (length(hyp_supported) > 0) {
    p_values <- vapply(hyp_supported, function(x) {
      value <- suppressWarnings(as.numeric(x$p_value))
      if (length(value) == 1L && is.finite(value)) value else Inf
    }, numeric(1))
    hyp_supported[[which.min(p_values)]]
  } else {
    NULL
  }

  parameter_lines <- character()
  if (is.finite(m2_scalar_num(param$carrying_capacity))) {
    parameter_lines <- c(parameter_lines, sprintf("Estimated saturation/capacity: %.2f", m2_scalar_num(param$carrying_capacity)))
  }
  if (is.finite(m2_scalar_num(param$growth_rate))) {
    parameter_lines <- c(parameter_lines, sprintf("Estimated growth-rate parameter: %.4f", m2_scalar_num(param$growth_rate)))
  }
  if (is.finite(m2_scalar_num(param$inflection_year))) {
    parameter_lines <- c(parameter_lines, sprintf("Estimated inflection year: %.2f", m2_scalar_num(param$inflection_year)))
  }

  lines <- c(
    "M2 Annual Production Analysis",
    "",
    sprintf("Selected interpretable regression model: %s", best_name),
    if (!is.null(benchmark_name) && !identical(benchmark_name, best_name)) {
      sprintf("Flexible benchmark winner: %s", benchmark_name)
    } else {
      NULL
    },
    sprintf("Composite selection score: %.4f", m2_scalar_num(best_reg$composite_score)),
    if (!is.null(best_reg$selection_reason)) paste("Selection rationale:", best_reg$selection_reason) else NULL,
    sprintf("Best forecasting model: %s", if (!is.null(best_forecast)) best_forecast else "NA"),
    sprintf("Estimated CAGR: %.2f%%", 100 * m2_scalar_num(trend_stats$cagr)),
    sprintf("Recent CAGR: %.2f%%", 100 * m2_scalar_num(trend_stats$recent_cagr)),
    sprintf("Sen slope: %.4f", m2_scalar_num(trend_stats$sen_slope)),
    sprintf("Mann-Kendall p-value: %.4f", m2_scalar_num(trend_stats$mann_kendall$p_value)),
    sprintf("Hurst exponent: %.4f", m2_scalar_num(trend_stats$hurst_exponent)),
    sprintf("Detected breakpoints: %s", if (length(changepoints) > 0) paste(changepoints, collapse = ", ") else "None"),
    paste("Hypothesis summary:", hyp_summary),
    if (!is.null(top_hypothesis)) {
      paste("Strongest statistical finding:", top_hypothesis$interpretation %||% top_hypothesis$hypothesis)
    } else {
      NULL
    },
    parameter_lines
  )

  tex <- c(
    "\\section*{M2 Annual Production Summary}",
    sprintf("\\textbf{Selected interpretable regression model}: %s\\\\", best_name),
    if (!is.null(benchmark_name) && !identical(benchmark_name, best_name)) {
      sprintf("\\textbf{Flexible benchmark winner}: %s\\\\", benchmark_name)
    } else {
      NULL
    },
    sprintf("\\textbf{Composite selection score}: %.4f\\\\", m2_scalar_num(best_reg$composite_score)),
    if (!is.null(best_reg$selection_reason)) sprintf("\\textbf{Selection rationale}: %s\\\\", best_reg$selection_reason) else NULL,
    sprintf("\\textbf{Best forecasting model}: %s\\\\", if (!is.null(best_forecast)) best_forecast else "NA"),
    sprintf("\\textbf{Estimated CAGR}: %.2f\\%%\\\\", 100 * m2_scalar_num(trend_stats$cagr)),
    sprintf("\\textbf{Recent CAGR}: %.2f\\%%\\\\", 100 * m2_scalar_num(trend_stats$recent_cagr)),
    sprintf("\\textbf{Sen slope}: %.4f\\\\", m2_scalar_num(trend_stats$sen_slope)),
    sprintf("\\textbf{Mann-Kendall p-value}: %.4f\\\\", m2_scalar_num(trend_stats$mann_kendall$p_value)),
    sprintf("\\textbf{Hurst exponent}: %.4f\\\\", m2_scalar_num(trend_stats$hurst_exponent)),
    sprintf("\\textbf{Detected breakpoints}: %s\\\\", if (length(changepoints) > 0) paste(changepoints, collapse = ", ") else "None"),
    sprintf("\\textbf{Hypothesis summary}: %s\\\\", hyp_summary),
    if (!is.null(top_hypothesis)) sprintf("\\textbf{Strongest statistical finding}: %s\\\\", top_hypothesis$interpretation %||% top_hypothesis$hypothesis) else NULL,
    if (length(parameter_lines) > 0) sprintf("\\textbf{Model parameters}: %s", paste(parameter_lines, collapse = "; ")) else NULL
  )

  list(lines = lines, tex = tex)
}
# <<< END FILE: R/module_m2/m2_run.R

# >>> BEGIN FILE: R/module_m2/m2_validate.R
# ============================================================================
# module_m2/m2_validate.R - Input validation for M2
# ============================================================================

#' Validate M2 input (annual production data)
#'
#' @param input A data frame with year and articles columns.
#' @param config A configuration list.
#' @export
validate_m2_input <- function(input, config = biblio_config()) {
  if (!is.data.frame(input)) {
    return(list(ok = FALSE, missing_columns = character(), n_rows = 0, n_cols = 0, error = "Not a data frame"))
  }

  normalized <- m2_normalize_input(input)
  col_check <- validate_required_columns(normalized, c("Year", "Articles"))
  list(
    ok = col_check$ok,
    missing_columns = col_check$missing_columns,
    n_rows = nrow(normalized),
    n_cols = ncol(normalized)
  )
}
# <<< END FILE: R/module_m2/m2_validate.R

# >>> BEGIN FILE: R/module_m2/render/m2_render_advanced_ts.R
# ============================================================================
# m2_render_advanced_ts.R - Advanced Time Series Visualization
# ============================================================================

#' Render advanced time series analysis
#'
#' @param data Output from compute_m2_advanced_ts
#' @param config Configuration list
#' @return List with plots
#' @export
render_m2_advanced_ts <- function(data, config = biblio_config()) {
  if (is.null(data) || data$status != "success") {
    return(list(plots = list(), status = data$status %||% "error"))
  }
  
  plots <- list()
  
  if (!is.null(data$sarima)) {
    plots$sarima <- create_sarima_plot(data$sarima, config)
  }
  
  if (!is.null(data$tbats)) {
    plots$tbats <- create_tbats_plot(data$tbats, config)
  }
  
  if (!is.null(data$prophet)) {
    plots$prophet <- create_prophet_plot(data$prophet, config)
  }
  
  if (!is.null(data$state_space)) {
    plots$state_space <- create_state_space_plot(data$state_space, config)
  }
  
  if (!is.null(data$comparison)) {
    plots$model_comparison <- create_ts_model_comparison_plot(data$comparison, config)
  }
  
  list(
    plots = plots,
    status = "success"
  )
}

#' Create SARIMA plot
#' @keywords internal
create_sarima_plot <- function(sarima_data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) return(NULL)
  if (is.null(sarima_data) || sarima_data$status != "success") return(NULL)
  
  years <- sarima_data$years
  fitted <- sarima_data$fitted
  forecast <- sarima_data$forecast
  
  df <- data.frame(
    year = c(years, years),
    value = c(fitted, forecast),
    type = c(rep("Fitted", length(years)), rep("Forecast", length(years)))
  )
  
  ggplot2::ggplot(df, ggplot2::aes(x = year, y = value, color = type)) +
    ggplot2::geom_line(linewidth = 1) +
    ggplot2::scale_color_manual(values = c("Fitted" = "#2166AC", "Forecast" = "#B2182B")) +
    ggplot2::labs(
      title = "SARIMA Model",
      x = "Year",
      y = "Articles",
      color = NULL
    ) +
  ieee_theme()
}

#' Create TBATS plot
#' @keywords internal
create_tbats_plot <- function(tbats_data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) return(NULL)
  if (is.null(tbats_data) || tbats_data$status != "success") return(NULL)
  
  years <- tbats_data$years
  fitted <- tbats_data$fitted
  
  df <- data.frame(year = years, fitted = fitted)
  
  ggplot2::ggplot(df, ggplot2::aes(x = year, y = fitted)) +
    ggplot2::geom_line(color = "#2166AC", linewidth = 1) +
    ggplot2::labs(
      title = "TBATS Model Fit",
      x = "Year",
      y = "Articles"
    ) +ieee_theme()
}

#' Create Prophet-style plot
#' @keywords internal
create_prophet_plot <- function(prophet_data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) return(NULL)
  if (is.null(prophet_data) || prophet_data$status != "success") return(NULL)
  
  trend <- prophet_data$trend
  years <- prophet_data$years %||% seq_along(trend)
  forecast_years <- prophet_data$forecast_years %||% numeric()
  forecast <- prophet_data$forecast$point %||% numeric()

  if (length(trend) == 0 || length(years) != length(trend)) {
    return(NULL)
  }

  df_trend <- data.frame(year = years, value = trend, component = "Trend")
  df_forecast <- if (length(forecast) > 0 && length(forecast_years) == length(forecast)) {
    data.frame(year = forecast_years, value = forecast, component = "Forecast")
  } else {
    data.frame(year = numeric(), value = numeric(), component = character(), stringsAsFactors = FALSE)
  }
  df <- rbind(df_trend, df_forecast)

  if (nrow(df) == 0) {
    return(NULL)
  }
  
  ggplot2::ggplot(df, ggplot2::aes(x = year, y = value, color = component)) +
    ggplot2::geom_line(linewidth = 1) +
    ggplot2::scale_color_manual(values = c("Trend" = "#2166AC", "Forecast" = "#67A9CF")) +
    ggplot2::labs(
      title = "Prophet-style Decomposition",
      x = "Year",
      y = "Articles",
      color = NULL
    ) +ieee_theme()
}

#' Create state space plot
#' @keywords internal
create_state_space_plot <- function(ss_data, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) return(NULL)
  if (is.null(ss_data) || ss_data$status != "success") return(NULL)
  
  years <- ss_data$years
  filtered <- ss_data$filtered
  smoothed <- ss_data$smoothed
  
  df <- data.frame(
    year = rep(years, 2),
    value = c(filtered, smoothed),
    type = c(rep("Filtered", length(years)), rep("Smoothed", length(years)))
  )
  
  ggplot2::ggplot(df, ggplot2::aes(x = year, y = value, color = type)) +
    ggplot2::geom_line(linewidth = 1) +
    ggplot2::scale_color_manual(values = c("Filtered" = "#2166AC", "Smoothed" = "#B2182B")) +
    ggplot2::labs(
      title = "State Space Model (Kalman Filter)",
      x = "Year",
      y = "Articles",
      color = NULL
    ) +ieee_theme()
}

#' Create time series model comparison plot
#' @keywords internal
create_ts_model_comparison_plot <- function(comparison, config) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) return(NULL)
  if (is.null(comparison) || nrow(comparison) == 0) return(NULL)
  
  comparison$model <- factor(comparison$model, levels = comparison$model)
  
  ggplot2::ggplot(comparison, ggplot2::aes(x = model, y = AIC)) +
    ggplot2::geom_col(fill = "#2166AC", alpha = 0.7) +
    ggplot2::coord_flip() +
    ggplot2::labs(
      title = "Time Series Model Comparison (AIC)",
      x = "Model",
      y = "AIC"
    ) +ieee_theme()
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m2/render/m2_render_advanced_ts.R

# >>> BEGIN FILE: R/module_m2/render/m2_render_diagnostics.R
# ============================================================================
# m2_render_diagnostics.R - Model Diagnostics Visualizations
# ============================================================================
# Residual ACF/PACF plots, model comparison, structural break timeline

#' Render model diagnostics plots
#'
#' @param diagnostics Output from compute_m2_diagnostics
#' @param config Configuration list
#' @return List with plots
#' @export
render_m2_diagnostics <- function(diagnostics, config = biblio_config()) {
  if (is.null(diagnostics) || diagnostics$status != "success") {
    return(list(plots = list(), status = "error: invalid diagnostics"))
  }
  
  plots <- list()
  
  # Model comparison plot
  if (!is.null(diagnostics$comparison) && nrow(diagnostics$comparison) > 0) {
    plots$model_comparison <- create_diagnostics_model_comparison_plot(diagnostics$comparison)
  }
  
  # CV results plot
  if (!is.null(diagnostics$cv_results) &&
      is.data.frame(diagnostics$cv_results$cv_results) &&
      nrow(diagnostics$cv_results$cv_results) > 0) {
    plots$cv_accuracy <- create_cv_accuracy_plot(diagnostics$cv_results)
  }
  
  # Forecast accuracy comparison
  if (!is.null(diagnostics$accuracy) && nrow(diagnostics$accuracy) > 0) {
    plots$accuracy_comparison <- create_accuracy_comparison_plot(diagnostics$accuracy)
  }

  if (!is.null(diagnostics$changepoint_profile$years) &&
      length(diagnostics$changepoint_profile$years) > 0 &&
      is.data.frame(diagnostics$series)) {
    plots$breakpoints <- create_breakpoint_timeline(
      years = diagnostics$series$Year,
      articles = diagnostics$series$Articles,
      breakpoints = diagnostics$changepoint_profile$years,
      config = config
    )
  }
  
  # Residual ACF/PACF plots
  if (!is.null(diagnostics$residuals)) {
    plots$diagnostics <- create_residual_diagnostics_plot(diagnostics$residuals)
  }
  
  # Model weights plot
  if (!is.null(diagnostics$weights)) {
    plots$weights <- create_model_weights_plot(diagnostics$weights)
  }
  
  list(plots = plots, status = "success")
}

#' Create model comparison plot
#' @keywords internal
create_diagnostics_model_comparison_plot <- function(comparison) {
  # Reshape for plotting
  models <- if ("model" %in% names(comparison)) comparison$model else comparison$Model
  aic_values <- if ("AIC" %in% names(comparison)) comparison$AIC else rep(NA_real_, length(models))
  bic_values <- if ("BIC" %in% names(comparison)) comparison$BIC else rep(NA_real_, length(models))
  composite_values <- if ("CompositeScore" %in% names(comparison)) comparison$CompositeScore else rep(NA_real_, length(models))
  n_models <- length(models)
  
  # AIC comparison
  df_aic <- data.frame(
    model = factor(models, levels = models),
    value = aic_values,
    metric = "AIC"
  )
  
  # BIC comparison
  df_bic <- data.frame(
    model = factor(models, levels = models),
    value = bic_values,
    metric = "BIC"
  )
  
  df <- rbind(df_aic, df_bic)
  if (any(is.finite(composite_values))) {
    df <- rbind(df, data.frame(
      model = factor(models, levels = models),
      value = composite_values,
      metric = "Composite"
    ))
  }
  
  # Normalize within metric
  df$value_norm <- ave(df$value, df$metric, FUN = function(x) (x - min(x)) / (max(x) - min(x) + 0.001))
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = model, y = value_norm, fill = metric)) +
    ggplot2::geom_col(position = ggplot2::position_dodge(width = 0.7),
                       width = 0.6, color = "black", linewidth = 0.2) +
    ggplot2::scale_fill_manual(values = c("AIC" = "#0072BD", "BIC" = "#D95319", "Composite" = "#77AC30")) +
    ggplot2::coord_flip() +
    ieee_theme_bar() +
    ggplot2::labs(
      title = "Model Comparison (AIC vs BIC)",
      x = NULL,
      y = "Normalized Score"
    ) +
    ggplot2::theme(legend.position = "bottom")
  
  ieee_mark_plot_layout(p, "full")
}

#' Create CV accuracy plot
#' @keywords internal
create_cv_accuracy_plot <- function(cv_results) {
  df <- cv_results$cv_results
  
  if (is.null(df) || nrow(df) == 0) return(NULL)
  if (!"MAE" %in% names(df) && "mae" %in% names(df)) df$MAE <- df$mae
  if (!"model" %in% names(df) && "Model" %in% names(df)) df$model <- df$Model
  if (!"fold" %in% names(df) && "Fold" %in% names(df)) df$fold <- df$Fold
  
  # Plot MAE across folds
  p <- ggplot2::ggplot(df, ggplot2::aes(x = factor(fold), y = MAE, color = model, group = model)) +
    ggplot2::geom_line(linewidth = 0.8) +
    ggplot2::geom_point(size = 2) +
    ggplot2::scale_color_brewer(palette = "Set1", name = "Model") +
    ggplot2::scale_x_discrete(name = "CV Fold") +
    ggplot2::scale_y_continuous(name = "Mean Absolute Error") +
    ieee_theme() +
    ggplot2::labs(title = "Cross-Validation Performance") +
    ggplot2::theme(legend.position = "right")
  
  ieee_mark_plot_layout(p, "full")
}

#' Create accuracy comparison plot
#' @keywords internal
create_accuracy_comparison_plot <- function(accuracy) {
  if (is.null(accuracy) || nrow(accuracy) == 0) return(NULL)

  if (!"model" %in% names(accuracy) && "Model" %in% names(accuracy)) {
    accuracy$model <- accuracy$Model
  }
  
  # Select metrics to plot
  metrics <- c("MAE", "RMSE", "MAPE", "SMAPE", "MASE", "TheilU", "Stability")
  available <- intersect(metrics, names(accuracy))
  
  if (length(available) == 0) return(NULL)
  
  df_list <- list()
  for (m in available) {
    df_list[[m]] <- data.frame(
      model = accuracy$model,
      metric = m,
      value = accuracy[[m]]
    )
  }
  
  df <- do.call(rbind, df_list)
  
  # Normalize within metric
  df$value_norm <- ave(df$value, df$metric, FUN = function(x) {
    (x - min(x, na.rm = TRUE)) / (max(x, na.rm = TRUE) - min(x, na.rm = TRUE) + 0.001)
  })
  
  colors <- c(
    "MAE" = "#0072BD",
    "RMSE" = "#D95319",
    "MAPE" = "#77AC30",
    "SMAPE" = "#A2142F",
    "MASE" = "#4DBBD5",
    "TheilU" = "#E64B35",
    "Stability" = "#3C5488"
  )
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = model, y = value_norm, fill = metric)) +
    ggplot2::geom_col(position = ggplot2::position_dodge(width = 0.7),
                       width = 0.6, color = "black", linewidth = 0.2) +
    ggplot2::scale_fill_manual(values = colors[available]) +
    ggplot2::coord_flip() +
    ieee_theme_bar() +
    ggplot2::labs(
      title = "Forecast Accuracy Comparison",
      x = NULL,
      y = "Normalized Score"
    ) +
    ggplot2::theme(legend.position = "bottom")
  
  ieee_mark_plot_layout(p, "full")
}

#' Create residual diagnostics plot
#' @keywords internal
create_residual_diagnostics_plot <- function(residuals) {
  models <- names(residuals)
  n_models <- length(models)
  
  if (n_models == 0) return(NULL)
  
  plots <- list()
  
  # Select first model with residuals
  first_model <- models[1]
  res <- residuals[[first_model]]
  
  if (!is.null(res)) {
    # ACF plot
    if (!is.null(res$acf) && !is.null(res$acf$values)) {
      df_acf <- data.frame(
        lag = res$acf$lags,
        acf = res$acf$values
      )
      
      ci <- qnorm(0.975) / sqrt(length(res$acf$values))
      
      acf_limit <- max(0.3, max(abs(c(df_acf$acf, ci)), na.rm = TRUE) * 1.15)
      p_acf <- ggplot2::ggplot(df_acf, ggplot2::aes(x = lag, y = acf)) +
        ggplot2::geom_segment(ggplot2::aes(xend = lag, yend = 0), color = "black", linewidth = 0.8) +
        ggplot2::geom_point(color = "black", size = 1.5) +
        ggplot2::geom_hline(yintercept = c(ci, -ci), linetype = "22", color = "#2F55D4", linewidth = 0.55) +
        ggplot2::geom_hline(yintercept = 0, color = "black", linewidth = 0.35) +
        ggplot2::scale_x_continuous(name = "Lag") +
        ggplot2::scale_y_continuous(name = "ACF", limits = c(-acf_limit, acf_limit)) +
        ieee_theme() +
        ggplot2::labs(title = paste("Residual ACF -", first_model))
      
      plots$acf <- ieee_mark_plot_layout(p_acf, "single")
    }
    
    # PACF plot
    if (!is.null(res$pacf) && !is.null(res$pacf$values)) {
      df_pacf <- data.frame(
        lag = res$pacf$lags,
        pacf = res$pacf$values
      )
      
      ci <- qnorm(0.975) / sqrt(length(res$pacf$values))
      
      pacf_limit <- max(0.3, max(abs(c(df_pacf$pacf, ci)), na.rm = TRUE) * 1.15)
      p_pacf <- ggplot2::ggplot(df_pacf, ggplot2::aes(x = lag, y = pacf)) +
        ggplot2::geom_segment(ggplot2::aes(xend = lag, yend = 0), color = "black", linewidth = 0.8) +
        ggplot2::geom_point(color = "black", size = 1.5) +
        ggplot2::geom_hline(yintercept = c(ci, -ci), linetype = "22", color = "#2F55D4", linewidth = 0.55) +
        ggplot2::geom_hline(yintercept = 0, color = "black", linewidth = 0.35) +
        ggplot2::scale_x_continuous(name = "Lag") +
        ggplot2::scale_y_continuous(name = "PACF", limits = c(-pacf_limit, pacf_limit)) +
        ieee_theme() +
        ggplot2::labs(title = paste("Residual PACF -", first_model))
      
      plots$pacf <- ieee_mark_plot_layout(p_pacf, "single")
    }
  }
  
  plots
}

#' Create model weights plot
#' @keywords internal
create_model_weights_plot <- function(weights) {
  if (is.null(weights) || length(weights) == 0) return(NULL)
  
  # Use AIC weights if available
  w <- if (!is.null(weights$aic)) weights$aic else weights[[1]]
  
  df <- data.frame(
    model = names(w),
    weight = as.numeric(w)
  )
  
  df$model <- factor(df$model, levels = df$model[order(df$weight)])
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = model, y = weight, fill = model)) +
    ggplot2::geom_col(width = 0.7, color = "black", linewidth = 0.2) +
    ggplot2::coord_flip() +
    ggplot2::scale_fill_brewer(palette = "Set1", guide = "none") +
    ggplot2::scale_y_continuous(name = "Weight", expand = ggplot2::expansion(mult = c(0, 0.1))) +
    ieee_theme_bar() +
    ggplot2::labs(title = "Model Weights (AIC-based)", x = NULL)
  
  ieee_mark_plot_layout(p, "single")
}

#' Create structural break timeline plot
#'
#' @param years Time points
#' @param articles Values
#' @param breakpoints Vector of break years
#' @param config Configuration
#' @return ggplot object
#' @export
create_breakpoint_timeline <- function(years, articles, breakpoints, config = biblio_config()) {
  df <- data.frame(year = years, articles = articles)
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = year, y = articles)) +
    ggplot2::geom_line(color = "#0072BD", linewidth = 0.8) +
    ggplot2::geom_point(color = "#0072BD", size = 1.5)
  
  if (length(breakpoints) > 0) {
    for (bp in breakpoints) {
      p <- p + ggplot2::geom_vline(xintercept = bp, color = "#D95319",
                                    linetype = "dashed", linewidth = 0.6)
    }
    
    # Add segment labels
    segment_labels <- data.frame(
      x = breakpoints,
      label = paste("Break", seq_along(breakpoints))
    )
    
    p <- p + ggplot2::annotate("text", x = segment_labels$x, y = max(articles),
                               label = segment_labels$label, vjust = -0.5,
                               color = "#D95319", size = 3)
  }
  
  p <- p +
    ggplot2::scale_x_continuous(name = "Year") +
    ggplot2::scale_y_continuous(name = "Articles") +
    ieee_theme_timeseries() +
    ggplot2::labs(
      title = "Structural Break Timeline",
      subtitle = sprintf("%d breakpoints detected", length(breakpoints))
    )
  
  ieee_mark_plot_layout(p, "full")
}

#' Create growth phase diagram
#'
#' @param years Time points
#' @param articles Values
#' @param phases Optional phase assignments
#' @param config Configuration
#' @return ggplot object
#' @export
create_growth_phase_diagram <- function(years, articles, phases = NULL, config = biblio_config()) {
  df <- data.frame(year = years, articles = articles)
  
  # Identify phases from data
  if (is.null(phases)) {
    # Simple phase detection
    n <- length(articles)
    
    # Calculate growth rate
    growth <- c(NA, diff(articles) / articles[-n])
    
    # Identify phases
    phases <- rep("growth", n)
    
    # Early phase (first 20%)
    early_end <- ceiling(n * 0.2)
    phases[1:early_end] <- "early"
    
    # Detect saturation
    if (n > 5) {
      recent_growth <- mean(tail(growth, 5), na.rm = TRUE)
      if (recent_growth < 0.02) {
        saturation_start <- max(1, n - 5)
        phases[saturation_start:n] <- "saturation"
      }
    }
  }
  
  df$phase <- phases
  
  colors <- c("early" = "#77AC30", "growth" = "#0072BD", "saturation" = "#D95319")
  
  p <- ggplot2::ggplot(df, ggplot2::aes(x = year, y = articles, color = phase)) +
    ggplot2::geom_line(linewidth = 0.8) +
    ggplot2::geom_point(size = 2) +
    ggplot2::scale_color_manual(values = colors, name = "Phase") +
    ggplot2::scale_x_continuous(name = "Year") +
    ggplot2::scale_y_continuous(name = "Articles") +
    ieee_theme_timeseries() +
    ggplot2::labs(title = "Growth Phase Diagram") +
    ggplot2::theme(legend.position = "bottom")
  
  ieee_mark_plot_layout(p, "full")
}

