# >>> BEGIN FILE: R/module_m2/utils/m2_model_contract.R
# ============================================================================
# m2_model_contract.R - Canonical model contract for M2
# ============================================================================

#' Null-coalescing helper for M2 internals
#' @keywords internal
m2_coalesce_null <- function(a, b) if (!is.null(a)) a else b

#' Safe numeric scalar conversion
#' @keywords internal
m2_scalar_num <- function(x, default = NA_real_) {
  value <- suppressWarnings(as.numeric(x)[1])
  if (!is.finite(value)) {
    return(default)
  }
  value
}

#' Safe numeric vector conversion
#' @keywords internal
m2_num_vec <- function(x) {
  if (is.null(x)) {
    return(numeric(0))
  }
  suppressWarnings(as.numeric(x))
}

#' Approximate Gaussian log-likelihood from residuals
#' @keywords internal
m2_residual_loglik <- function(residuals) {
  residuals <- residuals[is.finite(residuals)]
  n <- length(residuals)
  if (n == 0) {
    return(NA_real_)
  }

  sigma2 <- mean(residuals^2, na.rm = TRUE)
  sigma2 <- max(sigma2, .Machine$double.eps)
  -0.5 * n * (log(2 * pi * sigma2) + 1)
}

#' Information criteria for canonical cards
#' @keywords internal
m2_information_criteria <- function(model_object, residuals, n_params, n_obs) {
  if (!is.null(model_object)) {
    aic <- tryCatch(AIC(model_object), error = function(e) NA_real_)
    bic <- tryCatch(BIC(model_object), error = function(e) NA_real_)
    ll <- tryCatch(as.numeric(logLik(model_object)), error = function(e) NA_real_)
    return(list(AIC = m2_scalar_num(aic), BIC = m2_scalar_num(bic), logLik = m2_scalar_num(ll)))
  }

  loglik <- m2_residual_loglik(residuals)
  if (!is.finite(loglik) || !is.finite(n_params) || !is.finite(n_obs) || n_obs <= 0) {
    return(list(AIC = NA_real_, BIC = NA_real_, logLik = NA_real_))
  }

  list(
    AIC = -2 * loglik + 2 * n_params,
    BIC = -2 * loglik + log(n_obs) * n_params,
    logLik = loglik
  )
}

#' Compute scalar metrics for a fitted curve
#' @keywords internal
m2_compute_fit_metrics <- function(actual, fitted, n_params = 1L) {
  actual <- m2_num_vec(actual)
  fitted <- m2_num_vec(fitted)

  keep <- is.finite(actual) & is.finite(fitted)
  actual <- actual[keep]
  fitted <- fitted[keep]

  if (length(actual) == 0 || length(actual) != length(fitted)) {
    return(list(
      r_squared = NA_real_,
      adj_r_squared = NA_real_,
      rmse = NA_real_,
      mae = NA_real_,
      mape = NA_real_,
      smape = NA_real_,
      me = NA_real_,
      mbe = NA_real_,
      theil_u = NA_real_
    ))
  }

  residuals <- actual - fitted
  n <- length(actual)
  ss_res <- sum(residuals^2, na.rm = TRUE)
  ss_tot <- sum((actual - mean(actual, na.rm = TRUE))^2, na.rm = TRUE)
  r2 <- if (ss_tot > 0) 1 - ss_res / ss_tot else NA_real_
  if (is.finite(r2)) {
    r2 <- max(0, min(1, r2))
  }

  rmse <- sqrt(mean(residuals^2, na.rm = TRUE))
  mae <- mean(abs(residuals), na.rm = TRUE)
  me <- mean(residuals, na.rm = TRUE)

  nonzero <- abs(actual) > .Machine$double.eps
  mape <- if (any(nonzero)) mean(abs(residuals[nonzero] / actual[nonzero]), na.rm = TRUE) * 100 else NA_real_

  scale_term <- abs(actual) + abs(fitted)
  smape <- if (any(scale_term > .Machine$double.eps)) {
    mean(200 * abs(residuals) / pmax(scale_term, .Machine$double.eps), na.rm = TRUE)
  } else {
    NA_real_
  }

  adj_r2 <- if (is.finite(r2) && n > n_params + 1) {
    1 - (1 - r2) * (n - 1) / (n - n_params - 1)
  } else {
    r2
  }
  if (is.finite(adj_r2)) {
    adj_r2 <- max(0, min(1, adj_r2))
  }

  naive_scale <- mean(abs(diff(actual)), na.rm = TRUE)
  theil_u <- if (n > 1 && is.finite(naive_scale) && naive_scale > .Machine$double.eps) {
    rmse / naive_scale
  } else {
    NA_real_
  }

  list(
    r_squared = r2,
    adj_r_squared = adj_r2,
    rmse = rmse,
    mae = mae,
    mape = mape,
    smape = smape,
    me = me,
    mbe = me,
    theil_u = theil_u
  )
}

#' Durbin-Watson statistic
#' @keywords internal
m2_durbin_watson_stat <- function(residuals) {
  residuals <- residuals[is.finite(residuals)]
  if (length(residuals) < 2) {
    return(NA_real_)
  }
  denom <- sum(residuals^2, na.rm = TRUE)
  if (denom <= .Machine$double.eps) {
    return(NA_real_)
  }
  sum(diff(residuals)^2, na.rm = TRUE) / denom
}

#' Breusch-Pagan style heteroscedasticity test
#' @keywords internal
m2_breusch_pagan <- function(fitted, residuals) {
  keep <- is.finite(fitted) & is.finite(residuals)
  fitted <- fitted[keep]
  residuals <- residuals[keep]
  n <- length(residuals)

  if (n < 5) {
    return(list(statistic = NA_real_, p_value = NA_real_))
  }

  aux <- tryCatch(lm(I(residuals^2) ~ fitted), error = function(e) NULL)
  if (is.null(aux)) {
    return(list(statistic = NA_real_, p_value = NA_real_))
  }

  r2 <- tryCatch(summary(aux)$r.squared, error = function(e) NA_real_)
  if (!is.finite(r2)) {
    return(list(statistic = NA_real_, p_value = NA_real_))
  }

  stat <- n * r2
  list(
    statistic = stat,
    p_value = 1 - stats::pchisq(stat, df = 1)
  )
}

#' Basic residual diagnostics for a canonical model card
#' @keywords internal
m2_compute_card_diagnostics <- function(years, actual, fitted, residuals, n_params = 1L) {
  residuals <- m2_num_vec(residuals)
  years <- m2_num_vec(years)
  fitted <- m2_num_vec(fitted)

  keep <- is.finite(residuals)
  residuals <- residuals[keep]
  fitted <- fitted[keep]
  if (length(years) >= length(keep)) {
    years <- years[keep]
  }

  if (length(residuals) == 0) {
    return(list(
      shapiro_p = NA_real_,
      durbin_watson = NA_real_,
      ljung_box_p = NA_real_,
      breusch_pagan_p = NA_real_,
      breakpoint_count = 0L,
      breakpoint_years = numeric(0),
      max_abs_acf = NA_real_,
      stability_score = NA_real_
    ))
  }

  shapiro_p <- if (length(residuals) >= 3 && length(residuals) <= 5000) {
    tryCatch(stats::shapiro.test(residuals)$p.value, error = function(e) NA_real_)
  } else {
    NA_real_
  }

  dw <- m2_durbin_watson_stat(residuals)

  lag_max <- min(5L, length(residuals) - 1L)
  ljung_p <- if (lag_max >= 1L) {
    tryCatch(stats::Box.test(residuals, lag = lag_max, type = "Ljung-Box")$p.value, error = function(e) NA_real_)
  } else {
    NA_real_
  }

  acf_vals <- if (lag_max >= 1L) {
    tryCatch(stats::acf(residuals, plot = FALSE, lag.max = lag_max)$acf[-1], error = function(e) numeric(0))
  } else {
    numeric(0)
  }
  max_abs_acf <- if (length(acf_vals) > 0) max(abs(acf_vals), na.rm = TRUE) else NA_real_

  bp <- m2_breusch_pagan(fitted, residuals)

  breakpoints <- if (length(residuals) >= 10 && length(years) == length(residuals)) {
    tryCatch(detect_residual_breakpoints(years, residuals), error = function(e) NULL)
  } else {
    NULL
  }
  breakpoint_years <- if (!is.null(breakpoints)) m2_num_vec(breakpoints$breakpoint_years) else numeric(0)
  breakpoint_count <- length(breakpoint_years)

  score_parts <- c(
    if (is.finite(shapiro_p)) min(1, shapiro_p / 0.05) else NA_real_,
    if (is.finite(dw)) 1 - min(1, abs(dw - 2) / 2) else NA_real_,
    if (is.finite(ljung_p)) min(1, ljung_p / 0.05) else NA_real_,
    if (is.finite(bp$p_value)) min(1, bp$p_value / 0.05) else NA_real_,
    if (is.finite(max_abs_acf)) 1 - min(1, max_abs_acf) else NA_real_,
    1 - min(1, breakpoint_count / 3)
  )
  stability_score <- if (all(is.na(score_parts))) NA_real_ else mean(score_parts, na.rm = TRUE)

  list(
    shapiro_p = shapiro_p,
    durbin_watson = dw,
    ljung_box_p = ljung_p,
    breusch_pagan_p = bp$p_value,
    breakpoint_count = breakpoint_count,
    breakpoint_years = breakpoint_years,
    max_abs_acf = max_abs_acf,
    stability_score = stability_score
  )
}

#' Dense curve payload for plotting
#' @keywords internal
m2_build_curve_payload <- function(model_object, years, fitted, residuals) {
  years <- m2_num_vec(years)
  fitted <- m2_num_vec(fitted)
  residuals <- m2_num_vec(residuals)

  observed <- data.frame(
    Year = years,
    Fitted = fitted,
    Lower = fitted - 1.96 * stats::sd(residuals, na.rm = TRUE),
    Upper = fitted + 1.96 * stats::sd(residuals, na.rm = TRUE)
  )

  dense <- observed
  if (!is.null(model_object) && length(years) >= 2) {
    year_seq <- seq(min(years, na.rm = TRUE), max(years, na.rm = TRUE), length.out = max(100L, length(years)))
    pred_vals <- tryCatch(
      suppressWarnings(predict(model_object, newdata = data.frame(Year = year_seq))),
      error = function(e) rep(NA_real_, length(year_seq))
    )

    if (any(is.finite(pred_vals))) {
      se_vals <- tryCatch({
        pred_obj <- suppressWarnings(predict(model_object, newdata = data.frame(Year = year_seq), se.fit = TRUE))
        if (is.list(pred_obj) && "se.fit" %in% names(pred_obj)) {
          as.numeric(pred_obj$se.fit)
        } else {
          rep(stats::sd(residuals, na.rm = TRUE), length(year_seq))
        }
      }, error = function(e) rep(stats::sd(residuals, na.rm = TRUE), length(year_seq)))

      dense <- data.frame(
        Year = year_seq,
        Fitted = m2_num_vec(pred_vals),
        Lower = m2_num_vec(pred_vals) - 1.96 * se_vals,
        Upper = m2_num_vec(pred_vals) + 1.96 * se_vals
      )
    }
  }

  list(observed = observed, dense = dense)
}

#' Forecast payload helper
#' @keywords internal
m2_build_forecast_payload <- function(point = numeric(0),
                                      years = numeric(0),
                                      lower = NULL,
                                      upper = NULL,
                                      method = NA_character_) {
  list(
    point = m2_num_vec(point),
    years = m2_num_vec(years),
    lower = m2_num_vec(lower),
    upper = m2_num_vec(upper),
    method = method
  )
}

#' Approximate future forecast from a fitted regression object
#' @keywords internal
m2_forecast_from_regression_model <- function(model_object, years, residuals, horizon = 5L) {
  years <- m2_num_vec(years)
  residuals <- residuals[is.finite(residuals)]
  if (is.null(model_object) || length(years) == 0 || horizon <= 0) {
    return(m2_build_forecast_payload())
  }

  future_years <- seq(max(years, na.rm = TRUE) + 1, by = 1, length.out = horizon)
  preds <- tryCatch(
    suppressWarnings(predict(model_object, newdata = data.frame(Year = future_years))),
    error = function(e) rep(NA_real_, horizon)
  )
  preds <- m2_num_vec(preds)

  sigma <- stats::sd(residuals, na.rm = TRUE)
  sigma <- if (is.finite(sigma)) sigma else 0
  spread <- sigma * sqrt(seq_len(horizon))

  m2_build_forecast_payload(
    point = preds,
    years = future_years,
    lower = preds - 1.96 * spread,
    upper = preds + 1.96 * spread,
    method = "regression_extrapolation"
  )
}

#' Build canonical model card
#' @keywords internal
m2_new_model_card <- function(name,
                              family,
                              years,
                              actual,
                              fitted,
                              model_object = NULL,
                              forecast = NULL,
                              equation = NA_character_,
                              source = "regression",
                              target = "annual",
                              metadata = list()) {
  years <- m2_num_vec(years)
  actual <- m2_num_vec(actual)
  fitted <- m2_num_vec(fitted)

  keep <- is.finite(years) & is.finite(actual) & is.finite(fitted)
  years <- years[keep]
  actual <- actual[keep]
  fitted <- fitted[keep]
  residuals <- actual - fitted

  n_params <- m2_scalar_num(
    m2_coalesce_null(metadata$n_params, tryCatch(length(stats::coef(model_object)), error = function(e) NA_real_)),
    default = 1
  )

  metrics <- m2_compute_fit_metrics(actual, fitted, n_params = n_params)
  info <- m2_information_criteria(model_object, residuals, n_params = n_params, n_obs = length(actual))
  if (!is.null(metadata$AIC)) {
    info$AIC <- m2_scalar_num(metadata$AIC, info$AIC)
  }
  if (!is.null(metadata$BIC)) {
    info$BIC <- m2_scalar_num(metadata$BIC, info$BIC)
  }
  if (!is.null(metadata$logLik)) {
    info$logLik <- m2_scalar_num(metadata$logLik, info$logLik)
  }
  diag <- m2_compute_card_diagnostics(years, actual, fitted, residuals, n_params = n_params)
  curves <- m2_build_curve_payload(model_object, years, fitted, residuals)

  if (is.null(forecast)) {
    forecast <- m2_build_forecast_payload()
  }

  list(
    name = name,
    family = family,
    source = source,
    target = target,
    status = "success",
    class = if (is.null(model_object)) NA_character_ else class(model_object)[1],
    coefficients = if (is.null(model_object)) list() else tryCatch(as.list(stats::coef(model_object)), error = function(e) list()),
    equation = equation,
    n_params = n_params,
    years = years,
    actual = actual,
    fitted = fitted,
    residuals = residuals,
    metrics = metrics,
    diagnostics = diag,
    AIC = info$AIC,
    BIC = info$BIC,
    logLik = info$logLik,
    curve = curves,
    forecast = forecast,
    metadata = metadata
  )
}

#' Interpretability profile for regression models
#' @keywords internal
m2_model_interpretability_profile <- function(model_name, family = NA_character_) {
  key <- tolower(model_name %||% "")
  fam <- tolower(family %||% "")

  if (key %in% c("logistic", "logistic4p", "gompertz", "gompertzoffset", "richards", "weibull", "mmf", "monod", "asymptotic", "vonbertalanffy", "chapmanrichards", "korf", "hossfeld", "hill", "stannard", "baranyi")) {
    return(list(score = 1.00, headline_eligible = TRUE, saturation_capable = TRUE, benchmark_only = FALSE))
  }
  if (key %in% c("exponential", "exponentialoffset", "power", "logarithmic", "linear", "quadratic")) {
    return(list(score = 0.90, headline_eligible = TRUE, saturation_capable = FALSE, benchmark_only = FALSE))
  }
  if (key %in% c("cubic", "beta", "ratkowsky", "gaussian", "fourier")) {
    return(list(score = 0.65, headline_eligible = FALSE, saturation_capable = FALSE, benchmark_only = FALSE))
  }
  if (fam %in% c("spline", "periodic")) {
    return(list(score = 0.20, headline_eligible = FALSE, saturation_capable = FALSE, benchmark_only = TRUE))
  }

  list(score = 0.50, headline_eligible = FALSE, saturation_capable = FALSE, benchmark_only = FALSE)
}

#' Convert canonical card to comparison row
#' @keywords internal
m2_model_card_to_row <- function(card) {
  profile <- m2_model_interpretability_profile(card$name, card$family)
  data.frame(
    Model = card$name,
    Family = card$family,
    Source = card$source,
    Target = card$target,
    R2 = round(card$metrics$r_squared, 6),
    Adj_R2 = round(card$metrics$adj_r_squared, 6),
    RMSE = round(card$metrics$rmse, 4),
    MAE = round(card$metrics$mae, 4),
    MAPE = round(card$metrics$mape, 2),
    SMAPE = round(card$metrics$smape, 2),
    AIC = round(card$AIC, 4),
    BIC = round(card$BIC, 4),
    N_params = round(card$n_params, 0),
    Shapiro_P = round(card$diagnostics$shapiro_p, 4),
    DW = round(card$diagnostics$durbin_watson, 4),
    LjungBox_P = round(card$diagnostics$ljung_box_p, 4),
    BP_P = round(card$diagnostics$breusch_pagan_p, 4),
    Breakpoints = round(card$diagnostics$breakpoint_count, 0),
    Stability = round(card$diagnostics$stability_score, 4),
    TheilU = round(card$metrics$theil_u, 4),
    Interpretability = round(profile$score, 4),
    HeadlineEligible = isTRUE(profile$headline_eligible),
    SaturationCapable = isTRUE(profile$saturation_capable),
    BenchmarkOnly = isTRUE(profile$benchmark_only),
    Equation = m2_coalesce_null(card$equation, NA_character_),
    stringsAsFactors = FALSE
  )
}

#' Normalize a metric so that larger is always better
#' @keywords internal
m2_normalize_metric <- function(x, higher_is_better = TRUE) {
  x <- m2_num_vec(x)
  valid <- is.finite(x)
  out <- rep(NA_real_, length(x))
  if (!any(valid)) {
    return(out)
  }

  vals <- x[valid]
  if (!higher_is_better) {
    vals <- -vals
  }

  rng <- range(vals, na.rm = TRUE)
  if (!all(is.finite(rng)) || diff(rng) <= .Machine$double.eps) {
    out[valid] <- 1
    return(out)
  }

  out[valid] <- (vals - rng[1]) / (rng[2] - rng[1])
  out
}

#' Apply weighted model scoring to a comparison table
#' @keywords internal
m2_score_model_table <- function(comparison, weights = NULL) {
  if (!is.data.frame(comparison) || nrow(comparison) == 0) {
    return(comparison)
  }

  defaults <- c(
    Adj_R2 = 0.20,
    RMSE = 0.15,
    MAE = 0.10,
    SMAPE = 0.10,
    AIC = 0.10,
    BIC = 0.10,
    Stability = 0.15,
    LjungBox_P = 0.05,
    BP_P = 0.05
  )
  if (!is.null(weights) && length(weights) > 0) {
    defaults[names(weights)] <- as.numeric(weights)
  }

  scored <- comparison
  metric_map <- list(
    Adj_R2 = TRUE,
    RMSE = FALSE,
    MAE = FALSE,
    SMAPE = FALSE,
    AIC = FALSE,
    BIC = FALSE,
    Stability = TRUE,
    LjungBox_P = TRUE,
    BP_P = TRUE
  )

  weighted_parts <- list()
  used_weights <- numeric(0)

  for (metric in names(defaults)) {
    if (!metric %in% names(scored)) {
      next
    }
    col_name <- paste0(metric, "_Score")
    scored[[col_name]] <- m2_normalize_metric(scored[[metric]], higher_is_better = metric_map[[metric]])
    weighted_parts[[metric]] <- scored[[col_name]] * defaults[[metric]]
    used_weights <- c(used_weights, defaults[[metric]])
  }

  if (length(weighted_parts) == 0) {
    scored$CompositeScore <- NA_real_
    scored$Rank <- seq_len(nrow(scored))
    return(scored)
  }

  weighted_matrix <- do.call(cbind, weighted_parts)
  if (is.null(dim(weighted_matrix))) {
    weighted_matrix <- matrix(weighted_matrix, ncol = 1L)
  }
  available_matrix <- !is.na(weighted_matrix)
  weight_vector <- used_weights[seq_len(ncol(weighted_matrix))]
  available_weight_sum <- rowSums(t(t(available_matrix) * weight_vector), na.rm = TRUE)
  weighted_sum <- rowSums(weighted_matrix, na.rm = TRUE)
  scored$CompositeScore <- ifelse(available_weight_sum > 0, weighted_sum / available_weight_sum, NA_real_)
  scored$Rank <- rank(-scored$CompositeScore, ties.method = "first", na.last = "keep")
  if ("Interpretability" %in% names(scored)) {
    scored$NarrativeScore <- (0.82 * scored$CompositeScore) + (0.18 * scored$Interpretability)
    scored$NarrativeRank <- rank(-scored$NarrativeScore, ties.method = "first", na.last = "keep")
  }
  scored[order(scored$Rank, scored$RMSE), , drop = FALSE]
}

#' Extract residual diagnostics in renderer-friendly shape
#' @keywords internal
m2_card_residual_payload <- function(card) {
  residuals <- m2_num_vec(card$residuals)
  if (length(residuals) == 0) {
    return(NULL)
  }

  lag_max <- min(10L, length(residuals) - 1L)
  acf_obj <- if (lag_max >= 1L) {
    tryCatch(stats::acf(residuals, plot = FALSE, lag.max = lag_max), error = function(e) NULL)
  } else {
    NULL
  }
  pacf_obj <- if (lag_max >= 1L) {
    tryCatch(stats::pacf(residuals, plot = FALSE, lag.max = lag_max), error = function(e) NULL)
  } else {
    NULL
  }

  list(
    residuals = residuals,
    shapiro_wilk = list(p_value = card$diagnostics$shapiro_p),
    durbin_watson = list(statistic = card$diagnostics$durbin_watson),
    breusch_pagan = list(p_value = card$diagnostics$breusch_pagan_p),
    acf = list(
      lags = if (is.null(acf_obj)) numeric(0) else as.numeric(acf_obj$lag[-1]),
      values = if (is.null(acf_obj)) numeric(0) else as.numeric(acf_obj$acf[-1])
    ),
    pacf = list(
      lags = if (is.null(pacf_obj)) numeric(0) else seq_along(as.numeric(pacf_obj$acf)),
      values = if (is.null(pacf_obj)) numeric(0) else as.numeric(pacf_obj$acf)
    )
  )
}
# <<< END FILE: R/module_m2/utils/m2_model_contract.R

# >>> BEGIN FILE: R/module_m2/utils/m2_model_registry.R
# ============================================================================
# m2_model_registry.R - Build unified model registries for M2
# ============================================================================

#' Build unified model registries for M2 diagnostics
#' @keywords internal
m2_build_model_registry <- function(m2_data, input, config = biblio_config()) {
  input <- m2_normalize_input(input)
  years <- m2_num_vec(input$Year)
  articles <- m2_num_vec(input$Articles)
  cumulative <- cumsum(articles)

  annual_models <- list()
  cumulative_models <- list()

  if (!is.null(m2_data$regression$models)) {
    annual_models <- c(annual_models, m2_data$regression$models)
  }

  if (!is.null(m2_data$forecasting) && identical(m2_data$forecasting$status, "success")) {
    annual_models <- c(
      annual_models,
      m2_build_forecasting_cards(m2_data$forecasting, years, articles)
    )
  }

  if (!is.null(m2_data$advanced_ts) && identical(m2_data$advanced_ts$status, "success")) {
    annual_models <- c(
      annual_models,
      m2_build_advanced_ts_cards(m2_data$advanced_ts, years, articles)
    )
  }

  if (!is.null(m2_data$growth_models) && identical(m2_data$growth_models$status, "success")) {
    cumulative_models <- c(
      cumulative_models,
      m2_build_growth_cards(m2_data$growth_models, years, cumulative)
    )
  }

  list(
    annual = annual_models,
    cumulative = cumulative_models,
    all = c(annual_models, cumulative_models)
  )
}

#' Convert forecasting outputs to canonical cards
#' @keywords internal
m2_build_forecasting_cards <- function(forecasting, years, articles) {
  cards <- list()
  horizon <- m2_coalesce_null(forecasting$horizon, 0)
  future_years <- if (horizon > 0) (max(years) + 1):(max(years) + horizon) else numeric(0)

  candidates <- list(
    ARIMA = forecasting$arima,
    ETS = forecasting$ets,
    Naive = forecasting$naive
  )

  for (nm in names(candidates)) {
    result <- candidates[[nm]]
    if (is.null(result) || !identical(result$status, "success")) {
      next
    }

    forecast_point <- if (!is.null(result$forecast) && !is.null(result$forecast$point)) {
      result$forecast$point
    } else if (horizon > 0) {
      generate_forecast(result, horizon)
    } else {
      numeric(0)
    }

    lower <- if (!is.null(result$forecast) && !is.null(result$forecast$lower)) result$forecast$lower else NULL
    upper <- if (!is.null(result$forecast) && !is.null(result$forecast$upper)) result$forecast$upper else NULL

    cards[[nm]] <- m2_new_model_card(
      name = nm,
      family = tolower(nm),
      years = years,
      actual = articles,
      fitted = result$fitted,
      model_object = NULL,
      forecast = m2_build_forecast_payload(
        point = forecast_point,
        years = future_years,
        lower = lower,
        upper = upper,
        method = tolower(nm)
      ),
      equation = nm,
      source = "forecasting",
      target = "annual",
      metadata = list(
        AIC = result$AIC,
        BIC = result$BIC,
        logLik = result$logLik,
        n_params = length(m2_coalesce_null(result$coefficients, m2_coalesce_null(result$parameters, numeric(0))))
      )
    )
  }

  if (!is.null(forecasting$ensemble) && identical(forecasting$ensemble$status, "success")) {
    ensemble_fitted <- m2_build_ensemble_fitted(forecasting)
    cards$Ensemble <- m2_new_model_card(
      name = "Ensemble",
      family = "ensemble",
      years = years,
      actual = articles,
      fitted = ensemble_fitted,
      model_object = NULL,
      forecast = m2_build_forecast_payload(
        point = forecasting$ensemble$forecast,
        years = forecasting$ensemble$years,
        method = "ensemble"
      ),
      equation = "Weighted ensemble forecast",
      source = "forecasting",
      target = "annual",
      metadata = list(
        AIC = if (!is.null(forecasting$model_comparison$comparison$AIC)) {
          mean(forecasting$model_comparison$comparison$AIC, na.rm = TRUE)
        } else {
          NA_real_
        },
        BIC = if (!is.null(forecasting$model_comparison$comparison$BIC)) {
          mean(forecasting$model_comparison$comparison$BIC, na.rm = TRUE)
        } else {
          NA_real_
        },
        n_params = 3
      )
    )
  }

  cards
}

#' Build fitted ensemble series from component fits
#' @keywords internal
m2_build_ensemble_fitted <- function(forecasting) {
  fitted_candidates <- list(
    arima = forecasting$arima$fitted,
    ets = forecasting$ets$fitted,
    naive = forecasting$naive$fitted
  )
  lengths <- vapply(fitted_candidates, length, integer(1))
  if (length(unique(lengths[lengths > 0])) != 1) {
    return(numeric(0))
  }

  weights <- forecasting$ensemble$weights
  if (is.null(weights) || length(weights) != 3) {
    weights <- rep(1 / 3, 3)
  }

  as.numeric(weights[1] * fitted_candidates$arima +
    weights[2] * fitted_candidates$ets +
    weights[3] * fitted_candidates$naive)
}

#' Convert advanced time-series outputs to canonical cards
#' @keywords internal
m2_build_advanced_ts_cards <- function(advanced_ts, years, articles) {
  cards <- list()
  model_names <- c("sarima", "tbats", "prophet", "state_space", "dynamic_regression")

  for (nm in model_names) {
    result <- advanced_ts[[nm]]
    if (is.null(result) || !identical(result$status, "success") || is.null(result$fitted)) {
      next
    }

    forecast_payload <- if (!is.null(result$forecast)) {
      m2_build_forecast_payload(
        point = m2_coalesce_null(result$forecast$point, result$forecast),
        years = result$forecast_years,
        lower = result$forecast$lower,
        upper = result$forecast$upper,
        method = nm
      )
    } else {
      m2_build_forecast_payload()
    }

    cards[[toupper(nm)]] <- m2_new_model_card(
      name = toupper(nm),
      family = nm,
      years = years,
      actual = articles,
      fitted = result$fitted,
      model_object = m2_coalesce_null(result$model, NULL),
      forecast = forecast_payload,
      equation = nm,
      source = "advanced_ts",
      target = "annual",
      metadata = list(
        AIC = result$AIC,
        BIC = result$BIC,
        logLik = result$logLik,
        n_params = length(m2_coalesce_null(result$coefficients, m2_coalesce_null(result$params, numeric(0))))
      )
    )
  }

  cards
}

#' Convert growth outputs to canonical cards
#' @keywords internal
m2_build_growth_cards <- function(growth_models, years, cumulative) {
  cards <- list()
  model_names <- c("bass", "gompertz", "weibull", "richards", "von_bertalanffy", "mmf")

  for (nm in model_names) {
    result <- growth_models[[nm]]
    if (is.null(result) || !identical(result$status, "success") || is.null(result$fitted)) {
      next
    }

    forecast_years <- seq(max(years) + 1, by = 1, length.out = 5)
    forecast_obj <- tryCatch(forecast_growth_model(result, forecast_years), error = function(e) NULL)
    cards[[toupper(nm)]] <- m2_new_model_card(
      name = toupper(nm),
      family = "growth",
      years = years,
      actual = cumulative,
      fitted = result$fitted,
      model_object = NULL,
      forecast = m2_build_forecast_payload(
        point = if (!is.null(forecast_obj$cumulative)) forecast_obj$cumulative else numeric(0),
        years = if (!is.null(forecast_obj$years)) forecast_obj$years else forecast_years,
        method = paste0(nm, "_growth")
      ),
      equation = nm,
      source = "growth_models",
      target = "cumulative",
      metadata = list(
        AIC = result$AIC,
        BIC = result$BIC,
        n_params = length(m2_coalesce_null(result$params, numeric(0)))
      )
    )
  }

  cards
}
# <<< END FILE: R/module_m2/utils/m2_model_registry.R

# >>> BEGIN FILE: R/module_m2/utils/m2_performance_tests.R
# ============================================================================
# module_m2/utils/m2_performance_tests.R - Full statistical tests
# ============================================================================

#' @export
m2_full_performance <- function(x, y, model) {
  preds <- tryCatch(predict(model), error = function(e) NULL)
  if (is.null(preds)) return(list())

  residuals <- y - preds
  std_resid <- if (sd(residuals) > 0) residuals / sd(residuals) else residuals

  list(
    model_fit = m2_compute_model_fit(y, preds, model),
    error_metrics = m2_compute_error_metrics(y, preds),
    normality_tests = m2_test_normality(residuals),
    heteroscedasticity_tests = m2_test_heteroscedasticity(model, residuals),
    autocorrelation_tests = m2_test_autocorrelation(model, residuals),
    linearity_tests = m2_test_linearity(model),
    residuals = round(residuals, 4),
    std_residuals = round(std_resid, 4)
  )
}

#' Model fit metrics
m2_compute_model_fit <- function(y, preds, model) {
  ss_res <- sum((y - preds)^2)
  ss_tot <- sum((y - mean(y))^2)
  r2 <- if (ss_tot > 0) 1 - ss_res / ss_tot else 0
  n <- length(y)
  p <- length(coef(model))
  adj_r2 <- 1 - (1 - r2) * (n - 1) / (n - p - 1)

  list(
    r2 = round(max(0, min(1, r2)), 6),
    adj_r2 = round(max(0, min(1, adj_r2)), 6),
    aic = tryCatch(AIC(model), error = function(e) NA),
    bic = tryCatch(BIC(model), error = function(e) NA)
  )
}

#' Error metrics
m2_compute_error_metrics <- function(y, preds) {
  residuals <- y - preds
  n <- length(y)

  list(
    mse = round(mean(residuals^2), 4),
    rmse = round(sqrt(mean(residuals^2)), 4),
    mae = round(mean(abs(residuals)), 4),
    mape = round(mean(abs(residuals / y[y != 0])) * 100, 2),
    rae = round(sum(abs(residuals)) / sum(abs(y - mean(y))), 4)
  )
}

#' Normality tests (5 tests)
m2_test_normality <- function(residuals) {
  list(
    shapiro_wilk = tryCatch({
      t <- shapiro.test(residuals)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    kolmogorov_smirnov = tryCatch({
      t <- ks.test(residuals, "pnorm", mean = mean(residuals), sd = sd(residuals))
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    jarque_bera = tryCatch({
      t <- tseries::jarque.bera.test(residuals)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    anderson_darling = tryCatch({
      t <- nortest::ad.test(residuals)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    cramer_von_mises = tryCatch({
      t <- nortest::cvm.test(residuals)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA))
  )
}

#' Heteroscedasticity tests (3 tests)
m2_test_heteroscedasticity <- function(model, residuals) {
  list(
    breusch_pagan = tryCatch({
      t <- lmtest::bptest(model)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    white = tryCatch({
      # Simplified White test using squared residuals
      n <- length(residuals)
      fit <- lm(residuals^2 ~ 1)
      list(statistic = summary(fit)$r.squared * n, p_value = NA)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    goldfeld_quandt = tryCatch({
      t <- lmtest::gqtest(model)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA))
  )
}

#' Autocorrelation tests (3 tests)
m2_test_autocorrelation <- function(model, residuals) {
  list(
    durbin_watson = tryCatch({
      t <- lmtest::dwtest(model)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    ljung_box = tryCatch({
      t <- Box.test(residuals, lag = 10, type = "Ljung-Box")
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    breusch_godfrey = tryCatch({
      t <- lmtest::bgtest(model, order = 1)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA))
  )
}

#' Linearity tests (2 tests)
m2_test_linearity <- function(model) {
  list(
    ramsey_reset = tryCatch({
      t <- lmtest::resettest(model)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA)),

    harvey_collier = tryCatch({
      t <- lmtest::harvtest(model)
      list(statistic = t$statistic, p_value = t$p.value)
    }, error = function(e) list(statistic = NA, p_value = NA))
  )
}

#' ACF of residuals
m2_compute_acf <- function(residuals, max_lag = 20) {
  acf_vals <- tryCatch(acf(residuals, plot = FALSE, lag.max = max_lag)$acf[-1], error = function(e) numeric(0))
  round(acf_vals, 4)
}
# <<< END FILE: R/module_m2/utils/m2_performance_tests.R

# >>> BEGIN FILE: R/module_m3/compute/m3_compute_change_points.R
# ============================================================================
# m3_compute_change_points.R - Change-point analysis for M3
# ============================================================================

#' Compute change-point analysis on country-level time series
#'
#' @param prepared_data Output from \code{prepare_m3_country_data}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list containing change-point metrics
#' @export
m3_compute_change_points <- function(prepared_data, config = biblio_config()) {
  # We need annual data for change-point analysis.
  country_annual <- prepared_data$country_annual
  country_annual_citations <- prepared_data$country_annual_citations
  
  # If we don't have annual data, we return an empty result.
  if (nrow(country_annual) == 0) {
    return(list(
      productivity_change_points = tibble::tibble(),
      citations_change_points = tibble::tibble(),
      change_point_summary = list(
        productivity = list(
          n_countries_analyzed = 0,
          n_change_points = 0
        ),
        citations = list(
          n_countries_analyzed = 0,
          n_change_points = 0
        )
      ),
      status = "success: no annual data available"
    ))
  }
  
  # We'll analyze the top N countries by total productivity over the entire period.
  total_prod_per_country <- country_annual %>%
    dplyr::group_by(country) %>%
    dplyr::summarise(
      total_articles = sum(article_count),
      .groups = "drop"
    ) %>%
    dplyr::arrange(desc(total_articles))
  
  top_n <- config$top_n_countries
  top_countries <- total_prod_per_country %>%
    dplyr::slice(1:min(top_n, nrow(.))) %>%
    dplyr::pull(country)
  
  # Filter annual data for top countries
  annual_productivity_top <- country_annual %>%
    dplyr::filter(country %in% top_countries) %>%
    dplyr::arrange(country, PY)
  
  # For citations, if we have the annual citations data
  if (nrow(country_annual_citations) > 0) {
    annual_citations_top <- country_annual_citations %>%
      dplyr::filter(country %in% top_countries) %>%
      dplyr::arrange(country, PY)
  } else {
    annual_citations_top <- tibble::tibble()
  }
  
  # Helper to detect change points in a time series for a country
  # We'll use a simple method: compare the mean of the first half and second half.
  # If the absolute difference exceeds a threshold (e.g., 1 standard deviation of the series), we flag a change point at the midpoint.
  # This is very simplistic and exploratory.
  # We'll only do this if the time series has at least 4 points.
  detect_change_point <- function(df, value_col) {
    # df should have columns: country, PY, and the value column
    # We'll return a tibble with one row per country that has a change point, or empty.
    
    results <- list()
    
    for (country in unique(df$country)) {
      country_data <- df %>%
        dplyr::filter(country == !!country) %>%
        dplyr::arrange(PY)
      
      n <- nrow(country_data)
      if (n < 4) {
        next
      }
      
      values <- country_data[[value_col]]
      split <- ceiling(n/2)
      first_half <- values[1:split]
      second_half <- values[(split+1):n]
      
      mean_first <- mean(first_half)
      mean_second <- mean(second_half)
      sd_total <- sd(values)
      
      if (is.na(sd_total) || sd_total == 0) {
        next
      }
      
      diff <- abs(mean_second - mean_first)
      if (diff > sd_total) {
        # Change point at the split
        cp_year <- if (split < n) {
          # We'll take the year at the split (the last year of the first half)
          country_data$PY[split]
        } else {
          NA_integer_
        }
        results[[country]] <- tibble::tibble(
          country = country,
          change_point_year = cp_year,
          mean_before = mean_first,
          mean_after = mean_second,
          absolute_difference = diff
        )
      }
    }
    
    if (length(results) == 0) {
      return(tibble::tibble())
    } else {
      return(dplyr::bind_rows(results))
    }
  }
  
  # Detect change points for productivity
  if (nrow(annual_productivity_top) > 0) {
    productivity_cp <- detect_change_point(annual_productivity_top, "article_count")
  } else {
    productivity_cp <- tibble::tibble()
  }
  
  # Detect change points for citations if data available
  if (nrow(annual_citations_top) > 0) {
    citations_cp <- detect_change_point(annual_citations_top, "total_citations")
  } else {
    citations_cp <- tibble::tibble()
  }
  
  # Change point summary
  change_point_summary <- list(
    productivity = list(
      n_countries_analyzed = length(top_countries),
      n_change_points = nrow(productivity_cp)
    ),
    citations = list(
      n_countries_analyzed = length(top_countries),
      n_change_points = nrow(citations_cp)
    )
  )
  
  return(list(
    productivity_change_points = productivity_cp,
    citations_change_points = citations_cp,
    change_point_summary = change_point_summary,
    status = "success"
  ))
}
# <<< END FILE: R/module_m3/compute/m3_compute_change_points.R

# >>> BEGIN FILE: R/module_m3/compute/m3_compute_citations.R
# ============================================================================
# m3_compute_citations.R - Citation metrics for M3
# ============================================================================

#' Compute country citation metrics
#'
#' @param prepared_data Output from \code{prepare_m3_country_data}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list containing citation metrics
#' @export
m3_compute_citations <- function(prepared_data, config = biblio_config()) {
  # Extract the country summary (which includes article_count and total_citations)
  country_summary <- prepared_data$country_summary
  
  if (nrow(country_summary) == 0) {
    return(list(
      country_citations = tibble::tibble(),
      top_countries_by_citations = tibble::tibble(),
      top_countries_by_avg_citations = tibble::tibble(),
      citation_summary = list(
        total_citations = 0,
        total_countries = 0,
        gini_citations = NA_real_
      ),
      status = "error: no country data"
    ))
  }
  
  # Ensure we have total_citations column (should be present from preparation)
  if (!"total_citations" %in% names(country_summary)) {
    # If for some reason it's missing, set to 0
    country_summary <- country_summary %>%
      dplyr::mutate(total_citations = 0)
  }
  
  # Compute average citations per country
  country_summary <- country_summary %>%
    dplyr::mutate(
      average_citations = ifelse(article_count > 0, total_citations / article_count, 0)
    )
  
  # Total citations and number of countries
  total_citations <- sum(country_summary$total_citations)
  total_countries <- nrow(country_summary)
  
  # Compute Gini coefficient for citations
  # Sort by total_citations ascending for Lorenz
  sorted_citations <- sort(country_summary$total_citations)
  n <- length(sorted_citations)
  if (n == 0) {
    gini_citations <- NA_real_
  } else {
    # Cumulative proportion of countries
    cum_prop_countries <- (1:n) / n
    # Cumulative proportion of citations
    cum_prop_citations <- cumsum(sorted_citations) / sum(sorted_citations)
    # Area under Lorenz curve (trapezoidal rule)
    auc <- 0
    for (i in 2:n) {
      auc <- auc + (cum_prop_countries[i] - cum_prop_countries[i-1]) * (cum_prop_citations[i] + cum_prop_citations[i-1]) / 2
    }
    gini_citations <- 1 - 2 * auc
  }
  
  # Prepare the country citations table (full table with averages)
  country_citations <- country_summary %>%
    dplyr::arrange(desc(total_citations)) %>%
    dplyr::transmute(
      country = country,
      article_count = article_count,
      total_citations = total_citations,
      average_citations = average_citations
    )
  
  # Top N countries by total citations
  top_n <- config$top_n_countries
  top_countries_by_citations <- country_summary %>%
    dplyr::arrange(desc(total_citations)) %>%
    dplyr::slice(1:min(top_n, nrow(.))) %>%
    dplyr::transmute(
      rank = dplyr::row_number(),
      label = country,
      value = total_citations
    )
  
  # Top N countries by average citations (only those with at least 1 article, which is all)
  top_countries_by_avg_citations <- country_summary %>%
    dplyr::arrange(desc(average_citations)) %>%
    dplyr::slice(1:min(top_n, nrow(.))) %>%
    dplyr::transmute(
      rank = dplyr::row_number(),
      label = country,
      value = average_citations
    )
  
  # Citation summary
  citation_summary <- list(
    total_citations = total_citations,
    total_countries = total_countries,
    gini_citations = gini_citations
  )
  
  return(list(
    country_citations = country_citations,
    top_countries_by_citations = top_countries_by_citations,
    top_countries_by_avg_citations = top_countries_by_avg_citations,
    citation_summary = citation_summary,
    status = "success"
  ))
}
# <<< END FILE: R/module_m3/compute/m3_compute_citations.R

# >>> BEGIN FILE: R/module_m3/compute/m3_compute_collaboration_indices.R
# ============================================================================
# m3_compute_collaboration_indices.R - Country Collaboration Indices
# ============================================================================
# Computes collaboration indices for countries:
# - Salton's Index (cosine similarity)
# - Jaccard Index (intersection over union)
# - Affinity Index (publications ratio)
# - Collaboration Intensity Index
#
# IEEE Q1 Enhancement: Comprehensive bilateral collaboration metrics
# following advanced bibliometric methodologies.

#' Compute collaboration indices between countries
#'
#' @param prepared_data Output from prepare_m3_country_data
#' @param config Configuration list
#' @return List with collaboration indices
#' @export
compute_m3_collaboration_indices <- function(prepared_data, config = biblio_config()) {
  if (is.null(prepared_data) || prepared_data$status != "success") {
    return(list(
      indices = data.frame(),
      bilateral = data.frame(),
      summary = list(),
      status = "error: invalid prepared_data"
    ))
  }
  
  doc_country <- prepared_data$country_doc_level
  if (is.null(doc_country) || nrow(doc_country) == 0) {
    return(list(
      indices = data.frame(),
      bilateral = data.frame(),
      summary = list(),
      status = "error: no country data available"
    ))
  }
  
  collab_matrix <- build_collaboration_matrix(doc_country)
  
  if (is.null(collab_matrix) || nrow(collab_matrix) == 0) {
    return(list(
      indices = data.frame(),
      bilateral = data.frame(),
      summary = list(),
      status = "error: could not build collaboration matrix"
    ))
  }
  
  country_totals <- get_country_totals(doc_country)
  
  salton_matrix <- compute_salton_index(collab_matrix, country_totals)
  
  jaccard_matrix <- compute_jaccard_index(collab_matrix, country_totals)
  
  affinity_matrix <- compute_affinity_index(collab_matrix, country_totals)
  
  collaboration_intensity <- compute_collaboration_intensity(collab_matrix, country_totals)
  
  bilateral_collabs <- extract_bilateral_collaborations(
    salton_matrix, jaccard_matrix, affinity_matrix, country_totals
  )
  
  country_indices <- compile_country_indices(
    salton_matrix, jaccard_matrix, affinity_matrix, country_totals
  )
  
  summary_stats <- list(
    total_countries = nrow(country_totals),
    total_collaborations = sum(collab_matrix[upper.tri(collab_matrix)]),
    mean_salton = mean(salton_matrix[upper.tri(salton_matrix)], na.rm = TRUE),
    mean_jaccard = mean(jaccard_matrix[upper.tri(jaccard_matrix)], na.rm = TRUE),
    mean_affinity = mean(affinity_matrix[upper.tri(affinity_matrix)], na.rm = TRUE),
    top_collaborators = if (is.data.frame(bilateral_collabs) && nrow(bilateral_collabs) > 0 && "salton" %in% names(bilateral_collabs)) {
      head(bilateral_collabs[order(-bilateral_collabs$salton), , drop = FALSE], 10)
    } else {
      data.frame()
    },
    collaboration_density = {
      possible_pairs <- nrow(collab_matrix) * (nrow(collab_matrix) - 1) / 2
      if (is.finite(possible_pairs) && possible_pairs > 0) {
        sum(collab_matrix[upper.tri(collab_matrix)] > 0) / possible_pairs
      } else {
        0
      }
    }
  )
  
  list(
    indices = country_indices,
    bilateral = bilateral_collabs,
    summary = summary_stats,
    salton_matrix = salton_matrix,
    jaccard_matrix = jaccard_matrix,
    affinity_matrix = affinity_matrix,
    status = "success"
  )
}

#' Build collaboration matrix
#' @keywords internal
build_collaboration_matrix <- function(doc_country) {
  doc_id_valid <- !is.na(doc_country$doc_id) & !is.na(doc_country$country)
  
  if (sum(doc_id_valid) == 0) return(NULL)
  
  valid_data <- doc_country[doc_id_valid, ]
  
  docs_per_country <- split(valid_data$country, valid_data$doc_id)
  
  countries <- sort(unique(valid_data$country))
  n_countries <- length(countries)
  
  collab_matrix <- matrix(0, nrow = n_countries, ncol = n_countries,
                          dimnames = list(countries, countries))
  
  for (doc_id in names(docs_per_country)) {
    doc_countries <- unique(docs_per_country[[doc_id]])
    if (length(doc_countries) > 1) {
      for (i in 1:length(doc_countries)) {
        for (j in 1:length(doc_countries)) {
          c_i <- which(rownames(collab_matrix) == doc_countries[i])
          c_j <- which(colnames(collab_matrix) == doc_countries[j])
          if (length(c_i) > 0 && length(c_j) > 0) {
            collab_matrix[c_i, c_j] <- collab_matrix[c_i, c_j] + 1
          }
        }
      }
    }
  }
  
  collab_matrix
}

#' Get country totals
#' @keywords internal
get_country_totals <- function(doc_country) {
  doc_id_valid <- !is.na(doc_country$doc_id) & !is.na(doc_country$country)
  valid_data <- doc_country[doc_id_valid, ]
  
  totals <- aggregate(doc_id ~ country, data = valid_data, FUN = function(x) length(unique(x)))
  names(totals) <- c("country", "n_documents")
  
  totals[order(-totals$n_documents), ]
}

#' Compute Salton's Index (cosine similarity)
#' @keywords internal
compute_salton_index <- function(collab_matrix, country_totals) {
  n <- nrow(collab_matrix)
  salton <- matrix(0, nrow = n, ncol = n,
                   dimnames = dimnames(collab_matrix))
  
  doc_counts <- setNames(country_totals$n_documents, country_totals$country)
  
  for (i in 1:n) {
    for (j in 1:n) {
      if (i != j) {
        country_i <- rownames(collab_matrix)[i]
        country_j <- colnames(collab_matrix)[j]
        
        n_ij <- collab_matrix[i, j]
        
        n_i <- if (country_i %in% names(doc_counts)) doc_counts[country_i] else 1
        n_j <- if (country_j %in% names(doc_counts)) doc_counts[country_j] else 1
        
        denominator <- sqrt(n_i * n_j)
        
        salton[i, j] <- if (denominator > 0) {
          n_ij / denominator
        } else {
          0
        }
      }
    }
  }
  
  salton
}

#' Compute Jaccard Index
#' @keywords internal
compute_jaccard_index <- function(collab_matrix, country_totals) {
  n <- nrow(collab_matrix)
  jaccard <- matrix(0, nrow = n, ncol = n,
                    dimnames = dimnames(collab_matrix))
  
  doc_counts <- setNames(country_totals$n_documents, country_totals$country)
  
  for (i in 1:n) {
    for (j in 1:n) {
      if (i != j) {
        country_i <- rownames(collab_matrix)[i]
        country_j <- colnames(collab_matrix)[j]
        
        n_ij <- collab_matrix[i, j]
        
        n_i <- if (country_i %in% names(doc_counts)) doc_counts[country_i] else 1
        n_j <- if (country_j %in% names(doc_counts)) doc_counts[country_j] else 1
        
        union_count <- n_i + n_j - n_ij
        
        jaccard[i, j] <- if (union_count > 0) {
          n_ij / union_count
        } else {
          0
        }
      }
    }
  }
  
  jaccard
}

#' Compute Affinity Index
#' @keywords internal
compute_affinity_index <- function(collab_matrix, country_totals) {
  n <- nrow(collab_matrix)
  affinity <- matrix(0, nrow = n, ncol = n,
                     dimnames = dimnames(collab_matrix))
  
  doc_counts <- setNames(country_totals$n_documents, country_totals$country)
  
  for (i in 1:n) {
    for (j in 1:n) {
      if (i != j) {
        country_i <- rownames(collab_matrix)[i]
        country_j <- colnames(collab_matrix)[j]
        
        n_ij <- collab_matrix[i, j]
        
        n_i <- if (country_i %in% names(doc_counts)) doc_counts[country_i] else 1
        
        affinity[i, j] <- if (n_i > 0) {
          n_ij / n_i
        } else {
          0
        }
      }
    }
  }
  
  affinity
}

#' Compute Collaboration Intensity
#' @keywords internal
compute_collaboration_intensity <- function(collab_matrix, country_totals) {
  n <- nrow(collab_matrix)
  intensity <- matrix(0, nrow = n, ncol = n,
                      dimnames = dimnames(collab_matrix))
  
  total_collabs <- sum(collab_matrix) - sum(diag(collab_matrix))
  
  for (i in 1:n) {
    for (j in 1:n) {
      if (i != j) {
        n_ij <- collab_matrix[i, j]
        intensity[i, j] <- if (total_collabs > 0) {
          n_ij / total_collabs
        } else {
          0
        }
      }
    }
  }
  
  intensity
}

#' Extract bilateral collaborations
#' @keywords internal
extract_bilateral_collaborations <- function(salton, jaccard, affinity, country_totals) {
  n <- nrow(salton)
  countries <- rownames(salton)

  if (is.null(n) || n < 2) {
    return(data.frame())
  }
  
  pairs <- expand.grid(i = 1:n, j = 1:n)
  pairs <- pairs[pairs$i < pairs$j, ]
  
  if (nrow(pairs) == 0) {
    return(data.frame())
  }
  
  bilateral_list <- lapply(1:nrow(pairs), function(k) {
    i <- pairs$i[k]
    j <- pairs$j[k]
    
    data.frame(
      country_1 = countries[i],
      country_2 = countries[j],
      salton = salton[i, j],
      jaccard = jaccard[i, j],
      affinity_1to2 = affinity[i, j],
      affinity_2to1 = affinity[j, i]
    )
  })
  
  result <- do.call(rbind, bilateral_list)
  
  result$avg_affinity <- (result$affinity_1to2 + result$affinity_2to1) / 2
  
  result[order(-result$salton), ]
}

#' Compile country-level indices
#' @keywords internal
compile_country_indices <- function(salton, jaccard, affinity, country_totals) {
  countries <- rownames(salton)
  
  n_countries <- length(countries)
  
  indices_list <- lapply(1:n_countries, function(i) {
    country <- countries[i]
    
    n_docs <- if (country %in% country_totals$country) {
      country_totals$n_documents[country_totals$country == country]
    } else {
      0
    }
    
    peers_salton <- salton[i, -i]
    peers_jaccard <- jaccard[i, -i]
    peers_affinity <- affinity[i, -i]

    top_salton_partner_idx <- if (length(peers_salton) > 0 && any(is.finite(peers_salton))) which.max(peers_salton) else integer(0)
    top_salton_partner <- if (length(top_salton_partner_idx) > 0) {
      countries[-i][top_salton_partner_idx]
    } else {
      NA_character_
    }
    
    top_jaccard_partner_idx <- if (length(peers_jaccard) > 0 && any(is.finite(peers_jaccard))) which.max(peers_jaccard) else integer(0)
    top_jaccard_partner <- if (length(top_jaccard_partner_idx) > 0) {
      countries[-i][top_jaccard_partner_idx]
    } else {
      NA_character_
    }
    
    avg_salton <- if (length(peers_salton) > 0) mean(peers_salton, na.rm = TRUE) else NA_real_
    avg_jaccard <- if (length(peers_jaccard) > 0) mean(peers_jaccard, na.rm = TRUE) else NA_real_
    avg_affinity <- if (length(peers_affinity) > 0) mean(peers_affinity, na.rm = TRUE) else NA_real_
    
    max_salton <- if (length(peers_salton) > 0 && any(is.finite(peers_salton))) max(peers_salton, na.rm = TRUE) else NA_real_
    max_jaccard <- if (length(peers_jaccard) > 0 && any(is.finite(peers_jaccard))) max(peers_jaccard, na.rm = TRUE) else NA_real_
    max_affinity <- if (length(peers_affinity) > 0 && any(is.finite(peers_affinity))) max(peers_affinity, na.rm = TRUE) else NA_real_
    
    data.frame(
      country = country,
      n_documents = n_docs,
      avg_salton_index = avg_salton,
      max_salton_index = max_salton,
      top_salton_partner = top_salton_partner,
      avg_jaccard_index = avg_jaccard,
      max_jaccard_index = max_jaccard,
      top_jaccard_partner = top_jaccard_partner,
      avg_affinity_index = avg_affinity,
      max_affinity_index = max_affinity,
      collaboration_centrality = if (n_countries > 1) sum(salton[i, ], na.rm = TRUE) / (n_countries - 1) else 0
    )
  })
  
  result <- do.call(rbind, indices_list)

  result <- result[order(-result$n_documents), ]
  result$article_count <- result$n_documents
  total_documents <- sum(result$article_count, na.rm = TRUE)
  result$share <- if (is.finite(total_documents) && total_documents > 0) {
    result$article_count / total_documents
  } else {
    0
  }
  result$rank <- seq_len(nrow(result))

  result
}
# <<< END FILE: R/module_m3/compute/m3_compute_collaboration_indices.R

# >>> BEGIN FILE: R/module_m3/compute/m3_compute_country_profiles.R
# ============================================================================
# m3_compute_country_profiles.R - Country profile modeling for M3
# ============================================================================

#' Compute country profiles using multivariate data science techniques
#'
#' @param prepared_data Output from \code{prepare_m3_country_data}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list containing country profile metrics
#' @export
m3_compute_country_profiles <- function(prepared_data, config = biblio_config()) {
  # We need to build a feature matrix for each country.
  # We'll start with the country summary and then add features from other computations if available.
  # However, to keep this function self-contained, we'll compute the base features from the prepared data.
  # We can also use the results from other compute functions if we want to avoid recomputation, but for now we'll compute from prepared_data.
  
  country_summary <- prepared_data$country_summary
  
  if (nrow(country_summary) == 0) {
    return(list(
      country_features = tibble::tibble(),
      country_profiles = tibble::tibble(),
      pca_info = list(),
      clustering_info = list(),
      profile_summary = list(
        n_countries = 0,
        n_features = 0,
        clustering_performed = FALSE
      ),
      status = "error: no country data"
    ))
  }
  
  # Ensure we have the necessary columns
  if (!"article_count" %in% names(country_summary)) {
    country_summary <- country_summary %>%
      dplyr::mutate(article_count = 0)
  }
  if (!"total_citations" %in% names(country_summary)) {
    country_summary <- country_summary %>%
      dplyr::mutate(total_citations = 0)
  }
  if (!"average_citations" %in% names(country_summary)) {
    # We can compute it if we have article_count and total_citations
    country_summary <- country_summary %>%
      dplyr::mutate(average_citations = ifelse(article_count > 0, total_citations / article_count, 0))
  }
  
  # We also want SCP and MCP if available. However, the prepared_data does not have SCP/MCP by country.
  # We have two options:
  #   1. Compute SCP/MCP in this function (by calling the SCP/MCP computation or reusing the logic).
  #   2. Change the preparation function to include SCP/MCP by country.
  #
  # Since we are building the module, we can change the preparation function to include SCP/MCP by country.
  # But note: we have already written the preparation function and we are in the middle of the task.
  #
  # Alternatively, we can compute SCP/MCP here by reusing the logic from m3_compute_scp_mcp, but that would require the country-doc level data.
  # We have the country-doc level data in prepared_data.
  #
  # Let's compute SCP and MCP by country from the country-doc level data (which we have in prepared_data$country_doc_level).
  # We'll do a similar computation as in m3_compute_scp_mcp but just to get the SCP and MCP counts per country.
  #
  # We'll compute:
  #   scp: number of documents where the country is the only country
  #   mcp: number of documents where the country is one of multiple countries
  #
  # We'll use the country_doc_level data.
  
  country_doc_level <- prepared_data$country_doc_level
  
  if (nrow(country_doc_level) > 0) {
    # Compute the number of countries per document
    doc_country_counts <- country_doc_level %>%
      dplyr::group_by(doc_id) %>%
      dplyr::summarise(
        n_countries = dplyr::n_distinct(country),
        .groups = "drop"
      )
    
    # SCP documents: n_countries == 1
    scp_documents <- doc_country_counts %>%
      dplyr::filter(n_countries == 1) %>%
      dplyr::inner_join(country_doc_level, by = "doc_id") %>%
      dplyr::group_by(country) %>%
      dplyr::summarise(
        scp = dplyr::n(),
        .groups = "drop"
      )
    
    # MCP documents: n_countries > 1
    mcp_documents <- doc_country_counts %>%
      dplyr::filter(n_countries > 1) %>%
      dplyr::inner_join(country_doc_level, by = "doc_id") %>%
      dplyr::group_by(country) %>%
      dplyr::summarise(
        mcp = dplyr::n(),
        .groups = "drop"
      )
    
    # Now we want to join these with the country_summary
    country_summary <- country_summary %>%
      dplyr::left_join(scp_documents, by = "country") %>%
      dplyr::left_join(mcp_documents, by = "country") %>%
      dplyr::mutate(
        scp = dplyr::coalesce(scp, 0),
        mcp = dplyr::coalesce(mcp, 0)
      )
  } else {
    # If we don't have country-doc level data, set SCP and MCP to 0
    country_summary <- country_summary %>%
      dplyr::mutate(
        scp = 0,
        mcp = 0
      )
  }
  
  # Compute MCP ratio
  country_summary <- country_summary %>%
    dplyr::mutate(
      mcp_ratio = ifelse((scp + mcp) > 0, round(mcp / (scp + mcp) * 100, 1), NA_real_)
    )
  
  # Now we have the base features: article_count, total_citations, average_citations, scp, mcp, mcp_ratio
  # We can also add growth features if we have annual data and if the user wants to include them.
  # However, the task says we should implement growth dynamics where data supports it.
  # We can optionally include growth features (like CAGR) if annual data is available.
  # We'll check if we have annual data in prepared_data.
  
  # We'll prepare a feature matrix for the countries.
  # We'll select the features we want to include in the profiling.
  # We'll include:
  #   - article_count (productivity)
  #   - total_citations (impact)
  #   - average_citations (impact efficiency)
  #   - scp (collaboration: solo)
  #   - mcp (collaboration: multiple)
  #   - mcp_ratio (collaboration: proportion of multiple)
  #
  # We'll also consider adding growth features if annual data is available and if the number of years is sufficient.
  # But note: the task says we should not add fake complexity. We'll only add growth features if we have annual data and if we are computing growth dynamics.
  # However, to keep the profile stable, we might not include growth features in the profiling by default.
  # We'll leave it as an option in the config.
  
  # For now, we'll stick to the base features.
  # We'll create a feature tibble with these variables.
  
  country_features <- country_summary %>%
    dplyr::select(
      country,
      article_count,
      total_citations,
      average_citations,
      scp,
      mcp,
      mcp_ratio
    )
  
  # Now we want to standardize the features (z-score) for multivariate analysis.
  # We'll exclude the country column.
  feature_columns <- c("article_count", "total_citations", "average_citations", "scp", "mcp", "mcp_ratio")
  
  # Check if we have any non-zero variance in the features (if all zeros, we cannot standardize)
  # We'll compute the mean and sd for each feature, and if sd is 0, we set the standardized value to 0 (or NA?).
  # We'll set to 0 if sd is 0 (meaning all values are the same).
  
  # We'll create a standardized version of the features.
  country_features_z <- country_features %>%
    dplyr::mutate(
      dplyr::across(
        .cols  = dplyr::all_of(feature_columns),
        .fns   = ~ {
          s <- sd(.x, na.rm = TRUE)
          if (is.na(s) || s == 0) 0
          else (.x - mean(.x, na.rm = TRUE)) / s
        },
        .names = "{.col}_z"
      )
    )
  
  # Now we have the standardized features. We can optionally perform PCA and clustering.
  # We'll do PCA if we have at least 2 countries and 2 features.
  # We'll do clustering (k-means) if we have at least 2 countries and we want to get profiles.
  # However, note that the task says we should choose the simplest defensible method.
  # We'll do:
  #   - PCA for dimensionality reduction and to get a sense of the data structure.
  #   - Hierarchical clustering or k-means to get discrete profiles, but we will only do this if the number of countries is sufficient (e.g., > 5).
  #
  # We'll record in the diagnostics if we skip clustering due to insufficient data.
  
  # Prepare the PCA and clustering results.
  pca_info <- list()
  clustering_info <- list()
  
  # We'll only attempt PCA and clustering if we have at least 2 countries and 2 features with non-zero variance.
  # We'll check the number of countries and the number of features that have variance > 0.
  
  # Extract the standardized feature matrix (without country)
  feature_matrix <- country_features_z %>%
    dplyr::select(dplyr::all_of(paste0(feature_columns, "_z"))) %>%
    as.matrix()
  
  # Check if we have enough data for PCA and clustering
  n_countries <- nrow(country_features)
  n_features <- ncol(feature_matrix)
  
  # We'll consider that we need at least 2 countries and 2 features to do PCA.
  # For clustering, we'll need at least 2 countries and we'll set a minimum of 5 countries to attempt clustering (to avoid too many clusters).
  
  if (n_countries >= 2 && n_features >= 2) {
    # Perform PCA
    pca <- tryCatch({
      prcomp(feature_matrix, center = FALSE, scale. = FALSE) # Already centered and scaled
    }, error = function(e) {
      NULL
    })
    
    if (!is.null(pca)) {
      pca_info <- list(
        sdev = pca$sdev,
        rotation = pca$rotation,
        center = pca$center,
        scale = pca$scale,
        n_components = ncol(pca$rotation)
      )
      
      # We can also add the PCA scores (coordinates) to the country features if we want.
      # We'll add the first two principal components as new columns.
      pca_scores <- predict(pca, newdata = feature_matrix)
      country_features_z <- country_features_z %>%
        dplyr::mutate(
          PC1 = pca_scores[, 1],
          PC2 = if (ncol(pca_scores) >= 2) pca_scores[, 2] else NA_real_
        )
    }
  }
  
  # Clustering: we'll do k-means if we have at least 5 countries and we have PCA scores (or the standardized features).
  # We'll choose the number of clusters using the elbow method or a fixed small number (e.g., 3) for simplicity.
  # But note: we should not invent fancy ML if the data size is tiny.
  # We'll do:
  #   - If n_countries >= 5, we'll attempt k-means with k = min(3, floor(n_countries/2)) but at least 2.
  #   - We'll set k to 2 if n_countries is between 2 and 4, but we'll note that clustering with 2 countries is trivial.
  #   - We'll only do clustering if n_countries >= 2 and we have at least 2 features.
  #   - We'll use the standardized features (or the PCA scores if we want to reduce dimension) for clustering.
  #
  # We'll use the first two principal components if PCA was successful and we have at least 2 PCs, otherwise we use the standardized features.
  #
  # We'll record the clustering only if we perform it and if we consider it meaningful.
  #
  # We'll set a flag for whether clustering was performed.
  
  clustering_performed <- FALSE
  k <- NA_integer_
  cluster_assignments <- NA_integer_
  
  if (n_countries >= 2 && n_features >= 2) {
    # Determine the data to use for clustering: if we have PCA and at least 2 PCs, use the first 2 PCs.
    # Otherwise, use the standardized features.
    if (!is.null(pca_info) && !is.null(pca_info$n_components) && pca_info$n_components >= 2) {
      # Use the first two principal components
      clustering_data <- country_features_z %>%
        dplyr::select(PC1, PC2) %>%
        as.matrix()
    } else {
      # Use the standardized features
      clustering_data <- feature_matrix
    }
    
    # We'll attempt k-means with k from 1 to min(5, n_countries-1) and choose the k that minimizes the within-cluster sum of squares?
    # But we want to keep it simple. We'll fix k to 2 if n_countries >= 2, but we'll note that we are doing this for demonstration.
    # Alternatively, we can use the elbow method, but that is more complex.
    #
    # We'll do: if n_countries >= 5, we'll try k=3 and k=4 and choose the one with the better silhouette score? 
    # But we don't want to add too much complexity.
    #
    # We'll keep it simple: we'll set k = 2 if n_countries >= 2, and we'll note that this is for getting two profiles (high and low).
    # However, we must be cautious: with two clusters, we are splitting the data into two groups.
    #
    # We'll do:
    #   k <- 2
    #   But we will only perform clustering if n_countries >= 5? Actually, we can do it for any n_countries >= 2, but we'll record a warning if n_countries is small.
    #
    # We'll set k = 2 and perform k-means.
    #
    # We'll also compute the within-cluster sum of squares to see if the clustering is meaningful.
    #
    # We'll do:
    k <- 2
    set.seed(123) # for reproducibility
    kmeans_result <- tryCatch({
      kmeans(clustering_data, centers = k, nstart = 10)
    }, error = function(e) {
      NULL
    })
    
    if (!is.null(kmeans_result)) {
      clustering_performed <- TRUE
      cluster_assignments <- kmeans_result$cluster
      # We'll add the cluster assignments to the country features
      country_features_z <- country_features_z %>%
        dplyr::mutate(cluster = as.factor(cluster_assignments))
      
      clustering_info <- list(
        k = k,
        within_ss = kmeans_result$tot.withinss,
        size = kmeans_result$size,
        centers = kmeans_result$centers
      )
    }
  }
  
  # Now we have the country features with standardized values and optionally PCA scores and cluster assignments.
  # We want to return the country profiles. We'll define the country profiles as the country features with the cluster assignments (if performed) and the PCA scores (if available).
  #
  # We'll return:
  #   - country_features: the original features (with country)
  #   - country_profiles: the features with standardized values, PCA scores, and cluster assignments (if available)
  #   - pca_info: the PCA results
  #   - clustering_info: the clustering results
  #   - profile_summary: a summary of the profiling step
  #
  # We'll also note in the profile summary if clustering was performed and if PCA was performed.
  
  country_profiles <- country_features_z
  
  profile_summary <- list(
    n_countries = n_countries,
    n_features = n_features,
    pca_performed = !is.null(pca_info),
    clustering_performed = clustering_performed,
    k_for_clustering = ifelse(clustering_performed, k, NA_integer_)
  )
  
  return(list(
    country_features = country_features,
    country_profiles = country_profiles,
    pca_info = pca_info,
    clustering_info = clustering_info,
    profile_summary = profile_summary,
    status = "success"
  ))
}
# <<< END FILE: R/module_m3/compute/m3_compute_country_profiles.R

