#' Aggregate countries by region
#'
#' @param country_data Data frame with country, value columns
#' @param group_by Which regional grouping ("continent", "OECD", "BRICS", etc.)
#' @return List with aggregated data
#' @export
m3_aggregate_by_region <- function(country_data, group_by = "continent") {
  if (!is.data.frame(country_data) || !"country" %in% names(country_data)) {
    return(list(status = "error: invalid input"))
  }

  if (!"article_count" %in% names(country_data) && "value" %in% names(country_data)) {
    country_data$article_count <- country_data$value
  }
  if (!"value" %in% names(country_data) && "article_count" %in% names(country_data)) {
    country_data$value <- country_data$article_count
  }
  
  # Normalize country names
  country_data$country_norm <- toupper(trimws(as.character(country_data$country)))
  
  # Select grouping
  if (tolower(group_by) == "continent") {
    groups <- REGIONAL_GROUPS[c("Africa", "Asia", "Europe", "North America", 
                                "South America", "Oceania")]
  } else if (group_by %in% names(REGIONAL_GROUPS)) {
    groups <- REGIONAL_GROUPS[group_by]
  } else {
    return(list(status = "error: unknown grouping"))
  }
  
  # Aggregate
  aggregated <- list()
  unassigned <- country_data
  
  for (region_name in names(groups)) {
    countries_in_region <- groups[[region_name]]
    
    # Find matches
    matches <- unassigned$country_norm %in% countries_in_region
    region_data <- unassigned[matches, , drop = FALSE]
    
    if (nrow(region_data) > 0) {
      # Aggregate metrics
      region_summary <- list(
        region = region_name,
        n_countries = nrow(region_data),
        countries = unique(region_data$country),
        total_production = sum(region_data$value, na.rm = TRUE)
      )
      
      # Add other numeric columns
      numeric_cols <- sapply(country_data, is.numeric)
      numeric_cols <- setdiff(names(numeric_cols)[numeric_cols], "value")
      
      for (col in numeric_cols) {
        if (col %in% names(region_data)) {
          region_summary[[paste0("total_", col)]] <- sum(region_data[[col]], na.rm = TRUE)
          region_summary[[paste0("mean_", col)]] <- mean(region_data[[col]], na.rm = TRUE)
        }
      }
      
      aggregated[[region_name]] <- region_summary
      unassigned <- unassigned[!matches, , drop = FALSE]
    }
  }
  
  if (length(aggregated) == 0) {
    return(list(
      aggregated = list(),
      summary = tibble::tibble(
        region = character(),
        n_countries = integer(),
        total_production = numeric(),
        share = numeric()
      ),
      unassigned = if (nrow(unassigned) > 0) unassigned$country else character(0),
      n_unassigned = nrow(unassigned),
      n_regions = 0L,
      group_by = group_by,
      status = "success"
    ))
  }

  # Create summary data frame
  summary_df <- do.call(rbind, lapply(aggregated, function(x) {
    data.frame(
      region = x$region,
      n_countries = x$n_countries,
      total_production = x$total_production,
      stringsAsFactors = FALSE
    )
  }))
  
  # Calculate shares
  total_all <- sum(summary_df$total_production)
  summary_df$share <- if (total_all > 0) summary_df$total_production / total_all * 100 else 0
  
  list(
    aggregated = aggregated,
    summary = summary_df,
    unassigned = if (nrow(unassigned) > 0) unassigned$country else character(0),
    n_unassigned = nrow(unassigned),
    n_regions = length(aggregated),
    group_by = group_by,
    status = "success"
  )
}

#' Compute regional comparisons
#'
#' @param regional_data Output from m3_aggregate_by_region
#' @return List with comparative statistics
#' @export
m3_regional_comparison <- function(regional_data) {
  if (is.null(regional_data) || regional_data$status != "success") {
    return(list(status = "error: invalid input"))
  }
  
  summary <- regional_data$summary
  
  if (nrow(summary) < 2) {
    return(list(status = "error: need at least 2 regions"))
  }
  
  # Top region
  top_region <- summary$region[which.max(summary$total_production)]
  top_share <- max(summary$share)
  
  # Regional concentration
  gini_regional <- safe_gini(summary$total_production)
  
  # Statistical tests
  # Chi-square test for equal distribution
  expected <- rep(sum(summary$total_production) / nrow(summary), nrow(summary))
  chi_test <- suppressWarnings(chisq.test(summary$total_production, p = expected / sum(expected)))
  
  # Growth comparison (if year data available)
  growth_comparison <- list()
  
  list(
    top_region = top_region,
    top_share = top_share,
    regional_concentration = gini_regional,
    chi_square_test = list(
      statistic = chi_test$statistic,
      p_value = chi_test$p.value,
      significant = chi_test$p.value < 0.05
    ),
    dominance_ratio = max(summary$total_production) / min(summary$total_production[summary$total_production > 0]),
    n_regions = nrow(summary),
    status = "success"
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m3/compute/m3_compute_regional.R

# >>> BEGIN FILE: R/module_m3/compute/m3_compute_scp_mcp.R
# ============================================================================
# m3_compute_scp_mcp.R - SCP/MCP metrics for M3
# ============================================================================

#' Compute SCP (Single Country Publications) and MCP (Multiple Country Publications) metrics
#'
#' @param prepared_data Output from \code{prepare_m3_country_data}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list containing SCP/MCP metrics
#' @export
m3_compute_scp_mcp <- function(prepared_data, config = biblio_config()) {
  # Extract the country-doc level data
  country_doc_level <- prepared_data$country_doc_level
  
  if (nrow(country_doc_level) == 0) {
    return(list(
      scp_mcp = tibble::tibble(),
      scp_mcp_summary = list(
        total_scp = 0,
        total_mcp = 0,
        mcp_ratio = NA_real_
      ),
      status = "error: no country-doc level data"
    ))
  }
  
  # We need to compute, for each document, the number of distinct countries.
  # Then, for each document with exactly one country, assign SCP to that country.
  # For each document with more than one country, assign MCP to each country in that document.
  
  # Step 1: Compute the number of countries per document
  doc_country_counts <- country_doc_level %>%
    dplyr::group_by(doc_id) %>%
    dplyr::summarise(
      n_countries = dplyr::n_distinct(country),
      .groups = "drop"
    )
  
  # Step 2: Identify SCP documents (n_countries == 1) and get the country
  scp_documents <- doc_country_counts %>%
    dplyr::filter(n_countries == 1) %>%
    dplyr::inner_join(country_doc_level, by = "doc_id") %>%
    dplyr::group_by(country) %>%
    dplyr::summarise(
      scp = dplyr::n(),
      .groups = "drop"
    )
  
  # Step 3: Identify MCP documents (n_countries > 1) and get the countries
  mcp_documents <- doc_country_counts %>%
    dplyr::filter(n_countries > 1) %>%
    dplyr::inner_join(country_doc_level, by = "doc_id") %>%
    dplyr::group_by(country) %>%
    dplyr::summarise(
      mcp = dplyr::n(),
      .groups = "drop"
    )
  
  # Step 4: Combine SCP and MCP counts by country
  # We start with the country summary (which has article_count) to ensure we have all countries.
  country_summary <- prepared_data$country_summary %>%
    dplyr::select(country, article_count)
  
  # Left join SCP and MCP counts
  scp_mcp_df <- country_summary %>%
    dplyr::left_join(scp_documents, by = "country") %>%
    dplyr::left_join(mcp_documents, by = "country") %>%
    dplyr::mutate(
      scp = dplyr::coalesce(scp, 0),
      mcp = dplyr::coalesce(mcp, 0)
    ) %>%
    # Verify that article_count equals scp + mcp (should, by definition)
    dplyr::mutate(
      # We can add a check if we want, but for now we just compute the ratio.
      mcp_ratio = ifelse((scp + mcp) > 0, round(mcp / (scp + mcp) * 100, 1), NA_real_)
    ) %>%
    dplyr::arrange(desc(scp + mcp)) %>%
    dplyr::transmute(
      country = country,
      article_count = article_count,
      scp = scp,
      mcp = mcp,
      mcp_ratio = mcp_ratio
    )
  
  # Top N countries by SCP
  top_n <- config$top_n_countries
  top_countries_by_scp <- scp_mcp_df %>%
    dplyr::arrange(desc(scp)) %>%
    dplyr::slice(1:min(top_n, nrow(.))) %>%
    dplyr::transmute(
      rank = dplyr::row_number(),
      label = country,
      value = scp
    )
  
  # Top N countries by MCP
  top_countries_by_mcp <- scp_mcp_df %>%
    dplyr::arrange(desc(mcp)) %>%
    dplyr::slice(1:min(top_n, nrow(.))) %>%
    dplyr::transmute(
      rank = dplyr::row_number(),
      label = country,
      value = mcp
    )
  
  # Top N countries by MCP ratio (only those with at least one article, which is all)
  top_countries_by_mcp_ratio <- scp_mcp_df %>%
    dplyr::filter(!is.na(mcp_ratio)) %>%
    dplyr::arrange(desc(mcp_ratio)) %>%
    dplyr::slice(1:min(top_n, nrow(.))) %>%
    dplyr::transmute(
      rank = dplyr::row_number(),
      label = country,
      value = mcp_ratio
    )
  
  # Summary statistics
  total_scp <- sum(scp_mcp_df$scp)
  total_mcp <- sum(scp_mcp_df$mcp)
  overall_mcp_ratio <- ifelse((total_scp + total_mcp) > 0, round(total_mcp / (total_scp + total_mcp) * 100, 1), NA_real_)
  
  scp_mcp_summary <- list(
    total_scp = total_scp,
    total_mcp = total_mcp,
    mcp_ratio = overall_mcp_ratio
  )
  
  return(list(
    scp_mcp = scp_mcp_df,
    top_countries_by_scp = top_countries_by_scp,
    top_countries_by_mcp = top_countries_by_mcp,
    top_countries_by_mcp_ratio = top_countries_by_mcp_ratio,
    scp_mcp_summary = scp_mcp_summary,
    status = "success"
  ))
}
# <<< END FILE: R/module_m3/compute/m3_compute_scp_mcp.R

# >>> BEGIN FILE: R/module_m3/compute/m3_compute_similarity_clustering.R
# ============================================================================
# m3_compute_similarity_clustering.R - Country similarity and clustering for M3
# ============================================================================
# NOTE: This computes distance matrix and hierarchical clustering.
# PCA/k-means clustering is handled separately in m3_compute_country_profiles.R

#' Compute country similarity matrix and hierarchical clustering
#'
#' Builds a feature matrix from country metrics, computes distance matrix,
#' and performs hierarchical clustering.
#' All results are marked exploratory and require careful interpretation.
#'
#' @param prepared_data Output from \code{prepare_m3_country_data}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list containing similarity matrix, distance matrix, and clustering results
#' @export
m3_compute_similarity_clustering <- function(prepared_data, config = biblio_config()) {
  country_summary <- prepared_data$country_summary
  
  empty_result <- list(
    feature_matrix = matrix(nrow = 0, ncol = 0),
    distance_matrix = matrix(nrow = 0, ncol = 0),
    hierarchical_clustering = NULL,
    cluster_assignments = tibble::tibble(),
    similarity_summary = list(
      n_countries = 0,
      n_features = 0,
      clustering_performed = FALSE,
      method = "none",
      notes = character()
    ),
    status = "success: no country data",
    exploratory = TRUE
  )
  
  if (nrow(country_summary) == 0) {
    empty_result$status <- "error: no country data"
    return(empty_result)
  }
  
  notes <- character()
  
  # Ensure we have the necessary columns
  required_cols <- c("article_count", "total_citations")
  if (!all(required_cols %in% names(country_summary))) {
    notes <- c(notes, paste("Missing required columns:", 
                            paste(setdiff(required_cols, names(country_summary)), collapse = ", ")))
    empty_result$similarity_summary$notes <- notes
    return(empty_result)
  }
  
  # Build feature matrix
  # Features: article_count, total_citations, average_citations, scp, mcp
  # We'll compute SCP/MCP from country_doc_level if available
  
  country_doc_level <- prepared_data$country_doc_level
  
  # Compute SCP/MCP per country if we have country_doc_level
  if (nrow(country_doc_level) > 0) {
    doc_country_counts <- country_doc_level %>%
      dplyr::group_by(doc_id) %>%
      dplyr::summarise(
        n_countries = dplyr::n_distinct(country),
        .groups = "drop"
      )
    
    scp_documents <- doc_country_counts %>%
      dplyr::filter(n_countries == 1) %>%
      dplyr::inner_join(country_doc_level, by = "doc_id") %>%
      dplyr::group_by(country) %>%
      dplyr::summarise(scp = dplyr::n(), .groups = "drop")
    
    mcp_documents <- doc_country_counts %>%
      dplyr::filter(n_countries > 1) %>%
      dplyr::inner_join(country_doc_level, by = "doc_id") %>%
      dplyr::group_by(country) %>%
      dplyr::summarise(mcp = dplyr::n(), .groups = "drop")
    
    country_summary <- country_summary %>%
      dplyr::left_join(scp_documents, by = "country") %>%
      dplyr::left_join(mcp_documents, by = "country") %>%
      dplyr::mutate(
        scp = dplyr::coalesce(scp, 0),
        mcp = dplyr::coalesce(mcp, 0)
      )
  } else {
    country_summary <- country_summary %>%
      dplyr::mutate(scp = 0, mcp = 0)
  }
  
  # Compute average_citations if not present
  if (!"average_citations" %in% names(country_summary)) {
    country_summary <- country_summary %>%
      dplyr::mutate(
        average_citations = ifelse(article_count > 0, 
                                   total_citations / article_count, 0)
      )
  }
  
  # Create standardized feature matrix
  feature_cols <- c("article_count", "total_citations", "average_citations", "scp", "mcp")
  
  # Filter to countries with complete data
  country_features <- country_summary %>%
    dplyr::select(country, dplyr::all_of(feature_cols)) %>%
    dplyr::filter(complete.cases(.))
  
  n_countries <- nrow(country_features)
  if (n_countries < 2) {
    notes <- c(notes, "Similarity clustering requires at least 2 countries with complete data.")
    empty_result$similarity_summary$notes <- notes
    return(empty_result)
  }
  
  # Standardize features (z-score)
  feature_matrix <- as.matrix(country_features[, -1])
  
  # Handle zero variance columns
  feature_sds <- apply(feature_matrix, 2, sd, na.rm = TRUE)
  zero_var_cols <- which(feature_sds == 0 | is.na(feature_sds))
  
  if (length(zero_var_cols) > 0) {
    notes <- c(notes, paste("Removed", length(zero_var_cols), 
                           "constant feature(s) before clustering."))
    feature_matrix <- feature_matrix[, -zero_var_cols, drop = FALSE]
  }
  
  if (ncol(feature_matrix) < 2) {
    notes <- c(notes, "Need at least 2 features with variance for meaningful clustering.")
    empty_result$similarity_summary$notes <- notes
    return(empty_result)
  }
  
  # Standardize
  feature_means <- colMeans(feature_matrix)
  feature_sds <- apply(feature_matrix, 2, sd)
  feature_matrix_std <- scale(feature_matrix, center = feature_means, scale = feature_sds)
  
  # Replace NaN with 0 (happens when sd = 0)
  feature_matrix_std[is.na(feature_matrix_std)] <- 0
  
  # Compute distance matrix (Euclidean)
  distance_matrix <- tryCatch({
    dist(feature_matrix_std, method = "euclidean")
  }, error = function(e) {
    notes <<- c(notes, paste("Distance computation failed:", e$message))
    NULL
  })
  
  if (is.null(distance_matrix)) {
    empty_result$similarity_summary$notes <- notes
    return(empty_result)
  }
  
  # Hierarchical clustering (complete linkage)
  hc <- tryCatch({
    hclust(distance_matrix, method = "complete")
  }, error = function(e) {
    notes <<- c(notes, paste("Hierarchical clustering failed:", e$message))
    NULL
  })
  
  clustering_performed <- !is.null(hc)
  
  # Convert distance matrix to similarity matrix (for visualization)
  # Similarity = 1 / (1 + distance)
  sim_matrix <- tryCatch({
    as.matrix(1 / (1 + as.matrix(distance_matrix)))
  }, error = function(e) {
    notes <<- c(notes, paste("Similarity matrix computation failed:", e$message))
    matrix(nrow = 0, ncol = 0)
  })
  
  # Assign cluster labels if clustering was performed
  cluster_assignments <- tibble::tibble()
  if (clustering_performed && n_countries >= 3) {
    # Cut tree at k = min(3, n-1) clusters, but at least 2
    k_clusters <- min(3, n_countries - 1)
    k_clusters <- max(2, k_clusters)
    
    cluster_labels <- tryCatch({
      cutree(hc, k = k_clusters)
    }, error = function(e) {
      notes <<- c(notes, paste("Cluster assignment failed:", e$message))
      NULL
    })
    
    if (!is.null(cluster_labels)) {
      cluster_assignments <- tibble::tibble(
        country = country_features$country,
        cluster = factor(cluster_labels)
      )
    }
  }
  
  # Summary
  similarity_summary <- list(
    n_countries = n_countries,
    n_features = ncol(feature_matrix_std),
    clustering_performed = clustering_performed,
    method = if (clustering_performed) "hierarchical (complete linkage)" else "none",
    notes = notes
  )
  
  list(
    feature_matrix = feature_matrix_std,
    distance_matrix = distance_matrix,
    similarity_matrix = sim_matrix,
    hierarchical_clustering = hc,
    cluster_assignments = cluster_assignments,
    country_labels = country_features$country,
    similarity_summary = similarity_summary,
    status = "success",
    exploratory = TRUE
  )
}
# <<< END FILE: R/module_m3/compute/m3_compute_similarity_clustering.R

# >>> BEGIN FILE: R/module_m3/compute/m3_compute_spatial.R
# ============================================================================
# m3_compute_spatial.R - Spatial Statistics for Country Analysis
# ============================================================================
# Moran's I, Geary's C, Local Indicators of Spatial Association (LISA),
# Getis-Ord Gi* hot spot analysis, and distance-based collaboration analysis

#' Compute Moran's I spatial autocorrelation
#'
#' @param country_data Data frame with country, value columns
#' @param distance_matrix Optional pre-computed distance matrix
#' @return List with Moran's I statistic and significance test
#' @export
m3_compute_morans_i <- function(country_data, distance_matrix = NULL) {
  if (!is.data.frame(country_data) || !all(c("country", "value") %in% names(country_data))) {
    return(list(
      statistic = NA,
      p_value = NA,
      interpretation = "error: invalid input",
      status = "error"
    ))
  }
  
  values <- country_data$value
  n <- length(values)
  
  if (n < 4) {
    return(list(
      statistic = NA,
      p_value = NA,
      interpretation = "insufficient countries",
      status = "error"
    ))
  }
  
  # Use distance matrix or create inverse distance weights
  if (is.null(distance_matrix)) {
    # Create binary contiguity weights (simplified)
    # In practice, would use actual geographic distances
    W <- matrix(1, n, n) - diag(1, n)
  } else {
    W <- distance_matrix
    # Inverse distance weighting
    W <- 1 / (W + 0.001)  # Add small constant to avoid division by zero
  }
  
  # Row-standardize weights
  W <- W / rowSums(W)
  W[is.na(W)] <- 0
  
  # Moran's I calculation
  mean_val <- mean(values, na.rm = TRUE)
  dev <- values - mean_val
  
  numerator <- sum(W * outer(dev, dev), na.rm = TRUE)
  denominator <- sum(dev^2, na.rm = TRUE)
  if (!is.finite(denominator) || denominator <= 0) {
    return(list(
      statistic = NA_real_,
      p_value = NA_real_,
      interpretation = "Spatial variance is zero; Moran's I is undefined",
      status = "inconclusive"
    ))
  }
  
  moran_i <- (n / sum(W, na.rm = TRUE)) * (numerator / denominator)
  
  # Expected value under null
  expected_i <- -1 / (n - 1)
  
  # Variance (simplified)
  s1 <- 0.5 * sum((W + t(W))^2, na.rm = TRUE)
  s2 <- sum((rowSums(W) + colSums(W))^2, na.rm = TRUE)
  
  var_i <- (n^2 * s1 - n * s2 + 2 * s1) / (n^2 * (n - 1)^2 * sum(dev^2)^2) * sum(dev^2)^2
  
  # Simplified variance
  var_i <- (n^2 - 1) / (n^2 * (n - 1)^2) - expected_i^2
  if (!is.finite(var_i) || var_i <= 0) {
    return(list(
      statistic = moran_i,
      expected = expected_i,
      variance = var_i,
      z_score = NA_real_,
      p_value = NA_real_,
      significant = FALSE,
      interpretation = "Moran's I variance is undefined for the available spatial distribution",
      n_countries = n,
      status = "inconclusive"
    ))
  }
  
  # Z-score
  z_score <- (moran_i - expected_i) / sqrt(var_i)
  
  # P-value (two-tailed)
  p_value <- 2 * (1 - pnorm(abs(z_score)))
  if (!is.finite(moran_i) || !is.finite(p_value)) {
    return(list(
      statistic = moran_i,
      expected = expected_i,
      variance = var_i,
      z_score = z_score,
      p_value = p_value,
      significant = FALSE,
      interpretation = "Moran's I is undefined for the available spatial distribution",
      n_countries = n,
      status = "inconclusive"
    ))
  }
  
  # Interpretation
  if (moran_i > 0.3 && p_value < 0.05) {
    interpretation <- "Strong positive spatial autocorrelation: similar countries cluster"
  } else if (moran_i > 0 && p_value < 0.05) {
    interpretation <- "Weak positive spatial autocorrelation: some clustering"
  } else if (moran_i < -0.3 && p_value < 0.05) {
    interpretation <- "Strong negative spatial autocorrelation: dissimilar countries cluster"
  } else if (moran_i < 0 && p_value < 0.05) {
    interpretation <- "Weak negative spatial autocorrelation: some dispersal"
  } else {
    interpretation <- "No significant spatial autocorrelation: random distribution"
  }
  
  list(
    statistic = moran_i,
    expected = expected_i,
    variance = var_i,
    z_score = z_score,
    p_value = p_value,
    significant = p_value < 0.05,
    interpretation = interpretation,
    n_countries = n,
    status = "success"
  )
}

#' Compute Geary's C spatial autocorrelation
#'
#' @param country_data Data frame with country, value columns
#' @param distance_matrix Optional pre-computed distance matrix
#' @return List with Geary's C statistic and significance test
#' @export
m3_compute_gearys_c <- function(country_data, distance_matrix = NULL) {
  if (!is.data.frame(country_data) || !all(c("country", "value") %in% names(country_data))) {
    return(list(
      statistic = NA,
      p_value = NA,
      status = "error"
    ))
  }
  
  values <- country_data$value
  n <- length(values)
  
  if (n < 4) {
    return(list(
      statistic = NA,
      p_value = NA,
      status = "error: insufficient countries"
    ))
  }
  
  # Create weights matrix
  if (is.null(distance_matrix)) {
    W <- matrix(1, n, n) - diag(1, n)
  } else {
    W <- distance_matrix
    W <- 1 / (W + 0.001)
  }
  
  W <- W / sum(W)
  
  mean_val <- mean(values, na.rm = TRUE)
  
  # Geary's C calculation
  numerator <- sum(W * outer(values, values, function(x, y) (x - y)^2), na.rm = TRUE)
  denominator <- sum((values - mean_val)^2, na.rm = TRUE)
  if (!is.finite(denominator) || denominator <= 0) {
    return(list(
      statistic = NA_real_,
      p_value = NA_real_,
      interpretation = "Spatial variance is zero; Geary's C is undefined",
      status = "inconclusive"
    ))
  }
  
  geary_c <- (n - 1) / (2 * sum(W, na.rm = TRUE)) * numerator / denominator
  
  # Expected under null
  expected_c <- 1
  
  # Variance (simplified)
  var_c <- 1 / (2 * (n - 1))
  
  # Z-score
  z_score <- (geary_c - expected_c) / sqrt(var_c)
  p_value <- 2 * (1 - pnorm(abs(z_score)))
  if (!is.finite(geary_c) || !is.finite(p_value)) {
    return(list(
      statistic = geary_c,
      expected = expected_c,
      variance = var_c,
      z_score = z_score,
      p_value = p_value,
      significant = FALSE,
      interpretation = "Geary's C is undefined for the available spatial distribution",
      n_countries = n,
      status = "inconclusive"
    ))
  }
  
  # Interpretation
  if (geary_c < 0.5 && p_value < 0.05) {
    interpretation <- "Strong positive spatial autocorrelation"
  } else if (geary_c < 1 && p_value < 0.05) {
    interpretation <- "Weak positive spatial autocorrelation"
  } else if (geary_c > 1.5 && p_value < 0.05) {
    interpretation <- "Strong negative spatial autocorrelation"
  } else if (geary_c > 1 && p_value < 0.05) {
    interpretation <- "Weak negative spatial autocorrelation"
  } else {
    interpretation <- "No significant spatial autocorrelation"
  }
  
  list(
    statistic = geary_c,
    expected = expected_c,
    variance = var_c,
    z_score = z_score,
    p_value = p_value,
    significant = p_value < 0.05,
    interpretation = interpretation,
    n_countries = n,
    status = "success"
  )
}

#' Compute Getis-Ord Gi* hot spot analysis
#'
#' @param country_data Data frame with country, value, lat, lon columns
#' @param distance_matrix Optional pre-computed distance matrix
#' @return List with Gi* statistics and hot/cold spots
#' @export
m3_compute_getis_ord <- function(country_data, distance_matrix = NULL) {
  required_cols <- c("country", "value")
  if (!is.data.frame(country_data) || !all(required_cols %in% names(country_data))) {
    return(list(
      gi_values = data.frame(),
      hot_spots = character(0),
      cold_spots = character(0),
      status = "error: invalid input"
    ))
  }
  
  values <- country_data$value
  n <- length(values)
  
  if (n < 4) {
    return(list(
      gi_values = data.frame(),
      hot_spots = character(0),
      cold_spots = character(0),
      status = "error: insufficient countries"
    ))
  }
  
  # Create weights matrix
  if (is.null(distance_matrix)) {
    W <- matrix(1, n, n) - diag(1, n)
  } else {
    W <- distance_matrix
    W <- 1 / (W + 0.001)
  }
  
  # Row-standardize
  row_sums <- rowSums(W)
  row_sums[row_sums == 0] <- 1
  W <- W / row_sums
  
  mean_val <- mean(values, na.rm = TRUE)
  sd_val <- sd(values, na.rm = TRUE)
  if (!is.finite(sd_val) || sd_val <= 0) {
    return(list(
      gi_values = data.frame(),
      hot_spots = character(0),
      cold_spots = character(0),
      interpretation = "Insufficient spatial variation for Getis-Ord analysis",
      status = "inconclusive"
    ))
  }
  
  # Gi* for each location
  gi_values <- numeric(n)
  z_scores <- numeric(n)
  p_values <- numeric(n)
  
  for (i in 1:n) {
    # Weighted sum of neighbors
    weighted_sum <- sum(W[i, ] * values, na.rm = TRUE)
    
    # Gi* statistic (includes self)
    W_sum_i <- sum(W[i, ])
    
    # Gi* formula
    gi_values[i] <- (weighted_sum - mean_val * W_sum_i) / 
                   (sd_val * sqrt((n * W_sum_i - W_sum_i^2) / (n - 1)))
    
    # Z-score approximation
    z_scores[i] <- gi_values[i]
    p_values[i] <- 2 * (1 - pnorm(abs(z_scores[i])))
  }
  
  # Identify hot and cold spots
  hot_spots <- country_data$country[z_scores > 1.96 & p_values < 0.05]
  cold_spots <- country_data$country[z_scores < -1.96 & p_values < 0.05]
  
  # Confidence levels
  confidence <- ifelse(abs(z_scores) > 2.58, "99%",
                      ifelse(abs(z_scores) > 1.96, "95%",
                      ifelse(abs(z_scores) > 1.65, "90%", "Not significant")))
  
  results <- data.frame(
    country = country_data$country,
    value = values,
    gi_star = gi_values,
    z_score = z_scores,
    p_value = p_values,
    confidence = confidence,
    type = ifelse(z_scores > 1.96, "Hot spot",
                 ifelse(z_scores < -1.96, "Cold spot", "Not significant")),
    stringsAsFactors = FALSE
  )
  
  list(
    gi_values = results,
    hot_spots = hot_spots,
    cold_spots = cold_spots,
    n_hot_spots = length(hot_spots),
    n_cold_spots = length(cold_spots),
    global_gi = (sum(values) - n * mean_val) / (sd_val * sqrt(n - 1)),
    interpretation = sprintf("Found %d hot spots and %d cold spots at p<0.05", 
                           length(hot_spots), length(cold_spots)),
    status = "success"
  )
}

#' Compute Local Indicators of Spatial Association (LISA)
#'
#' @param country_data Data frame with country, value columns
#' @param distance_matrix Optional pre-computed distance matrix
#' @return List with LISA statistics and cluster types
#' @export
m3_compute_lisa <- function(country_data, distance_matrix = NULL) {
  required_cols <- c("country", "value")
  if (!is.data.frame(country_data) || !all(required_cols %in% names(country_data))) {
    return(list(
      lisa_values = data.frame(),
      clusters = data.frame(),
      status = "error: invalid input"
    ))
  }
  
  values <- country_data$value
  n <- length(values)
  countries <- country_data$country
  
  if (n < 4) {
    return(list(
      lisa_values = data.frame(),
      clusters = data.frame(),
      status = "error: insufficient countries"
    ))
  }
  
  # Create spatial weights
  if (is.null(distance_matrix)) {
    W <- matrix(1, n, n) - diag(1, n)
  } else {
    W <- distance_matrix
    W <- 1 / (W + 0.001)
  }
  
  # Row-standardize
  row_sums <- rowSums(W)
  row_sums[row_sums == 0] <- 1
  W <- W / row_sums
  
  mean_val <- mean(values, na.rm = TRUE)
  sd_val <- sd(values, na.rm = TRUE)
  if (!is.finite(sd_val) || sd_val <= 0) {
    return(list(
      lisa_values = data.frame(),
      clusters = data.frame(),
      interpretation = "Insufficient spatial variation for LISA analysis",
      status = "inconclusive"
    ))
  }
  
  # Standardized values
  z <- (values - mean_val) / sd_val
  
  # Local Moran's I for each location
  local_i <- numeric(n)
  p_values <- numeric(n)
  
  for (i in 1:n) {
    # Lagged value
    z_lag <- sum(W[i, ] * z)
    
    # Local Moran's I
    local_i[i] <- z[i] * z_lag
    
    # Permutation test for significance
    n_perm <- 499
    perm_i <- numeric(n_perm)
    for (p in 1:n_perm) {
      z_perm <- sample(z)
      z_lag_perm <- sum(W[i, ] * z_perm)
      perm_i[p] <- z[i] * z_lag_perm
    }
    
    p_values[i] <- (sum(perm_i >= local_i[i]) + 1) / (n_perm + 1)
  }
  
  # Determine cluster types
  # HH: High-High (high value surrounded by high values)
  # LL: Low-Low (low value surrounded by low values)
  # HL: High-Low (high value surrounded by low values) - outlier
  # LH: Low-High (low value surrounded by high values) - outlier
  
  cluster_types <- character(n)
  for (i in 1:n) {
    if (p_values[i] >= 0.05) {
      cluster_types[i] <- "Not significant"
    } else if (z[i] > 0 && local_i[i] > 0) {
      cluster_types[i] <- "HH"  # High-High cluster
    } else if (z[i] < 0 && local_i[i] > 0) {
      cluster_types[i] <- "LL"  # Low-Low cluster
    } else if (z[i] > 0 && local_i[i] < 0) {
      cluster_types[i] <- "HL"  # High-Low outlier
    } else {
      cluster_types[i] <- "LH"  # Low-High outlier
    }
  }
  
  results <- data.frame(
    country = countries,
    value = values,
    z_score = z,
    local_i = local_i,
    p_value = p_values,
    cluster_type = cluster_types,
    significant = p_values < 0.05,
    stringsAsFactors = FALSE
  )
  
  # Summary by cluster type
  cluster_summary <- data.frame(
    type = c("HH", "LL", "HL", "LH", "Not significant"),
    count = c(
      sum(cluster_types == "HH"),
      sum(cluster_types == "LL"),
      sum(cluster_types == "HL"),
      sum(cluster_types == "LH"),
      sum(cluster_types == "Not significant")
    ),
    countries = c(
      paste(countries[cluster_types == "HH"], collapse = ", "),
      paste(countries[cluster_types == "LL"], collapse = ", "),
      paste(countries[cluster_types == "HL"], collapse = ", "),
      paste(countries[cluster_types == "LH"], collapse = ", "),
      paste(countries[cluster_types == "Not significant"], collapse = ", ")
    ),
    stringsAsFactors = FALSE
  )
  
  list(
    lisa_values = results,
    clusters = cluster_summary,
    hh_clusters = countries[cluster_types == "HH"],
    ll_clusters = countries[cluster_types == "LL"],
    hl_outliers = countries[cluster_types == "HL"],
    lh_outliers = countries[cluster_types == "LH"],
    n_significant = sum(p_values < 0.05),
    interpretation = sprintf("%d countries in significant clusters (%d HH, %d LL, %d outliers)",
                           sum(p_values < 0.05),
                           sum(cluster_types == "HH"),
                           sum(cluster_types == "LL"),
                           sum(cluster_types %in% c("HL", "LH"))),
    status = "success"
  )
}

#' Compute gravity model for international collaboration
#'
#' @param collab_matrix Collaboration matrix (countries x countries)
#' @param distance_matrix Geographic distance matrix
#' @param country_attr Country attributes (GDP, population, etc.)
#' @return List with gravity model estimates
#' @export
m3_compute_gravity_model <- function(collab_matrix, distance_matrix, country_attr = NULL) {
  if (!is.matrix(collab_matrix) || !is.matrix(distance_matrix)) {
    return(list(
      coefficients = data.frame(),
      R_squared = NA,
      status = "error: invalid input"
    ))
  }
  
  n <- nrow(collab_matrix)
  
  if (n != nrow(distance_matrix)) {
    return(list(
      coefficients = data.frame(),
      R_squared = NA,
      status = "error: matrix dimension mismatch"
    ))
  }
  
  # Convert to vectors for regression
  # Collaboration_ij = A * (GDP_i^a * GDP_j^b) / (Distance_ij^d)
  
  # Log-linearize: log(Collab_ij) = log(A) + a*log(GDP_i) + b*log(GDP_j) - d*log(Distance_ij)
  
  # Get upper triangle (to avoid duplicates)
  collab_vec <- collab_matrix[upper.tri(collab_matrix)]
  dist_vec <- distance_matrix[upper.tri(distance_matrix)]
  
  # Remove zeros for log transformation
  valid_idx <- collab_vec > 0 & dist_vec > 0
  
  if (sum(valid_idx) < 10) {
    return(list(
      coefficients = data.frame(),
      R_squared = NA,
      status = "error: insufficient positive values"
    ))
  }
  
  collab_vec <- collab_vec[valid_idx]
  dist_vec <- dist_vec[valid_idx]
  
  # Simple gravity model: log(Collab_ij) = a - d*log(Distance_ij)
  log_collab <- log(collab_vec)
  log_dist <- log(dist_vec)
  
  fit <- lm(log_collab ~ log_dist)
  
  # Extract coefficients
  intercept <- coef(fit)[1]
  distance_coef <- coef(fit)[2]
  
  # Distance decay effect
  distance_effect <- -distance_coef
  
  # If country attributes provided, enhanced model
  if (!is.null(country_attr) && "production" %in% names(country_attr)) {
    # Add production attributes
    # This would require matching country indices
  }
  
  # Goodness of fit
  r_squared <- summary(fit)$r.squared
  
  # Interpretation
  interpretation <- if (distance_effect > 2) {
    "Strong distance effect: collaboration decreases sharply with distance"
  } else if (distance_effect > 1) {
    "Moderate distance effect: some distance decay in collaboration"
  } else {
    "Weak distance effect: distance plays minor role in collaboration"
  }
  
  coefficients_df <- data.frame(
    term = c("Intercept", "log(Distance)"),
    estimate = c(intercept, distance_coef),
    std_error = summary(fit)$coefficients[, 2],
    t_value = summary(fit)$coefficients[, 3],
    p_value = summary(fit)$coefficients[, 4]
  )
  
  list(
    coefficients = coefficients_df,
    distance_decay = distance_effect,
    R_squared = r_squared,
    AIC = AIC(fit),
    BIC = BIC(fit),
    interpretation = interpretation,
    near_effect = exp(intercept),  # Collaboration at unit distance
    status = "success"
  )
}

#' Create distance matrix from country coordinates
#'
#' @param countries Vector of country names
#' @param coords Data frame with country, lat, lon columns (optional)
#' @return Distance matrix in kilometers
#' @export
m3_create_distance_matrix <- function(countries, coords = NULL) {
  n <- length(countries)
  
  if (is.null(coords)) {
    # Would need rnaturalearth to get coordinates
    # Return placeholder matrix
    dist_matrix <- matrix(0, n, n)
    rownames(dist_matrix) <- colnames(dist_matrix) <- countries
    return(list(
      distance_matrix = dist_matrix,
      status = "error: coordinates not available - install rnaturalearth"
    ))
  }
  
  # Haversine distance calculation
  dist_matrix <- matrix(0, n, n)
  
  for (i in 1:n) {
    for (j in 1:n) {
      if (i != j) {
        lat1 <- coords$lat[coords$country == countries[i]]
        lon1 <- coords$lon[coords$country == countries[i]]
        lat2 <- coords$lat[coords$country == countries[j]]
        lon2 <- coords$lon[coords$country == countries[j]]
        
        if (length(lat1) == 1 && length(lat2) == 1) {
          dist_matrix[i, j] <- haversine_distance(lat1, lon1, lat2, lon2)
        }
      }
    }
  }
  
  rownames(dist_matrix) <- colnames(dist_matrix) <- countries
  
  list(
    distance_matrix = dist_matrix,
    status = "success"
  )
}

#' Haversine distance calculation
#' @keywords internal
haversine_distance <- function(lat1, lon1, lat2, lon2) {
  # Convert to radians
  lat1 <- lat1 * pi / 180
  lat2 <- lat2 * pi / 180
  lon1 <- lon1 * pi / 180
  lon2 <- lon2 * pi / 180
  
  # Haversine formula
  dlat <- lat2 - lat1
  dlon <- lon2 - lon1
  
  a <- sin(dlat / 2)^2 + cos(lat1) * cos(lat2) * sin(dlon / 2)^2
  c <- 2 * asin(sqrt(a))
  
  # Earth radius in km
  R <- 6371
  
  R * c
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
