# >>> BEGIN FILE: R/module_m3/render/m3_render_rankings.R
# ============================================================================
# m3_render_rankings.R - Rank structure plots for M3
# ============================================================================

#' Render rank structure plots
#'
#' @param rankings_data Output from \code{m3_compute_rankings}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list with \code{status} and \code{plots}
#' @export
m3_render_rankings <- function(rankings_data, config = biblio_config()) {
  stub <- list(status = "stub", plots = list())

  if (!is.list(rankings_data) || nrow(rankings_data$production_rankings) == 0) {
    return(stub)
  }

  plots <- list()

  # 1. Pareto-style cumulative production plot
  prod_rank <- rankings_data$production_rankings %>%
    dplyr::mutate(
      cumulative_share = cumsum(value) / sum(value)
    )

  plots$production_rank_cumshare <- ggplot2::ggplot(
    prod_rank,
    ggplot2::aes(x = rank, y = cumulative_share)
  ) +
    ggplot2::geom_area(fill = ieee_colors$blue, alpha = 0.15) +
    ggplot2::geom_line(color = ieee_colors$blue, linewidth = 0.6) +
    ggplot2::geom_hline(yintercept = 0.5, linetype = "dashed",
                        color = ieee_colors$gray, linewidth = 0.4) +
    ggplot2::geom_hline(yintercept = 0.8, linetype = "dotted",
                        color = ieee_colors$gray, linewidth = 0.4) +
    ggplot2::scale_y_continuous(labels = scales::percent_format(accuracy = 1),
                                limits = c(0, 1)) +
    ggplot2::labs(
      title = "Cumulative Production Share by Country Rank",
      x     = "Country Rank",
      y     = "Cumulative Share"
    ) +
    ieee_theme()

  # 2. Citations rank plot (if available)
  cit_rank <- rankings_data$citations_rankings
  if (nrow(cit_rank) >= 2 && sum(cit_rank$value) > 0) {
    cit_rank <- cit_rank %>%
      dplyr::mutate(cumulative_share = cumsum(value) / sum(value))

    plots$citations_rank_cumshare <- ggplot2::ggplot(
      cit_rank,
      ggplot2::aes(x = rank, y = cumulative_share)
    ) +
      ggplot2::geom_area(fill = ieee_colors$orange, alpha = 0.15) +
      ggplot2::geom_line(color = ieee_colors$orange, linewidth = 0.6) +
      ggplot2::geom_hline(yintercept = 0.5, linetype = "dashed",
                          color = ieee_colors$gray, linewidth = 0.4) +
      ggplot2::geom_hline(yintercept = 0.8, linetype = "dotted",
                          color = ieee_colors$gray, linewidth = 0.4) +
      ggplot2::scale_y_continuous(labels = scales::percent_format(accuracy = 1),
                                  limits = c(0, 1)) +
      ggplot2::labs(
        title = "Cumulative Citation Share by Country Rank",
        x     = "Country Rank",
        y     = "Cumulative Share"
      ) +
      ieee_theme()
  }

  list(status = "success", plots = plots)
}
# <<< END FILE: R/module_m3/render/m3_render_rankings.R

# >>> BEGIN FILE: R/module_m3/render/m3_render_sankey.R
# ============================================================================
# m3_render_sankey.R - Sankey Diagram for Collaboration Flows
# ============================================================================
# Creates Sankey diagrams for country collaboration networks
# (collaboration flows between countries/regions over time)

#' Render Sankey diagram for collaboration flows
#'
#' @param data Output from m3_compute_collaboration_indices or prepared data
#' @param type Type of Sankey: "country", "region", "temporal"
#' @param config Configuration list
#' @return List with Sankey plot
#' @export
render_m3_sankey <- function(data, type = "country", config = biblio_config()) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(list(plots = list(), status = "error: ggplot2 not installed"))
  }
  
  plots <- list()
  
  # Prepare flow data
  flow_data <- prepare_sankey_data(data, type, config)
  
  if (is.null(flow_data) || nrow(flow_data) == 0) {
    return(list(plots = list(), status = "error: no collaboration data"))
  }
  
  # Create Sankey using ggalluvial or network approach
  if (requireNamespace("ggalluvial", quietly = TRUE)) {
    plots$sankey <- create_alluvial_sankey(flow_data, type, config)
  } else {
    # Fallback to geom_segment approach
    plots$sankey <- create_segment_sankey(flow_data, type, config)
  }
  
  list(
    plots = plots,
    status = "success"
  )
}

#' Prepare data for Sankey diagram
#' @keywords internal
prepare_sankey_data <- function(data, type, config) {
  if (type == "country") {
    # Get collaboration matrix
    if (!is.null(data$collaboration_matrix)) {
      collab_matrix <- data$collaboration_matrix
    } else if (!is.null(data$collaboration_indices) && !is.null(data$collaboration_indices$matrix)) {
      collab_matrix <- data$collaboration_indices$matrix
    } else {
      return(NULL)
    }
    
    # Convert matrix to flow data
    flow_data <- matrix_to_flow(collab_matrix, config$top_n_countries %||% 20)
    
    return(flow_data)
    
  } else if (type == "temporal") {
    # Get temporal collaboration data
    if (!is.null(data$temporal_collaboration)) {
      return(data$temporal_collaboration)
    }
    return(NULL)
    
  } else if (type == "region") {
    # Aggregate by region
    if (!is.null(data$regional_collaboration)) {
      return(data$regional_collaboration)
    }
    return(NULL)
  }
  
  NULL
}

#' Convert collaboration matrix to flow format
#' @keywords internal
matrix_to_flow <- function(matrix, top_n) {
  # Get top countries
  total_collab <- rowSums(matrix, na.rm = TRUE) + colSums(matrix, na.rm = TRUE) - diag(matrix)
  top_countries <- names(sort(total_collab, decreasing = TRUE))[1:min(top_n, length(total_collab))]
  
  # Filter matrix to top countries
  matrix_subset <- matrix[top_countries, top_countries]
  
  # Create flow data
  flows <- data.frame(
    source = character(),
    target = character(),
    value = numeric(),
    stringsAsFactors = FALSE
  )
  
  for (i in seq_len(nrow(matrix_subset))) {
    for (j in seq_len(ncol(matrix_subset))) {
      if (i < j && matrix_subset[i, j] > 0) {
        flows <- rbind(flows, data.frame(
          source = rownames(matrix_subset)[i],
          target = colnames(matrix_subset)[j],
          value = matrix_subset[i, j],
          stringsAsFactors = FALSE
        ))
      }
    }
  }
  
  # Sort by value
  flows <- flows[order(-flows$value), ]
  
  flows
}

#' Create alluvial Sankey plot
#' @keywords internal
create_alluvial_sankey <- function(flow_data, type, config) {
  if (!requireNamespace("ggalluvial", quietly = TRUE)) {
    return(create_segment_sankey(flow_data, type, config))
  }
  
  # Limit to top flows
  top_n <- config$top_n_flows %||% 30
  flow_data <- flow_data[1:min(top_n, nrow(flow_data)), ]
  
  palette <- get_biblio_palette(n = length(unique(c(flow_data$source, flow_data$target))))
  
  # Create node positions
  nodes <- unique(c(flow_data$source, flow_data$target))
  node_df <- data.frame(
    name = nodes,
    id = seq_along(nodes),
    stringsAsFactors = FALSE
  )
  
  # Create alluvial format
  alluvial_df <- data.frame(
    source = factor(flow_data$source),
    target = factor(flow_data$target),
    value = flow_data$value,
    stringsAsFactors = FALSE
  )
  
  ggplot2::ggplot(alluvial_df,ggplot2::aes(
    axis1 = source,
    axis2 = target,
    y = value
  )) +
    ggalluvial::geom_alluvium(ggplot2::aes(fill = source), width = 1/12) +
    ggalluvial::geom_stratum(width = 1/12, fill = "grey50", color = "white") +
    ggplot2::geom_text(stat = "stratum", ggplot2::aes(label = after_stat(ggplot2::stratum)), size = 3) +
    ggplot2::scale_x_discrete(limits = c("Source", "Target"), expand = c(0.05, 0.05)) +
    ggplot2::scale_fill_manual(values = palette, guide = "none") +
    ggplot2::labs(
      title = "International Collaboration Network",
      subtitle = sprintf("Top %d collaboration flows", nrow(flow_data)),
      y = "Collaboration Count"
    ) +ieee_theme()
}

#' Create segment-based Sankey (fallback)
#' @keywords internal
create_segment_sankey <- function(flow_data, type, config) {
  top_n <- config$top_n_flows %||% 20
  flow_data <- flow_data[1:min(top_n, nrow(flow_data)), ]
  
  palette <- get_biblio_palette(n = nrow(flow_data))
  
  ggplot2::ggplot(flow_data, ggplot2::aes(
    x = 0,
    xend = 1,
    y = source,
    yend = target
  )) +
    ggplot2::geom_curve(
      ggplot2::aes(size = value, color = source),
      curvature = -0.2,
      alpha = 0.6
    ) +
    ggplot2::scale_size_continuous(range = c(0.5, 3), guide = "none") +
    ggplot2::scale_color_manual(values = palette, guide = "none") +
    ggplot2::labs(
      title = "International Collaboration Network",
      subtitle =sprintf("Top %d collaboration flows", nrow(flow_data))
    ) +ieee_theme() +
    ggplot2::theme(
      axis.title = ggplot2::element_blank(),
      axis.text = ggplot2::element_blank(),
      axis.ticks = ggplot2::element_blank()
    )
}

#' Render temporal Sankey diagram
#'
#' @param data Output from m3_compute_temporal_dynamics
#' @param config Configuration list
#' @return List with temporal Sankey plot
#' @export
render_m3_temporal_sankey <- function(data, config = biblio_config()) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) {
    return(list(plots = list(), status = "error: ggplot2 not installed"))
  }
  
  share_evolution <- data$share_evolution
  
  if (is.null(share_evolution) || nrow(share_evolution) == 0) {
    return(list(plots = list(), status = "error: no temporal data"))
  }
  
  # Prepare for alluvial plot
  years <- sort(unique(share_evolution$year))
  countries <- unique(share_evolution$country)
  
  # Get top countries
  top_countries <- share_evolution %>%
    dplyr::group_by(country) %>%
    dplyr::summarise(total = sum(share, na.rm = TRUE)) %>%
    dplyr::arrange(dplyr::desc(total)) %>%
    dplyr::slice(1:min(15, dplyr::n())) %>%
    dplyr::pull(country)
  
  # Filter and prepare
  plot_data <- share_evolution %>%
    dplyr::filter(country %in% top_countries) %>%
    dplyr::mutate(year_factor = factor(year))
  
  palette <- get_biblio_palette(n = length(top_countries))
  
  p <- ggplot2::ggplot(plot_data,
    ggplot2::aes(
      x = year_factor,
      stratum = country,
      alluvium = country,
      y = share,
      fill = country
    )
  ) +
    ggalluvial::geom_alluvium(alpha = 0.7) +
    ggalluvial::geom_stratum(alpha = 0.9, color = "white") +
    ggplot2::geom_text(stat = "stratum", ggplot2::aes(label = after_stat(ggplot2::stratum)), size = 2.5) +
    ggplot2::scale_fill_manual(values = palette, guide = "none") +
    ggplot2::labs(
      title = "Country Share Evolution Over Time",
      x = "Year",
      y = "Share (%)"
    ) +ieee_theme()
  
  list(plots = list(temporal_sankey = p), status = "success")
}

#' Build Sankey data table
#' @export
build_m3_sankey_table <- function(data, type = "country", config = biblio_config()) {
  flow_data <- prepare_sankey_data(data, type, config)
  
  if (is.null(flow_data)) {
    return(data.frame(
      source = character(),
      target = character(),
      value = numeric(),
      stringsAsFactors = FALSE
    ))
  }
  
  flow_data
}
# <<< END FILE: R/module_m3/render/m3_render_sankey.R

# >>> BEGIN FILE: R/module_m3/render/m3_render_scp_mcp.R
# ============================================================================
# m3_render_scp_mcp.R - Enhanced SCP/MCP Plots (IEEE Q1 Legacy Compatible)
# ============================================================================
# Creates legacy-style plots:
# - M3_p1_mcp_share_vs_year.png - MCP share over time
# - Stacked bar chart for SCP/MCP by country
# - MCP ratio ranking
# ============================================================================

#' Render all M3 SCP/MCP collaboration plots (Enhanced IEEE Q1 Quality)
#'
#' @param scp_mcp_data Output from m3_compute_scp_mcp
#' @param config Configuration list
#' @return List with plots
#' @export
m3_render_scp_mcp <- function(scp_mcp_data, config = biblio_config()) {
  if (!is.list(scp_mcp_data) || scp_mcp_data$status == "stub") {
    return(list(status = "stub", plots = list()))
  }
  
  plots <- list()
  
  top_n <- config$top_n_countries %||% 10
  df <- scp_mcp_data$scp_mcp
  
  if (is.null(df) || nrow(df) == 0) {
    return(list(status = "no data", plots = list()))
  }
  
  # 1. Stacked bar: SCP + MCP by country
  plots$stacked_bar <- create_scp_mcp_stacked_plot(df, top_n, config)
  
  # 2. MCP ratio ranking
  plots$mcp_ratio <- create_mcp_ratio_plot(df, top_n, config)
  
  # 3. M3_p1_mcp_share_vs_year - MCP share over time (if annual data available)
  if ("annual_scp_mcp" %in% names(scp_mcp_data) && !is.null(scp_mcp_data$annual_scp_mcp)) {
    plots$mcp_share_vs_year <- create_mcp_share_vs_year_plot(scp_mcp_data$annual_scp_mcp, config)
  }
  
  # 4. SCP/MCP proportion pie chart
  if ("total" %in% names(scp_mcp_data)) {
    plots$scp_mcp_pie <- create_scp_mcp_pie_plot(scp_mcp_data$total, config)
  }
  
  # 5. Top collaborating countries (highest MCP)
  if ("top_collaborators" %in% names(scp_mcp_data)) {
    plots$top_collaborators <- create_top_collaborators_plot(scp_mcp_data$top_collaborators, config)
  }
  
  list(status = "success", plots = plots)
}

#' Create SCP/MCP stacked bar plot
#' @keywords internal
create_scp_mcp_stacked_plot <- function(df, top_n, config) {
  df_top <- df %>%
    dplyr::arrange(dplyr::desc(article_count)) %>%
    dplyr::slice(seq_len(min(top_n, nrow(.)))) %>%
    dplyr::mutate(label_clean = substr(trimws(country), 1, 25))
  
  df_long <- df_top %>%
    dplyr::select(label_clean, scp, mcp) %>%
    tidyr::pivot_longer(
      cols = c(scp, mcp),
      names_to = "type",
      values_to = "count"
    ) %>%
    dplyr::mutate(type = toupper(type))
  
  df_long$label_clean <- factor(df_long$label_clean, 
                                  levels = rev(unique(df_long$label_clean)))
  
  p <- ggplot2::ggplot(df_long, ggplot2::aes(x = label_clean, y = count, fill = type)) +
    ggplot2::geom_col(color = "black", linewidth = 0.2, width = 0.7) +
    ggplot2::coord_flip() +
    ggplot2::scale_fill_manual(
      values = c(SCP = "#0072BD", MCP = "#D95319"),
      name = "Publication Type",
      labels = c("Single Country", "Multi-Country")
    ) +
    ggplot2::scale_y_continuous(
      name = "Number of Publications",
      labels = scales::label_number(big.mark = ","),
      expand = ggplot2::expansion(mult = c(0, 0.1))
    ) +
    ggplot2::labs(
      title = "SCP vs MCP by Country",
      subtitle = sprintf("Top %d countries by publication volume", top_n),
      x = NULL
    ) +
    ieee_theme_bar() +
    ggplot2::theme(
      legend.position = "bottom",
      legend.direction = "horizontal",
      plot.title = ggplot2::element_text(size = 10, face = "bold", hjust = 0.5),
      plot.subtitle = ggplot2::element_text(size = 8, hjust = 0.5, face = "italic")
    )
  
  p
}

#' Create MCP ratio plot
#' @keywords internal
create_mcp_ratio_plot <- function(df, top_n, config) {
  df_ratio <- df %>%
    dplyr::filter(!is.na(mcp_ratio)) %>%
    dplyr::arrange(dplyr::desc(mcp_ratio)) %>%
    dplyr::slice(seq_len(min(top_n, nrow(.)))) %>%
    dplyr::mutate(
      label_clean = substr(trimws(country), 1, 25),
      mcp_pct = mcp_ratio * 100
    )
  
  if (nrow(df_ratio) == 0) return(NULL)
  
  df_ratio$label_clean <- factor(df_ratio$label_clean, 
                                   levels = rev(df_ratio$label_clean))
  
  p <- ggplot2::ggplot(df_ratio, ggplot2::aes(x = label_clean, y = mcp_pct)) +
    ggplot2::geom_col(fill = "#7E2F8E", color = "black", linewidth = 0.3, width = 0.7) +
    ggplot2::geom_text(
      ggplot2::aes(label = sprintf("%.1f%%", mcp_pct)),
      hjust = -0.1,
      size = 2.5,
      family = "mono"
    ) +
    ggplot2::coord_flip() +
    ggplot2::scale_y_continuous(
      name = "MCP Ratio (%)",
      limits = c(0, 115),
      expand = ggplot2::expansion(mult = c(0, 0))
    ) +
    ggplot2::labs(
      title = "International Collaboration Rate",
      subtitle = sprintf("Top %d countries by MCP ratio", top_n),
      x = NULL
    ) +
    ieee_theme_bar() +
    ggplot2::theme(
      axis.text.y = ggplot2::element_text(size = 7)
    )
  
  p
}

#' Create MCP share vs year plot (M3_p1_mcp_share_vs_year)
#' @keywords internal
create_mcp_share_vs_year_plot <- function(annual_data, config) {
  if (is.null(annual_data) || nrow(annual_data) == 0) return(NULL)
  
  year_col <- if ("year" %in% names(annual_data)) "year" else "Year"
  
  # Calculate MCP share if not present
  if (!"mcp_share" %in% names(annual_data) && "mcp" %in% names(annual_data) && "scp" %in% names(annual_data)) {
    annual_data$mcp_share <- annual_data$mcp / (annual_data$mcp + annual_data$scp) * 100
  }
  
  if (!"mcp_share" %in% names(annual_data) && "mcp_count" %in% names(annual_data)) {
    total_col <- if ("total" %in% names(annual_data)) "total" else "article_count"
    annual_data$mcp_share <- annual_data$mcp_count / annual_data[[total_col]] * 100
  }
  
  mcp_col <- if ("mcp_share" %in% names(annual_data)) "mcp_share" else "mcp_ratio"
  
  p <- ggplot2::ggplot(annual_data, ggplot2::aes_string(x = year_col, y = mcp_col)) +
    ggplot2::geom_line(color = "#7E2F8E", linewidth = 0.8) +
    ggplot2::geom_point(color = "#7E2F8E", size = 2, alpha = 0.8) +
    ggplot2::geom_smooth(
      method = "loess",
      se = TRUE,
      color = "#D95319",
      fill = "#D95319",
      alpha = 0.2,
      linewidth = 0.6
    ) +
    ggplot2::geom_hline(
      yintercept = 50,
      linetype = "dashed",
      color = "#666666",
      linewidth = 0.4
    ) +
    ggplot2::annotate(
      "text",
      x = min(annual_data[[year_col]], na.rm = TRUE),
      y = 52,
      label = "50% threshold",
      hjust = 0,
      size = 2.5,
      color = "#666666"
    ) +
    ggplot2::scale_x_continuous(
      name = "Year",
      breaks = scales::breaks_pretty(n = 8)
    ) +
    ggplot2::scale_y_continuous(
      name = "MCP Share (%)",
      limits = c(0, 100),
      labels = scales::label_number(accuracy = 1)
    ) +
    ieee_theme_timeseries() +
    ggplot2::labs(
      title = "International Collaboration Trend Over Time",
      subtitle = "Multi-Country Publication (MCP) share evolution"
    ) +
    ggplot2::theme(
      plot.title = ggplot2::element_text(size = 10, face = "bold", hjust = 0.5),
      plot.subtitle = ggplot2::element_text(size = 8, hjust = 0.5, face = "italic")
    )
  
  p
}

#' Create SCP/MCP pie chart
#' @keywords internal
create_scp_mcp_pie_plot <- function(total_data, config) {
  if (is.null(total_data)) return(NULL)
  
  scp <- total_data$scp %||% total_data$scp_count %||% 0
  mcp <- total_data$mcp %||% total_data$mcp_count %||% 0
  total <- scp + mcp
  
  if (total == 0) return(NULL)
  
  pie_df <- data.frame(
    type = c("SCP", "MCP"),
    count = c(scp, mcp),
    pct = c(scp, mcp) / total * 100,
    label = c(
      sprintf("SCP\n%d (%.1f%%)", scp, scp / total * 100),
      sprintf("MCP\n%d (%.1f%%)", mcp, mcp / total * 100)
    )
  )
  
  p <- ggplot2::ggplot(pie_df, ggplot2::aes(x = "", y = count, fill = type)) +
    ggplot2::geom_col(color = "black", linewidth = 0.3, width = 1) +
    ggplot2::coord_polar("y", start = 0) +
    ggplot2::geom_text(
      ggplot2::aes(label = label),
      position = ggplot2::position_stack(vjust = 0.5),
      size = 3,
      family = "mono",
      fontface = "bold"
    ) +
    ggplot2::scale_fill_manual(
      values = c(SCP = "#0072BD", MCP = "#D95319"),
      guide = "none"
    ) +
    ggplot2::labs(title = "Overall SCP vs MCP Distribution") +
    ieee_theme() +
    ggplot2::theme(
      axis.text = ggplot2::element_blank(),
      axis.ticks = ggplot2::element_blank(),
      axis.title = ggplot2::element_blank(),
      panel.border = ggplot2::element_blank(),
      plot.title = ggplot2::element_text(size = 10, face = "bold", hjust = 0.5)
    )
  
  p
}

#' Create top collaborators plot
#' @keywords internal
create_top_collaborators_plot <- function(top_collab, config) {
  if (is.null(top_collab) || nrow(top_collab) == 0) return(NULL)
  
  top_n <- config$top_n_countries %||% 10
  top <- head(top_collab[order(-top_collab$mcp_ratio), ], top_n)
  top$country <- substr(trimws(top$country), 1, 25)
  top$country <- factor(top$country, levels = rev(top$country))
  
  p <- ggplot2::ggplot(top, ggplot2::aes(x = country, y = mcp_ratio * 100)) +
    ggplot2::geom_col(fill = "#4DBEEE", color = "black", linewidth = 0.3, width = 0.7) +
    ggplot2::coord_flip() +
    ggplot2::scale_y_continuous(
      name = "MCP Ratio (%)",
      limits = c(0, 100)
    ) +
    ggplot2::labs(
      title = "Top Collaborating Countries",
      subtitle = "Countries with highest international collaboration rate",
      x = NULL
    ) +
    ieee_theme_bar()
  
  p
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
