# ============================================================================
# m3_table_citations.R - Citation tables for M3
# ============================================================================

#' Build country citation tables
#'
#' @param citation_data Output from \code{m3_compute_citations}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list of tibbles: \code{full}, \code{top_total}, \code{top_avg}
#' @export
m3_table_citations <- function(citation_data, config = biblio_config()) {
  empty <- list(full = tibble::tibble(), top_total = tibble::tibble(), top_avg = tibble::tibble())
  if (!is.list(citation_data) || nrow(citation_data$country_citations) == 0) {
    return(empty)
  }

  full <- citation_data$country_citations %>%
    dplyr::mutate(average_citations = round(average_citations, 2)) %>%
    dplyr::rename(
      Country           = country,
      Articles          = article_count,
      `Total Citations` = total_citations,
      `Avg Citations`   = average_citations
    )

  top_total <- citation_data$top_countries_by_citations %>%
    dplyr::rename(Rank = rank, Country = label, `Total Citations` = value)

  top_avg <- citation_data$top_countries_by_avg_citations %>%
    dplyr::mutate(value = round(value, 2)) %>%
    dplyr::rename(Rank = rank, Country = label, `Avg Citations` = value)

  list(full = full, top_total = top_total, top_avg = top_avg)
}
# <<< END FILE: R/module_m3/tables/m3_table_citations.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_collaboration_indices.R
# ============================================================================
# m3_table_collaboration_indices.R - Table builder for collaboration indices
# ============================================================================

#' @export
m3_table_collaboration_indices <- function(result, config = biblio_config()) {
  status <- "stub"
  indices_table <- tibble::tibble()
  bilateral_table <- tibble::tibble()
  summary_list <- list()
  
  if (!is.null(result) && is.list(result) && result$status == "success") {
    status <- "success"
    
    if (!is.null(result$indices) && nrow(result$indices) > 0) {
      indices_table <- tibble::as_tibble(result$indices)
      indices_table$rank <- seq_len(nrow(indices_table))
      indices_table <- indices_table[, c("rank", "country", "n_documents", 
                                          "avg_salton_index", "max_salton_index", "top_salton_partner",
                                          "avg_jaccard_index", "max_jaccard_index", "top_jaccard_partner",
                                          "avg_affinity_index", "max_affinity_index", "collaboration_centrality")]
    }
    
    if (!is.null(result$bilateral) && nrow(result$bilateral) > 0) {
      bilateral_table <- tibble::as_tibble(result$bilateral)
      bilateral_table$rank <- seq_len(nrow(bilateral_table))
      bilateral_table <- bilateral_table[, c("rank", "country_1", "country_2", 
                                              "salton", "jaccard", 
                                              "affinity_1to2", "affinity_2to1", "avg_affinity")]
    }
    
    summary_list <- list(
      total_countries = result$summary$total_countries %||% NA_integer_,
      total_collaborations = result$summary$total_collaborations %||% NA_integer_,
      mean_salton = result$summary$mean_salton %||% NA_real_,
      mean_jaccard = result$summary$mean_jaccard %||% NA_real_,
      mean_affinity = result$summary$mean_affinity %||% NA_real_,
      collaboration_density = result$summary$collaboration_density %||% NA_real_
    )
  }
  
  list(
    status = status,
    indices = indices_table,
    bilateral = bilateral_table,
    summary = summary_list
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m3/tables/m3_table_collaboration_indices.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_country_regressions.R
# ============================================================================
# m3_table_country_regressions.R - Table builder for Country Regressions
# ============================================================================

#' @export
m3_table_country_regressions <- function(result, config = biblio_config()) {
  status <- "stub"
  regression_table <- tibble::tibble()
  hypothesis_table <- tibble::tibble()
  summary_list <- list()
  
  if (!is.null(result) && is.list(result) && result$status == "success") {
    status <- "success"
    
    if (!is.null(result$country_regressions)) {
      successful <- Filter(function(x) x$status == "success", result$country_regressions)
      
      if (length(successful) > 0) {
        regression_table <- do.call(rbind, lapply(names(successful), function(cntry) {
          x <- successful[[cntry]]
          tibble::tibble(
            country = cntry,
            n_years = x$n_years,
            year_start = x$year_range[1],
            year_end = x$year_range[2],
            total_articles = x$total_articles,
            mean_annual = round(x$mean_annual, 1),
            sd_annual = round(x$sd_annual %||% NA_real_, 2),
            slope = round(x$slope %||% NA_real_, 4),
            slope_pvalue = round(x$slope_pvalue %||% NA_real_, 4),
            growth_rate_pct = round(x$growth_rate %||% NA_real_, 2),
            trend_direction = x$trend_direction %||% "unknown",
            best_model = x$best_model %||% NA_character_,
            R2 = round(x$best_fit$R2 %||% NA_real_, 4)
          )
        }))
        
        regression_table <- regression_table[order(-regression_table$total_articles), ]
        regression_table$rank <- seq_len(nrow(regression_table))
        regression_table <- regression_table[, c("rank", "country", "n_years", "year_start", "year_end",
                                                 "total_articles", "mean_annual", "slope", "slope_pvalue",
                                                 "growth_rate_pct", "trend_direction", "best_model", "R2")]
      }
    }
    
    if (!is.null(result$hypotheses)) {
      hyp_list <- result$hypotheses$hyphypotheses
      if (is.null(hyp_list)) hyp_list <- result$hypotheses
      
      hypothesis_table <- do.call(rbind, lapply(names(hyp_list), function(h) {
        x <- hyp_list[[h]]
        tibble::tibble(
          hypothesis_id = gsub("H03_", "H", h),
          hyphypothesis = substr(x$hyphypothesis %||% x$hyphothesis %||% h, 1, 80),
          null_hyphypothesis = substr(x$null %||% "", 1, 80),
          result = x$result %||% "unknown",
          interpretation = substr(x$interpretation %||% "", 1, 100)
        )
      }))
    }
    
    if (!is.null(result$summary)) {
      summary_list <- result$summary
    }
  }
  
  list(
    status = status,
    regressions = regression_table,
    hypotheses = hypothesis_table,
    summary = summary_list
  )
}

`%||%` <- function(a, b) if (!is.null(a)) a else b
# <<< END FILE: R/module_m3/tables/m3_table_country_regressions.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_distribution_tests.R
# ============================================================================
# m3_table_distribution_tests.R - Distribution diagnostics tables for M3
# ============================================================================

#' Build distribution diagnostics table
#'
#' @param dist_data Output from \code{m3_compute_distribution_tests}
#' @param config A configuration list (see \code{biblio_config})
#' @return A tibble combining production and citation distribution stats
#' @export
m3_table_distribution_tests <- function(dist_data, config = biblio_config()) {
  if (!is.list(dist_data)) return(tibble::tibble())

  rows <- list()

  if (nrow(dist_data$production_distribution) > 0) {
    rows[["Production"]] <- dist_data$production_distribution %>%
      dplyr::mutate(Dimension = "Production")
  }
  if (nrow(dist_data$citations_distribution) > 0) {
    rows[["Citations"]] <- dist_data$citations_distribution %>%
      dplyr::mutate(Dimension = "Citations")
  }

  if (length(rows) == 0) return(tibble::tibble())

  dplyr::bind_rows(rows) %>%
    dplyr::select(Dimension, dplyr::everything(), -variable) %>%
    dplyr::mutate(dplyr::across(where(is.numeric), ~ round(.x, 4)))
}
# <<< END FILE: R/module_m3/tables/m3_table_distribution_tests.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_experiments.R
# ============================================================================
# m3_table_experiments.R - Experiments summary tables for M3
# ============================================================================

#' Build experiments summary tables
#'
#' @param experiments_data Output from \code{m3_compute_experiments}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list of tibbles: \code{quadrant}, \code{concentration}, \code{momentum}
#' @export
m3_table_experiments <- function(experiments_data, config = biblio_config()) {
  empty <- list(quadrant = tibble::tibble(), concentration = tibble::tibble(),
                momentum = tibble::tibble())
  if (!is.list(experiments_data)) return(empty)

  quadrant <- if (is.data.frame(experiments_data$quadrant) &&
                  nrow(experiments_data$quadrant) > 0) {
    experiments_data$quadrant %>%
      dplyr::mutate(avg_citations = round(avg_citations, 2)) %>%
      dplyr::arrange(quadrant, dplyr::desc(article_count)) %>%
      dplyr::rename(
        Country        = country,
        Articles       = article_count,
        `Total Cit.`   = total_citations,
        `Avg Cit.`     = avg_citations,
        Quadrant       = quadrant
      )
  } else tibble::tibble()

  concentration <- if (is.data.frame(experiments_data$concentration) &&
                       nrow(experiments_data$concentration) > 0) {
    experiments_data$concentration %>%
      dplyr::mutate(
        gini       = round(gini, 4),
        top1_share = round(top1_share * 100, 2)
      ) %>%
      dplyr::rename(
        `Top-k`           = top_k,
        `Gini`            = gini,
        `Top-1 Share (%)` = top1_share
      )
  } else tibble::tibble()

  momentum <- if (is.data.frame(experiments_data$momentum) &&
                  nrow(experiments_data$momentum) > 0) {
    experiments_data$momentum %>%
      dplyr::mutate(
        recent_mean    = round(recent_mean, 2),
        prior_mean     = round(prior_mean, 2),
        momentum_score = round(momentum_score, 3)
      ) %>%
      dplyr::rename(
        Country          = country,
        `Years`          = n_years,
        `Recent Mean`    = recent_mean,
        `Prior Mean`     = prior_mean,
        `Momentum Score` = momentum_score
      )
  } else tibble::tibble()

  list(quadrant = quadrant, concentration = concentration, momentum = momentum)
}
# <<< END FILE: R/module_m3/tables/m3_table_experiments.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_growth_dynamics.R
# ============================================================================
# m3_table_growth_dynamics.R - Growth dynamics tables for M3
# ============================================================================

#' Build growth dynamics tables
#'
#' @param growth_data Output from \code{m3_compute_growth_dynamics}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list of tibbles: \code{productivity_growth}, \code{citations_growth}
#' @export
m3_table_growth_dynamics <- function(growth_data, config = biblio_config()) {
  empty <- list(productivity_growth = tibble::tibble(), citations_growth = tibble::tibble())
  if (!is.list(growth_data)) return(empty)

  .clean_growth <- function(df) {
    if (!is.data.frame(df) || nrow(df) == 0) return(tibble::tibble())
    df %>%
      dplyr::mutate(
        cagr                    = round(cagr * 100, 2),
        slope                   = round(slope, 3),
        growth_rate_last_year   = round(growth_rate_last_year * 100, 2)
      ) %>%
      dplyr::rename(
        Country              = country,
        `Years`              = n_years,
        `Start Value`        = start_value,
        `End Value`          = end_value,
        `CAGR (%)`           = cagr,
        `Trend Slope`        = slope,
        `Last-Year Growth (%)` = growth_rate_last_year
      )
  }

  list(
    productivity_growth = .clean_growth(growth_data$productivity_growth),
    citations_growth    = .clean_growth(growth_data$citations_growth)
  )
}
# <<< END FILE: R/module_m3/tables/m3_table_growth_dynamics.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_inequality.R
# ============================================================================
# m3_table_inequality.R - Inequality summary tables for M3
# ============================================================================

#' Build inequality summary table
#'
#' @param inequality_data Output from \code{m3_compute_inequality}
#' @param config A configuration list (see \code{biblio_config})
#' @return A tibble summarizing inequality metrics for production and citations
#' @export
m3_table_inequality <- function(inequality_data, config = biblio_config()) {
  if (!is.list(inequality_data) || !is.list(inequality_data$inequality_summary)) {
    return(tibble::tibble())
  }

  s <- inequality_data$inequality_summary

  .fmt <- function(x) {
    if (is.null(x) || length(x) == 0) {
      return(NA_real_)
    }
    value <- suppressWarnings(as.numeric(x[1]))
    if (!length(value) || !is.finite(value)) {
      return(NA_real_)
    }
    round(value, 4)
  }

  tibble::tibble(
    Metric               = c("Gini Coefficient", "HHI",
                              "Normalized Entropy", "Top-5 Share (%)", "Top-10 Share (%)"),
    Production           = c(.fmt(s$production$gini),
                              .fmt(s$production$hhi),
                              .fmt(s$production$entropy),
                              .fmt(s$production$top5_share) * 100,
                              .fmt(s$production$top10_share) * 100),
    Citations            = c(.fmt(s$citations$gini),
                              .fmt(s$citations$hhi),
                              .fmt(s$citations$entropy),
                              .fmt(s$citations$top5_share) * 100,
                              .fmt(s$citations$top10_share) * 100)
  )
}
# <<< END FILE: R/module_m3/tables/m3_table_inequality.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_productivity.R
# ============================================================================
# m3_table_productivity.R - Production tables for M3
# ============================================================================

#' Build country production tables
#'
#' @param production_data Output from \code{m3_compute_production}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list of tibbles: \code{full} and \code{top}
#' @export
m3_table_productivity <- function(production_data, config = biblio_config()) {
  empty <- list(full = tibble::tibble(), top = tibble::tibble())
  if (!is.list(production_data) || nrow(production_data$country_production) == 0) {
    return(empty)
  }

  full <- production_data$country_production %>%
    dplyr::mutate(
      share            = round(share * 100, 2),
      cumulative_share = round(cumulative_share * 100, 2)
    ) %>%
    dplyr::rename(
      Country          = country,
      Articles         = article_count,
      `Share (%)`      = share,
      `Cum. Share (%)` = cumulative_share
    )

  top <- production_data$top_countries_by_production %>%
    dplyr::mutate(
      share            = round(share * 100, 2),
      cumulative_share = round(cumulative_share * 100, 2)
    ) %>%
    dplyr::rename(
      Rank             = rank,
      Country          = label,
      Articles         = value,
      `Share (%)`      = share,
      `Cum. Share (%)` = cumulative_share
    )

  list(full = full, top = top)
}
# <<< END FILE: R/module_m3/tables/m3_table_productivity.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_profiles.R
# ============================================================================
# m3_table_profiles.R - Country profile tables for M3
# ============================================================================

#' Build country profile feature table
#'
#' @param profiles_data Output from \code{m3_compute_country_profiles}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list of tibbles: \code{features} and \code{profiles}
#' @export
m3_table_profiles <- function(profiles_data, config = biblio_config()) {
  empty <- list(features = tibble::tibble(), profiles = tibble::tibble())
  if (!is.list(profiles_data)) return(empty)

  features <- if (nrow(profiles_data$country_features) > 0) {
    profiles_data$country_features %>%
      dplyr::mutate(
        average_citations = round(average_citations, 2),
        mcp_ratio         = round(mcp_ratio, 1)
      ) %>%
      dplyr::rename(
        Country           = country,
        Articles          = article_count,
        `Total Citations` = total_citations,
        `Avg Citations`   = average_citations,
        SCP               = scp,
        MCP               = mcp,
        `MCP Ratio (%)`   = mcp_ratio
      )
  } else tibble::tibble()

  # Profiles: drop z-score columns for display, keep country + cluster + PCs
  profiles <- if (nrow(profiles_data$country_profiles) > 0) {
    keep_cols <- c("country",
                   grep("_z$", names(profiles_data$country_profiles),
                        value = TRUE, invert = TRUE))
    profiles_data$country_profiles %>%
      dplyr::select(dplyr::any_of(keep_cols)) %>%
      dplyr::mutate(dplyr::across(where(is.numeric), ~ round(.x, 3)))
  } else tibble::tibble()

  list(features = features, profiles = profiles)
}
# <<< END FILE: R/module_m3/tables/m3_table_profiles.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_rankings.R
# ============================================================================
# m3_table_rankings.R - Rank diagnostics tables for M3
# ============================================================================

#' Build rank diagnostics tables
#'
#' @param rankings_data Output from \code{m3_compute_rankings}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list of tibbles: \code{production}, \code{citations}, \code{summary}
#' @export
m3_table_rankings <- function(rankings_data, config = biblio_config()) {
  empty <- list(production = tibble::tibble(), citations = tibble::tibble(),
                summary = tibble::tibble())
  if (!is.list(rankings_data)) return(empty)

  production <- if (nrow(rankings_data$production_rankings) > 0) {
    rankings_data$production_rankings %>%
      dplyr::mutate(cumulative_share = round(cumsum(value) / sum(value) * 100, 2)) %>%
      dplyr::rename(Rank = rank, Country = label, Articles = value,
                    `Cum. Share (%)` = cumulative_share)
  } else tibble::tibble()

  citations <- if (nrow(rankings_data$citations_rankings) > 0) {
    rankings_data$citations_rankings %>%
      dplyr::mutate(cumulative_share = round(cumsum(value) / sum(value) * 100, 2)) %>%
      dplyr::rename(Rank = rank, Country = label, Citations = value,
                    `Cum. Share (%)` = cumulative_share)
  } else tibble::tibble()

  rs <- rankings_data$rank_summary
  summary <- tibble::tibble(
    Dimension               = c("Production", "Citations"),
    `Gini`                  = c(round(rs$production$gini, 4),
                                 round(rs$citations$gini,  4)),
    `Top-10% Share`         = c(round(rs$production$top_heavy, 4),
                                 round(rs$citations$top_heavy,  4))
  )

  list(production = production, citations = citations, summary = summary)
}
# <<< END FILE: R/module_m3/tables/m3_table_rankings.R

# >>> BEGIN FILE: R/module_m3/tables/m3_table_scp_mcp.R
# ============================================================================
# m3_table_scp_mcp.R - SCP/MCP tables for M3
# ============================================================================

#' Build SCP/MCP collaboration tables
#'
#' @param scp_mcp_data Output from \code{m3_compute_scp_mcp}
#' @param config A configuration list (see \code{biblio_config})
#' @return A list of tibbles: \code{full}, \code{top_scp}, \code{top_mcp}, \code{top_ratio}
#' @export
m3_table_scp_mcp <- function(scp_mcp_data, config = biblio_config()) {
  empty <- list(full = tibble::tibble(), top_scp = tibble::tibble(),
                top_mcp = tibble::tibble(), top_ratio = tibble::tibble())
  if (!is.list(scp_mcp_data) || nrow(scp_mcp_data$scp_mcp) == 0) return(empty)

  full <- scp_mcp_data$scp_mcp %>%
    dplyr::rename(
      Country      = country,
      Articles     = article_count,
      SCP          = scp,
      MCP          = mcp,
      `MCP Ratio (%)` = mcp_ratio
    )

  top_scp <- scp_mcp_data$top_countries_by_scp %>%
    dplyr::rename(Rank = rank, Country = label, SCP = value)

  top_mcp <- scp_mcp_data$top_countries_by_mcp %>%
    dplyr::rename(Rank = rank, Country = label, MCP = value)

  top_ratio <- scp_mcp_data$top_countries_by_mcp_ratio %>%
    dplyr::rename(Rank = rank, Country = label, `MCP Ratio (%)` = value)

  list(full = full, top_scp = top_scp, top_mcp = top_mcp, top_ratio = top_ratio)
}
