# ============================================================================
# m5_run.R - M5 Citation Network Analysis Orchestrator
# ============================================================================

#' Run M5 module (Citation Network Analysis)
#'
#' @param input Bibliographic data frame with CR (cited references) field
#' @param config Configuration list
#' @param export Logical. If TRUE, exports artifacts to disk.
#' @return Module result object
#' @export
run_m5 <- function(input, config = biblio_config(), export = TRUE) {
  config <- merge_biblio_config(config)
  
  log_message("INFO", "Starting M5: Citation Network Analysis")
  
  # Validate input
  validation <- validate_m5_input(input, config)
  if (!validation$ok) {
    log_message("ERROR", "M5 validation failed: {msg}", msg = validation$error)
    return(create_error_result("m5", "Citation Network", validation$error))
  }
  
  # Build citation network
  log_message("INFO", "Building citation network...")
  citation_network <- m5_build_citation_network(input, config)
  
  if (citation_network$status != "success") {
    return(create_error_result("m5", "Citation Network", citation_network$status))
  }
  
  # Compute metrics
  log_message("INFO", "Computing citation metrics...")
  data <- list(
    network = citation_network,
    metrics = m5_compute_citation_metrics(citation_network, config),
    cocitation = m5_build_cocitation_network(input, config),
    coupling = m5_build_coupling_network(input, config),
    bursts = m5_detect_citation_bursts(input, config)
  )
  
  # Build result
  result <- new_module_result(
    module_id = "m5",
    module_name = "Citation Network Analysis",
    status = "success",
    inputs = list(n_records = nrow(input)),
    data = data,
    diagnostics = list()
  )
  
  # Render
  result <- m5_render_all(result, data, config)
  
  # Export
  if (export) {
    exported <- export_m5(result, config)
    manifest <- build_m5_manifest(result, exported, config)
    result <- attach_manifest_to_result(result, manifest)
  }
  
  log_message("INFO", "M5: Citation Network Analysis completed")
  result
}

#' Build citation network from references
#' @export
m5_build_citation_network <- function(input, config = biblio_config()) {
  # Parse cited references
  references <- parse_references(input$CR)
  
  # Create edge list: citing_paper -> cited_paper
  edges <- data.frame(
    from = character(),
    to = character(),
    stringsAsFactors = FALSE
  )
  
  for (i in seq_len(nrow(input))) {
    citing <- input$DI[i] %||% paste0("doc_", i)
    cited <- references[[i]]
    
    if (length(cited) > 0) {
      edges <- rbind(edges, data.frame(
        from = rep(citing, length(cited)),
        to = cited,
        stringsAsFactors = FALSE
      ))
    }
  }
  
  # Build graph
  if (requireNamespace("igraph", quietly = TRUE) && nrow(edges) > 0) {
    g <- igraph::graph_from_data_frame(edges, directed = TRUE)
    
    list(
      status = "success",
      graph = g,
      edges = edges,
      n_nodes = igraph::vcount(g),
      n_edges = igraph::ecount(g)
    )
  } else {
    list(
      status = "success",
      edges = edges,
      n_nodes = length(unique(c(edges$from, edges$to))),
      n_edges = nrow(edges)
    )
  }
}

#' Parse reference strings
#' @keywords internal
parse_references <- function(cr_field) {
  lapply(cr_field, function(cr) {
    if (is.na(cr) || cr == "") return(character())
    
    # Split by semicolon
    refs <- strsplit(cr, ";")[[1]]
    refs <- trimws(refs)
    
    # Extract DOI if present
    dois <- regmatches(refs, gregexpr("10\\.\\S+", refs))
    unlist(dois)
  })
}

#' Build co-citation network
#' @export
m5_build_cocitation_network <- function(input, config = biblio_config()) {
  references <- parse_references(input$CR)
  
  # Find pairs of papers cited together
  cocitation_pairs <- list()
  
  for (refs in references) {
    if (length(refs) >= 2) {
      pairs <- combn(refs, 2, simplify = FALSE)
      for (pair in pairs) {
        key <- paste(sort(pair), collapse = "::")
        cocitation_pairs[[key]] <- (cocitation_pairs[[key]] %||% 0) + 1
      }
    }
  }
  
  # Convert to data frame
  if (length(cocitation_pairs) > 0) {
    pairs_df <- data.frame(
      paper1 = sapply(strsplit(names(cocitation_pairs), "::"), `[`, 1),
      paper2 = sapply(strsplit(names(cocitation_pairs), "::"), `[`, 2),
      cocitation_count = unlist(cocitation_pairs),
      stringsAsFactors = FALSE
    )
    
    list(status = "success", pairs = pairs_df, n_pairs = nrow(pairs_df))
  } else {
    list(status = "error: no co-citations found")
  }
}

#' Build bibliographic coupling network
#' @export
m5_build_coupling_network <- function(input, config = biblio_config()) {
  references <- parse_references(input$CR)
  
  # Calculate coupling strength between papers
  n <- length(references)
  coupling <- data.frame(
    paper1 = character(),
    paper2 = character(),
    shared_references = integer(),
    stringsAsFactors = FALSE
  )
  
  for (i in 1:(n-1)) {
    for (j in (i+1):n) {
      shared <- length(intersect(references[[i]], references[[j]]))
      if (shared > 0) {
        coupling <- rbind(coupling, data.frame(
          paper1 = input$DI[i] %||% paste0("doc_", i),
          paper2 = input$DI[j] %||% paste0("doc_", j),
          shared_references = shared,
          stringsAsFactors = FALSE
        ))
      }
    }
  }
  
  list(status = "success", coupling = coupling, n_pairs = nrow(coupling))
}

#' Compute citation metrics
#' @export
m5_compute_citation_metrics <- function(network, config = biblio_config()) {
  if (!requireNamespace("igraph", quietly = TRUE) || is.null(network$graph)) {
    return(list(status = "error: igraph not available"))
  }
  
  g <- network$graph
  
  list(
    status = "success",
    degree = igraph::degree(g, mode = "all"),
    indegree = igraph::degree(g, mode = "in"),
    outdegree = igraph::degree(g, mode = "out"),
    betweenness = igraph::betweenness(g),
    closeness = igraph::closeness(g),
    pagerank = igraph::page_rank(g)$vector,
    eigenvector = igraph::eigen_centrality(g)$vector
  )
}

#' Detect citation bursts
#' @export
m5_detect_citation_bursts <- function(input, config = biblio_config()) {
  # Group citations by year
  yearly_citations <- input %>%
    dplyr::group_by(PY) %>%
    dplyr::summarise(n_citations = sum(TC, na.rm = TRUE), .groups = "drop")
  
  # Simple burst detection: years with >2x average
  avg_citations <- mean(yearly_citations$n_citations, na.rm = TRUE)
  
  bursts <- yearly_citations %>%
    dplyr::filter(n_citations > avg_citations * 2) %>%
    dplyr::mutate(burst_strength = n_citations / avg_citations)
  
  list(
    status = "success",
    bursts = bursts,
    avg_citations = avg_citations,
    n_bursts = nrow(bursts)
  )
}
# <<< END FILE: R/module_m5/m5_run.R

# >>> BEGIN FILE: R/module_m5/m5_validate.R
# ============================================================================
# m5_validate.R - Input validation for M5 Citation Network
# ============================================================================

#' Validate M5 input (citation network data)
#'
#' @param input A data frame with CR (cited references) field
#' @param config A configuration list
#' @return A list with ok, missing_columns, n_rows, n_cols, error
#' @export
validate_m5_input <- function(input, config = biblio_config()) {
  if (!is.data.frame(input)) {
    return(list(
      ok = FALSE,
      missing_columns = character(),
      n_rows = 0,
      n_cols = 0,
      error = "Input is not a data frame"
    ))
  }
  
  if (nrow(input) == 0) {
    return(list(
      ok = FALSE,
      missing_columns = character(),
      n_rows = 0,
      n_cols = ncol(input),
      error = "Input data frame is empty"
    ))
  }
  
  # CR (Cited References) is required for citation network analysis
  required <- "CR"
  col_check <- validate_required_columns(input, required)
  
  if (!col_check$ok) {
    return(list(
      ok = FALSE,
      missing_columns = col_check$missing_columns,
      n_rows = nrow(input),
      n_cols = ncol(input),
      error = paste("Missing required columns:", paste(col_check$missing_columns, collapse = ", "))
    ))
  }
  
  # Check CR column has data
  cr_col <- input$CR
  non_na_cr <- sum(!is.na(cr_col) & cr_col != "")
  if (non_na_cr < 3) {
    return(list(
      ok = FALSE,
      missing_columns = character(),
      n_rows = nrow(input),
      n_cols = ncol(input),
      error = "Insufficient cited references data (need at least 3 non-empty CR entries)"
    ))
  }
  
  list(
    ok = TRUE,
    missing_columns = character(),
    n_rows = nrow(input),
    n_cols = ncol(input),
    n_cited_refs = non_na_cr,
    error = NULL
  )
}
# <<< END FILE: R/module_m5/m5_validate.R

# >>> BEGIN FILE: R/module_m6/m6_run.R
# ============================================================================
# m6_run.R - M6 Topic Evolution Analysis
# ============================================================================

#' Run M6 module (Topic Evolution Analysis)
#'
#' @param input Bibliographic data frame with keywords
#' @param config Configuration list
#' @param export Logical. If TRUE, exports artifacts to disk.
#' @return Module result object
#' @export
run_m6 <- function(input, config = biblio_config(), export = TRUE) {
  config <- merge_biblio_config(config)
  
  log_message("INFO", "Starting M6: Topic Evolution Analysis")
  
  # Validate input
  validation <- validate_m6_input(input, config)
  if (!validation$ok) {
    log_message("ERROR", "M6 validation failed: {msg}", msg = validation$error)
    return(create_error_result("m6", "Topic Evolution", validation$error))
  }
  
  # Get the keyword column to use
  kw_col <- validation$keyword_column
  
  # Dynamic topic modeling
  log_message("INFO", "Computing dynamic topic model...")
  dtm <- m6_dynamic_topic_model(input, kw_col, config)
  
  if (dtm$status != "success") {
    return(create_error_result("m6", "Topic Evolution", dtm$status))
  }
  
  # Detect trends
  trends <- m6_detect_topic_trends(dtm, config)
  
  # Build result
  data <- list(
    dtm = dtm,
    trends = trends,
    evolution = m6_track_topic_evolution(dtm, config),
    emerging = m6_identify_emerging_topics(dtm, trends, config)
  )
  
  result <- new_module_result(
    module_id = "m6",
    module_name = "Topic Evolution Analysis",
    status = "success",
    inputs = list(n_records = nrow(input)),
    data = data,
    diagnostics = list()
  )
  
  # Render
  result <- m6_render_all(result, data, config)
  
  # Export
  if (export) {
    exported <- export_m6(result, config)
    manifest <- build_m6_manifest(result, exported, config)
    result <- attach_manifest_to_result(result, manifest)
  }
  
  log_message("INFO", "M6: Topic Evolution Analysis completed")
  result
}

#' Dynamic Topic Modeling
#' @export
m6_dynamic_topic_model <- function(input, kw_col, config = biblio_config()) {
  # Extract keywords by year
  yearly_keywords <- input %>%
    dplyr::filter(!is.na(.data[[kw_col]]), !is.na(PY)) %>%
    dplyr::group_by(PY) %>%
    dplyr::summarise(
      keywords = paste(.data[[kw_col]], collapse = "; "),
      n_docs = dplyr::n(),
      .groups = "drop"
    ) %>%
    dplyr::arrange(PY)
  
  if (nrow(yearly_keywords) < 3) {
    return(list(status = "error: insufficient time periods (need 3+ years)"))
  }
  
  # For each year, compute top keywords
  yearly_top_kw <- lapply(seq_len(nrow(yearly_keywords)), function(i) {
    kw_list <- strsplit(yearly_keywords$keywords[i], ";")[[1]]
    kw_list <- trimws(kw_list)
    kw_list <- tolower(kw_list)
    kw_list <- kw_list[nchar(kw_list) > 2]
    
    kw_freq <- sort(table(kw_list), decreasing = TRUE)
    head(kw_freq, 50)  # Top 50 per year
  })
  
  names(yearly_top_kw) <- yearly_keywords$PY
  
  list(
    status = "success",
    yearly_keywords = yearly_top_kw,
    years = yearly_keywords$PY,
    n_years = length(yearly_top_kw)
  )
}

#' Detect topic trends
#' @export
m6_detect_topic_trends <- function(dtm, config = biblio_config()) {
  # Get all unique keywords across all years
  all_keywords <- unique(unlist(lapply(dtm$yearly_keywords, names)))
  
  # Track each keyword over time
  keyword_trends <- lapply(all_keywords, function(kw) {
    freqs <- sapply(dtm$yearly_keywords, function(yearly) {
      ifelse(kw %in% names(yearly), yearly[kw], 0)
    })
    
    # Mann-Kendall trend test (simplified)
    years <- as.numeric(names(freqs))
    if (length(unique(freqs)) > 1) {
      trend <- ifelse(freqs[length(freqs)] > freqs[1], "increasing", "decreasing")
      strength <- abs(freqs[length(freqs)] - freqs[1]) / max(freqs, 1)
    } else {
      trend <- "stable"
      strength <- 0
    }
    
    list(
      keyword = kw,
      frequencies = freqs,
      trend = trend,
      strength = strength,
      total_freq = sum(freqs)
    )
  })
  
  names(keyword_trends) <- all_keywords
  
  # Categorize
  emerging <- names(which(sapply(keyword_trends, function(x) 
    x$trend == "increasing" && x$strength > 0.5)))
  
  declining <- names(which(sapply(keyword_trends, function(x) 
    x$trend == "decreasing" && x$strength > 0.5)))
  
  stable <- names(which(sapply(keyword_trends, function(x) 
    x$trend == "stable")))
  
  list(
    status = "success",
    trends = keyword_trends,
    emerging = emerging,
    declining = declining,
    stable = stable,
    n_emerging = length(emerging),
    n_declining = length(declining)
  )
}

#' Track topic evolution
#' @export
m6_track_topic_evolution <- function(dtm, config = biblio_config()) {
  # Compute keyword persistence across years
  years <- dtm$years
  n_years <- length(years)
  
  evolution <- lapply(seq_along(years)[-1], function(i) {
    prev_year <- years[i-1]
    curr_year <- years[i]
    
    prev_kw <- names(dtm$yearly_keywords[[i-1]])
    curr_kw <- names(dtm$yearly_keywords[[i]])
    
    list(
      from_year = prev_year,
      to_year = curr_year,
      retained = length(intersect(prev_kw, curr_kw)),
      new = length(setdiff(curr_kw, prev_kw)),
      dropped = length(setdiff(prev_kw, curr_kw)),
      retention_rate = length(intersect(prev_kw, curr_kw)) / length(prev_kw)
    )
  })
  
  list(
    status = "success",
    transitions = evolution,
    avg_retention = mean(sapply(evolution, function(x) x$retention_rate), na.rm = TRUE)
  )
}

#' Identify emerging topics
#' @export
m6_identify_emerging_topics <- function(dtm, trends, config = biblio_config()) {
  # Get top emerging keywords from last few years
  recent_years <- tail(dtm$years, 3)
  recent_keywords <- unique(unlist(lapply(recent_years, function(y) {
    names(dtm$yearly_keywords[[as.character(y)]])
  })))
  
  # Filter to those marked as emerging
  emerging_recent <- intersect(trends$emerging, recent_keywords)
  
  # Get trend details
  emerging_details <- lapply(emerging_recent, function(kw) {
    tr <- trends$trends[[kw]]
    list(
      keyword = kw,
      first_appearance = min(which(tr$frequencies > 0)),
      total_frequency = tr$total_freq,
      growth_rate = tr$strength
    )
  })
  
  # Sort by growth rate
  emerging_details <- emerging_details[order(-sapply(emerging_details, function(x) x$growth_rate))]
  
  list(
    status = "success",
    emerging_topics = head(emerging_details, 20),
    n_emerging = length(emerging_details)
  )
}
# <<< END FILE: R/module_m6/m6_run.R

# >>> BEGIN FILE: R/module_m6/m6_validate.R
# ============================================================================
# m6_validate.R - Input validation for M6 Topic Evolution
# ============================================================================

#' Validate M6 input (topic evolution data)
#'
#' @param input A data frame with keyword columns (DE or ID)
#' @param config A configuration list
#' @return A list with ok, missing_columns, n_rows, n_cols, error
#' @export
validate_m6_input <- function(input, config = biblio_config()) {
  if (!is.data.frame(input)) {
    return(list(
      ok = FALSE,
      missing_columns = character(),
      n_rows = 0,
      n_cols = 0,
      error = "Input is not a data frame"
    ))
  }
  
  if (nrow(input) == 0) {
    return(list(
      ok = FALSE,
      missing_columns = character(),
      n_rows = 0,
      n_cols = ncol(input),
      error = "Input data frame is empty"
    ))
  }
  
  # Either DE (author keywords) or ID (keywords plus) is required
  has_de <- "DE" %in% names(input)
  has_id <- "ID" %in% names(input)
  
  if (!has_de && !has_id) {
    return(list(
      ok = FALSE,
      missing_columns = c("DE", "ID"),
      n_rows = nrow(input),
      n_cols = ncol(input),
      error = "Missing keyword columns: need DE (author keywords) or ID (keywords plus)"
    ))
  }
  
  # Determine which column to use
  kw_col <- if (has_de) "DE" else "ID"
  
  # Check keyword column has data
  kw_data <- input[[kw_col]]
  non_na_kw <- sum(!is.na(kw_data) & kw_data != "")
  if (non_na_kw < 5) {
    return(list(
      ok = FALSE,
      missing_columns = character(),
      n_rows = nrow(input),
      n_cols = ncol(input),
      error = "Insufficient keyword data (need at least 5 non-empty keyword entries)"
    ))
  }
  
  # Check for year column (needed for topic evolution)
  if (!"PY" %in% names(input)) {
    return(list(
      ok = FALSE,
      missing_columns = "PY",
      n_rows = nrow(input),
      n_cols = ncol(input),
      error = "Missing PY (publication year) column required for topic evolution"
    ))
  }
  
  list(
    ok = TRUE,
    missing_columns = character(),
    n_rows = nrow(input),
    n_cols = ncol(input),
    keyword_column = kw_col,
    n_keywords = non_na_kw,
    error = NULL
  )
}
# <<< END FILE: R/module_m6/m6_validate.R

