# ============================================================================
# json_service.R - JSON export service
# ============================================================================

#' Write a JSON artifact file
#'
#' @param x Object to serialize.
#' @param path Character. Output file path.
#' @param auto_unbox Logical. Auto-unbox single-element vectors.
#' @param pretty Logical. Pretty-print JSON.
#' @return Invisibly returns the path.
#' @export
write_json_artifact <- function(x, path,
                                auto_unbox = TRUE,
                                pretty = TRUE) {
  # Create directory if needed
  dir_path <- dirname(path)
  if (!dir.exists(dir_path)) {
    dir_created <- dir.create(dir_path, recursive = TRUE, showWarnings = FALSE)
    if (!dir_created && !dir.exists(dir_path)) {
      cli::cli_warn("Failed to create directory: {dir_path}")
      return(invisible(NULL))
    }
  }
  
  # Validate input is serializable
  if (is.null(x)) {
    cli::cli_warn("Cannot write NULL object to JSON")
    return(invisible(NULL))
  }

  x <- json_sanitize_artifact(x)
  
  # Write with error handling
  tryCatch({
    jsonlite::write_json(x, path, auto_unbox = auto_unbox, pretty = pretty)
  }, error = function(e) {
    cli::cli_warn("Failed to write JSON to {path}: {e$message}")
  })
  
  invisible(path)
}

json_sanitize_artifact <- function(x) {
  if (is.null(x)) {
    return(NULL)
  }

  if (inherits(x, "table")) {
    return(as.data.frame(x, stringsAsFactors = FALSE))
  }

  if (inherits(x, "dist")) {
    return(json_sanitize_artifact(as.matrix(x)))
  }

  if (is.matrix(x)) {
    out <- as.data.frame(x, stringsAsFactors = FALSE)
    row_id <- rownames(x)
    if (is.null(row_id)) {
      row_id <- seq_len(nrow(out))
    }
    out <- cbind(rowname = row_id, out, stringsAsFactors = FALSE)
    rownames(out) <- NULL
    return(out)
  }

  if (is.data.frame(x)) {
    out <- x
    factor_cols <- vapply(out, is.factor, logical(1))
    out[factor_cols] <- lapply(out[factor_cols], as.character)
    return(out)
  }

  if (is.list(x)) {
    return(lapply(x, json_sanitize_artifact))
  }

  if (is.factor(x)) {
    return(as.character(x))
  }

  if (is.language(x) || inherits(x, "call")) {
    return(paste(deparse(x), collapse = " "))
  }

  x
}
# <<< END FILE: R/services/json_service.R

# >>> BEGIN FILE: R/services/plot_export_service.R
# ============================================================================
# plot_export_service.R - Plot export service
# ============================================================================

#' Export a plot artifact to PNG, SVG, and PDF
#'
#' @param plot A ggplot object.
#' @param path Character. Output file path (without extension).
#' @param width Numeric. Width in inches.
#' @param height Numeric. Height in inches.
#' @param dpi Numeric. Resolution in DPI.
#' @return Invisibly returns the character vector of paths.
#' @export
export_plot_artifact <- function(plot, path,
                                 width = 10,
                                 height = 6,
                                 dpi = 300) {
  if (inherits(plot, "recordedplot")) {
    return(export_recorded_plot_artifact(plot, path, width = width, height = height, dpi = dpi))
  }

  # Suppress any display devices in non-interactive mode
  if (!interactive()) {
    old_dev <- grDevices::dev.cur()
    on.exit(if (grDevices::dev.cur() != old_dev) grDevices::dev.off(), add = TRUE)
  }
  
  dir.create(dirname(path), recursive = TRUE, showWarnings = FALSE)

  png_path <- paste0(path, ".png")
  svg_path <- paste0(path, ".svg")
  pdf_path <- paste0(path, ".pdf")

  # Save PNG using Cairo if available (better for non-interactive)
  if (requireNamespace("Cairo", quietly = TRUE)) {
    suppressMessages(suppressWarnings(
      ggplot2::ggsave(
        filename = png_path,
        plot     = plot,
        width    = width,
        height   = height,
        dpi      = dpi,
        bg       = "white",
        type = "cairo"
      )
    ))
  } else {
    suppressMessages(suppressWarnings(
      ggplot2::ggsave(
        filename = png_path,
        plot     = plot,
        width    = width,
        height   = height,
        dpi      = dpi,
        bg       = "white"
      )
    ))
  }

  # Save SVG
  tryCatch({
    suppressMessages(suppressWarnings(
      ggplot2::ggsave(
        filename = svg_path,
        plot     = plot,
        width    = width,
        height   = height,
        device   = "svg",
        bg       = "white"
      )
    ))
  }, error = function(e) {
    # SVG might fail on some systems, that's ok
    NULL
  })

  tryCatch({
    suppressMessages(suppressWarnings(
      ggplot2::ggsave(
        filename = pdf_path,
        plot     = plot,
        width    = width,
        height   = height,
        device   = grDevices::pdf,
        bg       = "white"
      )
    ))
  }, error = function(e) {
    NULL
  })

  invisible(c(
    png = png_path,
    svg = if (file.exists(svg_path)) svg_path else NA_character_,
    pdf = if (file.exists(pdf_path)) pdf_path else NA_character_
  ))
}

#' Export a recorded base-R plot artifact to PNG, SVG, and PDF
#'
#' @param plot A recordedplot object.
#' @param path Character. Output file path without extension.
#' @param width Numeric. Width in inches.
#' @param height Numeric. Height in inches.
#' @param dpi Numeric. Resolution in DPI.
#' @return Invisibly returns the character vector of paths.
#' @keywords internal
export_recorded_plot_artifact <- function(plot, path,
                                          width = 10,
                                          height = 6,
                                          dpi = 300) {
  dir.create(dirname(path), recursive = TRUE, showWarnings = FALSE)

  png_path <- paste0(path, ".png")
  svg_path <- paste0(path, ".svg")
  pdf_path <- paste0(path, ".pdf")
  pixel_width <- max(1L, as.integer(round(width * dpi)))
  pixel_height <- max(1L, as.integer(round(height * dpi)))

  grDevices::png(filename = png_path, width = pixel_width, height = pixel_height, res = dpi)
  tryCatch({
    grDevices::replayPlot(plot)
  }, finally = {
    grDevices::dev.off()
  })

  tryCatch({
    grDevices::svg(filename = svg_path, width = width, height = height)
    tryCatch({
      grDevices::replayPlot(plot)
    }, finally = {
      grDevices::dev.off()
    })
  }, error = function(e) {
    NULL
  })

  tryCatch({
    grDevices::pdf(file = pdf_path, width = width, height = height)
    tryCatch({
      grDevices::replayPlot(plot)
    }, finally = {
      grDevices::dev.off()
    })
  }, error = function(e) {
    NULL
  })

  invisible(c(
    png = png_path,
    svg = if (file.exists(svg_path)) svg_path else NA_character_,
    pdf = if (file.exists(pdf_path)) pdf_path else NA_character_
  ))
}
# <<< END FILE: R/services/plot_export_service.R

# >>> BEGIN FILE: R/services/report_service.R
# ============================================================================
# report_service.R - Text report export service
# ============================================================================

#' Write a text report file
#'
#' @param lines Character vector. Lines of text.
#' @param path Character. Output file path.
#' @return Invisibly returns the path on success, NULL on failure.
#' @export
write_text_report <- function(lines, path) {
  # Validate input
  if (!is.character(lines)) {
    cli::cli_warn("lines must be a character vector")
    return(invisible(NULL))
  }
  
  if (length(lines) == 0) {
    cli::cli_warn("lines is empty, nothing to write")
    return(invisible(NULL))
  }
  
  # Validate path
  if (!is.character(path) || length(path) != 1) {
    cli::cli_warn("path must be a single character string")
    return(invisible(NULL))
  }
  
  # Create directory if needed
  dir_path <- dirname(path)
  if (!dir.exists(dir_path)) {
    dir_created <- dir.create(dir_path, recursive = TRUE, showWarnings = FALSE)
    if (!dir_created && !dir.exists(dir_path)) {
      cli::cli_warn("Failed to create directory: {dir_path}")
      return(invisible(NULL))
    }
  }
  
  # Write with error handling
  tryCatch({
    writeLines(lines, path)
    cli::cli_alert_info("Report saved: {path}")
    invisible(path)
  }, error = function(e) {
    cli::cli_warn("Failed to write report to {path}: {e$message}")
    invisible(NULL)
  })
}
# <<< END FILE: R/services/report_service.R

# >>> BEGIN FILE: R/style/ieee_theme.R
# ============================================================================
# ieee_theme.R - IEEE publication theme and export sizing
# ============================================================================
# Export policy:
# - Single column: 3.50 in x 2.80 in
# - Full width:    7.16 in x 4.05 in
# The package may still use different plot themes internally (map, polar,
# timeseries), but export sizing is reduced to these two IEEE layouts.
# ============================================================================

#' IEEE theme for single-column figures (Enhanced)
#'
#' @param base_size Base font size (default 8pt for IEEE)
#' @param font_family Font family
#' @param grid_major Show major grid lines
#' @param grid_minor Show minor grid lines
#' @return A ggplot2 theme object
#' @export
ieee_theme <- function(base_size = 8, font_family = "sans",
                       grid_major = TRUE, grid_minor = FALSE) {
  t <- ggplot2::theme_bw(base_size = base_size, base_family = font_family)
  
  t <- t + ggplot2::theme(
    plot.title = ggplot2::element_text(
      size = base_size + 1.2, face = "bold", hjust = 0,
      margin = ggplot2::margin(b = 3, t = 0)
    ),
    plot.subtitle = ggplot2::element_text(
      size = base_size - 0.4, hjust = 0, face = "plain", color = "#333333",
      margin = ggplot2::margin(b = 4)
    ),
    plot.caption = ggplot2::element_text(
      size = base_size - 1.6, hjust = 0, color = "#555555",
      margin = ggplot2::margin(t = 4)
    ),
    axis.title = ggplot2::element_text(
      size = base_size, face = "bold",
      margin = ggplot2::margin(t = 4, r = 4, b = 2)
    ),
    axis.title.x = ggplot2::element_text(margin = ggplot2::margin(t = 6, b = 2)),
    axis.title.y = ggplot2::element_text(margin = ggplot2::margin(r = 6), angle = 90),
    axis.text = ggplot2::element_text(
      size = base_size - 1, color = "black",
      margin = ggplot2::margin(t = 2, r = 2)
    ),
    axis.text.x = ggplot2::element_text(angle = 0, hjust = 0.5, vjust = 0.5),
    axis.text.y = ggplot2::element_text(hjust = 1),
    axis.ticks = ggplot2::element_line(linewidth = 0.3, color = "black"),
    axis.ticks.length = ggplot2::unit(0.15, "cm"),
    axis.line = ggplot2::element_line(linewidth = 0.5, color = "black"),
    panel.border = ggplot2::element_rect(linewidth = 0.5, fill = NA, color = "black"),
    panel.grid.major = if (grid_major) {
      ggplot2::element_line(linewidth = 0.25, color = "#E0E0E0", linetype = "solid")
    } else {
      ggplot2::element_blank()
    },
    panel.grid.minor = if (grid_minor) {
      ggplot2::element_line(linewidth = 0.15, color = "#F0F0F0", linetype = "dotted")
    } else {
      ggplot2::element_blank()
    },
    panel.background = ggplot2::element_rect(fill = "white", color = NA),
    plot.background = ggplot2::element_rect(fill = "white", color = NA),
    legend.position = "bottom",
    legend.direction = "horizontal",
    legend.box = "horizontal",
    legend.justification = c(0.5, 0.5),
    legend.title = ggplot2::element_text(size = base_size - 1, face = "bold"),
    legend.text = ggplot2::element_text(size = base_size - 2),
    legend.key.size = ggplot2::unit(0.5, "cm"),
    legend.key = ggplot2::element_rect(fill = "white", color = NA),
    legend.background = ggplot2::element_rect(fill = "white", color = NA),
    legend.margin = ggplot2::margin(t = 2, r = 2, b = 2, l = 2),
    legend.box.background = ggplot2::element_rect(fill = NA, color = NA),
    legend.spacing = ggplot2::unit(0.1, "cm"),
    strip.background = ggplot2::element_rect(fill = "#F0F0F0", color = "black", linewidth = 0.3),
    strip.text = ggplot2::element_text(size = base_size - 1, face = "bold"),
    strip.text.x = ggplot2::element_text(margin = ggplot2::margin(t = 2, b = 2)),
    strip.text.y = ggplot2::element_text(angle = 0),
    plot.margin = ggplot2::margin(t = 7, r = 8, b = 7, l = 8)
  )
  
  t
}

